    def _sanitize_profile_id(self, raw: str) -> str:
        return sanitize_profile_id(raw)

    def _profile_cache_key(self, profile: dict | None = None, model_override: str = "") -> str:
        row = profile if isinstance(profile, dict) else dict(self.model_profiles.get(self.active_profile_id, {}))
        provider = str(row.get("provider", self.ollama.provider) or self.ollama.provider).strip().lower()
        base_url = str(row.get("base_url", self.ollama.base_url) or self.ollama.base_url).strip().lower()
        endpoint = str(row.get("endpoint", self.ollama.endpoint) or self.ollama.endpoint).strip().lower()
        model = str(model_override or row.get("model", self.ollama.model) or self.ollama.model).strip().lower()
        return "|".join([provider, base_url, endpoint, model])

    def _capabilities_from_profile(self, profile: dict | None = None, model_override: str = "") -> dict[str, bool]:
        row = profile if isinstance(profile, dict) else dict(self.model_profiles.get(self.active_profile_id, {}))
        provider = str(row.get("provider", self.ollama.provider) or self.ollama.provider)
        model = str(model_override or row.get("model", self.ollama.model) or self.ollama.model)
        declared = parse_capability_overrides(row.get("capabilities", {}))
        inferred = infer_model_multimodal_capabilities(provider, model)
        merged = merge_multimodal_capabilities(inferred, declared)
        key = self._profile_cache_key(row, model)
        cached = self.multimodal_capability_cache.get(key, {})
        if isinstance(cached, dict):
            merged = merge_multimodal_capabilities(merged, parse_capability_overrides(cached.get("capabilities", {})))
        return merged

    def _ensure_active_profile_capabilities(self, force_probe: bool = False) -> dict[str, bool]:
        profile = dict(self.model_profiles.get(self.active_profile_id, {}))
        if not profile:
            return default_multimodal_capabilities()
        key = self._profile_cache_key(profile)
        if not force_probe:
            cached = self.multimodal_capability_cache.get(key, {})
            if isinstance(cached, dict):
                caps = parse_capability_overrides(cached.get("capabilities", {}))
                if caps:
                    merged_cached = merge_multimodal_capabilities(
                        self._capabilities_from_profile(profile),
                        caps,
                    )
                    profile["capabilities"] = merged_cached
                    self.model_profiles[self.active_profile_id] = profile
                    return merged_cached
        try:
            probed = self.ollama.probe_multimodal_capabilities(force=True if force_probe else False)
            merged = merge_multimodal_capabilities(self._capabilities_from_profile(profile), probed)
            entry = self.ollama.probe_cache_entry()
            self.multimodal_capability_cache[key] = {
                "capabilities": merged,
                "details": entry.get("details", {}),
                "updated_at": float(entry.get("updated_at", now_ts()) or now_ts()),
                "provider": str(profile.get("provider", "")),
                "model": str(profile.get("model", "")),
            }
            profile["capabilities"] = merged
            self.model_profiles[self.active_profile_id] = profile
            self.updated_at = now_ts()
            self._persist()
            return merged
        except Exception as exc:
            merged = self._capabilities_from_profile(profile)
            self.multimodal_capability_cache[key] = {
                "capabilities": merged,
                "details": {"probe_error": trim(str(exc), 240)},
                "updated_at": now_ts(),
                "provider": str(profile.get("provider", "")),
                "model": str(profile.get("model", "")),
            }
            return merged

    def _recent_multimodal_inputs(self, max_items: int = 4, max_total_bytes: int = 12 * 1024 * 1024) -> list[dict]:
        caps = self._capabilities_from_profile()
        wants_image = bool(caps.get("input_image", False))
        wants_audio = bool(caps.get("input_audio", False))
        wants_video = bool(caps.get("input_video", False))
        if not (wants_image or wants_audio or wants_video):
            return []
        kind_allow = set()
        if wants_image:
            kind_allow.add("image")
        if wants_audio:
            kind_allow.add("audio")
        if wants_video:
            kind_allow.add("video")
        items: list[dict] = []
        used_rel: set[str] = set()
        total = 0
        with self.lock:
            rows = list(self.uploads)
        for row in reversed(rows):
            kind = str(row.get("kind", "") or "").strip().lower()
            if kind not in kind_allow:
                continue
            rel = str(row.get("workspace_path", "") or "").strip()
            if not rel:
                continue
            try:
                fp = safe_path(rel, self.files_root)
            except Exception:
                continue
            if not fp.exists() or not fp.is_file():
                continue
            # Skip image formats that need conversion — handled by _run_read_media
            if kind == "image" and fp.suffix.lower() in IMAGE_FORMATS_NEED_CONVERSION:
                continue
            size = int(fp.stat().st_size or 0)
            if size <= 0 or size > 20 * 1024 * 1024:
                continue
            if total + size > max_total_bytes:
                continue
            try:
                data = fp.read_bytes()
            except Exception:
                continue
            mime = str(row.get("mime", "") or "").strip() or guess_mime_from_name(str(row.get("filename", "") or ""), f"{kind}/octet-stream")
            items.append(
                {
                    "upload_id": str(row.get("id", "")),
                    "type": kind,
                    "name": str(row.get("filename", fp.name)),
                    "mime": mime,
                    "data_b64": base64.b64encode(data).decode("ascii"),
                    "workspace_path": rel,
                }
            )
            used_rel.add(rel)
            total += size
            if len(items) >= max_items:
                break
        items.reverse()
        if wants_image and len(items) < max_items and total < max_total_bytes:
            extra = self._recent_local_image_inputs(
                max_items=max_items - len(items),
                max_total_bytes=max_total_bytes - total,
                used_rel=used_rel,
            )
            items.extend(extra)
        # Merge pending media inputs from read_file (multimodal file reads)
        with self.lock:
            pending = list(getattr(self, "_pending_media_inputs", []))
            self._pending_media_inputs = []
        for media in pending:
            kind = str(media.get("type", "") or "").strip().lower()
            if kind not in kind_allow:
                continue
            rel = str(media.get("workspace_path", "") or "")
            if rel in used_rel:
                continue
            if len(items) >= max_items:
                break
            items.append(media)
            used_rel.add(rel)
        return items

    def _latest_user_message_ts(self) -> float:
        with self.lock:
            rows = list(self.messages)
        for row in reversed(rows):
            if str(row.get("role", "")).strip() != "user":
                continue
            try:
                return float(row.get("ts", 0.0) or 0.0)
            except Exception:
                return 0.0
        return 0.0

    def _emit_multimodal_attach_status(
        self,
        *,
        scope: str,
        media_inputs: list[dict] | None,
        caps: dict | None = None,
        roles: list[str] | None = None,
    ):
        rows = [x for x in (media_inputs or []) if isinstance(x, dict)]
        if not rows:
            return
        media_types = ",".join(sorted({str(x.get("type", "") or "").strip().lower() for x in rows if str(x.get("type", "") or "").strip()}))
        image_names = [
            str(x.get("name", "")).strip()
            for x in rows
            if str(x.get("type", "")).strip().lower() == "image" and str(x.get("name", "")).strip()
        ]
        name_preview = ", ".join(image_names[:3])
        role_text = ",".join(
            [r for r in [self._sanitize_agent_bubble_role(x) for x in (roles or [])] if r]
        )
        role_note = f"; roles={role_text}" if role_text else ""
        cap_note = f" capabilities={json_dumps(caps)}" if isinstance(caps, dict) and caps else ""
        self._emit(
            "status",
            {
                "summary": (
                    f"multimodal inputs attached ({scope}: {len(rows)} files: {media_types}"
                    f"{'; images=' + name_preview if name_preview else ''}{role_note}){cap_note}"
                )
            },
        )

    def _resolve_role_multimodal_payload(
        self,
        *,
        role: str,
        latest_user_ts: float,
        media_inputs_pool: list[dict] | None,
        media_seen_ts_by_role: dict[str, float],
    ) -> list[dict] | None:
        role_key = self._sanitize_agent_bubble_role(role)
        if (not role_key) or (not media_inputs_pool) or latest_user_ts <= 0:
            return None
        seen_ts = float(media_seen_ts_by_role.get(role_key, 0.0) or 0.0)
        if latest_user_ts <= seen_ts:
            return None
        media_seen_ts_by_role[role_key] = latest_user_ts
        return list(media_inputs_pool)

    def _recent_local_image_inputs(
        self,
        *,
        max_items: int,
        max_total_bytes: int,
        used_rel: set[str] | None = None,
    ) -> list[dict]:
        out: list[dict] = []
        if max_items <= 0 or max_total_bytes <= 0:
            return out
        seen = set(used_rel or set())
        total = 0

        def accept_file(fp: Path):
            nonlocal total
            if not fp.exists() or (not fp.is_file()):
                return
            if fp.suffix.lower() not in IMAGE_EXTS:
                return
            if fp.suffix.lower() in IMAGE_FORMATS_NEED_CONVERSION:
                return
            try:
                rel = self._session_rel(fp)
            except Exception:
                return
            if rel in seen:
                return
            try:
                size = int(fp.stat().st_size or 0)
            except Exception:
                return
            if size <= 0 or size > 20 * 1024 * 1024:
                return
            if total + size > max_total_bytes:
                return
            try:
                data = fp.read_bytes()
            except Exception:
                return
            mime = guess_mime_from_name(fp.name, "image/png")
            out.append(
                {
                    "upload_id": "",
                    "type": "image",
                    "name": fp.name,
                    "mime": mime,
                    "data_b64": base64.b64encode(data).decode("ascii"),
                    "workspace_path": rel,
                    "source": "local_file",
                }
            )
            total += size
            seen.add(rel)

        # Priority 1: image paths explicitly mentioned by user in recent messages.
        tokens: list[str] = []
        with self.lock:
            recent_msgs = list(self.messages[-80:])
        for row in reversed(recent_msgs):
            if str(row.get("role", "")).strip() != "user":
                continue
            content = str(row.get("content", "") or "")
            for m in re.finditer(r"([^\s\"'<>]+?\.(?:png|jpg|jpeg|webp|bmp|gif|tiff|tif|avif|heic|heif|svg))", content, re.IGNORECASE):
                token = str(m.group(1) or "").strip()
                if token and token not in tokens:
                    tokens.append(token)
            if len(tokens) >= 24:
                break
        for raw in tokens:
            if len(out) >= max_items:
                break
            candidate = raw.strip().strip("()[]{}")
            if not candidate:
                continue
            if candidate.startswith("file://"):
                candidate = candidate[7:]
            candidate_path = Path(candidate)
            try:
                fp = candidate_path.resolve() if candidate_path.is_absolute() else safe_path(candidate, self.files_root)
            except Exception:
                continue
            if fp.is_absolute():
                try:
                    if not fp.resolve().is_relative_to(self.files_root.resolve()):
                        continue
                except Exception:
                    continue
            accept_file(fp)

        # Priority 2: latest image files in session workspace.
        if len(out) < max_items:
            candidates: list[Path] = []
            try:
                for fp in self.files_root.rglob("*"):
                    if len(candidates) >= 320:
                        break
                    if not fp.is_file():
                        continue
                    if fp.suffix.lower() not in IMAGE_EXTS:
                        continue
                    candidates.append(fp)
            except Exception:
                candidates = []
            try:
                candidates.sort(key=lambda p: p.stat().st_mtime, reverse=True)
            except Exception:
                pass
            for fp in candidates:
                if len(out) >= max_items:
                    break
                accept_file(fp)
        return out[:max_items]

    def _save_generated_media(self, media_type: str, payload: dict, filename: str = "") -> dict:
        mtype = str(media_type or "").strip().lower()
        blob = payload.get("bytes", b"")
        if not isinstance(blob, (bytes, bytearray)) or not blob:
            raise ValueError("generated media payload is empty")
        mime = str(payload.get("mime", "") or f"{mtype}/octet-stream").split(";", 1)[0].strip().lower()
        ext = guess_ext_from_mime(mime, fallback=f".{mtype if mtype else 'bin'}")
        safe_name = self._safe_upload_name(filename or f"generated_{mtype}{ext}")
        if "." not in safe_name:
            safe_name = f"{safe_name}{ext}"
        target = self.files_root / "generated_media" / safe_name
        target.parent.mkdir(parents=True, exist_ok=True)
        i = 2
        while target.exists():
            target = target.with_name(f"{target.stem}_{i}{target.suffix}")
            i += 1
        target.write_bytes(bytes(blob))
        workspace_rel = self._session_rel(target)
        upload_id = make_id("gen")
        meta = {
            "id": upload_id,
            "filename": target.name,
            "original_name": filename or target.name,
            "mime": mime,
            "kind": mtype,
            "size": int(target.stat().st_size),
            "uploaded_at": now_ts(),
            "stored_path": str(target),
            "workspace_path": workspace_rel,
            "parsed_excerpt": "",
            "generated": True,
        }
        with self.lock:
            self.uploads.append(meta)
            self.uploads = self.uploads[-80:]
            self.updated_at = now_ts()
            self._persist()
        self._emit(
            "upload",
            {
                "filename": target.name,
                "workspace_path": workspace_rel,
                "kind": mtype,
                "size": int(target.stat().st_size),
                "summary": f"generated {mtype}: {workspace_rel}",
                "preview": "",
            },
        )
        return {
            "ok": True,
            "media_type": mtype,
            "workspace_path": workspace_rel,
            "filename": target.name,
            "mime": mime,
            "size": int(target.stat().st_size),
        }

    def _ensure_ollama_profile(self):
        for pid, profile in list(self.model_profiles.items()):
            if str(profile.get("provider", "")).lower() != "ollama":
                continue
            row = dict(profile)
            sid = self._sanitize_profile_id(str(row.get("id", pid) or pid))
            model = str(row.get("model", self.ollama.model) or self.ollama.model).strip()
            base = extract_base_url(str(row.get("base_url", self.ollama.base_url) or self.ollama.base_url)).strip()
            row["id"] = sid
            row["label"] = str(row.get("label", "") or "Ollama").strip() or "Ollama"
            row["model"] = model
            row["base_url"] = base
            row["selection"] = f"{sid}::{row.get('model','')}"
            self.model_profiles[sid] = row
            if sid != pid:
                self.model_profiles.pop(pid, None)
            return
        if self.model_profiles:
            return
        self.model_profiles["ollama"] = {
            "id": "ollama",
            "provider": "ollama",
            "label": "Ollama",
            "model": self.ollama.model,
            "base_url": self.ollama.base_url,
            "temperature": 0.2,
            "request_timeout": DEFAULT_REQUEST_TIMEOUT,
            "selection": f"ollama::{self.ollama.model}",
            "capabilities": infer_model_multimodal_capabilities("ollama", self.ollama.model),
            "media_endpoints": {},
            "source": "fallback",
        }

    def _init_llm_profiles(self, config: dict):
        parsed = parse_llm_config_profiles(config, self.ollama.base_url, self.ollama.model)
        self.model_profiles = {}
        for idx, profile in enumerate(parsed.get("profiles", [])):
            pid = self._sanitize_profile_id(str(profile.get("id") or f"profile-{idx+1}"))
            if pid in self.model_profiles:
                n = 2
                while f"{pid}-{n}" in self.model_profiles:
                    n += 1
                pid = f"{pid}-{n}"
            row = dict(profile)
            row["id"] = pid
            row["selection"] = f"{pid}::{row.get('model','')}"
            self.model_profiles[pid] = row
        if not self.model_profiles:
            fallback = {
                "id": "ollama",
                "provider": "ollama",
                "label": "Ollama",
                "model": self.ollama.model,
                "base_url": self.ollama.base_url,
                "temperature": 0.2,
                "request_timeout": DEFAULT_REQUEST_TIMEOUT,
                "selection": f"ollama::{self.ollama.model}",
                "capabilities": infer_model_multimodal_capabilities("ollama", self.ollama.model),
                "media_endpoints": {},
                "source": "fallback",
            }
            self.model_profiles["ollama"] = fallback
        self._ensure_ollama_profile()
        requested = self._sanitize_profile_id(str(parsed.get("default_profile_id", "")))
        self.active_profile_id = requested if requested in self.model_profiles else next(iter(self.model_profiles.keys()))
        self._apply_active_profile()

    def _apply_active_profile(self):
        profile = self.model_profiles.get(self.active_profile_id)
        if not profile:
            return
        row = dict(profile)
        timeout_floor = max(MIN_TIMEOUT_SECONDS, int(self.max_run_seconds or 0))
        row["request_timeout"] = normalize_timeout_seconds(
            row.get("request_timeout", DEFAULT_REQUEST_TIMEOUT),
            minimum=timeout_floor,
            maximum=MAX_TIMEOUT_SECONDS,
            fallback=max(DEFAULT_REQUEST_TIMEOUT, timeout_floor),
        )
        key = self._profile_cache_key(row)
        cached = self.multimodal_capability_cache.get(key, {})
        if isinstance(cached, dict):
            cached_caps = parse_capability_overrides(cached.get("capabilities", {}))
            if cached_caps:
                merged = merge_multimodal_capabilities(self._capabilities_from_profile(row), cached_caps)
                row["capabilities"] = merged
                self.model_profiles[self.active_profile_id] = row
        self.model_profiles[self.active_profile_id] = row
        profile = row
        self.ollama.apply_profile(profile)
        self.thinking = False

    def _profile_is_runnable(self, profile: dict) -> bool:
        if not isinstance(profile, dict):
            return False
        provider = str(profile.get("provider", "") or "").strip().lower()
        model = str(profile.get("model", "") or "").strip()
        if provider in {"", "unknown", "config_only"}:
            return False
        if not model:
            return False
        if provider == "ollama":
            base = str(profile.get("base_url", self.ollama.base_url) or self.ollama.base_url).strip()
            return bool(base)
        if is_openai_compat_provider(provider):
            endpoint = str(profile.get("endpoint", "") or "").strip()
            base = str(profile.get("base_url", "") or "").strip()
            return bool(endpoint or complete_chat_endpoint(base))
        if provider == "custom_http":
            endpoint = str(profile.get("endpoint", "") or "").strip()
            return bool(endpoint)
        if provider == "anthropic":
            api_key = str(profile.get("api_key", "") or "").strip()
            endpoint = str(profile.get("endpoint", "") or "").strip()
            base = str(profile.get("base_url", "") or "").strip()
            return bool(api_key and (endpoint or base))
        return False

    def _option_is_runnable(self, option: dict) -> bool:
        if not isinstance(option, dict):
            return False
        pid = str(option.get("profile_id", "") or "")
        base = dict(self.model_profiles.get(pid, {}))
        if option.get("provider") is not None:
            base["provider"] = option.get("provider")
        if option.get("model") is not None:
            base["model"] = option.get("model")
        if str(base.get("provider", "")).lower() == "ollama" and not str(base.get("base_url", "")).strip():
            base["base_url"] = self.ollama.base_url
        return self._profile_is_runnable(base)

    def _pick_runnable_selection(self, preferred_provider: str = "", exclude: set[str] | None = None) -> str:
        blocked = set(exclude or set())
        entries = list(self.model_catalog().get("options", []))
        if preferred_provider:
            pref = str(preferred_provider or "")
            entries.sort(
                key=lambda x: (
                    0 if str(x.get("provider", "")) == pref else 1,
                    str(x.get("profile_id", "")),
                )
            )
        for item in entries:
            selection = str(item.get("selection", "") or "")
            if not selection or selection in blocked:
                continue
            if not self._option_is_runnable(item):
                continue
            return selection
        return ""

    def model_catalog(self, force_probe: bool = False) -> dict:
        if force_probe:
            self._ensure_active_profile_capabilities(force_probe=True)
        opts = []
        ollama_profile_id = ""
        ollama_base = self.ollama.base_url
        for pid, profile in sorted(self.model_profiles.items(), key=lambda x: x[0]):
            model = str(profile.get("model", "") or "")
            selection = f"{pid}::{model}"
            label = f"{profile.get('label', pid)} | {model or '(no-model)'}"
            cache_key = self._profile_cache_key(profile)
            cache_entry = self.multimodal_capability_cache.get(cache_key, {})
            caps = self._capabilities_from_profile(profile)
            if (not ollama_profile_id) and str(profile.get("provider", "")).lower() == "ollama":
                ollama_profile_id = pid
                ollama_base = str(profile.get("base_url", ollama_base) or ollama_base)
            opts.append(
                {
                    "selection": selection,
                    "profile_id": pid,
                    "provider": profile.get("provider", "unknown"),
                    "model": model,
                    "label": label,
                    "source": profile.get("source", ""),
                    "thinking_hint": bool(profile.get("thinking_hint", False)),
                    "thinking_stream": bool(profile.get("thinking_stream", False)),
                    "capabilities": caps,
                    "capabilities_probed": bool(cache_entry),
                    "capabilities_probed_at": float(cache_entry.get("updated_at", 0.0) or 0.0)
                    if isinstance(cache_entry, dict)
                    else 0.0,
                }
            )
        if not ollama_profile_id:
            ollama_profile_id = "ollama"
        seen = {str(x.get("selection", "")) for x in opts}
        for pid, profile in sorted(self.model_profiles.items(), key=lambda x: x[0]):
            if str(profile.get("provider", "")).lower() != "ollama":
                continue
            base = str(profile.get("base_url", self.ollama.base_url) or self.ollama.base_url).strip()
            if not base:
                continue
            tags = list_ollama_models_cached(base, force_refresh=bool(force_probe))
            if tags:
                if pid == self.active_profile_id:
                    self.ollama_env_tags = list(tags)
            elif pid == self.active_profile_id and self.ollama_env_tags:
                tags = list(self.ollama_env_tags)
            for tag in tags:
                selection = f"{pid}::{tag}"
                if selection in seen:
                    continue
                seen.add(selection)
                tag_profile = dict(profile)
                tag_profile["model"] = tag
                tag_cache_key = self._profile_cache_key(tag_profile, tag)
                tag_cache_entry = self.multimodal_capability_cache.get(tag_cache_key, {})
                tag_caps = self._capabilities_from_profile(tag_profile, model_override=tag)
                opts.append(
                    {
                        "selection": selection,
                        "profile_id": pid,
                        "provider": "ollama",
                        "model": tag,
                        "label": f"{profile.get('label', 'Ollama')} | {tag}",
                        "source": "ollama-tags",
                        "thinking_hint": bool(profile.get("thinking_hint", self.thinking)),
                        "thinking_stream": bool(profile.get("thinking_stream", self.ollama.thinking_stream)),
                        "capabilities": tag_caps,
                        "capabilities_probed": bool(tag_cache_entry),
                        "capabilities_probed_at": float(tag_cache_entry.get("updated_at", 0.0) or 0.0)
                        if isinstance(tag_cache_entry, dict)
                        else 0.0,
                    }
                )
        runnable_opts = [x for x in opts if self._option_is_runnable(x)]
        if runnable_opts:
            opts = runnable_opts
        active = self.model_profiles.get(self.active_profile_id, {})
        selected = f"{self.active_profile_id}::{active.get('model','')}" if active else ""
        option_map = {str(x.get("selection", "")) for x in opts}
        if active and selected and selected not in option_map:
            active_cache_key = self._profile_cache_key(active if isinstance(active, dict) else {})
            active_cache_entry = self.multimodal_capability_cache.get(active_cache_key, {})
            opts.insert(
                0,
                {
                    "selection": selected,
                    "profile_id": self.active_profile_id,
                    "provider": active.get("provider", "unknown"),
                    "model": str(active.get("model", "") or ""),
                    "label": f"{active.get('label', self.active_profile_id)} | {str(active.get('model', '') or '(no-model)')}",
                    "source": active.get("source", "active-profile"),
                    "thinking_hint": bool(active.get("thinking_hint", False)),
                    "thinking_stream": bool(active.get("thinking_stream", False)),
                    "capabilities": self._capabilities_from_profile(active if isinstance(active, dict) else {}),
                    "capabilities_probed": bool(active_cache_entry),
                    "capabilities_probed_at": float(active_cache_entry.get("updated_at", 0.0) or 0.0)
                    if isinstance(active_cache_entry, dict)
                    else 0.0,
                },
            )
            option_map.add(selected)
        if opts and selected not in option_map:
            selected = str(opts[0].get("selection", ""))
        active_caps = self._capabilities_from_profile(active if isinstance(active, dict) else {})
        active_cache = self.multimodal_capability_cache.get(self._profile_cache_key(active if isinstance(active, dict) else {}), {})
        return {
            "provider": active.get("provider", "ollama"),
            "selected": selected,
            "models": [x["selection"] for x in opts],
            "options": opts,
            "thinking": self.thinking,
            "thinking_mode": "auto",
            "active_capabilities": active_caps,
            "active_capabilities_probed": bool(active_cache),
            "active_capabilities_probed_at": float(active_cache.get("updated_at", 0.0) or 0.0)
            if isinstance(active_cache, dict)
            else 0.0,
        }

    def set_runtime_selection(
        self,
        selection: str,
        model_override: str | None = None,
        *,
        reset_failures: bool = True,
    ) -> dict:
        raw = str(selection or "").strip()
        explicit_profile = "::" in raw
        if "::" in raw:
            pid, selected_model = raw.split("::", 1)
        else:
            pid, selected_model = self.active_profile_id, raw
        pid = self._sanitize_profile_id(pid)
        if pid not in self.model_profiles:
            if pid.startswith("ollama"):
                self.model_profiles[pid] = {
                    "id": pid,
                    "provider": "ollama",
                    "label": "Ollama",
                    "model": self.ollama.model,
                    "base_url": self.ollama.base_url,
                    "temperature": 0.2,
                    "request_timeout": DEFAULT_REQUEST_TIMEOUT,
                    "selection": f"{pid}::{self.ollama.model}",
                    "capabilities": infer_model_multimodal_capabilities("ollama", self.ollama.model),
                    "media_endpoints": {},
                    "source": "auto-added",
                }
            else:
                raise ValueError(f"profile not found: {pid}")
        profile = dict(self.model_profiles[pid])
        if model_override is not None and str(model_override).strip():
            profile["model"] = str(model_override).strip()
        elif str(selected_model).strip():
            profile["model"] = str(selected_model).strip()
        if not self._profile_is_runnable(profile) and not explicit_profile and str(selected_model).strip():
            fallback = self._pick_runnable_selection(preferred_provider="ollama")
            if fallback:
                fpid = self._sanitize_profile_id(fallback.split("::", 1)[0])
                if fpid in self.model_profiles:
                    pid = fpid
                    profile = dict(self.model_profiles[fpid])
                    profile["model"] = str(selected_model).strip()
        if not self._profile_is_runnable(profile):
            provider = str(profile.get("provider", "") or "unknown")
            model_text = str(profile.get("model", "") or "")
            raise ValueError(
                f"profile '{pid}' is not runnable (provider={provider}, model={model_text or '(empty)'})"
            )
        profile["selection"] = f"{pid}::{profile.get('model','')}"
        self.model_profiles[pid] = profile
        self.active_profile_id = pid
        if reset_failures:
            self.failed_selections = []
        self._apply_active_profile()
        self._ensure_active_profile_capabilities(force_probe=False)
        self.updated_at = now_ts()
        self._persist()
        self._emit(
            "status",
            {
                "summary": f"model selected: {profile.get('provider')} / {profile.get('model','')}",
            },
        )
        return self.model_catalog()

    def load_llm_config(self, config: dict, source: str = "") -> dict:
        parsed = parse_llm_config_profiles(config, self.ollama.base_url, self.ollama.model)
        self.multimodal_capability_cache = {}
        OllamaClient.clear_global_probe_cache()
        self.ollama.clear_probe_cache()
        merged: dict[str, dict] = {}
        for idx, profile in enumerate(parsed.get("profiles", [])):
            pid = self._sanitize_profile_id(str(profile.get("id") or f"profile-{idx+1}"))
            row = dict(profile)
            row["id"] = pid
            row["source"] = source or row.get("source", "uploaded-config")
            row["selection"] = f"{pid}::{row.get('model','')}"
            merged[pid] = row
        self.model_profiles = merged
        self._ensure_ollama_profile()
        if not self.model_profiles:
            self._init_llm_profiles({})
        default_pid = self._sanitize_profile_id(str(parsed.get("default_profile_id", "")))
        if default_pid in self.model_profiles:
            self.active_profile_id = default_pid
        elif not self.active_profile_id or self.active_profile_id not in self.model_profiles:
            self.active_profile_id = next(iter(self.model_profiles.keys()))
        active_profile = dict(self.model_profiles.get(self.active_profile_id, {}))
        if not self._profile_is_runnable(active_profile):
            fallback = self._pick_runnable_selection()
            if fallback:
                fpid, fmodel = fallback.split("::", 1) if "::" in fallback else (self.active_profile_id, "")
                self.active_profile_id = self._sanitize_profile_id(fpid)
                if self.active_profile_id in self.model_profiles and fmodel.strip():
                    row = dict(self.model_profiles[self.active_profile_id])
                    row["model"] = fmodel.strip()
                    row["selection"] = f"{self.active_profile_id}::{row.get('model','')}"
                    self.model_profiles[self.active_profile_id] = row
        self._apply_active_profile()
        self._ensure_active_profile_capabilities(force_probe=False)
        self.updated_at = now_ts()
        self._persist()
        self._emit(
            "model_config",
            {
                "source": source,
                "profiles": len(parsed.get("profiles", [])),
                "active_profile": self.active_profile_id,
                "summary": f"llm config loaded: {len(parsed.get('profiles', []))} profiles",
            },
        )
        return self.model_catalog()

    def _load_if_exists(self):
        if self.state_path.exists():
            try:
                raw = self.crypto.read_json(self.state_path, {})
                self.messages = raw.get("messages", [])
                self.activity = raw.get("activity", [])
                self.operations = raw.get("operations", [])
                raw_code_preview = raw.get("code_preview_index", {})
                if isinstance(raw_code_preview, dict):
                    clean_code_preview: dict[str, list[dict]] = {}
                    for path_key, stage_rows in raw_code_preview.items():
                        rel = normalize_rel_preview_path(path_key)
                        if not rel or (not isinstance(stage_rows, list)):
                            continue
                        normalized_rows: list[dict] = []
                        for row in stage_rows[-(CODE_PREVIEW_STAGE_MAX_PER_FILE * 2) :]:
                            if not isinstance(row, dict):
                                continue
                            sid = str(row.get("id", "") or "").strip()
                            if not sid:
                                continue
                            normalized_rows.append(
                                {
                                    "id": sid,
                                    "ts": float(row.get("ts", 0.0) or 0.0),
                                    "path": rel,
                                    "tool": str(row.get("tool", "") or ""),
                                    "change_type": str(row.get("change_type", "") or ""),
                                    "added": int(row.get("added", 0) or 0),
                                    "deleted": int(row.get("deleted", 0) or 0),
                                    "before_blob": str(row.get("before_blob", "") or ""),
                                    "after_blob": str(row.get("after_blob", "") or ""),
                                    "bytes_after": int(row.get("bytes_after", 0) or 0),
                                    "lines_after": int(row.get("lines_after", 0) or 0),
                                }
                            )
                        if normalized_rows:
                            clean_code_preview[rel] = normalized_rows[-CODE_PREVIEW_STAGE_MAX_PER_FILE :]
                    self.code_preview_index = clean_code_preview
                self.teammates = raw.get("teammates", {})
                uploads = raw.get("uploads", [])
                self.uploads = uploads if isinstance(uploads, list) else []
                profiles = raw.get("model_profiles", {})
                if isinstance(profiles, dict) and profiles:
                    self.model_profiles = {}
                    for k, v in profiles.items():
                        if not isinstance(v, dict):
                            continue
                        pid = self._sanitize_profile_id(str(k))
                        row = dict(v)
                        row["id"] = pid
                        row["selection"] = f"{pid}::{row.get('model','')}"
                        self.model_profiles[pid] = row
                raw_cap_cache = raw.get("multimodal_capability_cache", {})
                if isinstance(raw_cap_cache, dict):
                    clean_cache: dict[str, dict] = {}
                    for ckey, centry in raw_cap_cache.items():
                        key = str(ckey or "").strip()
                        if not key or not isinstance(centry, dict):
                            continue
                        caps = parse_capability_overrides(centry.get("capabilities", {}))
                        clean_cache[key] = {
                            "capabilities": merge_multimodal_capabilities(default_multimodal_capabilities(), caps),
                            "details": centry.get("details", {}) if isinstance(centry.get("details"), dict) else {},
                            "updated_at": float(centry.get("updated_at", 0.0) or 0.0),
                            "provider": str(centry.get("provider", "")),
                            "model": str(centry.get("model", "")),
                        }
                    self.multimodal_capability_cache = clean_cache
                raw_skill_cache = raw.get("skill_load_cache", {})
                if isinstance(raw_skill_cache, dict):
                    clean_skill_cache: dict[str, dict] = {}
                    for skey, srow in raw_skill_cache.items():
                        key = str(skey or "").strip()
                        if not key or not isinstance(srow, dict):
                            continue
                        body_z = str(srow.get("body_z", "") or "").strip()
                        if not body_z:
                            continue
                        clean_skill_cache[key] = {
                            "fingerprint": str(srow.get("fingerprint", "") or ""),
                            "body_z": body_z,
                            "updated_at": float(srow.get("updated_at", 0.0) or 0.0),
                        }
                    self.skill_load_cache = clean_skill_cache
                active = raw.get("active_profile_id")
                if isinstance(active, str) and active.strip():
                    self.active_profile_id = self._sanitize_profile_id(active)
                self.todo.items = raw.get("todos", [])
                self.thinking = False
                self.context_token_upper_bound = int(
                    raw.get("context_token_upper_bound", self.context_token_upper_bound)
                )
                self.context_token_upper_bound = max(
                    MIN_CONTEXT_TOKEN_LIMIT,
                    min(self.max_context_token_limit, self.context_token_upper_bound),
                )
                self.truncation_count = int(raw.get("truncation_count", self.truncation_count) or 0)
                self.last_truncation_ts = float(raw.get("last_truncation_ts", self.last_truncation_ts) or 0.0)
                ids = raw.get("truncation_rescue_task_ids", [])
                if isinstance(ids, list):
                    clean_ids = []
                    for x in ids:
                        try:
                            clean_ids.append(int(x))
                        except Exception:
                            pass
                    self.truncation_rescue_task_ids = clean_ids[:12]
                archives = raw.get("context_archives", [])
                if isinstance(archives, list):
                    clean_archives = []
                    for seg in archives[-(MAX_CONTEXT_ARCHIVE_SEGMENTS * 2):]:
                        if not isinstance(seg, dict):
                            continue
                        sid = str(seg.get("id", "")).strip()
                        rel_path = str(seg.get("path", "")).strip()
                        if not sid or not rel_path:
                            continue
                        clean_archives.append(
                            {
                                "id": sid,
                                "path": rel_path,
                                "reason": str(seg.get("reason", "")),
                                "messages": int(seg.get("messages", 0) or 0),
                                "bytes": int(seg.get("bytes", 0) or 0),
                                "sha256": str(seg.get("sha256", "")),
                                "created_at": float(seg.get("created_at", 0.0) or 0.0),
                                "first_ts": float(seg.get("first_ts", 0.0) or 0.0),
                                "last_ts": float(seg.get("last_ts", 0.0) or 0.0),
                            }
                        )
                    self.context_archives = clean_archives[-MAX_CONTEXT_ARCHIVE_SEGMENTS:]
                # Restore file_buffer_index
                raw_fbi = raw.get("file_buffer_index", {})
                if isinstance(raw_fbi, dict):
                    clean_fbi: dict[str, dict] = {}
                    for ref_id, entry in raw_fbi.items():
                        if isinstance(entry, dict) and entry.get("path"):
                            clean_fbi[str(ref_id)] = {
                                "path": str(entry.get("path", "")),
                                "chars": int(entry.get("chars", 0) or 0),
                                "summary": trim(str(entry.get("summary", "") or ""), 200),
                            }
                    self.file_buffer_index = clean_fbi
                self.last_compact_reason = str(raw.get("last_compact_reason", self.last_compact_reason) or "")
                self.last_compact_ts = float(raw.get("last_compact_ts", self.last_compact_ts) or 0.0)
                pref = str(raw.get("plan_mode_user_preference", "auto") or "auto").lower()
                self.plan_mode_user_preference = pref if pref in PLAN_MODE_USER_CHOICES else "auto"
                self.reviewer_debug_mode = bool(raw.get("reviewer_debug_mode", False))
                self.reviewer_debug_rounds = int(raw.get("reviewer_debug_rounds", 0) or 0)
                self.reviewer_debug_context = trim(str(raw.get("reviewer_debug_context", "") or ""), 1000)
                self.developer_edit_fail_streaks = dict(raw.get("developer_edit_fail_streaks", {})) if isinstance(raw.get("developer_edit_fail_streaks"), dict) else {}
                self.developer_edit_last_diag = {}
                pending_inputs = raw.get("pending_user_inputs", [])
                if isinstance(pending_inputs, list):
                    clean_pending: list[dict] = []
                    for row in pending_inputs[-60:]:
                        if not isinstance(row, dict):
                            continue
                        text = trim(str(row.get("content", "") or "").strip(), 6000)
                        if not text:
                            continue
                        clean_pending.append(
                            {
                                "id": int(row.get("id", 0) or 0),
                                "content": text,
                                "queued_at": float(row.get("queued_at", 0.0) or 0.0),
                                "queued_round": int(row.get("queued_round", 0) or 0),
                                "delay_rounds": int(row.get("delay_rounds", 0) or 0),
                                "next_round": int(row.get("next_round", 0) or 0),
                                "applied_count": int(row.get("applied_count", 0) or 0),
                                "last_applied_round": int(row.get("last_applied_round", -1) or -1),
                                "delay_reason": str(row.get("delay_reason", "")),
                                "run_generation": int(row.get("run_generation", 0) or 0),
                            }
                        )
                    self.pending_user_inputs = clean_pending[-40:]
                    max_id = 0
                    for row in self.pending_user_inputs:
                        try:
                            max_id = max(max_id, int(row.get("id", 0) or 0))
                        except Exception:
                            continue
                    self.live_input_seq = max(self.live_input_seq, max_id)
                self.run_generation = int(raw.get("run_generation", self.run_generation) or self.run_generation)
                self.agent_round_index = int(raw.get("agent_round_index", self.agent_round_index) or 0)
                self.current_phase = str(raw.get("current_phase", self.current_phase) or "idle")
                self.current_tool_name = str(raw.get("current_tool_name", self.current_tool_name) or "")
                self.execution_mode = normalize_execution_mode(
                    raw.get("execution_mode", self.execution_mode),
                    default=self.execution_mode,
                )
                try:
                    lvl = int(raw.get("runtime_task_level", self.runtime_task_level) or 0)
                except Exception:
                    lvl = 0
                self.runtime_task_level = lvl if lvl in TASK_LEVEL_CHOICES else 0
                try:
                    _utlo = int(raw.get("user_task_level_override", 0) or 0)
                except Exception:
                    _utlo = 0
                self.user_task_level_override = _utlo if _utlo in (0, *TASK_LEVEL_CHOICES) else 0
                self.runtime_execution_mode = normalize_execution_mode(
                    raw.get("runtime_execution_mode", self.runtime_execution_mode),
                    default="",
                )
                self.runtime_assigned_expert = self._sanitize_agent_role(
                    raw.get("runtime_assigned_expert", self.runtime_assigned_expert)
                )
                raw_participants = raw.get("runtime_participants", [])
                participants: list[str] = []
                if isinstance(raw_participants, list):
                    for item in raw_participants[:8]:
                        role = self._sanitize_agent_role(item)
                        if role and role not in participants:
                            participants.append(role)
                self.runtime_participants = participants[:3]
                try:
                    self.runtime_round_budget = int(raw.get("runtime_round_budget", self.runtime_round_budget) or 0)
                except Exception:
                    self.runtime_round_budget = 0
                self.runtime_requires_confirmation = bool(
                    raw.get("runtime_requires_confirmation", self.runtime_requires_confirmation)
                )
                self.runtime_confirmation_needed = bool(
                    raw.get("runtime_confirmation_needed", self.runtime_confirmation_needed)
                )
                self.runtime_task_judgement = trim(
                    str(raw.get("runtime_task_judgement", self.runtime_task_judgement) or ""),
                    200,
                )
                self.runtime_task_type = trim(str(raw.get("runtime_task_type", self.runtime_task_type) or ""), 40)
                self.runtime_task_complexity = trim(
                    str(raw.get("runtime_task_complexity", self.runtime_task_complexity) or ""),
                    20,
                )
                scale_pref = str(raw.get("runtime_scale_preference", self.runtime_scale_preference) or "").strip().lower()
                self.runtime_scale_preference = scale_pref if scale_pref in TASK_SCALE_PREFERENCES else "balanced"
                self.runtime_direct_objective = trim(
                    str(raw.get("runtime_direct_objective", self.runtime_direct_objective) or ""),
                    800,
                )
                self.runtime_reclassify_goal = trim(
                    str(raw.get("runtime_reclassify_goal", self.runtime_reclassify_goal) or ""),
                    4000,
                )
                self.runtime_reclassify_required = bool(
                    raw.get("runtime_reclassify_required", self.runtime_reclassify_required)
                )
                self.runtime_complexity_floor = str(
                    raw.get("runtime_complexity_floor", self.runtime_complexity_floor) or ""
                )
                self.runtime_task_level_floor = int(
                    raw.get("runtime_task_level_floor", self.runtime_task_level_floor) or 0
                )
                self.runtime_task_level_ceiling = int(
                    raw.get("runtime_task_level_ceiling", self.runtime_task_level_ceiling) or 0
                )
                self.runtime_goal_reset_pending = bool(
                    raw.get("runtime_goal_reset_pending", self.runtime_goal_reset_pending)
                )
                # Restore plan mode state
                self.runtime_plan_mode_needed = bool(raw.get("runtime_plan_mode_needed", False))
                self.runtime_plan_approved = bool(raw.get("runtime_plan_approved", False))
                raw_proposal = raw.get("runtime_plan_proposal", {})
                self.runtime_plan_proposal = dict(raw_proposal) if isinstance(raw_proposal, dict) else {}
                self.runtime_plan_choice = str(raw.get("runtime_plan_choice", "") or "")
                self.active_agent_role = str(raw.get("active_agent_role", self.active_agent_role) or "").strip().lower()
                raw_contexts = raw.get("contexts", {})
                if isinstance(raw_contexts, dict):
                    clean_contexts: dict[str, list[dict]] = {}
                    for role in AGENT_ROLES:
                        rows = raw_contexts.get(role, [])
                        if not isinstance(rows, list):
                            rows = []
                        clean_rows = []
                        for row in rows[-600:]:
                            if isinstance(row, dict):
                                clean_rows.append(dict(row))
                        clean_contexts[role] = clean_rows[-400:]
                    self.contexts = clean_contexts
                raw_manager_context = raw.get("manager_context", [])
                if isinstance(raw_manager_context, list):
                    clean_manager_context: list[dict] = []
                    for row in raw_manager_context[-600:]:
                        if isinstance(row, dict):
                            clean_manager_context.append(dict(row))
                    self.manager_context = clean_manager_context[-400:]
                raw_agent_messages = raw.get("agent_messages", [])
                if isinstance(raw_agent_messages, list):
                    clean_am: list[dict] = []
                    for row in raw_agent_messages[-1200:]:
                        if isinstance(row, dict):
                            clean_am.append(dict(row))
                    self.agent_messages = clean_am[-800:]
                raw_blackboard = raw.get("blackboard", {})
                self.blackboard = self._normalize_blackboard(raw_blackboard)
                raw_bus = raw.get("agent_bus_messages", [])
                if isinstance(raw_bus, list):
                    clean_bus = []
                    for row in raw_bus[-400:]:
                        if isinstance(row, dict):
                            clean_bus.append(dict(row))
                    self.agent_bus_messages = clean_bus[-240:]
                raw_routes = raw.get("manager_routes", [])
                if isinstance(raw_routes, list):
                    clean_routes = []
                    for row in raw_routes[-400:]:
                        if isinstance(row, dict):
                            clean_routes.append(dict(row))
                    self.manager_routes = clean_routes[-240:]
                self.render_frame_seq = int(raw.get("render_frame_seq", self.render_frame_seq) or 0)
                self.render_frame_received = int(raw.get("render_frame_received", self.render_frame_received) or 0)
                self.render_frame_last_ts = float(raw.get("render_frame_last_ts", self.render_frame_last_ts) or 0.0)
                self.render_frame_last_kind = str(raw.get("render_frame_last_kind", self.render_frame_last_kind) or "")
                latest_render = raw.get("render_frame_latest", {})
                if isinstance(latest_render, dict):
                    self.render_frame_latest = latest_render
                self.event_seq = int(raw.get("event_seq", self.event_seq) or 0)
                self.created_at = raw.get("created_at", self.created_at)
                self.updated_at = raw.get("updated_at", self.updated_at)
                self.ui_language = normalize_ui_language(raw.get("ui_language", self.ui_language))
            except Exception:
                pass
        if self.meta_path.exists():
            try:
                meta = self.crypto.read_json(self.meta_path, {})
                self.title = meta.get("title", self.title)
            except Exception:
                pass
        if not self.model_profiles:
            self._init_llm_profiles({})
        if self.context_limit_locked:
            self.context_token_upper_bound = self.max_context_token_limit
        # Ensure previous-run volatile state and control-hint artifacts are cleared on load.
        self._reset_runtime_state_locked(purge_runtime_hints=True)
        self._ensure_ollama_profile()
        if self.active_profile_id not in self.model_profiles:
            self.active_profile_id = next(iter(self.model_profiles.keys()))
        active_profile = dict(self.model_profiles.get(self.active_profile_id, {}))
        if not self._profile_is_runnable(active_profile):
            fallback = self._pick_runnable_selection()
            if fallback:
                fpid, fmodel = fallback.split("::", 1) if "::" in fallback else (self.active_profile_id, "")
                self.active_profile_id = self._sanitize_profile_id(fpid)
                if self.active_profile_id in self.model_profiles and fmodel.strip():
                    row = dict(self.model_profiles[self.active_profile_id])
                    row["model"] = fmodel.strip()
                    row["selection"] = f"{self.active_profile_id}::{row.get('model','')}"
                    self.model_profiles[self.active_profile_id] = row
        self._set_ui_language(self.ui_language, relabel_todos=True)
        self._apply_active_profile()
        self._prune_skill_load_cache()
        with self.lock:
            self._prune_code_preview_locked()
        self._persist()

    def _persist(self):
        self._prune_skill_load_cache()
        self._prune_code_preview_locked()
        data = {
            "id": self.id,
            "title": self.title,
            "ui_language": self.ui_language,
            "messages": self.messages[-400:],
            "activity": self.activity[-300:],
            "operations": self.operations[-500:],
            "code_preview_index": self.code_preview_index,
            "teammates": self.teammates,
            "uploads": self.uploads[-80:],
            "model_profiles": self.model_profiles,
            "active_profile_id": self.active_profile_id,
            "multimodal_capability_cache": self.multimodal_capability_cache,
            "skill_load_cache": self.skill_load_cache,
            "todos": self.todo.snapshot(),
            "thinking": self.thinking,
            "context_token_upper_bound": self.context_token_upper_bound,
            "context_limit_locked": bool(self.context_limit_locked),
            "truncation_count": self.truncation_count,
            "last_truncation_ts": self.last_truncation_ts,
            "truncation_rescue_task_ids": self.truncation_rescue_task_ids[:12],
            "context_archives": self.context_archives[-MAX_CONTEXT_ARCHIVE_SEGMENTS:],
            "file_buffer_index": dict(self.file_buffer_index) if self.file_buffer_index else {},
            "last_compact_reason": self.last_compact_reason,
            "last_compact_ts": self.last_compact_ts,
            "plan_mode_user_preference": str(self.plan_mode_user_preference or "auto"),
            "reviewer_debug_mode": bool(self.reviewer_debug_mode),
            "reviewer_debug_rounds": int(self.reviewer_debug_rounds or 0),
            "reviewer_debug_context": trim(str(self.reviewer_debug_context or ""), 1000),
            "developer_edit_fail_streaks": dict(self.developer_edit_fail_streaks) if self.developer_edit_fail_streaks else {},
            "pending_user_inputs": self.pending_user_inputs[-40:],
            "run_generation": int(self.run_generation),
            "agent_round_index": int(self.agent_round_index),
            "current_phase": str(self.current_phase or "idle"),
            "current_tool_name": str(self.current_tool_name or ""),
            "execution_mode": normalize_execution_mode(self.execution_mode, default=EXECUTION_MODE_SYNC),
            "runtime_task_level": int(self.runtime_task_level or 0),
            "user_task_level_override": int(self.user_task_level_override or 0),
            "runtime_execution_mode": (
                normalize_execution_mode(self.runtime_execution_mode, default="")
                if str(self.runtime_execution_mode or "").strip()
                else ""
            ),
            "runtime_assigned_expert": self._sanitize_agent_role(self.runtime_assigned_expert),
            "runtime_participants": [
                role for role in [self._sanitize_agent_role(x) for x in self.runtime_participants] if role
            ][:3],
            "runtime_round_budget": int(self.runtime_round_budget or 0),
            "runtime_requires_confirmation": bool(self.runtime_requires_confirmation),
            "runtime_confirmation_needed": bool(self.runtime_confirmation_needed),
            "runtime_task_judgement": trim(str(self.runtime_task_judgement or ""), 200),
            "runtime_task_type": trim(str(self.runtime_task_type or ""), 40),
            "runtime_task_complexity": trim(str(self.runtime_task_complexity or ""), 20),
            "runtime_scale_preference": (
                str(self.runtime_scale_preference or "balanced").strip().lower()
                if str(self.runtime_scale_preference or "").strip().lower() in TASK_SCALE_PREFERENCES
                else "balanced"
            ),
            "runtime_direct_objective": trim(str(self.runtime_direct_objective or ""), 800),
            "runtime_reclassify_goal": trim(str(self.runtime_reclassify_goal or ""), 4000),
            "runtime_reclassify_required": bool(self.runtime_reclassify_required),
            "runtime_complexity_floor": str(self.runtime_complexity_floor or ""),
            "runtime_task_level_floor": int(self.runtime_task_level_floor or 0),
            "runtime_task_level_ceiling": int(self.runtime_task_level_ceiling or 0),
            "runtime_goal_reset_pending": bool(self.runtime_goal_reset_pending),
            "runtime_plan_mode_needed": bool(self.runtime_plan_mode_needed),
            "runtime_plan_approved": bool(self.runtime_plan_approved),
            "runtime_plan_proposal": dict(self.runtime_plan_proposal) if self.runtime_plan_proposal else {},
            "runtime_plan_choice": str(self.runtime_plan_choice or ""),
            "active_agent_role": str(self.active_agent_role or ""),
            "contexts": {role: list(self.contexts.get(role, []))[-400:] for role in AGENT_ROLES},
            "manager_context": list(self.manager_context)[-400:],
            "agent_messages": list(self.agent_messages)[-800:],
            "blackboard": self._normalize_blackboard(self.blackboard),
            "agent_bus_messages": list(self.agent_bus_messages)[-240:],
            "manager_routes": list(self.manager_routes)[-240:],
            "render_frame_seq": int(self.render_frame_seq),
            "render_frame_received": int(self.render_frame_received),
            "render_frame_last_ts": float(self.render_frame_last_ts or 0.0),
            "render_frame_last_kind": str(self.render_frame_last_kind or ""),
            "render_frame_latest": self.render_frame_latest if isinstance(self.render_frame_latest, dict) else {},
            "event_seq": int(self.event_seq or 0),
            "created_at": self.created_at,
            "updated_at": self.updated_at,
        }
        self.crypto.write_json(self.state_path, data)
        self.crypto.write_json(self.meta_path, {"id": self.id, "title": self.title, "updated_at": self.updated_at})

    def _is_runtime_control_hint(self, content: object) -> bool:
        txt = str(content or "").strip().lower()
        if not txt:
            return False
        for prefix in RUNTIME_CONTROL_HINT_PREFIXES:
            if txt.startswith(prefix):
                return True
        return False

    def _prune_runtime_retry_hints(self) -> int:
        if not self.messages:
            return 0
        removed = 0
        kept: list[dict] = []
        for row in self.messages:
            role = str(row.get("role", "")).strip()
            content = str(row.get("content", "") or "").strip().lower()
            if role == "user" and any(content.startswith(prefix) for prefix in RETRY_RUNTIME_HINT_PREFIXES):
                removed += 1
                continue
            kept.append(row)
        if removed > 0:
            self.messages = kept[-400:]
        return removed

    def _is_retry_runtime_hint_text(self, role: object, content: object) -> bool:
        if str(role or "").strip() != "user":
            return False
        txt = str(content or "").strip().lower()
        if not txt:
            return False
        return any(txt.startswith(prefix) for prefix in RETRY_RUNTIME_HINT_PREFIXES)

    def _sanitize_runtime_context_for_model(self) -> dict:
        if not self.messages:
            return {"removed": 0, "retry_hints_removed": 0, "tool_errors_removed": 0}
        latest_retry_idx = -1
        latest_tool_error_idx = -1
        for idx in range(len(self.messages) - 1, -1, -1):
            row = self.messages[idx] if isinstance(self.messages[idx], dict) else {}
            role = str(row.get("role", "")).strip()
            content = row.get("content", "")
            low = str(content or "").strip().lower()
            if latest_retry_idx < 0 and self._is_retry_runtime_hint_text(role, content):
                latest_retry_idx = idx
            if latest_tool_error_idx < 0 and role == "tool" and low.startswith("error:"):
                latest_tool_error_idx = idx
            if latest_retry_idx >= 0 and latest_tool_error_idx >= 0:
                break
        retry_removed = 0
        tool_error_removed = 0
        kept: list[dict] = []
        for idx, row in enumerate(self.messages):
            item = row if isinstance(row, dict) else {"role": "", "content": str(row or "")}
            role = str(item.get("role", "")).strip()
            content = item.get("content", "")
            low = str(content or "").strip().lower()
            if self._is_retry_runtime_hint_text(role, content):
                if idx != latest_retry_idx:
                    retry_removed += 1
                    continue
            if role == "tool" and low.startswith("error:") and idx != latest_tool_error_idx:
                tool_error_removed += 1
                continue
            kept.append(item)
        removed = retry_removed + tool_error_removed
        if removed > 0:
            self.messages = kept[-400:]
        return {
            "removed": int(removed),
            "retry_hints_removed": int(retry_removed),
            "tool_errors_removed": int(tool_error_removed),
        }

    def _reset_runtime_state_locked(self, *, purge_runtime_hints: bool = False) -> int:
        removed_hints = 0
        if purge_runtime_hints and self.messages:
            kept: list[dict] = []
            for row in self.messages:
                role = str(row.get("role", "")).strip()
                content = row.get("content", "")
                if role == "user" and self._is_runtime_control_hint(content):
                    removed_hints += 1
                    continue
                kept.append(row)
            if removed_hints > 0:
                self.messages = kept[-400:]
        self.pending_user_inputs = []
        self.cancel_requested = False
        self.current_phase = "idle"
        self.current_tool_name = ""
        self.active_agent_role = ""
        self.rounds_without_todo = 0
        self.last_todo_reminder_ts = 0.0
        self.todo_reminder_count = 0
        self.todo_write_issue_count = 0
        self.todo_last_issue = ""
        self.tool_retry_counts = {}
        self.bash_read_loop_fp = ""
        self.bash_read_loop_count = 0
        self.stall_severity_score = 0
        self.stall_severity_sources = []
        self.stall_escalation_triggered = False
        self.stall_escalation_round = 0
        self.live_thinking_text = ""
        self.live_thinking_last_emit = 0.0
        self.live_truncation_text = ""
        self.live_truncation_kind = ""
        self.live_truncation_tool = ""
        self.live_truncation_active = False
        self.live_truncation_attempts = 0
        self.live_truncation_tokens = 0
        self.live_truncation_last_emit = 0.0
        self.live_run_notice_active = False
        self.live_run_notice_label = ""
        self.live_run_notice_started_at = 0.0
        self.live_run_notice_elapsed = 0.0
        self.run_model_active_seconds = 0.0
        self.agent_round_index = 0
        _utlo = int(getattr(self, 'user_task_level_override', 0) or 0)
        self.runtime_task_level = _utlo if _utlo in TASK_LEVEL_CHOICES else 0
        self.runtime_execution_mode = ""
        self.runtime_assigned_expert = ""
        self.runtime_participants = []
        self.runtime_round_budget = 0
        self.runtime_requires_confirmation = False
        self.runtime_confirmation_needed = False
        self.runtime_task_judgement = ""
        self.runtime_task_type = ""
        self.runtime_task_complexity = ""
        self.runtime_scale_preference = "balanced"
        self.runtime_direct_objective = ""
        self.runtime_reclassify_goal = ""
        self.runtime_reclassify_required = False
        self.runtime_goal_reset_pending = False
        self.runtime_plan_mode_needed = False
        self.runtime_code_reference_text = ""
        self.runtime_code_reference_meta = {}
        return removed_hints

    def _restore_runtime_policy_from_blackboard_locked(self) -> None:
        bb = self._ensure_blackboard()
        profile = bb.get("task_profile", {}) if isinstance(bb.get("task_profile"), dict) else {}
        judgement = bb.get("manager_judgement", {}) if isinstance(bb.get("manager_judgement"), dict) else {}
        try:
            level = int(
                getattr(self, "user_task_level_override", 0)
                or profile.get("task_level", judgement.get("task_level", 0))
                or 0
            )
        except Exception:
            level = 0
        if level not in TASK_LEVEL_CHOICES:
            return
        self.runtime_task_level = int(level)
        self._prev_applied_task_level = int(level)
        self.runtime_execution_mode = normalize_execution_mode(
            profile.get("execution_mode", judgement.get("execution_mode", self.execution_mode or EXECUTION_MODE_SYNC)),
            default=EXECUTION_MODE_SYNC,
        )
        assigned = self._sanitize_agent_role(
            str(
                profile.get(
                    "assigned_expert",
                    judgement.get("assigned_expert", self.runtime_assigned_expert or "developer"),
                )
                or ""
            )
        ) or "developer"
        participants: list[str] = []
        raw_participants = profile.get(
            "participants",
            judgement.get("participants", profile.get("recommended_agents", [])),
        )
        if isinstance(raw_participants, list):
            for item in raw_participants:
                role = self._sanitize_agent_role(item)
                if role and role not in participants:
                    participants.append(role)
        self.runtime_assigned_expert = assigned
        self.runtime_participants = participants or [assigned]
        try:
            round_budget = int(profile.get("round_budget", self.runtime_round_budget or 0) or 0)
        except Exception:
            round_budget = int(self.runtime_round_budget or 0)
        if round_budget <= 0:
            try:
                remaining = int(judgement.get("remaining_rounds", 0) or 0)
            except Exception:
                remaining = 0
            round_budget = int(remaining)
        self.runtime_round_budget = int(round_budget)
        self.runtime_requires_confirmation = bool(
            profile.get("requires_user_confirmation", self.runtime_requires_confirmation)
        )
        self.runtime_confirmation_needed = bool(self.runtime_requires_confirmation)
        self.runtime_task_judgement = trim(
            str(judgement.get("progress", self.runtime_task_judgement) or ""),
            200,
        )
        task_type = trim(
            str(profile.get("task_type", judgement.get("task_type", self.runtime_task_type or "")) or "").strip().lower(),
            40,
        )
        if task_type in TASK_PROFILE_TYPES:
            self.runtime_task_type = task_type
        complexity = trim(
            str(profile.get("complexity", judgement.get("complexity", self.runtime_task_complexity or "")) or "").strip().lower(),
            20,
        )
        if complexity in TASK_COMPLEXITY_LEVELS:
            self.runtime_task_complexity = complexity
        scale_preference = trim(
            str(
                profile.get(
                    "scale_preference",
                    judgement.get("scale_preference", self.runtime_scale_preference or "balanced"),
                )
                or ""
            ).strip().lower(),
            20,
        )
        if scale_preference in TASK_SCALE_PREFERENCES:
            self.runtime_scale_preference = scale_preference
        self.runtime_direct_objective = trim(
            str(profile.get("direct_objective", self.runtime_direct_objective or "") or "").strip(),
            800,
        )

    def _reset_blackboard_plan_state_locked(self) -> None:
        """Clear plan/todo/skills state from a completed run so the next run starts fresh.

        Called from submit_user_message when a new user request arrives after a
        previous run finished (running=False, not awaiting plan choice).
        Prevents the manager from seeing status=COMPLETED + all todos done and
        immediately routing to 'finish' again on the very first round.
        """
        bb = self._ensure_blackboard()
        bb["project_todos"] = []
        bb["plan"] = {}
        bb["plan_steps"] = []
        bb["plan_step_cursor"] = 0
        bb["plan_step_total"] = 0
        bb["status"] = ""
        bb["approval"] = ""
        bb["plan_findings"] = ""
        bb["plan_proposal"] = ""
        bb["plan_risks"] = ""
        bb["plan_meta"] = {}
        bb["loaded_skills"] = {}
        bb["loaded_skills_goal_sig"] = ""
        self.blackboard = bb
        self.runtime_plan_mode_needed = False
        self.runtime_plan_approved = False
        self.runtime_plan_proposal = {}
        self.runtime_plan_choice = ""
        self.runtime_task_level_floor = 0
        self.runtime_task_level_ceiling = 0
        self.runtime_complexity_floor = ""
        try:
            self.todo.items = []
        except Exception:
            pass
        # Clean up stale plan.md file from previous run
        try:
            _pf = self._plan_file_path()
            if _pf.exists():
                _pf.unlink()
        except Exception:
            pass

    def _event_payload_with_agent_role(self, kind: str, data: dict | None) -> dict:
        payload = dict(data or {})
        if self._sanitize_agent_bubble_role(payload.get("agent_role", "")):
            return payload
        role_name = str(payload.get("role", "") or "").strip().lower()
        if role_name == "user":
            return payload
        active_role = self._sanitize_agent_bubble_role(self.active_agent_role)
        if active_role:
            payload["agent_role"] = active_role
            return payload
        phase = str(self.current_phase or "").strip().lower()
        if phase.startswith("manager"):
            payload["agent_role"] = "manager"
            return payload
        m = re.match(r"^agent:(explorer|developer|reviewer)(?::|$)", phase)
        if m:
            payload["agent_role"] = self._sanitize_agent_bubble_role(m.group(1))
            return payload
        mode = self._effective_execution_mode()
        kind_key = str(kind or "").strip().lower()
        if (
            kind_key == "message"
            and role_name == "assistant"
            and mode in {EXECUTION_MODE_SEQUENTIAL, EXECUTION_MODE_SYNC}
        ):
            payload["agent_role"] = "developer"
        return payload

    def _next_event_seq(self) -> int:
        with self.lock:
            self.event_seq = int(self.event_seq) + 1
            return int(self.event_seq)

    def _emit(self, kind: str, data: dict):
        payload = self._event_payload_with_agent_role(kind, data)
        event = {
            "id": make_id("evt"),
            "seq": self._next_event_seq(),
            "ts": now_ts(),
            "type": kind,
            "session_id": self.id,
            "data": payload,
        }
        self.events.publish(event)
        self.operations.append(event)
        self.operations = self.operations[-500:]
        self.activity.append(
            {
                "ts": event["ts"],
                "type": kind,
                "summary": payload.get("summary") or payload.get("text") or payload.get("name") or kind,
            }
        )
        self.activity = self.activity[-300:]

    def _emit_transient(self, kind: str, data: dict):
        payload = self._event_payload_with_agent_role(kind, data)
        event = {
            "id": make_id("evt"),
            "seq": self._next_event_seq(),
            "ts": now_ts(),
            "type": kind,
            "session_id": self.id,
            "data": payload,
        }
        self.events.publish(event)

    def _safe_numeric(self, raw: object, default: float = 0.0, low: float = -1e9, high: float = 1e9) -> float:
        try:
            v = float(raw)
            if v != v or v in (float("inf"), float("-inf")):
                return float(default)
            if v < low:
                return float(low)
            if v > high:
                return float(high)
            return v
        except Exception:
            return float(default)

    def _sanitize_render_frame_payload(self, payload: dict) -> dict:
        src = payload if isinstance(payload, dict) else {}
        out: dict[str, object] = {}
        kind = str(src.get("kind", "") or "").strip().lower()[:48] or "generic"
        out["kind"] = kind
        width = int(self._safe_numeric(src.get("width", 0), default=0.0, low=0.0, high=8192.0))
        height = int(self._safe_numeric(src.get("height", 0), default=0.0, low=0.0, high=8192.0))
        if width > 0:
            out["width"] = width
        if height > 0:
            out["height"] = height
        out["clear"] = bool(src.get("clear", False))
        bg = str(src.get("bg", "") or "").strip()
        if bg:
            out["bg"] = trim(bg, 64)
        text = str(src.get("text", "") or "")
        if text:
            out["text"] = trim(text, 4000)
        summary = str(src.get("summary", "") or "")
        if summary:
            out["summary"] = trim(summary, 220)
        mime = str(src.get("mime", "") or "").strip().lower()
        if mime.startswith("image/"):
            out["mime"] = mime
        image_b64 = str(src.get("image_b64", "") or "").strip()
        if image_b64 and len(image_b64) <= RENDER_FRAME_MAX_B64_CHARS:
            out["image_b64"] = image_b64
        points_raw = src.get("points", [])
        points_out = []
        if isinstance(points_raw, list):
            for row in points_raw[:RENDER_FRAME_MAX_POINTS]:
                if not isinstance(row, dict):
                    continue
                x = self._safe_numeric(row.get("x", 0.0), default=0.0)
                y = self._safe_numeric(row.get("y", 0.0), default=0.0)
                p = {
                    "x": x,
                    "y": y,
                    "size": self._safe_numeric(row.get("size", 1.6), default=1.6, low=0.1, high=80.0),
                    "color": trim(str(row.get("color", "") or ""), 48),
                    "alpha": self._safe_numeric(row.get("alpha", 1.0), default=1.0, low=0.0, high=1.0),
                }
                points_out.append(p)
        if points_out:
            out["points"] = points_out
        lines_raw = src.get("lines", [])
        lines_out = []
        if isinstance(lines_raw, list):
            for line in lines_raw[:RENDER_FRAME_MAX_LINES]:
                if not isinstance(line, dict):
                    continue
                pts = line.get("points", [])
                if not isinstance(pts, list):
                    continue
                clean_pts = []
                for pt in pts[:RENDER_FRAME_MAX_LINE_POINTS]:
                    if not isinstance(pt, (list, tuple)) or len(pt) < 2:
                        continue
                    clean_pts.append(
                        [
                            self._safe_numeric(pt[0], default=0.0),
                            self._safe_numeric(pt[1], default=0.0),
                        ]
                    )
                if len(clean_pts) < 2:
                    continue
                lines_out.append(
                    {
                        "points": clean_pts,
                        "color": trim(str(line.get("color", "") or ""), 48),
                        "width": self._safe_numeric(line.get("width", 1.6), default=1.6, low=0.1, high=80.0),
                        "alpha": self._safe_numeric(line.get("alpha", 1.0), default=1.0, low=0.0, high=1.0),
                    }
                )
        if lines_out:
            out["lines"] = lines_out
        meta_raw = src.get("meta", {})
        if isinstance(meta_raw, dict):
            meta_out: dict[str, str] = {}
            for k, v in list(meta_raw.items())[:20]:
                key = trim(str(k or "").strip(), 48)
                if not key:
                    continue
                meta_out[key] = trim(str(v or ""), 240)
            if meta_out:
                out["meta"] = meta_out
        return out

    def push_render_frame(self, payload: dict) -> dict:
        clean = self._sanitize_render_frame_payload(payload if isinstance(payload, dict) else {})
        now_tick = now_ts()
        with self.lock:
            self.render_frame_seq = int(self.render_frame_seq) + 1
            seq = int(self.render_frame_seq)
            self.render_frame_received = int(self.render_frame_received) + 1
            self.render_frame_last_ts = now_tick
            self.render_frame_last_kind = str(clean.get("kind", "") or "generic")
            latest_meta = {
                "kind": self.render_frame_last_kind,
                "width": int(clean.get("width", 0) or 0),
                "height": int(clean.get("height", 0) or 0),
                "points": len(clean.get("points", []) or []),
                "lines": len(clean.get("lines", []) or []),
                "has_image": bool(clean.get("image_b64")),
                "summary": str(clean.get("summary", "") or ""),
                "ts": now_tick,
            }
            self.render_frame_latest = latest_meta
            payload_view = dict(clean)
            payload_view["seq"] = seq
            payload_view["ts"] = now_tick
            self.render_frame_last_payload = payload_view
            self.updated_at = now_tick
            self._persist()
        event_payload = dict(clean)
        event_payload["seq"] = seq
        event_payload["ts"] = now_tick
        self._emit_transient("render_frame", event_payload)
        if (now_tick - float(self.render_frame_last_activity_emit or 0.0)) >= RENDER_FRAME_ACTIVITY_INTERVAL_SECONDS:
            self.render_frame_last_activity_emit = now_tick
            self._emit(
                "render_bridge",
                {
                    "seq": seq,
                    "kind": str(clean.get("kind", "generic") or "generic"),
                    "points": len(clean.get("points", []) or []),
                    "lines": len(clean.get("lines", []) or []),
                    "has_image": bool(clean.get("image_b64")),
                    "summary": (
                        f"render frame seq={seq} kind={clean.get('kind','generic')} "
                        f"points={len(clean.get('points', []) or [])} lines={len(clean.get('lines', []) or [])}"
                    ),
                },
            )
        return {
            "ok": True,
            "seq": seq,
            "kind": str(clean.get("kind", "generic") or "generic"),
            "points": len(clean.get("points", []) or []),
            "lines": len(clean.get("lines", []) or []),
            "has_image": bool(clean.get("image_b64")),
        }

    def render_state_payload(self) -> dict:
        with self.lock:
            seq = int(self.render_frame_seq)
            payload = dict(self.render_frame_last_payload) if isinstance(self.render_frame_last_payload, dict) else {}
            latest = dict(self.render_frame_latest) if isinstance(self.render_frame_latest, dict) else {}
            out = {
                "ok": True,
                "seq": seq,
                "received": int(self.render_frame_received),
                "last_ts": float(self.render_frame_last_ts or 0.0),
                "last_kind": str(self.render_frame_last_kind or ""),
                "latest": latest,
            }
            if payload:
                payload.setdefault("seq", seq)
                payload.setdefault("ts", float(self.render_frame_last_ts or now_ts()))
                out["frame"] = payload
            return out

    def _prune_skill_load_cache(self):
        if not isinstance(self.skill_load_cache, dict):
            self.skill_load_cache = {}
            return
        rows = []
        for key, row in self.skill_load_cache.items():
            if not isinstance(row, dict):
                continue
            body_z = str(row.get("body_z", "") or "")
            if not body_z:
                continue
            updated_at = float(row.get("updated_at", 0.0) or 0.0)
            rows.append((str(key), row, updated_at))
        rows.sort(key=lambda x: x[2], reverse=True)
        kept: dict[str, dict] = {}
        total = 0
        for key, row, _ in rows:
            z = str(row.get("body_z", "") or "")
            zlen = len(z)
            if len(kept) >= SKILL_RUNTIME_CACHE_MAX_ENTRIES:
                continue
            if total + zlen > SKILL_RUNTIME_CACHE_MAX_BYTES:
                continue
            kept[key] = row
            total += zlen
        self.skill_load_cache = kept

    def _ensure_skills_ready(self, force: bool = False):
        now = now_ts()
        if (not force) and self.skills_last_refresh_ts > 0 and (
            now - self.skills_last_refresh_ts
        ) < SKILL_REFRESH_MIN_INTERVAL_SECONDS:
            return
        # Fast path: if already prepared, check skills dir mtime only
        if (not force) and self.skills_runtime_prepared:
            try:
                skills_dir = self.skills.skills_root
                dir_mtime = skills_dir.stat().st_mtime if skills_dir.exists() else 0.0
                cached_mtime = getattr(self, "_skills_dir_mtime_cache", 0.0)
                if dir_mtime > 0 and dir_mtime == cached_mtime:
                    self.skills_last_refresh_ts = now
                    return
                self._skills_dir_mtime_cache = dir_mtime
            except Exception:
                pass
        if force or (not self.skills_runtime_prepared):
            ensure_runtime_skills(self.skills.skills_root)
            self.skills_runtime_prepared = True
        prev_fp = str(self.skills.fingerprint or "")
        self.skills.reload(force=force)
        self.skills_last_refresh_ts = now
        if prev_fp and self.skills.fingerprint and prev_fp != self.skills.fingerprint:
            self.skill_load_cache = {}

    def _load_skill_with_cache(self, name: str, load_source: str = "manual") -> str:
        self._ensure_skills_ready(force=False)
        key, err = self.skills._resolve_name(name)
        if err or not key:
            return err or "Error: skill not found"
        fp = str(self.skills.fingerprint or "")
        row = self.skill_load_cache.get(key, {})
        if isinstance(row, dict):
            cached_fp = str(row.get("fingerprint", "") or "")
            body_z = str(row.get("body_z", "") or "")
            if body_z and cached_fp and cached_fp == fp:
                restored = decompress_text_blob(body_z)
                if restored:
                    self._broadcast_loaded_skill(key, restored, load_source=load_source)
                    return restored
        text = self.skills.load(name)
        if text and not str(text).startswith("Error:"):
            self.skill_load_cache[key] = {
                "fingerprint": fp,
                "body_z": compress_text_blob(text),
                "updated_at": now_ts(),
            }
            self._prune_skill_load_cache()
            self.updated_at = now_ts()
            self._persist()
            self._broadcast_loaded_skill(key, text, load_source=load_source)
        return text

    def _broadcast_loaded_skill(self, skill_key: str, skill_text: str, *, load_source: str = "manual"):
        """Broadcast a loaded skill to blackboard, global single-agent context, and agent contexts."""
        # 1. Write skill reference to blackboard so all agents are aware
        bb = self._ensure_blackboard()
        loaded_skills = bb.get("loaded_skills", {})
        if not isinstance(loaded_skills, dict):
            loaded_skills = {}
        skill_row = self.skills.skills.get(skill_key, {}) if isinstance(getattr(self.skills, "skills", {}), dict) else {}
        meta = skill_row.get("meta", {}) if isinstance(skill_row.get("meta"), dict) else {}
        skill_name = str(skill_row.get("name", skill_key) or skill_key).strip() or skill_key
        skill_path = str(skill_row.get("skill_path", "") or "").strip()
        aliases = self.skills._skill_aliases(meta)
        loaded_skills[skill_key] = {
            "loaded_at": now_ts(),
            "size": len(skill_text),
            "preview": trim(skill_text, 300),
            "skill_name": skill_name,
            "skill_path": skill_path,
            "aliases": aliases,
        }
        bb["loaded_skills"] = loaded_skills
        self.blackboard = bb
        self._blackboard_touch()
        # 2. Inject full skill content into messages (model needs it to follow instructions)
        #    but mark it so the frontend renders only a compact card
        skill_desc = str(skill_row.get("description", "-")).strip()
        inject_msg = (
            f"<loaded-skill name=\"{skill_key}\">\n"
            f"A skill has been loaded. IMPORTANT: This skill's workflow, tools, and commands "
            f"OVERRIDE the plan's implementation approach for any step where it applies. "
            f"Read the full instructions below and follow them exactly — do NOT substitute a "
            f"different tool, library, or language unless the skill explicitly allows it.\n"
            f"{trim(skill_text, 12000)}\n"
            f"</loaded-skill>"
        )
        # UI display text: concise format that matches frontend's skill_loaded card regex
        ui_display = f"[skill loaded: {skill_name}] {trim(skill_desc, 200)}"
        self.messages.append(
            {
                "role": "user",
                "content": inject_msg,
                "ts": now_ts(),
                "agent_role": "shared",
                "_skill_notify": True,
                "_ui_text": ui_display,
            }
        )
        self.messages = self.messages[-400:]
        # Also inject into agent_messages for multi-agent mode
        self.agent_messages.append(
            {
                "role": "user",
                "content": inject_msg,
                "ts": now_ts(),
                "agent_role": "shared",
            }
        )
        am_limit = self._tier_agent_context_limits(self._context_compression_tier())["agent_messages"]
        if len(self.agent_messages) > int(am_limit * 1.5):
            self.agent_messages = self.agent_messages[-am_limit:]
        self._emit("status", {
            "summary": f"skill loaded: {skill_name}" + (f" ({load_source})" if load_source and load_source != "manual" else ""),
        })

    def _loaded_skills_goal_signature(self, goal_text: str) -> str:
        goal = trim(str(goal_text or ""), 1200).strip().lower()
        if not goal:
            return ""
        return hashlib.sha1(goal.encode("utf-8", errors="ignore")).hexdigest()

    def _current_plan_step_row(self, board: dict | None = None) -> dict | None:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        todos = bb.get("project_todos", [])
        if not isinstance(todos, list):
            return None
        for row in todos:
            if isinstance(row, dict) and row.get("category") == "plan_step" and row.get("status") == "in_progress":
                return row
        return None

    def _current_plan_step_text(self, board: dict | None = None) -> str:
        row = self._current_plan_step_row(board)
        return trim(str((row or {}).get("content", "") or "").strip(), 400)

    def _current_plan_step_full_text(self, board: dict | None = None, max_len: int = 1200) -> str:
        row = self._current_plan_step_row(board)
        return trim(
            str((row or {}).get("full_content", "") or (row or {}).get("content", "") or "").strip(),
            max_len,
        )

    def _current_execution_focus_text(self) -> str:
        bb = self._ensure_blackboard()
        parts: list[str] = []
        goal = trim(str(self.runtime_reclassify_goal or self._latest_user_goal_text() or ""), 1200)
        if goal:
            parts.append(goal)
        step_text = self._current_plan_step_text(bb)
        if step_text:
            parts.append(f"Current plan step: {step_text}")
        profile = bb.get("task_profile", {}) if isinstance(bb.get("task_profile"), dict) else {}
        objective = trim(str(profile.get("direct_objective", "") or "").strip(), 600)
        if objective:
            parts.append(f"Direct objective: {objective}")
        plan = bb.get("plan", {}) if isinstance(bb.get("plan"), dict) else {}
        plan_phase = trim(str(plan.get("phase", "") or "").strip(), 60)
        if plan_phase:
            parts.append(f"Plan phase: {plan_phase}")
        deduped: list[str] = []
        seen: set[str] = set()
        for item in parts:
            norm = re.sub(r"\s+", " ", str(item or "").strip()).strip()
            if not norm:
                continue
            low = norm.lower()
            if low in seen:
                continue
            seen.add(low)
            deduped.append(norm)
        return "\n".join(deduped)

    def _refresh_loaded_skills_for_execution_focus(self, trigger: str = ""):
        focus = self._current_execution_focus_text()
        if focus:
            self._auto_discover_and_load_skills(focus, trigger=trigger)

    def _loaded_skill_rows(self, board: dict | None = None) -> dict[str, dict]:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        loaded = bb.get("loaded_skills", {})
        return loaded if isinstance(loaded, dict) else {}

    def _clear_loaded_skill_contexts(self):
        def _filter_rows(rows: list[dict]) -> list[dict]:
            kept: list[dict] = []
            for row in rows or []:
                if not isinstance(row, dict):
                    continue
                content = str(row.get("content", "") or "")
                if "<loaded-skill name=" in content:
                    continue
                kept.append(row)
            return kept
        self.messages = _filter_rows(list(self.messages))[-400:]
        am_limit = self._tier_agent_context_limits(self._context_compression_tier())["agent_messages"]
        self.agent_messages = _filter_rows(list(self.agent_messages))[-am_limit:]
        for role in AGENT_ROLES:
            self.contexts[role] = _filter_rows(list(self.contexts.get(role, [])))[-400:]
        self.manager_context = _filter_rows(list(self.manager_context))[-400:]

    def _prepare_loaded_skills_for_goal(self, goal_text: str, trigger: str = "") -> dict:
        goal_sig = self._loaded_skills_goal_signature(goal_text)
        bb = self._ensure_blackboard()
        current_sig = str(bb.get("loaded_skills_goal_sig", "") or "")
        loaded = bb.get("loaded_skills", {})
        if not isinstance(loaded, dict):
            loaded = {}
        changed = bool(goal_sig and current_sig and goal_sig != current_sig)
        if changed:
            bb["loaded_skills"] = {}
            bb["loaded_skills_goal_sig"] = goal_sig
            bb["loaded_skills_goal_preview"] = trim(str(goal_text or ""), 240)
            self.blackboard = bb
            self._blackboard_touch()
            self._clear_loaded_skill_contexts()
            self._emit(
                "status",
                {
                    "summary": (
                        "loaded skills reset for new goal"
                        + (f" ({trigger})" if str(trigger or "").strip() else "")
                    )
                },
            )
            loaded = {}
        elif goal_sig and current_sig != goal_sig:
            bb["loaded_skills_goal_sig"] = goal_sig
            bb["loaded_skills_goal_preview"] = trim(str(goal_text or ""), 240)
            self.blackboard = bb
            self._blackboard_touch()
        return {
            "goal_sig": goal_sig,
            "current_sig": current_sig,
            "goal_changed": changed,
            "loaded": loaded,
        }

    def _auto_discover_and_load_skills(self, goal_text: str, trigger: str = ""):
        """Skill discovery: LLM semantic match (with timeout) → keyword fallback → lazy load."""
        try:
            self._ensure_skills_ready(force=False)
        except Exception:
            return
        skill_meta = self.skills.list_metadata()
        if not skill_meta:
            return
        goal = trim(str(goal_text or self.runtime_reclassify_goal or self._latest_user_goal_text() or ""), 600)
        if not goal:
            return
        # Sig = user goal + current plan step text.
        # Plan step text changes per node → triggers per-node skill reload (desired).
        # direct_objective changes every manager round → excluded to prevent per-round reload.
        _user_goal = trim(str(self.runtime_reclassify_goal or self._latest_user_goal_text() or goal), 600)
        _plan_step = self._current_plan_step_text()
        stable_sig = trim((_user_goal + "::step::" + _plan_step) if _plan_step else _user_goal, 600)
        prep = self._prepare_loaded_skills_for_goal(stable_sig, trigger=trigger)
        already_loaded = prep.get("loaded", {})
        # Allow up to 4 concurrent non-conflicting skills for complex tasks
        if isinstance(already_loaded, dict) and len(already_loaded) >= 4 and not bool(prep.get("goal_changed", False)):
            return
        goal_low = goal.lower()
        # Build skill catalog
        skill_catalog: list[dict] = []
        for s in skill_meta:
            name = str(s.get("name", "")).strip()
            qname = str(s.get("qualified_name", name)).strip()
            desc = trim(str(s.get("description", "")).strip(), 200)
            meta = s.get("meta", {}) if isinstance(s.get("meta"), dict) else {}
            keywords: list[str] = []
            keywords.append(name.lower())
            keywords.extend(str(x).strip().lower() for x in self.skills._skill_aliases(meta))
            keywords.extend(str(x).strip().lower() for x in self.skills._skill_triggers(meta))
            keywords.extend(str(x).strip().lower() for x in self.skills._skill_keywords(meta))
            if name and desc and desc != "-":
                skill_catalog.append(
                    {
                        "name": name,
                        "qname": qname,
                        "desc": desc,
                        "keywords": [x for x in keywords if x],
                    }
                )
        if not skill_catalog:
            return

        matched_names: list[str] = []

        # --- Path 1 (primary): LLM task analysis → skill selection (5s timeout) ---
        llm_result: list[str] = []
        def _llm_match():
            try:
                catalog_text = "\n".join(f"- {s['qname']}: {s['desc']}" for s in skill_catalog[:30])
                rsp = self.ollama.chat(
                    [{"role": "user", "content": (
                        f"/no_think\n"
                        f"Available skills:\n{catalog_text}\n\n"
                        f"Task: {goal}\n\n"
                        f"Which skills are relevant? Reply ONLY a JSON array. Max 3. [] if none."
                    )}],
                    system="/no_think\nOutput ONLY a JSON array.",
                    max_tokens=120,
                    think=False,
                )
                answer = str(rsp.get("content", "") or "").strip()
                m = re.search(r'\[([^\]]*)\]', answer)
                if m:
                    try:
                        names = json.loads(f"[{m.group(1)}]")
                        if isinstance(names, list):
                            llm_result.extend([str(n).strip() for n in names if str(n).strip()][:3])
                    except Exception:
                        pass
            except Exception:
                pass
        t = threading.Thread(target=_llm_match, daemon=True)
        t.start()
        t.join(timeout=5.0)
        if llm_result:
            matched_names = llm_result
            self._emit("status", {"summary": f"skill discovery (LLM task analysis): {matched_names} ({trigger})"})

        # --- Path 2 (fallback): Keyword match only if LLM returned nothing ---
        if not matched_names:
            matched_names = self._keyword_match_skills(goal_low, skill_catalog)
            if matched_names:
                self._emit("status", {"summary": f"skill discovery (keyword fallback): {matched_names} ({trigger})"})

        # --- Path 3: Deferred LLM pickup if still running ---
        if not matched_names and t.is_alive():
            def _deferred_llm_pickup():
                t.join(timeout=8.0)
                if llm_result and not self._loaded_skill_rows():
                    for name_str in llm_result[:3]:
                        try:
                            self._load_skill_with_cache(name_str, load_source=f"auto:llm-deferred:{trigger or 'discovery'}")
                        except Exception:
                            pass
            threading.Thread(target=_deferred_llm_pickup, daemon=True).start()

        # --- Load matched skills: multi-skill with conflict detection ---
        # Filter out infrastructure/recovery skills that shouldn't be auto-triggered
        _INFRA_SKILL_PATTERNS = {
            "execution-degradation", "context-management", "context-recall",
            "skill-creator", "skills_gen", "agent-builder",
        }
        task_skills: list[str] = []
        infra_skills: list[str] = []
        for name_str in matched_names[:4]:
            name_low = str(name_str or "").strip().lower()
            is_infra = any(pat in name_low for pat in _INFRA_SKILL_PATTERNS)
            if is_infra:
                infra_skills.append(name_str)
            else:
                task_skills.append(name_str)
        if not task_skills:
            return
        # Detect conflicts among candidate skills before loading
        to_load: list[str] = []
        conflicts: list[tuple[str, str, str]] = []  # (skill_a, skill_b, reason)
        for candidate in task_skills:
            # Check conflict with already-loaded skills
            conflict_with = self._detect_skill_conflict(candidate, already_loaded)
            if conflict_with:
                conflicts.append((candidate, conflict_with[0], conflict_with[1]))
                continue
            # Check conflict with skills we're about to load
            conflict_with_pending = None
            for pending in to_load:
                reason = self._check_skill_pair_conflict(candidate, pending)
                if reason:
                    conflict_with_pending = (pending, reason)
                    break
            if conflict_with_pending:
                conflicts.append((candidate, conflict_with_pending[0], conflict_with_pending[1]))
                continue
            to_load.append(candidate)
        # Load all non-conflicting skills
        loaded_count = 0
        loaded_names: list[str] = []
        for name_str in to_load:
            if isinstance(already_loaded, dict) and any(name_str in k for k in already_loaded):
                continue
            result = self._load_skill_with_cache(name_str, load_source=f"auto:{trigger or 'discovery'}")
            if result and not str(result).startswith("Error:"):
                loaded_count += 1
                loaded_names.append(name_str)
        # If conflicts found, emit to frontend for user decision
        if conflicts:
            conflict_details = []
            for skill_a, skill_b, reason in conflicts[:3]:
                conflict_details.append({"blocked": skill_a, "conflicts_with": skill_b, "reason": reason})
            self._emit("skill_conflict", {
                "loaded": loaded_names,
                "conflicts": conflict_details,
                "summary": (
                    "Skill conflict detected: "
                    + "; ".join(f"'{c[0]}' conflicts with '{c[1]}' ({c[2]})" for c in conflicts[:3])
                    + ". Please choose which to keep."
                ),
            })
        if loaded_count > 0:
            self._emit("status", {
                "summary": f"skills loaded: {', '.join(loaded_names)}" + (
                    f" | conflicts deferred to user: {', '.join(c[0] for c in conflicts[:3])}" if conflicts else ""
                ) + (f" ({trigger})" if trigger else ""),
            })

    def _detect_skill_conflict(self, candidate: str, loaded: dict) -> tuple[str, str] | None:
        """Check if candidate skill conflicts with any already-loaded skill.
        Returns (conflicting_skill_key, reason) or None."""
        if not isinstance(loaded, dict) or not loaded:
            return None
        for skill_key, row in loaded.items():
            if not isinstance(row, dict):
                continue
            reason = self._check_skill_pair_conflict(candidate, str(row.get("skill_name", skill_key)))
            if reason:
                return (str(row.get("skill_name", skill_key)), reason)
        return None

    def _check_skill_pair_conflict(self, skill_a: str, skill_b: str) -> str:
        """Check if two skills conflict (overlapping functionality).
        Returns conflict reason string, or empty string if no conflict."""
        a_low = str(skill_a or "").strip().lower()
        b_low = str(skill_b or "").strip().lower()
        if not a_low or not b_low or a_low == b_low:
            return ""
        # Define conflict groups: skills in the same group are mutually exclusive
        _CONFLICT_GROUPS = [
            # PDF processors
            ({"pdf", "kimi-pdf", "minimax-pdf"}, "PDF processing"),
            # Word/DOCX processors
            ({"docx", "kimi-docx", "minimax-docx"}, "Word document processing"),
            # Excel/XLSX processors
            ({"xlsx", "kimi-xlsx", "minimax-xlsx"}, "Excel/spreadsheet processing"),
            # PPT/PPTX processors
            ({"ppt", "ppt-master", "pptx", "academic-pptx", "slide-making-skill"}, "Presentation/PPT processing"),
            # Research orchestrators
            ({"deep-research-orchestrator", "research-orchestrator-pro"}, "Research orchestration"),
            # Frontend design
            ({"frontend-design", "frontend-composition-algorithm", "canvas-design", "web-artifacts-builder"}, "Frontend/web design"),
        ]
        # Normalize: strip common prefixes/suffixes for matching
        def _norm(name: str) -> set[str]:
            tokens = set()
            tokens.add(name)
            # Strip provider prefix
            if ":" in name:
                tokens.add(name.split(":", 1)[-1])
            # Strip common prefixes
            for prefix in ("local:", "ext-", "minimax-", "kimi-"):
                if name.startswith(prefix):
                    tokens.add(name[len(prefix):])
            return tokens
        a_tokens = _norm(a_low)
        b_tokens = _norm(b_low)
        for group, reason in _CONFLICT_GROUPS:
            a_in = bool(a_tokens & group)
            b_in = bool(b_tokens & group)
            if a_in and b_in:
                return reason
        return ""

    def _keyword_match_skills(self, goal_low: str, skill_catalog: list[dict]) -> list[str]:
        """Metadata-driven keyword skill matching — no hardcoded mappings.

        Compatible with all three skill ecosystems:
        - Minimax: explicit triggers arrays + metadata.category
        - skills-main: triggers extracted from description text
        - awesome-claude-skills: triggers extracted from description text

        All matching is based on keywords/aliases/triggers declared in each
        skill's SKILL.md YAML front-matter or extracted from description,
        making it compatible with any agent runtime (claude-code, codex, opencode).
        """
        _STOP_WORDS = frozenset({
            "skill", "skills", "this", "that", "with", "from", "your", "will",
            "used", "tool", "when", "use", "the", "and", "for", "any", "also",
            "file", "files", "want", "wants", "user", "like", "make", "create",
            "should", "include", "including", "mention", "need", "needs",
        })
        scored: list[tuple[int, int, str]] = []
        for s in skill_catalog:
            qname = str(s.get("qname", "")).strip()
            if not qname:
                continue
            score = 0
            longest = 0
            # Phase 1: Match explicit keywords (from triggers + aliases + keywords metadata)
            for kw in s.get("keywords", []) or []:
                token = str(kw or "").strip().lower()
                if not token or token in _STOP_WORDS:
                    continue
                if token in goal_low:
                    longest = max(longest, len(token))
                    # Multi-word matches get higher score
                    score += 5 if " " in token else 2
            # Phase 2: Match skill name tokens
            name = str(s.get("name", "")).strip().lower()
            if name and name not in _STOP_WORDS:
                name_tokens = [t for t in re.split(r"[-_\s]+", name) if t and len(t) >= 3 and t not in _STOP_WORDS]
                for nt in name_tokens:
                    if nt in goal_low:
                        score += 2
                        longest = max(longest, len(nt))
            # Phase 3: Description-based matching (for skills without explicit keywords)
            desc = str(s.get("desc", "")).strip().lower()
            if score == 0 and desc:
                # Extract meaningful words from description (4+ chars, not stop words)
                desc_words = set()
                for w in re.split(r"[\s,;/|().\"']+", desc):
                    w = w.strip()
                    if len(w) >= 4 and w not in _STOP_WORDS:
                        desc_words.add(w)
                for w in desc_words:
                    if w in goal_low:
                        score += 1
                        longest = max(longest, len(w))
                # Also try 2-gram phrases from description
                desc_tokens = desc.split()
                for i in range(len(desc_tokens) - 1):
                    bigram = f"{desc_tokens[i]} {desc_tokens[i+1]}"
                    if len(bigram) >= 6 and bigram in goal_low:
                        score += 3
                        longest = max(longest, len(bigram))
            if score > 0:
                scored.append((score, longest, qname))
        if not scored:
            return []
        scored.sort(reverse=True)
        matched: list[str] = []
        for _, _, qname in scored:
            if qname not in matched:
                matched.append(qname)
            if len(matched) >= 3:
                break
        return matched[:3]

    def _loaded_skills_prompt_hint(self, *, for_role: str = "") -> str:
        """Unified skill awareness hint for any system prompt."""
        bb = self._ensure_blackboard()
        loaded = bb.get("loaded_skills", {})
        skill_count = len(self.skills.skills) if hasattr(self.skills, "skills") else 0
        if isinstance(loaded, dict) and loaded:
            names = ", ".join(
                str((row or {}).get("skill_name", key) or key).strip() or key
                for key, row in list(loaded.items())[:5]
            )
            return (
                f"ACTIVE SKILLS: {names}. "
                "Follow the loaded skill instructions for the current step. "
                f"When moving to a different step that needs a DIFFERENT skill, call load_skill to switch "
                f"(or unload the current one first if it's no longer needed). "
                f"{skill_count} skills available total. "
            )
        return (
            f"SKILL SYSTEM: {skill_count} skills available. "
            "Skills are loaded ON-DEMAND — decide when you need one based on the CURRENT step, not upfront. "
            "For specialized output (reports, slides/PPT, deep research, code review, PDF analysis): "
            "call list_skills to discover options, then load_skill to activate the right one. "
            "Load a skill AT THE MOMENT you begin the step that requires it. "
            "Unload it (via unload_skill) when moving to a different step that needs a different skill. "
            "For simple tasks, direct questions, and multimodal analysis, do NOT load skills. "
        )

    def _skills_awareness_block(self, for_role: str = "developer") -> str:
        """Canonical skills-awareness block shared by single, sync, and plan-mode.
        Returns: loaded-skills hint  +  newline  +  'Skills:\\n<catalog>'
        Keeps all three modes in sync — change here propagates everywhere.
        """
        hint = self._loaded_skills_prompt_hint(for_role=for_role)
        return f"{hint}\nSkills:\n{self.skills.descriptions()}\n"

    def _refresh_runtime_code_reference(self, text: str):
        cb = getattr(self, "reference_prepare_callback", None)
        payload: dict = {}
        if callable(cb):
            try:
                raw = cb(self, str(text or ""))
                payload = dict(raw) if isinstance(raw, dict) else {}
            except Exception:
                payload = {}
        self.runtime_code_reference_text = trim(str(payload.get("code_text", payload.get("text", "")) or ""), 8000)
        meta = payload.get("code_meta", payload.get("meta", {}))
        self.runtime_code_reference_meta = dict(meta) if isinstance(meta, dict) else {}

    def _runtime_code_reference_prompt_block(self, max_chars: int = 4200) -> str:
        text = trim(str(getattr(self, "runtime_code_reference_text", "") or ""), max_chars)
        if not text:
            return ""
        meta = dict(getattr(self, "runtime_code_reference_meta", {}) or {})
        tags: list[str] = []
        route = str(meta.get("route", meta.get("requested_route", "")) or "").strip()
        if route:
            tags.append(f"route={route}")
        result_count = int(meta.get("result_count", meta.get("top_results", 0)) or 0)
        if result_count > 0:
            tags.append(f"results={result_count}")
        header = "Code Library Context"
        if tags:
            header += " [" + ", ".join(tags) + "]"
        return (
            f"{header}:\n"
            "Prioritize these code-library references for code implementation/review tasks before generic reasoning. "
            "If a reference conflicts with the current workspace file, trust the current workspace after verification.\n"
            f"{text}"
        )

    def _knowledge_library_prompt_block(self) -> str:
        info: dict = {}
        cb = getattr(self, "knowledge_library_status_callback", None)
        if callable(cb):
            try:
                raw = cb(self)
                info = dict(raw) if isinstance(raw, dict) else {}
            except Exception:
                info = {}
        root = str(info.get("root", "") or getattr(self, "knowledge_library_root", "") or "").strip()
        stats = info.get("stats", {}) if isinstance(info.get("stats", {}), dict) else {}
        docs = int(stats.get("documents", info.get("documents", 0)) or 0)
        chunks = int(stats.get("chunks", info.get("chunks", 0)) or 0)
        tasks = int(stats.get("tasks", info.get("tasks", 0)) or 0)
        ready = bool(info.get("ready", False) or docs > 0 or chunks > 0)
        tags = [f"ready={'yes' if ready else 'no'}", f"documents={docs}", f"chunks={chunks}"]
        if root:
            tags.insert(0, f"root={root}")
        if tasks > 0:
            tags.append(f"tasks={tasks}")
        header = "Knowledge Library"
        if tags:
            header += " [" + ", ".join(tags) + "]"
        return (
            f"{header}:\n"
            "Global TF-Graph_IDF RAG library for imported documents, PDFs, and research material. "
            "IMPORTANT: When the task involves a topic you may have documents for — research, analysis, "
            "fact-checking, synthesis — FIRST call query_knowledge_library(query='<topic>', top_k=8) "
            "to retrieve grounded references BEFORE generating your answer. "
            "Use route='hybrid' for best recall on broad topics; route='fast' for keyword lookups. "
            "Do not infer readiness from session/files or uploads — query the library directly."
        )

    def _multimodal_capability_block(self) -> str:
        """Return a brief system-prompt note about native multimodal capabilities.

        Injected into system prompt so the model knows it can directly analyze
        images/audio/video rather than falling back to text-only workarounds.
        Returns empty string when the active model has no multimodal input caps.
        """
        try:
            caps = self._capabilities_from_profile()
        except Exception:
            return ""
        types = []
        if caps.get("input_image"):
            types.append("images")
        if caps.get("input_audio"):
            types.append("audio")
        if caps.get("input_video"):
            types.append("video")
        if not types:
            return ""
        joined = "/".join(types)
        return (
            f"MULTIMODAL: This model supports native {joined} analysis. "
            f"When {joined} are attached or loaded via read_file, analyze them DIRECTLY "
            "using your built-in perception capabilities — do not describe them as "
            "inaccessible or attempt text-only workarounds. "
        )

    def _code_library_prompt_block(self) -> str:
        info: dict = {}
        cb = getattr(self, "code_library_status_callback", None)
        if callable(cb):
            try:
                raw = cb(self)
                info = dict(raw) if isinstance(raw, dict) else {}
            except Exception:
                info = {}
        root = str(info.get("root", "") or getattr(self, "code_library_root", "") or "").strip()
        stats = info.get("stats", {}) if isinstance(info.get("stats", {}), dict) else {}
        docs = int(stats.get("documents", info.get("documents", 0)) or 0)
        chunks = int(stats.get("chunks", info.get("chunks", 0)) or 0)
        tasks = int(stats.get("tasks", info.get("tasks", 0)) or 0)
        source_roots = [str(x).strip() for x in (info.get("source_roots", []) or []) if str(x).strip()]
        ready = bool(info.get("ready", False) or docs > 0 or chunks > 0)
        tags = [f"ready={'yes' if ready else 'no'}", f"documents={docs}", f"chunks={chunks}"]
        if root:
            tags.insert(0, f"root={root}")
        if tasks > 0:
            tags.append(f"tasks={tasks}")
        if source_roots:
            tags.append(f"source_roots={len(source_roots)}")
        header = "Code Library"
        if tags:
            header += " [" + ", ".join(tags) + "]"
        source_hint = ""
        if source_roots:
            preview = ", ".join(source_roots[:3])
            if len(source_roots) > 3:
                preview += ", ..."
            source_hint = (
                f" Discovered external raw code-corpus roots: {preview}. "
                "Those raw corpora are source trees, not the query index itself, unless they have been imported into the Code Library."
            )
        return (
            f"{header}:\n"
            "This is the global Code Graph Library for imported source-code references used in implementation and review tasks. "
            "It lives at the workspace root, not inside the current session files directory and not inside `.clouds_coder`."
            f"{source_hint} "
            "Do not infer code-library readiness by inspecting `session/files`, `uploads`, or `.clouds_coder/long_output`. "
            "Use `query_code_library` to check readiness or retrieve grounded code references from the global library."
        )

    def _system_prompt(self) -> str:
        try:
            self._ensure_skills_ready(force=False)
        except Exception:
            pass
        uploads_ctx = self._uploads_prompt_block()
        html_hint = self._html_frontend_boost_instruction()
        research_hint = self._deep_research_boost_instruction()
        knowledge_hint = self._knowledge_library_prompt_block()
        code_hint = self._code_library_prompt_block()
        code_ref_block = self._runtime_code_reference_prompt_block()
        runtime_level = int(self.runtime_task_level or 0)
        runtime_mode = self._effective_execution_mode()
        budget = int(self.runtime_round_budget or 0)
        html_block = f"{html_hint}\n\n" if html_hint else ""
        research_block = f"{research_hint}\n\n" if research_hint else ""
        knowledge_block = f"{knowledge_hint}\n\n" if knowledge_hint else ""
        code_hint_block = f"{code_hint}\n\n" if code_hint else ""
        code_block = f"{code_ref_block}\n\n" if code_ref_block else ""
        _is_single_no_enhance = (
            runtime_mode == EXECUTION_MODE_SINGLE
            and not self.single_advance_prompt_enhance
        )
        # Dynamic skill awareness — unified hint
        skill_hint = self._loaded_skills_prompt_hint(for_role="developer")
        if _is_single_no_enhance and not self._ensure_blackboard().get("loaded_skills"):
            skill_hint = (
                "Use load_skill for workspace-paths and tool-best-practices if needed. "
                "Use list_skills to discover available skills for specific tasks. "
            )
        plan_steps_block = ""
        plan_ctx = self._plan_steps_context_for_manager()
        if plan_ctx:
            plan_steps_block = f"{plan_ctx}\n"
        plan_todo_note = self._plan_todo_discipline_prompt(role="developer")
        plan_todo_block = f"{plan_todo_note}\n" if plan_todo_note else ""
        mm_block = self._multimodal_capability_block()
        mm_hint = f"{mm_block}\n" if mm_block else ""
        return (
            f"You are a coding agent. Workspace: \"{self.files_root}\" ($SESSION_ROOT). "
            f"Offline JS libraries root: $JS_LIB_ROOT. "
            f"Structure: flat .js files at $JS_LIB_ROOT/<name>.min.js; "
            f"pptxgenjs at $JS_LIB_ROOT/pptxgenjs/dist/pptxgen.cjs.js (CommonJS require) or pptxgen.bundle.js (browser). "
            f"Do NOT look in node_modules — libs are installed directly under $JS_LIB_ROOT. "
            f"Task level={runtime_level}, mode={runtime_mode}, "
            f"budget={'unlimited' if budget <= 0 else budget}. "
            f"Context limit ~{self.context_token_upper_bound} tokens. "
            f"{_detect_os_shell_instruction()} "
            "Use tools to inspect, edit, and execute. "
            "Call finish_current_task only when the overall user task is done. "
            f"{skill_hint}"
            f"{mm_hint}"
            f"{plan_steps_block}"
            f"{plan_todo_block}"
            f"{html_block}"
            f"{research_block}"
            f"{knowledge_block}"
            f"{code_hint_block}"
            f"{code_block}"
            f"{model_language_instruction(self.ui_language)}\n\n"
            f"Uploads:\n{uploads_ctx}\n\n"
            f"Skills:\n{self.skills.descriptions()}"
        )

    def _estimate_tokens(self) -> int:
        # Core: messages (global or agent context depending on mode)
        if self._is_multi_agent_mode():
            # In multi-agent mode, the actual context sent to the model is per-role
            # agent_messages filtered by active role. Use the largest agent context
            # as the representative cost, since that's the bottleneck.
            agent_max = 0
            for role in (self.runtime_participants or AGENT_ROLES):
                ctx = self._agent_context(role)
                if ctx:
                    cost = len(json_dumps(ctx)) // 4
                    if cost > agent_max:
                        agent_max = cost
            msg_tokens = max(agent_max, len(json_dumps(self.messages)) // 4)
        else:
            msg_tokens = len(json_dumps(self.messages)) // 4
        # Overhead: system prompt + tools (always present in API calls)
        try:
            sys_tokens = len(self._system_prompt()) // 4
        except Exception:
            sys_tokens = 300
        tools_tokens = len(json_dumps(TOOLS)) // 4 if TOOLS else 0
        return msg_tokens + sys_tokens + tools_tokens

    def _context_budget_metrics(self, token_estimate: int | None = None) -> dict:
        limit = max(1, int(self.context_token_upper_bound or 0))
        used = max(0, int(token_estimate if token_estimate is not None else self._estimate_tokens()))
        left = max(0, limit - used)
        left_pct = max(0.0, min(100.0, (left * 100.0) / limit))
        used_pct = max(0.0, min(100.0, (used * 100.0) / limit))
        return {
            "limit": limit,
            "used": used,
            "left": left,
            "left_percent": left_pct,
            "used_percent": used_pct,
        }

    def _context_compression_tier(self, metrics: dict | None = None) -> int:
        """Return compression tier 0-3 based on context budget.
        Tier 0: >40% left (normal)
        Tier 1: 20-40% left (light — aggressive microcompact, trim outputs)
        Tier 2: 10-20% left (medium — compact agent contexts, file buffer)
        Tier 3: <10% left (heavy — deep compact everything)
        """
        m = metrics or self._context_budget_metrics()
        left = int(m.get("left", 0))
        left_pct = float(m.get("left_percent", 100.0)) / 100.0
        if left < COMPACT_TIER2_ABS:
            return 3
        if left < COMPACT_TIER1_ABS:
            return max(2, 3 if left_pct < COMPACT_TIER3_PCT else 2)
        if left_pct < COMPACT_TIER3_PCT:
            return 3
        if left_pct < COMPACT_TIER2_PCT:
            return 2
        if left_pct < COMPACT_TIER1_PCT:
            return 1
        return 0

    def _tier_agent_context_limits(self, tier: int) -> dict:
        """Return message count limits for agent_messages, contexts, manager_context by tier."""
        t = min(max(tier, 0), 3)
        return {
            "agent_messages": [AGENT_MSG_LIMIT_TIER0, AGENT_MSG_LIMIT_TIER1, AGENT_MSG_LIMIT_TIER2, AGENT_MSG_LIMIT_TIER3][t],
            "context_per_role": [AGENT_CTX_LIMIT_TIER0, AGENT_CTX_LIMIT_TIER1, AGENT_CTX_LIMIT_TIER2, AGENT_CTX_LIMIT_TIER3][t],
            "manager_context": [MANAGER_CTX_LIMIT_TIER0, MANAGER_CTX_LIMIT_TIER1, MANAGER_CTX_LIMIT_TIER2, MANAGER_CTX_LIMIT_TIER3][t],
        }

    def _compact_agent_contexts(self, tier: int):
        """Compress agent_messages, manager_context, and per-role contexts based on tier."""
        limits = self._tier_agent_context_limits(tier)
        am_limit = limits["agent_messages"]
        ctx_limit = limits["context_per_role"]
        mgr_limit = limits["manager_context"]
        # 1. Microcompact agent messages (tier >= 1)
        if tier >= 1:
            keep = max(1, 3 - tier)  # tier1=2, tier2=1, tier3=0(but min 1)
            self._microcompact_agent_messages(self.agent_messages, keep_recent=keep)
        # 2. Trim agent_messages to limit
        if len(self.agent_messages) > am_limit:
            self.agent_messages = self.agent_messages[-am_limit:]
        # 3. Trim manager_context
        if len(self.manager_context) > mgr_limit:
            self.manager_context = self.manager_context[-mgr_limit:]
        # 4. Trim per-role contexts
        for role in AGENT_ROLES:
            ctx = self.contexts.get(role, [])
            if len(ctx) > ctx_limit:
                self.contexts[role] = ctx[-ctx_limit:]
        # 5. Tier 2+: offload large content in agent messages to file buffer
        if tier >= 2:
            self._offload_agent_message_content(self.agent_messages)
            self._offload_agent_message_content(self.manager_context)
        # 6. Tier 3: aggressive content trimming
        if tier >= 3:
            for msg in self.agent_messages:
                c = msg.get("content", "")
                if isinstance(c, str) and len(c) > 600:
                    msg["content"] = trim(c, 600)
            for msg in self.manager_context:
                c = msg.get("content", "")
                if isinstance(c, str) and len(c) > 600:
                    msg["content"] = trim(c, 600)
        # 7. Plan mode context compression — tiered by ctx_left
        self._compact_plan_context(tier)

    def _compact_plan_context(self, tier: int):
        """Compress plan mode context based on tier.
        Tier 0: keep everything
        Tier 1: trim plan findings to last 3
        Tier 2: drop plan findings, keep only plan steps + user choice
        Tier 3: minimal — only plan steps and chosen option title
        """
        bb = self._ensure_blackboard()
        plan = bb.get("plan")
        if not isinstance(plan, dict):
            return
        if tier <= 0:
            return
        if tier == 1:
            # Keep last 3 findings
            findings = plan.get("findings", [])
            if isinstance(findings, list) and len(findings) > 3:
                plan["findings"] = findings[-3:]
        elif tier == 2:
            # Drop findings entirely, keep steps + proposal summary
            plan.pop("findings", None)
            proposal = plan.get("proposal", {})
            if isinstance(proposal, dict):
                # Trim option details — keep only chosen option
                chosen_id = str(plan.get("chosen", "") or "")
                options = proposal.get("options", [])
                if isinstance(options, list) and chosen_id:
                    proposal["options"] = [
                        o for o in options
                        if isinstance(o, dict) and o.get("id") == chosen_id
                    ]
                    # Trim chosen option — drop pros/cons/risk
                    for o in proposal.get("options", []):
                        o.pop("pros", None)
                        o.pop("cons", None)
                        o.pop("risk", None)
        elif tier >= 3:
            # Minimal: keep execution snapshot fields that drive plan.md/todos.
            compact_plan = {
                "phase": plan.get("phase", ""),
                "chosen": plan.get("chosen", ""),
                "steps": plan.get("steps", []),
            }
            for key in ("title", "summary", "risk"):
                value = plan.get(key)
                if value:
                    compact_plan[key] = value
            bb["plan"] = compact_plan
        self.blackboard = bb
        # Also trim plan proposal in runtime state
        if tier >= 2 and self.runtime_plan_proposal:
            chosen_id = str(self.runtime_plan_choice or "")
            if chosen_id:
                options = self.runtime_plan_proposal.get("options", [])
                if isinstance(options, list):
                    self.runtime_plan_proposal["options"] = [
                        o for o in options if isinstance(o, dict) and o.get("id") == chosen_id
                    ]
            if tier >= 3:
                # Only clear proposal if plan is fully done
                plan_phase = str(bb.get("plan", {}).get("phase", ""))
                if plan_phase not in ("executing", "awaiting_choice"):
                    self.runtime_plan_proposal = {}

    def _apply_auto_compact_if_needed(self, reason: str = "auto") -> bool:
        metrics = self._context_budget_metrics()
        tier = self._context_compression_tier(metrics)
        # Tier 1+: apply progressively aggressive microcompact
        if tier >= 1:
            keep = max(1, 3 - tier)
            self._microcompact(keep_recent=keep)
        else:
            self._microcompact()
        # Tier 2+: compact agent contexts proactively
        if tier >= 2:
            self._compact_agent_contexts(tier)
        # Re-check after tier-based compression
        metrics = self._context_budget_metrics()
        used = int(metrics.get("used", 0) or 0)
        limit = max(1, int(metrics.get("limit", 0) or 0))
        if used < limit:
            return False
        now_tick = now_ts()
        if (now_tick - float(self.last_compact_ts or 0.0)) < 0.8:
            return False
        self._auto_compact(reason)
        return True

    def _estimate_output_tokens(self, text: str, thinking_text: str = "", tool_calls: list | None = None) -> int:
        t_main = len(str(text or "")) // 4
        t_think = len(str(thinking_text or "")) // 4
        t_tools = 0
        for tc in tool_calls or []:
            try:
                t_tools += len(json_dumps(tc)) // 4
            except Exception:
                t_tools += len(str(tc)) // 4
        return max(1, t_main + t_think + t_tools)

    def _derive_context_limit_from_output(self, output_tokens: int) -> int:
        estimated = int(
            max(MIN_CONTEXT_TOKEN_LIMIT, min(self.max_context_token_limit, output_tokens * 12))
        )
        return max(MIN_CONTEXT_TOKEN_LIMIT, min(self.max_context_token_limit, estimated))

    def _trim_truncated_tail_line(self, text: str) -> str:
        src = str(text or "")
        if not src:
            return ""
        if src.endswith("\n"):
            return src
        idx = src.rfind("\n")
        head = src[: idx + 1] if idx >= 0 else ""
        tail = src[idx + 1 :] if idx >= 0 else src
        tail_s = tail.strip()
        if not tail_s:
            return head.rstrip("\n")
        if re.search(r"[,:\-({\[`\"'`]+$", tail_s):
            return head.rstrip("\n")
        return src

    def _pair_completion_suffix(self, text: str) -> str:
        src = str(text or "")
        if not src:
            return ""
        src = src[-TRUNCATION_PAIR_SCAN_CHARS:]
        suffix = ""
        if src.count("```") % 2 == 1:
            suffix += "\n```"
        stack: list[str] = []
        in_string = False
        escaped = False
        for ch in src:
            if in_string:
                if escaped:
                    escaped = False
                    continue
                if ch == "\\":
                    escaped = True
                    continue
                if ch == "\"":
                    in_string = False
                continue
            if ch == "\"":
                in_string = True
                continue
            if ch in "{[(":
                stack.append(ch)
                continue
            if ch == ")" and stack and stack[-1] == "(":
                stack.pop()
                continue
            if ch == "]" and stack and stack[-1] == "[":
                stack.pop()
                continue
            if ch == "}" and stack and stack[-1] == "{":
                stack.pop()
                continue
        if in_string:
            suffix += "\""
        closer = {"(": ")", "[": "]", "{": "}"}
        while stack:
            suffix += closer.get(stack.pop(), "")
        return suffix

    def _merge_continuation_text(self, base: str, cont: str) -> str:
        left = str(base or "")
        right = str(cont or "")
        if not right.strip():
            return left
        merged_right = right.lstrip()
        merged_right = re.sub(
            r"^(继续|接下来|以下是续写|continuation[:：]?|continue[:：]?)\s*",
            "",
            merged_right,
            flags=re.IGNORECASE,
        )
        max_scan = min(TRUNCATION_OVERLAP_SCAN_CHARS, len(left), len(merged_right))
        for k in range(max_scan, 24, -1):
            if left[-k:] == merged_right[:k]:
                merged_right = merged_right[k:]
                break
        if not merged_right:
            return left
        if left and merged_right:
            if not left.endswith(("\n", " ", "\t")) and not merged_right.startswith(
                ("\n", " ", "\t", ".", ",", "，", "。", ";", "；", ":", "：", ")", "]", "}")
            ):
                return left + "\n" + merged_right
        return left + merged_right

    def _publish_live_truncation(
        self,
        *,
        text: str,
        attempts: int,
        tokens: int,
        active: bool,
        kind: str = "",
        tool: str = "",
        force_emit: bool = False,
    ):
        now_tick = now_ts()
        with self.lock:
            prev_active = bool(self.live_truncation_active)
            prev_text = str(self.live_truncation_text or "")
            prev_attempts = int(self.live_truncation_attempts or 0)
            prev_tokens = int(self.live_truncation_tokens or 0)
            prev_kind = str(self.live_truncation_kind or "")
            prev_tool = str(self.live_truncation_tool or "")
            clipped = str(text or "")
            if len(clipped) > TRUNCATION_LIVE_BUFFER_MAX_CHARS:
                clipped = clipped[-TRUNCATION_LIVE_BUFFER_MAX_CHARS:]
            attempts_now = max(0, int(attempts or 0))
            tokens_now = max(0, int(tokens or 0))
            active_now = bool(active)
            kind_now = str(kind or "").strip()
            tool_now = str(tool or "").strip()
            self.live_truncation_text = clipped
            self.live_truncation_attempts = attempts_now
            self.live_truncation_tokens = tokens_now
            self.live_truncation_active = active_now
            self.live_truncation_kind = kind_now
            self.live_truncation_tool = tool_now
            changed = (
                prev_active != active_now
                or prev_text != clipped
                or prev_attempts != attempts_now
                or prev_tokens != tokens_now
                or prev_kind != kind_now
                or prev_tool != tool_now
            )
            if changed:
                self.updated_at = now_tick
            should_emit = bool(force_emit)
            if changed and active_now:
                should_emit = should_emit or (now_tick - self.live_truncation_last_emit >= 0.35)
            if changed and (prev_active != active_now):
                should_emit = True
            if should_emit:
                self.live_truncation_last_emit = now_tick
        if should_emit:
            self._emit_transient(
                "truncation_delta",
                {
                    "summary": (
                        f"truncation continuation {'active' if active else 'updated'} "
                        f"(attempts={max(0, int(attempts or 0))}, tokens≈{max(0, int(tokens or 0))}"
                        f"{'; kind=' + str(kind).strip() if str(kind).strip() else ''}"
                        f"{'; tool=' + str(tool).strip() if str(tool).strip() else ''})"
                    ),
                    "attempts": max(0, int(attempts or 0)),
                    "tokens": max(0, int(tokens or 0)),
                    "active": bool(active),
                    "kind": str(kind or "").strip(),
                    "tool": str(tool or "").strip(),
                },
            )

    def _clear_live_truncation(self):
        self._publish_live_truncation(text="", attempts=0, tokens=0, active=False, force_emit=False)

    def _build_truncation_continue_prompt(
        self,
        partial_text: str,
        *,
        attempt: int,
        max_attempts: int,
        output_tokens: int,
    ) -> str:
        tail = str(partial_text or "")
        if len(tail) > TRUNCATION_CONTINUATION_TAIL_CHARS:
            tail = tail[-TRUNCATION_CONTINUATION_TAIL_CHARS:]
        pair_hint = self._pair_completion_suffix(tail)
        return (
            "<truncation-continue>"
            "Your previous assistant output was truncated by token limit. "
            f"attempt={attempt}/{max_attempts}, previous_tokens≈{max(0, int(output_tokens or 0))}. "
            "Continue from the exact cut-off position only. "
            "Do NOT restart from the beginning. Do NOT add meta commentary. "
            "If delimiters/fences are left open, close them correctly.\n"
            f"Pair-completion hint: {pair_hint if pair_hint else '(none)'}\n"
            "Current tail context:\n"
            "```text\n"
            f"{tail}\n"
            "```\n"
            "</truncation-continue>"
        )

    def _continue_truncated_assistant_output(
        self,
        *,
        partial_text: str,
        output_tokens: int,
        pinned_selection: str,
        kind: str = "assistant",
        tool_name: str = "",
        max_passes: int = TRUNCATION_CONTINUATION_MAX_PASSES,
        max_tokens: int = TRUNCATION_CONTINUATION_MAX_TOKENS,
    ) -> tuple[str, int, dict]:
        working = str(partial_text or "")
        tokens_now = max(1, int(output_tokens or self._estimate_output_tokens(working, "", [])))
        attempts = 0
        resolved = False
        if not working.strip():
            return working, tokens_now, {"attempts": 0, "resolved": False}

        now_tick = now_ts()
        if now_tick - self.last_truncation_ts >= 0.2:
            self.truncation_count += 1
        self.last_truncation_ts = now_tick
        old_bound = int(self.context_token_upper_bound)
        new_bound = self._derive_context_limit_from_output(tokens_now)
        self.context_token_upper_bound = min(old_bound, new_bound)

        self._publish_live_truncation(
            text=working,
            attempts=0,
            tokens=tokens_now,
            active=True,
            kind=kind,
            tool=tool_name,
            force_emit=True,
        )
        sys_prompt = (
            "You are continuing a truncated output. "
            "Return ONLY the continuation text (no markdown, no code fences unless already open, no meta). "
            "Do not restart from the beginning."
        )
        if kind == "tool_args":
            sys_prompt = (
                "You are continuing a truncated JSON payload for tool arguments. "
                "Return ONLY the continuation bytes that must be appended to the existing JSON. "
                "No markdown, no explanations."
            )
        sys_prompt = f"{sys_prompt}\n\n{model_language_instruction(self.ui_language)}"

        for idx in range(max(1, int(max_passes or TRUNCATION_CONTINUATION_MAX_PASSES))):
            attempts = idx + 1
            trimmed = self._trim_truncated_tail_line(working)
            prompt = self._build_truncation_continue_prompt(
                trimmed,
                attempt=attempts,
                max_attempts=max(1, int(max_passes or TRUNCATION_CONTINUATION_MAX_PASSES)),
                output_tokens=tokens_now,
            )
            assist_echo = (
                trimmed
                if len(trimmed) <= TRUNCATION_CONTINUATION_ECHO_CHARS
                else trimmed[-TRUNCATION_CONTINUATION_ECHO_CHARS:]
            )
            carry_msgs = [
                {"role": "assistant", "content": assist_echo, "ts": now_ts()},
                {"role": "user", "content": prompt, "ts": now_ts()},
            ]
            self._emit(
                "status",
                {
                    "summary": (
                        "truncation continuation pass "
                        f"{attempts}/{max(1, int(max_passes or TRUNCATION_CONTINUATION_MAX_PASSES))} "
                        f"(tokens≈{tokens_now})"
                    )
                },
            )
            try:
                rsp = self._chat_with_same_model_retry(
                    carry_msgs,
                    tools=None,
                    system=sys_prompt,
                    max_tokens=max(800, int(max_tokens or TRUNCATION_CONTINUATION_MAX_TOKENS)),
                    think=False,
                    stream_thinking=False,
                    on_thinking_chunk=self._append_live_thinking,
                    pinned_selection=pinned_selection,
                    context_label="truncation continuation",
                    retries=1,
                    media_inputs=None,
                )
            except Exception as exc:
                self._emit(
                    "status",
                    {"summary": f"truncation continuation failed: {trim(str(exc), 180)}"},
                )
                break
            cont = str(rsp.get("content") or "")
            if not cont.strip():
                break
            merged = self._merge_continuation_text(trimmed, cont)
            if merged == working:
                break
            working = merged
            tokens_now = self._estimate_output_tokens(working, "", [])
            self._publish_live_truncation(
                text=working,
                attempts=attempts,
                tokens=tokens_now,
                active=True,
                kind=kind,
                tool=tool_name,
                force_emit=False,
            )
            if not self._looks_like_truncated_generation(working, [], tokens_now):
                resolved = True
                break

        finalized = self._trim_truncated_tail_line(working)
        suffix = self._pair_completion_suffix(finalized)
        if suffix and (not finalized.endswith(suffix)):
            finalized = f"{finalized}{suffix}"
            tokens_now = self._estimate_output_tokens(finalized, "", [])
            if not self._looks_like_truncated_generation(finalized, [], tokens_now):
                resolved = True

        self._publish_live_truncation(
            text=finalized,
            attempts=attempts,
            tokens=tokens_now,
            active=False,
            kind=kind,
            tool=tool_name,
            force_emit=True,
        )
        return finalized, tokens_now, {"attempts": attempts, "resolved": bool(resolved)}

    def _parse_tool_args_text(self, text: str) -> tuple[dict, str]:
        src = str(text or "").strip()
        if not src:
            return {}, "empty"
        direct = extract_json_object_from_text(src, {})
        if direct:
            return direct, ""
        repaired = repair_truncated_json_object(src)
        if repaired and repaired != src:
            boxed = extract_json_object_from_text(repaired, {})
            if boxed:
                return boxed, ""
        return {}, "json-parse-failed"

    def _looks_like_raw_toolcall_blob(self, text: str) -> bool:
        raw = str(text or "").strip().lower()
        if not raw:
            return False
        if "<toolcall" not in raw and "<tool_call" not in raw and "<tool-call" not in raw:
            return False
        if '"name"' in raw and '"arguments"' in raw:
            return True
        signals = (
            "write_file",
            "writefile",
            "read_file",
            "readfile",
            "edit_file",
            "todo",
            "tool_call",
        )
        return any(sig in raw for sig in signals)

    def _sanitize_assistant_text_for_runtime(self, text: str, tool_calls: list | None = None) -> tuple[str, dict]:
        raw = str(text or "")
        clean = raw.strip()
        meta = {"filtered": False, "reason": "", "original_chars": len(raw)}
        if not clean:
            return raw, meta
        # Filter raw <tool_call> XML regardless of size — any size is invalid display content
        if not tool_calls and self._looks_like_raw_toolcall_blob(clean):
            note = (
                "[toolcall payload omitted: detected inline <toolcall> text. "
                "Please regenerate a compact structured tool call.]"
            )
            meta.update({"filtered": True, "reason": "raw_toolcall"})
            return note, meta
        if len(raw) > int(ASSISTANT_TEXT_PERSIST_MAX_CHARS):
            clipped = trim(raw, int(ASSISTANT_TEXT_PERSIST_MAX_CHARS))
            meta.update({"filtered": True, "reason": "oversized_assistant_text"})
            return clipped, meta
        return raw, meta

    def _inject_toolcall_overflow_hint(self, role: str = ""):
        now = now_ts()
        if (now - float(self.last_toolcall_overflow_hint_ts or 0.0)) < 6.0:
            return
        self.last_toolcall_overflow_hint_ts = now
        hint = (
            "<toolcall-overflow-recovery>"
            "检测到上一轮输出了超长 inline <toolcall> 文本（可能已截断），该内容已被系统省略以保护前端渲染。"
            "请立即重发：仅输出一个结构化工具调用，不要在普通文本中粘贴超长 JSON 或全文代码。"
            "如需写大文件，请分段调用写文件工具。"
            "</toolcall-overflow-recovery>"
        )
        role_key = self._sanitize_agent_role(role)
        if role_key:
            self._append_agent_context_message(
                role_key,
                {"role": "user", "content": hint, "ts": now, "agent_role": role_key},
                mirror_to_global=False,
            )
            self._emit(
                "status",
                {
                    "summary": (
                        f"{self._agent_display_name(role_key)} output overflow detected; "
                        "inline toolcall payload was suppressed and recovery hint injected"
                    )
                },
            )
            return
        self.messages.append({"role": "user", "content": hint, "ts": now})
        self._emit(
            "status",
            {
                "summary": (
                    "oversized inline toolcall payload suppressed; "
                    "recovery hint injected for next model turn"
                )
            },
        )

    def _recover_tool_args_from_malformed(
        self,
        *,
        name: str,
        raw_args: object,
        pinned_selection: str,
    ) -> tuple[bool, dict, str]:
        if not isinstance(raw_args, (str, dict, list)):
            return False, {}, "no raw_args"
        raw = str(raw_args or "").strip()
        if not raw:
            return False, {}, "empty raw_args"
        parsed, _ = self._parse_tool_args_text(raw)
        if parsed:
            return True, parsed, "parsed"
        out_tokens = self._estimate_output_tokens(raw, "", [])
        repaired_text, _, meta = self._continue_truncated_assistant_output(
            partial_text=raw,
            output_tokens=out_tokens,
            pinned_selection=pinned_selection,
            kind="tool_args",
            tool_name=name,
            max_passes=2,
            max_tokens=1400,
        )
        parsed2, err2 = self._parse_tool_args_text(repaired_text)
        if parsed2:
            attempts = int(meta.get("attempts", 0) or 0)
            return True, parsed2, f"continued-passes={attempts}"
        return False, {}, err2 or "recover-failed"

    def _recover_tool_args_from_missing(
        self,
        *,
        name: str,
        args: dict,
        missing: list[str],
        pinned_selection: str,
    ) -> tuple[bool, dict, str]:
        if not isinstance(args, dict):
            return False, {}, "args-not-object"
        src = json_dumps(args)
        if not src:
            return False, {}, "empty"
        prompt = (
            "Tool arguments appear incomplete (likely truncated). "
            f"Missing required keys: {', '.join(missing)}. "
            "Return ONLY a complete JSON object for the same tool call."
        )
        user_msg = (
            "<tool-args-recover>\n"
            f"tool={name}\n"
            f"{prompt}\n"
            "Current partial args:\n"
            "```json\n"
            f"{src}\n"
            "```\n"
            "</tool-args-recover>"
        )
        try:
            rsp = self._chat_with_same_model_retry(
                [{"role": "user", "content": user_msg, "ts": now_ts()}],
                tools=None,
                system=(
                    "You repair tool argument JSON. Return ONLY one valid JSON object and nothing else.\n\n"
                    + model_language_instruction(self.ui_language)
                ),
                max_tokens=1000,
                think=False,
                stream_thinking=False,
                on_thinking_chunk=self._append_live_thinking,
                pinned_selection=pinned_selection,
                context_label="tool args recover",
                retries=1,
                media_inputs=None,
            )
        except Exception as exc:
            return False, {}, trim(str(exc), 140)
        out = str(rsp.get("content") or "")
        parsed, err = self._parse_tool_args_text(out)
        if parsed:
            return True, parsed, "model-repaired"
        return False, {}, err or "model-repair-failed"

    def _looks_like_truncated_generation(
        self,
        text: str,
        tool_calls: list | None,
        output_tokens: int,
    ) -> bool:
        raw = str(text or "").strip()
        if not raw:
            return False
        # Strong structural truncation signals.
        if raw.count("```") % 2 == 1:
            return True
        if raw.endswith(("{", "[", "(")):
            return True
        # If model already emitted tool calls, avoid false-positive text truncation detection.
        if tool_calls:
            return False

        near_limit = output_tokens >= int(self.max_output_tokens * 0.90)
        # Mid-size outputs (e.g. planning text ending with a Chinese colon) should not be
        # treated as truncation unless close to max tokens or JSON-like unfinished payload.
        json_like_tail = bool(
            re.search(r"[\{\[][^}\]]*$", raw[-280:]) or re.search(r"\"[^\"]*\"\s*:\s*$", raw[-180:])
        )
        if raw.endswith((",", ":", "：")):
            if near_limit or json_like_tail:
                return True
            return False
        if raw.endswith("-"):
            if near_limit and not re.search(r"[。！？.!?]$", raw[:-1].rstrip()):
                return True
            return False

        if not near_limit:
            return False
        if re.search(r"[。！？.!?]$", raw):
            return False
        if len(raw) < 120:
            return False
        return True

    def _has_open_truncation_tasks(self) -> bool:
        for task in self.tasks.list_objects():
            subject = str(task.get("subject", ""))
            status = str(task.get("status", ""))
            if subject.startswith("[TRUNCATION]") and status in {"pending", "in_progress"}:
                return True
        return False

    def _create_truncation_subtasks(self, reason: str) -> list[int]:
        if self._has_open_truncation_tasks():
            return []
        goal = self._latest_user_goal_text()
        subjects = [
            f"[TRUNCATION] Scope and split: {trim(goal, 88)}",
            "[TRUNCATION] Implement current chunk with tools",
            "[TRUNCATION] Verify output and finish next chunk",
        ]
        ids: list[int] = []
        for idx, subject in enumerate(subjects):
            desc = (
                f"auto-created due to truncation: {trim(reason, 180)}; "
                f"step={idx + 1}/{len(subjects)}"
            )
            row = parse_json_object(self.tasks.create(subject, desc), {})
            task_id = int(row.get("id", 0) or 0)
            if task_id > 0:
                ids.append(task_id)
        if not ids:
            return []
        self.tasks.update(ids[0], status="in_progress")
        for i in range(1, len(ids)):
            self.tasks.update(ids[i], add_blocked_by=[ids[i - 1]])
        self.truncation_rescue_task_ids = list(ids)
        self._emit(
            "status",
            {
                "summary": f"truncation subtasks created: {', '.join(str(x) for x in ids)}",
            },
        )
        return ids

    def _ensure_truncation_todos(self):
        if self.todo.snapshot():
            return
        try:
            self.todo.update(
                [
                    {
                        "content": "Split task into small subtasks",
                        "status": "in_progress",
                    },
                    {
                        "content": "Execute one subtask and persist intermediate result",
                        "status": "pending",
                    },
                    {
                        "content": "Validate and continue remaining subtasks",
                        "status": "pending",
                    },
                ]
            )
        except Exception:
            pass

    def _inject_truncation_rescue_hint(self, reason: str, output_tokens: int, task_ids: list[int]):
        ids_txt = ", ".join(str(x) for x in task_ids) if task_ids else "(reuse existing tasks)"
        self._prune_runtime_retry_hints()
        self.messages.append(
            {
                "role": "user",
                "content": (
                    "<truncate-rescue>"
                    f"Detected truncation: {trim(reason, 220)}. "
                    f"Estimated output tokens: {output_tokens}. "
                    f"Current context upper bound: {self.context_token_upper_bound}. "
                    f"Subtasks: {ids_txt}. "
                    "Before retrying failed tool calls, first create/update a compact TodoWrite plan (3-7 items) "
                    "that splits work into chunks. "
                    "Execute one subtask at a time, keep tool arguments complete JSON and concise. "
                    "After each subtask, update task/todo status before moving on."
                    "</truncate-rescue>"
                ),
                "ts": now_ts(),
            }
        )

    def _handle_truncation_rescue(
        self,
        reason: str,
        output_tokens: int,
        source: str = "",
        *,
        allow_compact: bool = True,
    ):
        now_tick = now_ts()
        if now_tick - self.last_truncation_ts < 1.5:
            return
        self.truncation_count += 1
        self.last_truncation_ts = now_tick
        old_bound = self.context_token_upper_bound
        if not self.context_limit_locked:
            new_bound = self._derive_context_limit_from_output(output_tokens)
            self.context_token_upper_bound = min(old_bound, new_bound)
            if self.context_token_upper_bound < old_bound:
                self._emit(
                    "status",
                    {
                        "summary": (
                            f"context upper bound adjusted {old_bound}->{self.context_token_upper_bound} "
                            f"(output_tokens≈{output_tokens})"
                        )
                    },
                )
        if allow_compact and self._estimate_tokens() > self.context_token_upper_bound:
            self._auto_compact(f"truncation-rescue:{source or 'auto'}")
        self._ensure_truncation_todos()
        task_ids = self._create_truncation_subtasks(reason)
        self._inject_truncation_rescue_hint(reason, output_tokens, task_ids)

    def _find_tool_name_by_id(self, messages: list[dict], tool_use_id: str) -> str:
        """Find tool name from preceding assistant message by tool_use_id."""
        if not tool_use_id:
            return ""
        for msg in reversed(messages):
            if msg.get("role") != "assistant":
                continue
            for tc in msg.get("tool_calls", []):
                if isinstance(tc, dict) and tc.get("id") == tool_use_id:
                    fn = tc.get("function", {})
                    return str(fn.get("name", "")) if isinstance(fn, dict) else ""
            content = msg.get("content")
            if isinstance(content, list):
                for block in content:
                    if isinstance(block, dict) and block.get("type") == "tool_use" and block.get("id") == tool_use_id:
                        return str(block.get("name", ""))
        return ""

    def _microcompact(self, keep_recent: int = 3):
        """Replace old tool results with compact placeholders to save tokens.

        Handles both OpenAI-style (role=tool) and Anthropic-style (tool_result blocks)
        messages. Keeps the most recent `keep_recent` tool interactions intact.
        """
        # Phase 1: OpenAI-style role=tool messages
        tool_messages = [m for m in self.messages if m.get("role") == "tool"]
        if len(tool_messages) > keep_recent:
            kept = tool_messages[-keep_recent:]
            keep_ids = {id(x) for x in kept}
            for msg in self.messages:
                if msg.get("role") == "tool" and id(msg) not in keep_ids:
                    content = msg.get("content", "")
                    if isinstance(content, str) and len(content) > 120:
                        msg["content"] = "[cleared by microcompact]"

        # Phase 2: Anthropic-style tool_result blocks in user messages
        assistant_indices = [i for i, m in enumerate(self.messages) if m.get("role") == "assistant"]
        if len(assistant_indices) <= keep_recent:
            return
        cutoff = assistant_indices[-keep_recent]
        for i in range(cutoff):
            msg = self.messages[i]
            if msg.get("role") == "user" and isinstance(msg.get("content"), list):
                changed = False
                new_content = []
                for block in msg["content"]:
                    if isinstance(block, dict) and block.get("type") == "tool_result":
                        block_content = block.get("content", "")
                        if isinstance(block_content, str) and len(block_content) > 120:
                            tool_id = block.get("tool_use_id", "")
                            tool_name = self._find_tool_name_by_id(self.messages[:i], tool_id) or "tool"
                            new_content.append({
                                "type": "tool_result",
                                "tool_use_id": tool_id,
                                "content": f"[Previous: used {tool_name}]",
                            })
                            changed = True
                        else:
                            new_content.append(block)
                    else:
                        new_content.append(block)
                if changed:
                    msg["content"] = new_content

    def _microcompact_agent_messages(self, messages: list[dict], keep_recent: int = 3):
        """Apply microcompact to an agent-specific message list (e.g. agent_messages filtered by role)."""
        tool_messages = [m for m in messages if m.get("role") == "tool"]
        if len(tool_messages) > keep_recent:
            kept = tool_messages[-keep_recent:]
            keep_ids = {id(x) for x in kept}
            for msg in messages:
                if msg.get("role") == "tool" and id(msg) not in keep_ids:
                    content = msg.get("content", "")
                    if isinstance(content, str) and len(content) > 120:
                        msg["content"] = "[cleared by microcompact]"
        assistant_indices = [i for i, m in enumerate(messages) if m.get("role") == "assistant"]
        if len(assistant_indices) <= keep_recent:
            return
        cutoff = assistant_indices[-keep_recent]
        for i in range(cutoff):
            msg = messages[i]
            if msg.get("role") == "user" and isinstance(msg.get("content"), list):
                changed = False
                new_content = []
                for block in msg["content"]:
                    if isinstance(block, dict) and block.get("type") == "tool_result":
                        block_content = block.get("content", "")
                        if isinstance(block_content, str) and len(block_content) > 120:
                            tool_id = block.get("tool_use_id", "")
                            tool_name = self._find_tool_name_by_id(messages[:i], tool_id) or "tool"
                            new_content.append({
                                "type": "tool_result",
                                "tool_use_id": tool_id,
                                "content": f"[Previous: used {tool_name}]",
                            })
                            changed = True
                        else:
                            new_content.append(block)
                    else:
                        new_content.append(block)
                if changed:
                    msg["content"] = new_content

    def _estimate_messages_tokens(self, rows: list[dict]) -> int:
        try:
            return len(json_dumps(rows)) // 4
        except Exception:
            total = 0
            for row in rows:
                total += len(str(row.get("content", ""))) // 4
            return total

    def _select_compact_tail(self, token_budget: int, min_count: int = 4, max_count: int = 48) -> list[dict]:
        if not self.messages:
            return []
        budget = max(1000, int(token_budget))
        selected: list[dict] = []
        total = 0
        for row in reversed(self.messages):
            row_tokens = max(1, self._estimate_messages_tokens([row]))
            if selected and len(selected) >= min_count and (total + row_tokens) > budget:
                break
            selected.append(row)
            total += row_tokens
            if len(selected) >= max_count:
                break
        selected.reverse()
        return [dict(x) for x in selected]

    def _archive_context_segment(self, rows: list[dict], reason: str) -> dict:
        if not rows:
            return {}
        seg_id = f"ctxseg_{int(now_ts())}_{uuid.uuid4().hex[:8]}"
        fp = self.context_archive_dir / f"{seg_id}.jsonl"
        sha = hashlib.sha256()
        first_ts = 0.0
        last_ts = 0.0
        count = 0
        with fp.open("w", encoding="utf-8") as handle:
            for idx, row in enumerate(rows):
                line = json_dumps(row)
                payload = (line + "\n").encode("utf-8")
                sha.update(payload)
                handle.write(line + "\n")
                msg_ts = float(row.get("ts", 0.0) or 0.0)
                if idx == 0:
                    first_ts = msg_ts
                last_ts = msg_ts
                count += 1
        rel_path = fp.relative_to(self.root).as_posix()
        seg = {
            "id": seg_id,
            "path": rel_path,
            "reason": str(reason or ""),
            "messages": count,
            "bytes": int(fp.stat().st_size if fp.exists() else 0),
            "sha256": sha.hexdigest(),
            "created_at": now_ts(),
            "first_ts": first_ts,
            "last_ts": last_ts,
        }
        self.context_archives.append(seg)
        self.context_archives = self.context_archives[-MAX_CONTEXT_ARCHIVE_SEGMENTS:]
        return seg

    # --- File buffer methods (修改 7) ---

    def _write_file_buffer_entry(self, content: str, label: str = "") -> dict:
        """Write large content to disk and return entry metadata."""
        ref_id = f"fb_{int(now_ts())}_{uuid.uuid4().hex[:6]}"
        fp = self.file_buffer_dir / f"{ref_id}.txt"
        fp.write_text(content, encoding="utf-8")
        summary = trim(content, 120).replace("\n", " ")
        entry = {
            "path": fp.relative_to(self.root).as_posix(),
            "chars": len(content),
            "summary": summary,
            "label": str(label or ""),
        }
        self.file_buffer_index[ref_id] = entry
        # Prune old entries if over limit
        if len(self.file_buffer_index) > FILE_BUFFER_MAX_FILES:
            oldest_keys = sorted(self.file_buffer_index.keys())[:len(self.file_buffer_index) - FILE_BUFFER_MAX_FILES]
            for k in oldest_keys:
                old_path = self.root / self.file_buffer_index[k].get("path", "")
                if old_path.exists():
                    try:
                        old_path.unlink()
                    except Exception:
                        pass
                del self.file_buffer_index[k]
        return {
            "ref_id": ref_id,
            "path": entry["path"],
            "chars": int(entry["chars"]),
            "summary": summary,
            "placeholder": f"[file_buffer:{ref_id} chars={len(content)} summary={summary}]",
        }

    def _offload_to_file_buffer(self, content: str, label: str = "") -> str:
        """Write large content to disk, return compact reference placeholder."""
        if len(content) < FILE_BUFFER_CONTENT_THRESHOLD:
            return content
        return str(self._write_file_buffer_entry(content, label=label).get("placeholder", content))

    def _load_from_file_buffer(self, ref_id: str) -> str:
        """Load content from file buffer by reference ID."""
        entry = self.file_buffer_index.get(ref_id)
        if not entry:
            return f"[file_buffer:{ref_id} not found]"
        fp = self.root / entry.get("path", "")
        if not fp.exists():
            return f"[file_buffer:{ref_id} file missing]"
        try:
            return fp.read_text(encoding="utf-8")
        except Exception as exc:
            return f"[file_buffer:{ref_id} read error: {exc}]"

    def _is_long_listing_command(self, command: str) -> bool:
        text = str(command or "").strip().lower()
        if not text:
            return False
        segments = re.split(r"(?:&&|\|\||;|\||\n)+", text)
        wrappers = {"env", "command", "builtin", "time", "nohup"}
        for seg in segments:
            part = seg.strip()
            if not part:
                continue
            try:
                tokens = shlex.split(part, posix=(os.name != "nt"))
            except Exception:
                tokens = part.split()
            if not tokens:
                continue
            cmd_name = ""
            for tok in tokens:
                if re.match(r"^[A-Za-z_][A-Za-z0-9_]*=.*$", tok):
                    continue
                base = Path(tok).name.lower()
                if base in wrappers:
                    continue
                cmd_name = base
                break
            if cmd_name in {"ls", "find", "rg", "fd", "tree"}:
                return True
        return False

    def _paginate_text(self, text: str, page_chars: int, max_pages: int | None = None) -> list[str]:
        src = str(text or "")
        if not src:
            return [""]
        page_chars = max(256, int(page_chars or 0))
        pages: list[str] = []
        cursor = 0
        total = len(src)
        while cursor < total:
            end = min(total, cursor + page_chars)
            if end < total:
                newline = src.rfind("\n", cursor, end)
                if newline > cursor + int(page_chars * 0.55):
                    end = newline + 1
            chunk = src[cursor:end].rstrip("\n")
            pages.append(chunk)
            cursor = end
            while cursor < total and src[cursor] == "\n":
                cursor += 1
            if max_pages is not None and len(pages) >= max_pages:
                break
        return pages or [""]

    def _prune_long_output_files(self):
        try:
            files = sorted(
                self.long_output_dir.glob("*.txt"),
                key=lambda fp: fp.stat().st_mtime,
            )
        except Exception:
            return
        overflow = len(files) - LONG_OUTPUT_TEMP_MAX_FILES
        if overflow <= 0:
            return
        for fp in files[:overflow]:
            try:
                fp.unlink()
            except Exception:
                pass

    def _write_long_output_artifact(self, content: str, command: str) -> str:
        base = ""
        try:
            tokens = shlex.split(str(command or ""), posix=(os.name != "nt"))
        except Exception:
            tokens = str(command or "").split()
        for tok in tokens:
            if re.match(r"^[A-Za-z_][A-Za-z0-9_]*=.*$", tok):
                continue
            base = Path(tok).name.lower()
            if base in {"env", "command", "builtin", "time", "nohup"}:
                continue
            break
        stem = re.sub(r"[^a-z0-9._-]+", "-", base or "output").strip("-") or "output"
        fp = self.long_output_dir / f"{int(now_ts() * 1000)}_{stem}_{uuid.uuid4().hex[:6]}.txt"
        fp.write_text(str(content or ""), encoding="utf-8")
        self._prune_long_output_files()
        return self._session_rel(fp)

    def _prepare_shell_output_payload(self, command: str, output_text: str, cwd: Path | None = None) -> dict:
        clean = str(output_text or "").strip()
        if not clean:
            clean = "(no output)"
        is_listing = self._is_long_listing_command(command)
        model_pages = self._paginate_text(clean, LONG_OUTPUT_MODEL_PAGE_CHARS)
        ui_pages_all = self._paginate_text(clean, LONG_OUTPUT_UI_PAGE_CHARS)
        ui_pages = ui_pages_all[:LONG_OUTPUT_UI_PREVIEW_MAX_PAGES]
        temp_output_path = ""
        buffer_ref = ""
        buffer_chars = 0
        strategy = "inline"
        model_truncated = False
        ui_truncated = len(ui_pages_all) > len(ui_pages)
        should_temp = is_listing and (
            len(clean) > LONG_OUTPUT_LISTING_OFFLOAD_CHARS or len(model_pages) > 1 or ui_truncated
        )
        should_buffer = should_temp or len(model_pages) > 1 or ui_truncated or len(clean) >= FILE_BUFFER_CONTENT_THRESHOLD * 4
        if should_temp:
            temp_output_path = self._write_long_output_artifact(clean, command)
            strategy = "temp-read_file"
        elif len(model_pages) > 1:
            strategy = "paged-inline"
        if should_buffer:
            entry = self._write_file_buffer_entry(clean, label="shell-output")
            buffer_ref = str(entry.get("ref_id", ""))
            buffer_chars = int(entry.get("chars", 0) or 0)
        model_output = clean
        if len(model_pages) > 1 or should_temp:
            model_truncated = True
            preview = (
                self._run_read(temp_output_path, LONG_OUTPUT_READ_PAGE_LINES, 0)
                if temp_output_path
                else model_pages[0]
            )
            parts = [
                (
                    f"[long_output chars={len(clean)} pages={len(model_pages)} "
                    f"strategy={strategy}{f' cwd={cwd}' if cwd else ''}]"
                )
            ]
            if temp_output_path:
                parts.append(
                    f"use read_file path=\"{temp_output_path}\" offset=0 limit={LONG_OUTPUT_READ_PAGE_LINES}"
                )
            if buffer_ref:
                parts.append(f"buffer_ref={buffer_ref}")
            parts.append(f"preview_page=1/{len(model_pages)}")
            parts.append(preview)
            if len(model_pages) > 1:
                parts.append(f"... ({len(model_pages) - 1} more page(s) omitted from model context)")
            model_output = "\n".join(parts)
        return {
            "output": model_output,
            "output_full_chars": len(clean),
            "output_full_lines": clean.count("\n") + (1 if clean else 0),
            "ui_output_preview": ui_pages[0] if ui_pages else "",
            "ui_output_pages": ui_pages,
            "ui_output_page_count": len(ui_pages),
            "ui_output_page_total": len(ui_pages_all),
            "ui_truncated": bool(ui_truncated),
            "model_truncated": bool(model_truncated),
            "buffer_ref": buffer_ref,
            "buffer_chars": buffer_chars,
            "temp_output_path": temp_output_path,
            "long_output_strategy": strategy,
            "output_page_index": 1,
            "output_page_count": len(model_pages),
        }

    def _offload_agent_message_content(self, messages: list[dict]):
        """Scan messages and offload large string content to file buffer."""
        for msg in messages:
            content = msg.get("content", "")
            if isinstance(content, str) and len(content) >= FILE_BUFFER_CONTENT_THRESHOLD:
                msg["content"] = self._offload_to_file_buffer(content, label=msg.get("role", ""))
            elif isinstance(content, list):
                for block in content:
                    if isinstance(block, dict):
                        bc = block.get("content", "")
                        if isinstance(bc, str) and len(bc) >= FILE_BUFFER_CONTENT_THRESHOLD:
                            block["content"] = self._offload_to_file_buffer(bc, label=block.get("type", ""))

    def _summarize_compact_rows(self, rows: list[dict]) -> str:
        if not rows:
            return "(no archived rows)"
        snippet = json_dumps(rows)[-96_000:]
        try:
            resp = self.ollama.chat(
                [
                    {
                        "role": "user",
                        "content": (
                            "Summarize unfinished work, key decisions, and pending next actions in <= 10 bullets.\n"
                            f"{snippet}"
                        ),
                    }
                ],
                max_tokens=900,
                think=False,
            )
            text = str(resp.get("content", "")).strip()
            if text:
                return trim(text, 4000)
        except Exception as exc:
            return f"(summary failed: {exc})"
        return "(summary unavailable)"

    def _open_work_brief(self) -> str:
        alias = {
            "todo": "pending",
            "doing": "in_progress",
            "inprogress": "in_progress",
            "in-progress": "in_progress",
            "done": "completed",
            "finish": "completed",
            "finished": "completed",
        }

        def norm_status(raw: object, fallback: str) -> str:
            key = str(raw or "").strip().lower()
            mapped = alias.get(key, key or fallback)
            if mapped in {"pending", "in_progress", "completed", "blocked"}:
                return mapped
            return fallback

        todo_open: list[str] = []
        focus = ""
        for row in self.todo.snapshot():
            status = norm_status(row.get("status", ""), "pending")
            if status not in {"pending", "in_progress"}:
                continue
            content = normalize_work_text(row.get("content", ""), status) or str(row.get("content", "")).strip()
            content = trim(content or "(empty todo)", 140)
            if status == "in_progress" and not focus:
                focus = content
            todo_open.append(f"- [{status}] {content}")

        task_open: list[str] = []
        for row in self.tasks.list_objects():
            status = norm_status(row.get("status", ""), "pending")
            if status not in {"pending", "in_progress", "blocked"}:
                continue
            subject = normalize_work_text(row.get("subject", ""), status) or str(row.get("subject", "")).strip()
            subject = trim(subject or "(empty task)", 140)
            owner = str(row.get("owner", "") or "").strip()
            owner_txt = f" @{owner}" if owner else ""
            task_open.append(f"- #{row.get('id')} [{status}] {subject}{owner_txt}")

        lines = [f"Open todos ({len(todo_open)}):"]
        lines.extend(todo_open[:6] if todo_open else ["- none"])
        if focus:
            lines.append(f"Current focus: {focus}")
        lines.append(f"Open tasks ({len(task_open)}):")
        lines.extend(task_open[:6] if task_open else ["- none"])
        # Checkpoint drift detection
        bb = self._ensure_blackboard()
        cps = bb.get("checkpoints", [])
        if isinstance(cps, list) and len(cps) >= 2:
            latest_cp = cps[-1] if isinstance(cps[-1], dict) else {}
            prev_cp = cps[-2] if isinstance(cps[-2], dict) else {}
            if self._checkpoint_detect_drift(latest_cp, prev_cp):
                cp_round = int(latest_cp.get("round", 0) or 0)
                lines.append(f"⚠️ 自 round {cp_round} 以来无实质进展，需要换策略。")
        return "\n".join(lines)

    def _failure_aware_brief(self) -> str:
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return ""
        lines: list[str] = []
        # Unresolved errors (unified) — grouped by category
        all_errors = fl.get("errors", [])
        unresolved = [e for e in all_errors if isinstance(e, dict) and int(e.get("count", 0) or 0) > 0]
        # Fallback: if errors is empty but compilation_errors has data, use that
        if not unresolved:
            comp_errors = fl.get("compilation_errors", [])
            unresolved = [e for e in comp_errors if isinstance(e, dict) and int(e.get("count", 0) or 0) > 0]
            for e in unresolved:
                if "category" not in e:
                    e["category"] = "compilation"
        if unresolved:
            lines.append("## ⚠️ 已知问题（勿重复尝试）")
            by_cat: dict[str, list] = {}
            for e in unresolved:
                cat = str(e.get("category", "unknown") or "unknown")
                by_cat.setdefault(cat, []).append(e)
            cat_labels = dict(ERROR_CATEGORY_DEFS)
            for cat, errs in by_cat.items():
                label = cat_labels.get(cat, {}).get("label", cat) if cat in cat_labels else cat
                lines.append(f"{label} (未解决):")
                for e in errs[:8]:
                    f = str(e.get("file", "") or "")
                    msg = str(e.get("error_msg", "") or "")
                    cnt = int(e.get("count", 1) or 1)
                    lines.append(f"- {f}: {trim(msg, 120)} (出现 {cnt} 次)")
        # Failed fix attempts
        fixes = fl.get("attempted_fixes", [])
        if fixes:
            lines.append("已尝试修复 (失败):")
            for fx in fixes[-6:]:
                if not isinstance(fx, dict):
                    continue
                fix_desc = str(fx.get("fix", "") or "")
                result = str(fx.get("result", "") or "")
                lines.append(f"- {trim(fix_desc, 100)} → {trim(result, 60)}")
        # Repeated delegations
        delegations = fl.get("repeated_delegations", [])
        repeated = [d for d in delegations if isinstance(d, dict) and int(d.get("count", 0) or 0) >= 2]
        if repeated:
            lines.append("重复委派 (需换策略):")
            for d in repeated[:5]:
                tgt = str(d.get("target", "") or "")
                cnt = int(d.get("count", 1) or 1)
                preview = str(d.get("instruction_preview", "") or "")
                lines.append(f"- {tgt} 收到相同指令 {cnt} 次: {trim(preview, 80)}")
        # Stall events
        stalls = fl.get("stall_events", [])
        if stalls:
            lines.append(f"停滞事件: {len(stalls)} 次 (最近: {str(stalls[-1].get('reason', '') if isinstance(stalls[-1], dict) else '')})")
        if not lines:
            return ""
        return trim("\n".join(lines), 800)

    def _create_checkpoint_snapshot(self) -> dict:
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger", {})
        if not isinstance(fl, dict):
            fl = {}
        comp_errors = fl.get("errors", []) or fl.get("compilation_errors", [])
        active_errors = len([e for e in comp_errors if isinstance(e, dict) and int(e.get("count", 0) or 0) > 0])
        artifacts = bb.get("code_artifacts", {})
        artifacts_keys = sorted(artifacts.keys()) if isinstance(artifacts, dict) else []
        files_hash = hashlib.sha1(str(artifacts_keys).encode("utf-8")).hexdigest()[:12]
        try:
            todo_snap = json_dumps(self.todo.snapshot()) if hasattr(self, "todo") else ""
        except Exception:
            todo_snap = ""
        todos_hash = hashlib.sha1(todo_snap.encode("utf-8")).hexdigest()[:12]
        stall_events = fl.get("stall_events", [])
        delegations = fl.get("repeated_delegations", [])
        return {
            "round": int(getattr(self, "agent_round_index", 0) or 0),
            "ts": float(now_ts()),
            "active_errors_count": active_errors,
            "files_modified_hash": files_hash,
            "todos_hash": todos_hash,
            "stall_count": len(stall_events) if isinstance(stall_events, list) else 0,
            "delegation_count": sum(
                int(d.get("count", 0) or 0) for d in delegations if isinstance(d, dict)
            ) if isinstance(delegations, list) else 0,
        }

    def _checkpoint_detect_drift(self, current: dict, previous: dict) -> bool:
        if not isinstance(current, dict) or not isinstance(previous, dict):
            return False
        errors_not_reduced = int(current.get("active_errors_count", 0) or 0) >= int(previous.get("active_errors_count", 0) or 0)
        files_unchanged = str(current.get("files_modified_hash", "")) == str(previous.get("files_modified_hash", ""))
        stalls_increased = int(current.get("stall_count", 0) or 0) > int(previous.get("stall_count", 0) or 0)
        return errors_not_reduced and files_unchanged and stalls_increased

    def _maybe_create_checkpoint(self):
        bb = self._ensure_blackboard()
        cps = bb.get("checkpoints", [])
        if not isinstance(cps, list):
            cps = []
        current_round = int(getattr(self, "agent_round_index", 0) or 0)
        if cps:
            last_cp = cps[-1] if isinstance(cps[-1], dict) else {}
            last_round = int(last_cp.get("round", 0) or 0)
            if current_round - last_round < CHECKPOINT_INTERVAL_ROUNDS:
                return
        snapshot = self._create_checkpoint_snapshot()
        cps.append(snapshot)
        bb["checkpoints"] = cps[-CHECKPOINT_MAX_COUNT:]
        self.blackboard = bb

    def _classify_message_priority(self, msg: dict, index: int, total: int) -> int:
        """Return 0-10 priority score. Higher = more important to keep during compression."""
        score = 0
        role = str(msg.get("role", ""))
        content = str(msg.get("content", "") or "")
        content_low = content[:2000].lower()
        # Factor 1: Recency (0-3 points) — newest messages most valuable
        recency = index / max(1, total - 1) if total > 1 else 1.0
        score += int(recency * 3)
        # Factor 2: Role weight — system/user messages more important than tool output
        role_weights = {"system": 3, "user": 2, "assistant": 2, "tool": 1}
        score += role_weights.get(role, 1)
        # Factor 3: Task progress markers (+2)
        if any(kw in content_low for kw in ("todowrite", "plan_step", "finish_task", "finish_current_task", "approved-plan")):
            score += 2
        # Factor 4: Error/critical info (+2) — essential for debugging continuity
        if "error:" in content_low or "traceback" in content_low or "exception" in content_low:
            score += 2
        # Factor 5: Goal/task context (+1)
        goal = str(getattr(self, "runtime_reclassify_goal", "") or self._latest_user_goal_text() or "").lower()[:200]
        if goal:
            goal_words = [w for w in goal.split() if len(w) > 3]
            matches = sum(1 for w in goal_words if w in content_low)
            if matches >= 2:
                score += 1
        # Factor 6: Skill content (+1) — preserve loaded skill context
        if "<loaded-skill" in content or "_skill_notify" in str(msg):
            score += 1
        # Factor 7: Compact-resume notes are always max priority
        if "<compact-resume>" in content or "<STATE_HANDOFF>" in content:
            score = 10
        return min(10, score)

    def _priority_compress_messages(self, messages: list[dict], target_tokens: int, tier: int) -> list[dict]:
        """Priority-based message compression: high-priority messages kept intact,
        mid-priority compressed to summaries, low-priority reduced to one-liners."""
        total = len(messages)
        scored: list[tuple[int, int, dict]] = []
        for i, msg in enumerate(messages):
            priority = self._classify_message_priority(msg, i, total)
            scored.append((priority, i, msg))
        # Sort by priority descending, then by index descending (recent first)
        scored.sort(key=lambda x: (x[0], x[1]), reverse=True)
        # Build result respecting token budget
        kept: list[tuple[int, dict]] = []
        current_tokens = 0
        for priority, idx, msg in scored:
            content = str(msg.get("content", "") or "")
            msg_tokens = max(1, len(content) // 4)
            if priority >= 7:
                # High priority: keep intact
                kept.append((idx, dict(msg)))
                current_tokens += msg_tokens
            elif priority >= 4:
                # Mid priority: compress content to 500 chars if over budget
                compressed = dict(msg)
                if current_tokens + msg_tokens > target_tokens and len(content) > 500:
                    role = msg.get("role", "tool")
                    compressed["content"] = trim(content, 500) + " [compressed]"
                kept.append((idx, compressed))
                current_tokens += max(1, len(str(compressed.get("content", ""))) // 4)
            else:
                # Low priority: one-liner summary if over budget
                if current_tokens > target_tokens * 0.8:
                    continue  # Drop entirely if way over budget
                compressed = dict(msg)
                role = msg.get("role", "tool")
                if role == "tool" and len(content) > 120:
                    # Extract tool name from nearby assistant message
                    compressed["content"] = f"[tool output, {len(content)} chars]"
                elif len(content) > 200:
                    compressed["content"] = trim(content, 200) + " [truncated]"
                kept.append((idx, compressed))
                current_tokens += max(1, len(str(compressed.get("content", ""))) // 4)
            if current_tokens > target_tokens:
                break
        # Re-sort by original index to maintain conversation order
        kept.sort(key=lambda x: x[0])
        return [msg for _, msg in kept]

    def _auto_compact(self, reason: str):
        context_before = self._context_budget_metrics()
        tier = self._context_compression_tier(context_before)
        transcript_dir = self.root / "transcripts"
        transcript_dir.mkdir(parents=True, exist_ok=True)
        transcript_path = transcript_dir / f"transcript_{int(now_ts())}.jsonl"
        with transcript_path.open("w", encoding="utf-8") as handle:
            for msg in self.messages:
                handle.write(json_dumps(msg) + "\n")
        # Adjust tail budget based on tier — lower tier = smaller tail
        if tier >= 3:
            tail_budget = max(2000, min(6000, int(self.context_token_upper_bound * 0.20)))
        elif tier >= 2:
            tail_budget = max(3000, min(10_000, int(self.context_token_upper_bound * 0.28)))
        else:
            tail_budget = max(4500, min(16_000, int(self.context_token_upper_bound * 0.35)))
        tail = self._select_compact_tail(tail_budget)
        if len(tail) >= len(self.messages):
            tail = self._select_compact_tail(max(2200, int(tail_budget * 0.55)), min_count=4, max_count=20)
        archived_rows = self.messages[:-len(tail)] if tail else list(self.messages)
        seg = self._archive_context_segment(archived_rows, reason) if archived_rows else {}
        summary = self._summarize_compact_rows(archived_rows)
        seg_id = str(seg.get("id", "")) if isinstance(seg, dict) else ""
        seg_msg_count = int(seg.get("messages", 0) or 0) if isinstance(seg, dict) else 0
        seg_path = str(seg.get("path", "")) if isinstance(seg, dict) else ""
        continuation = (
            f"If details are missing, call context_recall with segment_id='{seg_id}', max_messages=40, offset=0."
            if seg_id
            else "If details are missing, call context_recall with recent_segments=2."
        )
        # Create checkpoint before compaction
        self._maybe_create_checkpoint()
        # Build state handoff for lossless continuity
        state_handoff = self._build_state_handoff()
        failure_brief = self._failure_aware_brief()
        failure_section = f"{failure_brief}\n" if failure_brief else ""
        compact_note = (
            "<compact-resume>\n"
            f"reason: {reason}\n"
            f"tier: {tier}\n"
            f"transcript: {transcript_path}\n"
            f"archive_segment: {seg_id or 'none'} messages={seg_msg_count} path={seg_path or '-'}\n"
            f"{state_handoff}\n"
            f"{self._open_work_brief()}\n"
            f"{failure_section}"
            f"summary:\n{summary}\n"
            f"{continuation}\n"
            "Continue exploring from current pending work; do not restart from scratch.\n"
            "</compact-resume>"
        )
        tail.append({"role": "user", "content": compact_note, "ts": now_ts()})
        # Adjust target tokens based on tier
        if tier >= 3:
            target_tokens = max(2000, min(8000, int(self.context_token_upper_bound * 0.35)))
        elif tier >= 2:
            target_tokens = max(3000, min(12_000, int(self.context_token_upper_bound * 0.45)))
        else:
            target_tokens = max(4000, min(20_000, int(self.context_token_upper_bound * 0.55)))
        # Priority-based compression: keep important messages, compress/drop low-value ones
        if self._estimate_messages_tokens(tail) > target_tokens:
            compact_note_msg = tail[-1]  # preserve the compact-resume note
            tail_without_note = tail[:-1]
            compressed_tail = self._priority_compress_messages(tail_without_note, target_tokens, tier)
            compressed_tail.append(compact_note_msg)
            tail = compressed_tail
        # Final safety: if still over budget, trim from front
        while len(tail) > 5 and self._estimate_messages_tokens(tail) > target_tokens:
            tail.pop(0)
        self.messages = tail
        # Compact agent contexts in sync (critical fix for re-wall prevention)
        self._compact_agent_contexts(max(tier, 1))
        # Tier 2+: offload remaining large content in messages to file buffer
        if tier >= 2:
            for msg in self.messages:
                c = msg.get("content", "")
                if isinstance(c, str) and len(c) >= FILE_BUFFER_CONTENT_THRESHOLD * 2:
                    msg["content"] = self._offload_to_file_buffer(c, label="compact-msg")
        self.last_compact_reason = str(reason or "")
        self.last_compact_ts = now_ts()
        self._emit(
            "compact",
            {
                "summary": f"context compacted ({reason}) tier={tier} archives={len(self.context_archives)}",
                "reason": str(reason or ""),
                "tier": tier,
                "archive_segment": seg_id,
                "archived_messages": seg_msg_count,
                "context_limit_before": int(context_before.get("limit", 0)),
                "context_used_before": int(context_before.get("used", 0)),
                "context_left_before": int(context_before.get("left", 0)),
                "context_left_percent_before": round(float(context_before.get("left_percent", 0.0)), 2),
            },
        )

    def _build_state_handoff(self) -> str:
        """Build a lossless state handoff string for compact-resume note.
        Captures: goal, progress, current node state, active agent, round info."""
        bb = self._ensure_blackboard()
        parts: list[str] = ["<STATE_HANDOFF>"]
        # 1. Original goal
        goal = trim(str(bb.get("original_goal", "") or ""), 500)
        if goal:
            parts.append(f"GOAL: {goal}")
        # 2. Current progress / manager judgement
        judgement = bb.get("manager_judgement", {})
        if isinstance(judgement, dict):
            progress = str(judgement.get("progress", "") or "")
            remaining = judgement.get("remaining_rounds", "")
            if progress:
                parts.append(f"PROGRESS: {progress}")
            if remaining != "":
                parts.append(f"REMAINING_ROUNDS: {remaining}")
        # 3. Active agent and phase
        active_role = str(getattr(self, "runtime_active_role", "") or "")
        phase = str(getattr(self, "current_phase", "") or "")
        round_idx = int(getattr(self, "agent_round_index", 0) or 0)
        parts.append(f"ROUND: {round_idx}, ACTIVE_AGENT: {active_role or 'none'}, PHASE: {phase or 'idle'}")
        # 4. Task profile
        tp = bb.get("task_profile", {})
        if isinstance(tp, dict):
            task_type = str(tp.get("task_type", "") or "")
            complexity = str(tp.get("complexity", "") or "")
            if task_type:
                parts.append(f"TASK_TYPE: {task_type}, COMPLEXITY: {complexity}")
        # 5. Last delegate instruction (if multi-agent)
        last_del = bb.get("last_delegate", {})
        if isinstance(last_del, dict) and last_del.get("instruction"):
            parts.append(f"LAST_DELEGATE: {trim(str(last_del.get('instruction', '')), 200)}")
        # 6. Key blackboard entries (code_artifacts keys, review_feedback)
        artifacts = bb.get("code_artifacts", {})
        if isinstance(artifacts, dict) and artifacts:
            parts.append(f"CODE_ARTIFACTS: {', '.join(sorted(artifacts.keys())[:10])}")
        review = bb.get("review_feedback", "")
        if review:
            parts.append(f"REVIEW_FEEDBACK: {trim(str(review), 200)}")
        # 7. Failure context
        fl = bb.get("failure_ledger", {})
        if isinstance(fl, dict):
            fixes = fl.get("attempted_fixes", [])
            recent_fixes = [fx for fx in fixes[-3:] if isinstance(fx, dict)]
            if recent_fixes:
                fix_lines = []
                for fx in recent_fixes:
                    f = trim(str(fx.get("file", "") or ""), 80)
                    result = str(fx.get("result", "") or "")
                    fix_lines.append(f"  {f} -> {result}")
                parts.append("ATTEMPTED_FIXES:\n" + "\n".join(fix_lines))
            unresolved = [e for e in fl.get("errors", []) if isinstance(e, dict) and int(e.get("count", 0) or 0) > 0]
            if unresolved:
                err_lines = [f"  [{e.get('category','')}] {e.get('file','')}: {trim(str(e.get('error_msg','')), 120)}" for e in unresolved[:3]]
                parts.append("UNRESOLVED_ERRORS:\n" + "\n".join(err_lines))
        if self.developer_edit_fail_streaks:
            stuck = ", ".join(f"{k}({v}x)" for k, v in self.developer_edit_fail_streaks.items())
            parts.append(f"EDIT_STALLS: {stuck}")
        # 8. Plan step progress
        plan_todos = bb.get("project_todos", [])
        if isinstance(plan_todos, list) and plan_todos:
            completed = sum(1 for t in plan_todos if isinstance(t, dict) and t.get("status") == "completed")
            total_steps = len(plan_todos)
            cursor = int(bb.get("plan_step_cursor", 0) or 0)
            current_step = ""
            for t in plan_todos:
                if isinstance(t, dict) and t.get("status") == "in_progress":
                    current_step = trim(str(t.get("content", "")), 200)
                    break
            parts.append(f"PLAN_PROGRESS: {completed}/{total_steps} completed, cursor={cursor}")
            if current_step:
                parts.append(f"CURRENT_STEP: {current_step}")
        # 9. Loaded skills
        loaded_skills = bb.get("loaded_skills", {})
        if isinstance(loaded_skills, dict) and loaded_skills:
            skill_names = [str(v.get("skill_name", k)) for k, v in list(loaded_skills.items())[:5] if isinstance(v, dict)]
            parts.append(f"ACTIVE_SKILLS: {', '.join(skill_names)}")
        # 10. Recent tool calls summary
        recent_tools: list[str] = []
        for msg in self.messages[-20:]:
            tc = msg.get("tool_calls", [])
            if isinstance(tc, list):
                for call in tc:
                    if isinstance(call, dict):
                        fname = str(call.get("function", {}).get("name", "")).strip()
                        if fname and fname not in recent_tools:
                            recent_tools.append(fname)
        if recent_tools:
            parts.append(f"RECENT_TOOLS: {', '.join(recent_tools[-8:])}")
        parts.append("</STATE_HANDOFF>")
        return "\n".join(parts)

    def _git_status_map(self, cwd: Path) -> dict[str, str]:
        try:
            check = subprocess.run(
                ["git", "rev-parse", "--is-inside-work-tree"],
                cwd=cwd,
                capture_output=True,
                text=True,
                timeout=8,
            )
            if check.returncode != 0:
                return {}
            r = subprocess.run(
                ["git", "status", "--porcelain"],
                cwd=cwd,
                capture_output=True,
                text=True,
                timeout=8,
            )
            if r.returncode != 0:
                return {}
            out = {}
            for line in r.stdout.splitlines():
                if not line.strip():
                    continue
                status = line[:2].strip()
                path = line[3:]
                if " -> " in path:
                    path = path.split(" -> ", 1)[1]
                out[path.strip()] = status
            return out
        except Exception:
            return {}

    def _status_delta(self, before: dict[str, str], after: dict[str, str]) -> list[str]:
        keys = set(before.keys()) | set(after.keys())
        changed = []
        for k in sorted(keys):
            if before.get(k) != after.get(k):
                changed.append(k)
        return changed[:60]

    def _normalize_tool_path_text(self, path_text: object) -> str:
        raw = str(path_text or "").strip().replace("\\", "/")
        if not raw:
            raise ValueError("path is required")
        if len(raw) >= 2 and raw[0] == raw[-1] and raw[0] in {"'", "\""}:
            raw = raw[1:-1].strip()
            if not raw:
                raise ValueError("path is required")
        low = raw.lower()
        if low in {"/workspace", "/workspace/"}:
            return "."
        if low.startswith("/workspace/"):
            rel = raw[len("/workspace/") :].lstrip("/")
            return rel or "."
        if low in {"/js_lib", "/js_lib/"}:
            return ".__js_lib__"
        if low.startswith("/js_lib/"):
            rel = raw[len("/js_lib/") :].lstrip("/")
            return f".__js_lib__/{rel}" if rel else ".__js_lib__"
        if low in {SKILLS_VIRTUAL_PREFIX, f"{SKILLS_VIRTUAL_PREFIX}/"}:
            return ".__skills__"
        if low.startswith(f"{SKILLS_VIRTUAL_PREFIX}/"):
            rel = raw[len(SKILLS_VIRTUAL_PREFIX) :].lstrip("/")
            return f".__skills__/{rel}" if rel else ".__skills__"
        candidate = Path(raw)
        if candidate.is_absolute():
            raise ValueError(
                "illegal absolute path. use relative path, '/workspace/<relative>', or '/skills/<relative>' only"
            )
        norm = candidate.as_posix().strip()
        if not norm:
            raise ValueError("path is required")
        return norm

    def _reject_non_workspace_absolute_tool_path(self, raw_path: object) -> str:
        txt = str(raw_path or "").strip().strip("'\"")
        if not txt:
            return ""
        if not txt.startswith("/"):
            return ""
        low = txt.lower()
        if (
            low in {"/workspace", "/workspace/", SKILLS_VIRTUAL_PREFIX, f"{SKILLS_VIRTUAL_PREFIX}/", "/js_lib", "/js_lib/"}
            or low.startswith("/workspace/")
            or low.startswith(f"{SKILLS_VIRTUAL_PREFIX}/")
            or low.startswith("/js_lib/")
        ):
            return ""
        return (
            "Error: illegal absolute path for agent tool call. "
            "Use relative path, '/workspace/<relative>', or '/skills/<relative>' only."
        )

    def _session_path(self, path_text: str) -> Path:
        normalized = self._normalize_tool_path_text(path_text)
        if normalized == ".__skills__" or normalized.startswith(".__skills__/"):
            rel = normalized[len(".__skills__") :].lstrip("/")
            return self.skills.resolve_virtual_skill_path(rel or ".")
        if normalized == ".__js_lib__" or normalized.startswith(".__js_lib__/"):
            rel = normalized[len(".__js_lib__") :].lstrip("/")
            return safe_path(rel or ".", self.js_lib_root)
        return safe_path(normalized, self.files_root)

    def _session_rel(self, path: Path) -> str:
        target = path.resolve()
        root = self.files_root.resolve()
        if target.is_relative_to(root):
            return target.relative_to(root).as_posix()
        try:
            js_lib_root = self.js_lib_root.resolve()
            if target.is_relative_to(js_lib_root):
                rel = target.relative_to(js_lib_root).as_posix()
                return f"/js_lib/{rel}".replace("//", "/")
        except Exception:
            pass
        try:
            virtual_skill_path = self.skills.public_virtual_skill_path_for_abs(target)
            if virtual_skill_path:
                return virtual_skill_path
        except Exception:
            pass
        return str(target)

    def _is_runtime_managed_session_path(self, path_text: object) -> bool:
        try:
            target = self._session_path(self._normalize_tool_path_text(path_text)).resolve()
            return target == self._plan_file_path().resolve()
        except Exception:
            return False

    def _runtime_managed_path_tool_error(self, path_text: object, action: str) -> str:
        if not self._is_runtime_managed_session_path(path_text):
            return ""
        return (
            f"Error: {action} blocked for runtime-managed file '{PLAN_FILE_RELATIVE_PATH}'. "
            "This file mirrors the approved execution plan and is auto-generated from blackboard state. "
            "Use read_file to inspect it; do not modify it with write_file/edit_file."
        )

    def _code_preview_bucket_dir(self, rel_path: str) -> Path:
        rel = normalize_rel_preview_path(rel_path)
        digest = hashlib.sha1(rel.encode("utf-8", errors="ignore")).hexdigest()[:14]
        target = self.code_preview_dir / digest
        target.mkdir(parents=True, exist_ok=True)
        return target

    def _write_code_preview_blob(self, rel_path: str, stage_id: str, kind: str, text: str) -> str:
        bucket = self._code_preview_bucket_dir(rel_path)
        fp = bucket / f"{stage_id}.{kind}.txt"
        fp.write_text(str(text or ""), encoding="utf-8")
        return fp.relative_to(self.root).as_posix()

    def _read_code_preview_blob(self, rel_blob_path: str) -> str:
        rel = normalize_rel_preview_path(rel_blob_path)
        if not rel:
            return ""
        try:
            fp = safe_path(rel, self.root)
        except Exception:
            return ""
        if not fp.exists() or not fp.is_file():
            return ""
        return try_read_text(fp, max_bytes=CODE_PREVIEW_STAGE_MAX_BYTES * 2) or ""

    def _drop_code_preview_stage_files(self, stage: dict):
        for key in ("before_blob", "after_blob"):
            rel = normalize_rel_preview_path(stage.get(key, ""))
            if not rel:
                continue
            try:
                fp = safe_path(rel, self.root)
                if fp.exists() and fp.is_file():
                    fp.unlink()
            except Exception:
                continue

    def _prune_code_preview_locked(self):
        cleaned: dict[str, list[dict]] = {}
        removed: list[dict] = []
        for path, stages in (self.code_preview_index or {}).items():
            rel = normalize_rel_preview_path(path)
            if not rel or (not isinstance(stages, list)):
                continue
            valid: list[dict] = []
            for row in stages:
                if not isinstance(row, dict):
                    continue
                sid = str(row.get("id", "") or "").strip()
                if not sid:
                    continue
                valid.append(
                    {
                        "id": sid,
                        "ts": float(row.get("ts", 0.0) or 0.0),
                        "path": rel,
                        "tool": str(row.get("tool", "") or ""),
                        "change_type": str(row.get("change_type", "") or ""),
                        "added": int(row.get("added", 0) or 0),
                        "deleted": int(row.get("deleted", 0) or 0),
                        "before_blob": str(row.get("before_blob", "") or ""),
                        "after_blob": str(row.get("after_blob", "") or ""),
                        "bytes_after": int(row.get("bytes_after", 0) or 0),
                        "lines_after": int(row.get("lines_after", 0) or 0),
                    }
                )
            if len(valid) > CODE_PREVIEW_STAGE_MAX_PER_FILE:
                removed.extend(valid[: -CODE_PREVIEW_STAGE_MAX_PER_FILE])
                valid = valid[-CODE_PREVIEW_STAGE_MAX_PER_FILE :]
            if valid:
                cleaned[rel] = valid
        total = sum(len(v) for v in cleaned.values())
        while total > CODE_PREVIEW_STAGE_MAX_TOTAL:
            oldest_path = ""
            oldest_ts = None
            for path, rows in cleaned.items():
                if not rows:
                    continue
                ts = float(rows[0].get("ts", 0.0) or 0.0)
                if oldest_ts is None or ts < oldest_ts:
                    oldest_ts = ts
                    oldest_path = path
            if not oldest_path:
                break
            popped = cleaned[oldest_path].pop(0)
            removed.append(popped)
            total -= 1
            if not cleaned[oldest_path]:
                cleaned.pop(oldest_path, None)
        self.code_preview_index = cleaned
        for row in removed:
            self._drop_code_preview_stage_files(row)

    def _record_code_preview_stage(
        self,
        *,
        rel_path: str,
        before_text: str,
        after_text: str,
        change_type: str,
        tool_name: str,
        added: int,
        deleted: int,
    ) -> dict | None:
        rel = normalize_rel_preview_path(rel_path)
        if not rel or (not is_code_preview_candidate(rel)):
            return None
        after_raw = str(after_text or "")
        after_bytes = len(after_raw.encode("utf-8", errors="ignore"))
        if after_bytes > CODE_PREVIEW_STAGE_MAX_BYTES:
            return None
        before_raw = str(before_text or "")
        if len(before_raw.encode("utf-8", errors="ignore")) > CODE_PREVIEW_STAGE_MAX_BYTES:
            before_raw = ""
        stage_id = f"stage_{int(now_ts() * 1000)}_{uuid.uuid4().hex[:6]}"
        try:
            before_blob = self._write_code_preview_blob(rel, stage_id, "before", before_raw)
            after_blob = self._write_code_preview_blob(rel, stage_id, "after", after_raw)
        except Exception:
            return None
        ts = now_ts()
        stage = {
            "id": stage_id,
            "ts": ts,
            "path": rel,
            "tool": str(tool_name or ""),
            "change_type": str(change_type or "modified"),
            "added": int(added or 0),
            "deleted": int(deleted or 0),
            "before_blob": before_blob,
            "after_blob": after_blob,
            "bytes_after": after_bytes,
            "lines_after": after_raw.count("\n") + (1 if after_raw else 0),
        }
        with self.lock:
            rows = list(self.code_preview_index.get(rel, []))
            rows.append(stage)
            self.code_preview_index[rel] = rows
            self._prune_code_preview_locked()
            final_rows = list(self.code_preview_index.get(rel, []))
            stage_count = len(final_rows)
            stage_index = stage_count
            self.updated_at = now_ts()
        return {
            "id": stage_id,
            "index": stage_index,
            "count": stage_count,
            "path": rel,
            "change_type": stage.get("change_type", "modified"),
            "added": int(stage.get("added", 0) or 0),
            "deleted": int(stage.get("deleted", 0) or 0),
            "ts": float(stage.get("ts", ts) or ts),
        }

    def code_preview_stages(self, rel_path: str) -> dict:
        fp = self._session_path(rel_path)
        rel = self._session_rel(fp)
        rel = normalize_rel_preview_path(rel)
        if not rel:
            raise ValueError("path required")
        with self.lock:
            stages = list(self.code_preview_index.get(rel, []))
        out = []
        total = len(stages)
        for i, row in enumerate(stages, start=1):
            added = int(row.get("added", 0) or 0)
            deleted = int(row.get("deleted", 0) or 0)
            out.append(
                {
                    "id": str(row.get("id", "") or ""),
                    "index": i,
                    "total": total,
                    "ts": float(row.get("ts", 0.0) or 0.0),
                    "change_type": str(row.get("change_type", "modified") or "modified"),
                    "added": added,
                    "deleted": deleted,
                    "label": f"#{i} (+{added}/-{deleted})",
                    "bytes_after": int(row.get("bytes_after", 0) or 0),
                    "lines_after": int(row.get("lines_after", 0) or 0),
                    "virtual": False,
                }
            )
        if not out and is_code_preview_candidate(rel) and fp.exists() and fp.is_file():
            txt = try_read_text(fp, max_bytes=CODE_PREVIEW_STAGE_MAX_BYTES) or ""
            out = [
                {
                    "id": "current",
                    "index": 1,
                    "total": 1,
                    "ts": float(now_ts()),
                    "change_type": "current",
                    "added": 0,
                    "deleted": 0,
                    "label": "#1 (current)",
                    "bytes_after": len(txt.encode("utf-8", errors="ignore")),
                    "lines_after": txt.count("\n") + (1 if txt else 0),
                    "virtual": True,
                }
            ]
        return {"path": rel, "latest_id": (out[-1]["id"] if out else ""), "stages": out}

    def code_preview_payload(self, rel_path: str, stage_id: str = "latest") -> dict:
        fp = self._session_path(rel_path)
        rel = normalize_rel_preview_path(self._session_rel(fp))
        if not rel:
            raise ValueError("path required")
        requested = str(stage_id or "latest").strip() or "latest"
        with self.lock:
            stages = list(self.code_preview_index.get(rel, []))
        before_text = ""
        after_text = ""
        stage_meta: dict = {}
        total = len(stages)
        idx = -1
        if stages:
            if requested.lower() in {"", "latest", "current"}:
                idx = len(stages) - 1
            else:
                for i, row in enumerate(stages):
                    if str(row.get("id", "")).strip() == requested:
                        idx = i
                        break
            if idx >= 0:
                stage_meta = dict(stages[idx])
                before_text = self._read_code_preview_blob(str(stage_meta.get("before_blob", "") or ""))
                after_text = self._read_code_preview_blob(str(stage_meta.get("after_blob", "") or ""))
                if not after_text and fp.exists() and fp.is_file():
                    after_text = try_read_text(fp, max_bytes=CODE_PREVIEW_STAGE_MAX_BYTES) or ""
                if not before_text and after_text:
                    before_text = after_text
        if not stage_meta:
            if requested.lower() not in {"", "latest", "current"}:
                raise KeyError(f"stage not found: {requested}")
            if not fp.exists() or not fp.is_file():
                raise FileNotFoundError(f"file not found: {rel}")
            after_text = try_read_text(fp, max_bytes=CODE_PREVIEW_STAGE_MAX_BYTES) or ""
            before_text = after_text
            stage_meta = {
                "id": "current",
                "ts": now_ts(),
                "change_type": "current",
                "added": 0,
                "deleted": 0,
                "bytes_after": len(after_text.encode("utf-8", errors="ignore")),
                "lines_after": after_text.count("\n") + (1 if after_text else 0),
                "virtual": True,
            }
            idx = 0
            total = max(total, 1)
        rows, truncated = build_code_preview_rows(before_text, after_text, max_rows=CODE_PREVIEW_STAGE_MAX_ROWS)
        stage_out = {
            "id": str(stage_meta.get("id", "current") or "current"),
            "index": int(idx + 1),
            "total": int(total if total > 0 else 1),
            "ts": float(stage_meta.get("ts", 0.0) or 0.0),
            "change_type": str(stage_meta.get("change_type", "modified") or "modified"),
            "added": int(stage_meta.get("added", 0) or 0),
            "deleted": int(stage_meta.get("deleted", 0) or 0),
            "virtual": bool(stage_meta.get("virtual", False)),
            "bytes_after": int(stage_meta.get("bytes_after", len(after_text.encode("utf-8", errors="ignore"))) or 0),
            "lines_after": int(stage_meta.get("lines_after", after_text.count("\n") + (1 if after_text else 0)) or 0),
        }
        return {
            "path": rel,
            "requested_stage": requested,
            "stage": stage_out,
            "rows": rows,
            "row_count": len(rows),
            "truncated": bool(truncated),
            "full_text": after_text,
        }

