    def _looks_like_substantial_informative_reply(self, text: str) -> bool:
        raw = str(text or "")
        clean = strip_thinking_content(raw).strip()
        if not clean:
            return False
        if len(clean) < 110:
            return False
        low = clean.lower()
        if "```" in clean:
            return True
        bullet_count = len(
            re.findall(
                r"(?m)^\s*(?:[-*]|\d+\.)\s+\S+",
                clean,
            )
        )
        if bullet_count >= 2:
            return True
        section_count = len(re.findall(r"(?m)^\s{0,3}#{1,6}\s+\S+", clean))
        if section_count >= 1:
            return True
        informative_markers = [
            "here's what",
            "here is what",
            "what i built",
            "what was built",
            "changes made",
            "implemented",
            "created",
            "updated",
            "fixed",
            "completed",
            "summary",
            "已完成",
            "完成了",
            "修复了",
            "修改了",
            "实现了",
            "总结",
            "说明如下",
            "结果如下",
            "已完成",
            "修復了",
            "修改了",
            "實作了",
            "總結",
            "說明如下",
            "結果如下",
            "実装しました",
            "修正しました",
            "更新しました",
            "作成しました",
            "まとめ",
            "結果は以下",
        ]
        if any(x in low for x in informative_markers):
            return True
        path_like = bool(
            re.search(
                r"(?:/users/|[a-z]:\\\\|\.py\b|\.js\b|\.ts\b|\.html\b|\.css\b|\.md\b)",
                low,
            )
        )
        sentence_count = len(re.findall(r"[.!?。！？]", clean))
        return path_like and sentence_count >= 2

    def _looks_like_direct_question_request(self, text: str) -> bool:
        raw = str(text or "").strip()
        t = raw.lower()
        if not t:
            return False
        if len(t) <= 220 and ("?" in t or "？" in raw):
            return True
        if len(t) > 220:
            return False
        markers = [
            "是什么",
            "是什麼",
            "为什么",
            "為什麼",
            "怎么",
            "如何",
            "explain",
            "what is",
            "why",
            "how to",
            "difference",
            "差異",
            "とは",
            "なぜ",
            "どうやって",
            "どうすれば",
            "違い",
            "何ですか",
        ]
        return any(x in t for x in markers)

    def _todo_should_block_auto_continue(self, assistant_text: str = "") -> bool:
        if not self.todo.has_open_items():
            return False
        if self._looks_like_conclusive_reply(assistant_text):
            return False
        if self._looks_like_substantial_informative_reply(assistant_text):
            return False
        goal = self._latest_user_goal_text()
        if self._looks_like_direct_question_request(goal) and (not self._looks_nontrivial_request(goal)):
            return False
        return self._looks_nontrivial_request(goal)

    def _is_long_running_engineering_context(self) -> bool:
        goal = self._latest_user_goal_text()
        if not self._looks_nontrivial_request(goal):
            return False
        rows = self.todo.snapshot()
        if not rows:
            return False
        open_count = sum(1 for row in rows if str(row.get("status", "pending")) != "completed")
        active_count = sum(1 for row in rows if str(row.get("status", "pending")) == "in_progress")
        return open_count >= 2 or active_count >= 1

    def _detect_endpoint_intent(self, text: str, tool_calls: list | None = None) -> dict:
        if tool_calls:
            return {"matched": False, "score": 0, "reasons": ["tool-calls-present"]}
        raw = str(text or "")
        clean = strip_thinking_content(raw).strip()
        if not clean:
            return {"matched": False, "score": 0, "reasons": ["empty-content"]}
        score = 0
        reasons: list[str] = []
        if self._looks_like_conclusive_reply(clean):
            score += 4
            reasons.append("conclusive-marker")
        if self._looks_like_substantial_informative_reply(clean):
            score += 2
            reasons.append("substantial-reply")
        if "```" in clean:
            score += 2
            reasons.append("contains-code-block")
        if len(clean) >= 220:
            score += 1
            reasons.append("long-form-output")
        tail = clean[-220:].lower()
        endpoint_markers = [
            "希望这能帮到你",
            "解释如上",
            "代码已修改完毕",
            "请查看上述代码",
            "已完成",
            "all set",
            "ready to use",
            "as requested",
            "that is all",
            "希望這能幫到你",
            "說明如上",
            "程式碼已修改完成",
            "請查看上述程式碼",
            "完了しました",
            "以上です",
            "ご確認ください",
        ]
        if any(x in tail for x in endpoint_markers):
            score += 2
            reasons.append("endpoint-tail-marker")
        if self._looks_like_incomplete_reply(clean):
            score -= 3
            reasons.append("incomplete-marker")
        if self._looks_like_user_decision_needed(clean):
            score -= 3
            reasons.append("decision-needed")
        threshold = 4 if self._is_long_running_engineering_context() else 3
        return {
            "matched": bool(score >= threshold),
            "score": int(score),
            "threshold": int(threshold),
            "reasons": reasons[:6],
        }

    def _infer_arbiter_status_from_text(self, text: str) -> str:
        low = str(text or "").strip().lower()
        if not low:
            return ""
        if any(
            x in low
            for x in [
                "task_completed",
                "task completed",
                "已完成",
                "完成",
                "已完成了",
                "done",
                "completed",
                "finished",
                "任務完成",
                "完了",
                "完了しました",
            ]
        ):
            return "TASK_COMPLETED"
        if any(
            x in low
            for x in [
                "valid_planning",
                "valid planning",
                "plan",
                "planning",
                "next step",
                "analysis",
                "计划",
                "計畫",
                "规划",
                "規劃",
                "下一步",
                "分析",
                "計画",
                "次のステップ",
            ]
        ):
            return "VALID_PLANNING"
        if any(
            x in low
            for x in [
                "empty_rambling",
                "empty rambling",
                "rambling",
                "idle",
                "stalled",
                "hallucination",
                "空想",
                "停滞",
                "停滯",
                "だらだら",
            ]
        ):
            return "EMPTY_RAMBLING"
        return ""

    def _normalize_arbiter_status(self, raw_status: str, fallback_text: str = "") -> str:
        key = str(raw_status or "").strip().upper().replace("-", "_").replace(" ", "_")
        aliases = {
            "TASK_COMPLETE": "TASK_COMPLETED",
            "COMPLETED": "TASK_COMPLETED",
            "DONE": "TASK_COMPLETED",
            "VALID_PLAN": "VALID_PLANNING",
            "PLANNING": "VALID_PLANNING",
            "PLAN": "VALID_PLANNING",
            "EMPTY": "EMPTY_RAMBLING",
            "RAMBLING": "EMPTY_RAMBLING",
            "IDLE": "EMPTY_RAMBLING",
        }
        status = aliases.get(key, key)
        if status in {"TASK_COMPLETED", "VALID_PLANNING", "EMPTY_RAMBLING"}:
            return status
        inferred = self._infer_arbiter_status_from_text(fallback_text)
        return inferred or ""

    def _arbiter_context_snapshot(self, assistant_text: str, thinking_text: str = "") -> dict:
        rows = self.todo.snapshot()
        open_count = sum(1 for x in rows if str(x.get("status", "pending")) != "completed")
        in_progress_count = sum(1 for x in rows if str(x.get("status", "pending")) == "in_progress")
        active_rows = []
        for row in rows:
            if str(row.get("status", "pending")) != "in_progress":
                continue
            content = normalize_work_text(row.get("content", ""), "in_progress") or str(row.get("content", "")).strip()
            if content:
                active_rows.append(trim(content, 140))
            if len(active_rows) >= 3:
                break
        snapshot = {
            "goal": self._latest_user_goal_text(),
            "todo_open_count": int(open_count),
            "todo_in_progress_count": int(in_progress_count),
            "todo_active": active_rows,
            "assistant_reply": trim(strip_thinking_content(str(assistant_text or "")).strip(), 2200),
            "assistant_thinking": trim(str(thinking_text or "").strip(), 700),
            "agent_round_index": int(self.agent_round_index),
        }
        # Inject plan step progress so arbiter knows overall completion state
        bb = self._ensure_blackboard()
        plan_todos = bb.get("project_todos", [])
        plan_steps = [t for t in plan_todos if t.get("category") == "plan_step"]
        if plan_steps:
            completed = len([t for t in plan_steps if t.get("status") == "completed"])
            total = len(plan_steps)
            snapshot["plan_progress"] = f"{completed}/{total} steps completed"
            if completed < total:
                snapshot["plan_warning"] = (
                    f"IMPORTANT: Only {completed}/{total} plan steps are completed. "
                    "Do NOT classify as TASK_COMPLETED unless ALL steps are done."
                )
        return snapshot

    def _build_arbiter_client(self) -> OllamaClient:
        client = OllamaClient(self.ollama.base_url, self.ollama.model)
        active_profile = dict(self.model_profiles.get(self.active_profile_id, {}))
        if active_profile:
            try:
                client.apply_profile(active_profile)
            except Exception:
                pass
        model_override = str(self.arbiter_model or "").strip()
        if model_override:
            client.model = model_override
        client.thinking_stream = False
        client.timeout = max(0.2, float(self.arbiter_timeout_seconds or ARBITER_DEFAULT_TIMEOUT_SECONDS))
        return client

    def _call_arbiter_llm(self, assistant_text: str, thinking_text: str = "") -> dict:
        clean = strip_thinking_content(str(assistant_text or "")).strip()
        if not self.arbiter_enabled:
            return {"status": "DISABLED", "reasoning": "arbiter disabled", "raw": ""}
        if len(clean) < int(ARBITER_TRIGGER_MIN_CONTENT_CHARS):
            return {"status": "SKIP_SHORT", "reasoning": "content too short", "raw": ""}
        snapshot = self._arbiter_context_snapshot(clean, thinking_text)
        arbiter_system = (
            "You are a task-state arbiter. "
            "Classify worker output into exactly one status: "
            "TASK_COMPLETED, VALID_PLANNING, or EMPTY_RAMBLING. "
            "Return strict JSON only."
        )
        arbiter_user = (
            "Read the snapshot and classify the worker state.\n"
            "Status definitions:\n"
            "- TASK_COMPLETED: worker already completed user's target and gave final deliverable/summary.\n"
            "- VALID_PLANNING: worker output is meaningful planning/analysis that should continue into execution.\n"
            "- EMPTY_RAMBLING: worker is stalling, repeating, or hallucinating with no actionable progress.\n"
            "Output JSON only:\n"
            "{\"status\":\"TASK_COMPLETED|VALID_PLANNING|EMPTY_RAMBLING\",\"reasoning\":\"<=40 words\"}\n\n"
            f"Snapshot:\n{json_dumps(snapshot, indent=2)}"
        )
        box: dict[str, object] = {}

        def _runner():
            try:
                arbiter_client = self._build_arbiter_client()
                rsp = arbiter_client.chat(
                    [{"role": "user", "content": arbiter_user}],
                    system=arbiter_system,
                    max_tokens=int(self.arbiter_max_tokens),
                    temperature=float(self.arbiter_temperature),
                    think=False,
                    stream_thinking=False,
                )
                box["rsp"] = rsp
            except Exception as exc:
                box["error"] = exc

        thread = threading.Thread(target=_runner, daemon=True)
        thread.start()
        thread.join(timeout=max(0.2, float(self.arbiter_timeout_seconds or ARBITER_DEFAULT_TIMEOUT_SECONDS)))
        if thread.is_alive():
            return {"status": "ARBITER_TIMEOUT", "reasoning": "arbiter timeout", "raw": ""}
        err = box.get("error")
        if isinstance(err, Exception):
            return {"status": "ARBITER_ERROR", "reasoning": trim(str(err), 220), "raw": ""}
        rsp = box.get("rsp") if isinstance(box.get("rsp"), dict) else {}
        raw_content = trim(str((rsp or {}).get("content", "") or ""), 2000)
        payload = extract_json_object_from_text(raw_content, {})
        status = self._normalize_arbiter_status(str(payload.get("status", "") or ""), raw_content)
        if not status:
            status = self._infer_arbiter_status_from_text(raw_content)
        reasoning = trim(
            str(payload.get("reasoning", payload.get("reason", "")) or ""),
            280,
        ) or trim(raw_content, 280)
        return {
            "status": status or "UNKNOWN",
            "reasoning": reasoning,
            "raw": raw_content,
            "model": str(self.arbiter_model or self.ollama.model or "").strip(),
        }

    def _inject_arbiter_continue_hint(self, decision: dict):
        reasoning = trim(str(decision.get("reasoning", "") or "").strip(), 180)
        self._prune_runtime_retry_hints()
        self.messages.append(
            {
                "role": "user",
                "content": (
                    "<arbiter-continue>"
                    "系统仲裁判定：当前回复属于有效计划。请立即推进执行：下一轮必须调用一个具体工具，"
                    "不要重复口头计划，不要新增无意义 Todo。"
                    f"{(' 判定依据: ' + reasoning + '。') if reasoning else ''}"
                    "</arbiter-continue>"
                ),
                "ts": now_ts(),
            }
        )

    def _mark_all_done_silently(self, reason: str = "") -> dict:
        summary = trim(str(reason or "").strip(), 160) or "arbiter: task completed"
        # Protect plan_step todos — they must only be completed by _advance_plan_step
        bb = self._ensure_blackboard()
        plan_todos = bb.get("project_todos", [])
        saved_plan_steps: dict[str, dict] = {}
        for t in plan_todos:
            if t.get("category") == "plan_step" and t.get("status") != "completed":
                saved_plan_steps[str(t.get("id", ""))] = {
                    "status": t.get("status", "pending"),
                    "completed_at": t.get("completed_at"),
                    "completed_by": t.get("completed_by", ""),
                    "evidence": t.get("evidence", ""),
                }
        result = self.todo.complete_all_open(summary)
        # Restore plan_step todos to their original state
        if saved_plan_steps:
            bb = self._ensure_blackboard()
            for t in bb.get("project_todos", []):
                tid = str(t.get("id", ""))
                if tid in saved_plan_steps:
                    t["status"] = saved_plan_steps[tid]["status"]
                    t["completed_at"] = saved_plan_steps[tid]["completed_at"]
                    t["completed_by"] = saved_plan_steps[tid]["completed_by"]
                    t["evidence"] = saved_plan_steps[tid]["evidence"]
            self.blackboard = bb
            self._sync_todos_from_blackboard(reason="plan-step-restore")
        updated = int(result.get("updated", 0) or 0)
        total = int(result.get("total", 0) or 0)
        pending_steps = len(saved_plan_steps)
        self._prune_runtime_retry_hints()
        self._emit(
            "status",
            {
                "summary": (
                    f"arbiter marked task completed; todos completed={updated}/{total}"
                    + (f"; {pending_steps} plan steps protected (still pending)" if pending_steps else "")
                )
            },
        )
        return result

    def _generate_run_completion_summary(self):
        """Generate a brief summary bubble when a run completes, so user isn't left without feedback."""
        if self.cancel_requested:
            return
        bb = self._ensure_blackboard()
        plan = bb.get("plan", {}) if isinstance(bb.get("plan"), dict) else {}
        plan_phase = str(plan.get("phase", "") or "").strip().lower()
        proposal_waiting = bool(self.runtime_plan_proposal) and not bool(self.runtime_plan_approved)
        board_has_proposal = isinstance(plan.get("proposal"), dict) and bool(plan.get("proposal"))
        # Guard: plan mode paused for user selection or still in intermediate planning phases
        if (
            (plan_phase in {"awaiting_choice", "research", "synthesis"} and not self.runtime_plan_approved)
            or proposal_waiting
            or (plan_phase == "awaiting_choice" and board_has_proposal)
        ):
            return
        # Guard: approved-plan execution uses its own plan/todo progress UI; avoid redundant completion bubble
        if self.runtime_plan_approved or plan_phase == "executing":
            return
        # Guard: in single-agent mode the developer already replied directly — no redundant summary
        _exec_mode = self._effective_execution_mode()
        if _exec_mode == EXECUTION_MODE_SINGLE:
            for _m in reversed(self.messages[-20:]):
                if not isinstance(_m, dict):
                    continue
                _r = str(_m.get("role", "") or "")
                _ar = str(_m.get("agent_role", "") or "")
                if _r == "assistant" and _ar not in ("manager", "planner", ""):
                    return
        _summary_role = "developer"
        try:
            board_md = self._blackboard_read_state_markdown(max_items=10)
            # Collect completed plan steps
            plan_steps = [t for t in bb.get("project_todos", []) if t.get("category") == "plan_step"]
            completed = [t for t in plan_steps if t.get("status") == "completed"]
            pending = [t for t in plan_steps if t.get("status") != "completed"]
            # Collect recent file operations from step_files
            step_files = bb.get("step_files", {})
            file_list = []
            for _sf_key, entries in (step_files.items() if isinstance(step_files, dict) else []):
                if isinstance(entries, list):
                    for e in entries[-5:]:
                        fp = str(e.get("path", "") if isinstance(e, dict) else e or "").strip()
                        if fp:
                            file_list.append(fp)
            file_list = list(dict.fromkeys(file_list))[-10:]  # Dedupe, last 10
            # Build context for LLM summary
            goal = trim(str(bb.get("original_goal", "") or self.runtime_reclassify_goal or ""), 600)
            lang_hint = model_language_instruction(self.ui_language)
            parts = [f"GOAL: {goal}"] if goal else []
            if completed:
                parts.append(f"COMPLETED STEPS ({len(completed)}/{len(plan_steps)}):")
                for t in completed:
                    idx = int(t.get("plan_step_index", 0) or 0) + 1
                    parts.append(f"  ✅ {idx}. {trim(str(t.get('content', '')), 100)}")
            if pending:
                parts.append(f"REMAINING ({len(pending)}):")
                for t in pending[:3]:
                    idx = int(t.get("plan_step_index", 0) or 0) + 1
                    parts.append(f"  ⬜ {idx}. {trim(str(t.get('content', '')), 100)}")
            if file_list:
                parts.append(f"FILES CREATED/MODIFIED: {', '.join(file_list[:8])}")
            if board_md:
                parts.append(f"BLACKBOARD STATE:\n{trim(board_md, 800)}")
            context = "\n".join(parts)
            # --- Supplement context from messages history when plan steps are unavailable ---
            # (pure sync mode: no plan steps, so file_list/ops may be empty above)
            files_from_msgs: list[str] = []
            ops_from_msgs: list[str] = []
            agent_conclusion = ""
            for _m in self.messages[-60:]:
                if not isinstance(_m, dict):
                    continue
                _role = _m.get("role", "")
                # file_patch type → extract file location
                if _m.get("type") == "file_patch":
                    _loc = str(_m.get("location", "") or _m.get("path", "") or "").strip()
                    if _loc and _loc not in files_from_msgs:
                        files_from_msgs.append(_loc)
                # command output → capture brief preview
                if _m.get("type") == "command" and _role == "system":
                    _cmd = trim(str(_m.get("content", "") or ""), 120)
                    if _cmd:
                        ops_from_msgs.append(_cmd)
                # last non-manager/non-planner assistant reply → agent self-description
                if _role == "assistant" and str(_m.get("agent_role", "") or "") not in ("manager", "planner"):
                    _txt = str(_m.get("content", "") or "").strip()
                    if _txt:
                        agent_conclusion = trim(_txt, 400)
            # Merge: use message-derived file list only when step_files gave nothing
            if not file_list and files_from_msgs:
                file_list = files_from_msgs[:8]
            # Append agent conclusion and bash ops to context if not already present
            if agent_conclusion and "AGENT LAST OUTPUT" not in context:
                context += f"\nAGENT LAST OUTPUT:\n{agent_conclusion}"
            if ops_from_msgs and "BASH OPS" not in context:
                context += f"\nBASH OPS (last {min(3, len(ops_from_msgs))}):\n" + "\n".join(ops_from_msgs[-3:])
            # ---
            prompt = (
                f"{lang_hint}\n"
                "Generate a BRIEF completion summary for the user (3-8 sentences).\n"
                "Include: what was accomplished, key files created, and any remaining work.\n"
                "Use markdown formatting. Be concise and informative.\n"
                f"Do NOT include code blocks unless essential.\n\n"
                f"CONTEXT:\n{context}"
            )
            rsp = self.ollama.chat(
                [{"role": "user", "content": prompt}],
                max_tokens=800,
                temperature=0.3,
            )
            summary_text = str(rsp.get("content", "") or "").strip()
            if not summary_text or len(summary_text) < 10:
                summary_text = self._generate_static_completion_summary(
                    completed, pending, file_list, goal, agent_text=agent_conclusion
                )
            self.messages.append({
                "role": "assistant",
                "content": summary_text,
                "ts": now_ts(),
                "agent_role": _summary_role,
            })
            self._emit("message", {
                "role": "assistant",
                "text": trim(summary_text, int(ASSISTANT_MESSAGE_EVENT_MAX_CHARS)),
                "summary": "run completion summary",
                "agent_role": _summary_role,
            })
        except Exception:
            try:
                bb = self._ensure_blackboard()
                plan_steps = [t for t in bb.get("project_todos", []) if t.get("category") == "plan_step"]
                completed = [t for t in plan_steps if t.get("status") == "completed"]
                pending = [t for t in plan_steps if t.get("status") != "completed"]
                goal = trim(str(bb.get("original_goal", "") or ""), 200)
                summary_text = self._generate_static_completion_summary(completed, pending, [], goal)
                self.messages.append({
                    "role": "assistant",
                    "content": summary_text,
                    "ts": now_ts(),
                    "agent_role": _summary_role,
                })
                self._emit("message", {
                    "role": "assistant",
                    "text": trim(summary_text, int(ASSISTANT_MESSAGE_EVENT_MAX_CHARS)),
                    "summary": "run completion summary (static)",
                    "agent_role": _summary_role,
                })
            except Exception:
                pass

    def _generate_static_completion_summary(
        self,
        completed: list[dict],
        pending: list[dict],
        file_list: list[str],
        goal: str,
        agent_text: str = "",
    ) -> str:
        """Static fallback summary when LLM call fails."""
        lines = ["## ✅ 任务执行完成\n"]
        if goal:
            lines.append(f"**目标：** {trim(goal, 200)}\n")
        total = len(completed) + len(pending)
        if completed:
            lines.append(f"**进度：** {len(completed)}/{total} 步骤已完成")
            for t in completed[-5:]:
                idx = int(t.get("plan_step_index", 0) or 0) + 1
                lines.append(f"- ✅ {idx}. {trim(str(t.get('content', '')), 80)}")
        if pending:
            lines.append(f"\n**待完成：** {len(pending)} 步骤")
            for t in pending[:3]:
                idx = int(t.get("plan_step_index", 0) or 0) + 1
                lines.append(f"- ⬜ {idx}. {trim(str(t.get('content', '')), 80)}")
        # When no plan steps exist (pure sync mode), show agent conclusion text instead
        if not completed and agent_text:
            lines.append(f"\n**执行摘要：** {trim(agent_text, 300)}")
        if file_list:
            lines.append(f"\n**涉及文件：** {', '.join(file_list[:6])}")
        return "\n".join(lines)

    def _should_soft_pause_no_action(self, assistant_text: str, tool_calls: list | None = None) -> bool:
        if tool_calls:
            return False
        clean = strip_thinking_content(str(assistant_text or "")).strip()
        if not clean:
            return False
        if bool(self.arbiter_enabled):
            return False
        if len(clean) >= 100 or self._looks_nontrivial_request(clean):
            return True
        if self._is_long_running_engineering_context():
            return False
        if self._looks_like_incomplete_reply(clean):
            return False
        return True

    def _todo_active_brief(self) -> str:
        rows = self.todo.snapshot()
        if not rows:
            return self._ui_text("todo_no_todos")
        active = []
        open_count = 0
        done_count = 0
        for row in rows:
            status = str(row.get("status", "pending"))
            content = normalize_work_text(row.get("content", ""), status) or str(row.get("content", "")).strip()
            if status == "completed":
                done_count += 1
            else:
                open_count += 1
            if status == "in_progress":
                active.append(trim(content or "(empty todo)", 140))
        if active:
            lines = [f"Active todos ({len(active)}):"]
            for item in active[:3]:
                lines.append(f"- {item}")
            lines.append(f"Open={open_count}, Completed={done_count}")
            return "\n".join(lines)
        return f"No active in_progress todo. Open={open_count}, Completed={done_count}"

    def clear_stale_todos(self) -> dict:
        result = self.todo.clear_all()
        self.rounds_without_todo = 0
        self.todo_reminder_count = 0
        self.todo_write_issue_count = 0
        self.todo_last_issue = ""
        self.updated_at = now_ts()
        self._persist()
        self._emit(
            "status",
            {
                "summary": (
                    "stale todos cleared by user "
                    f"(removed={int(result.get('removed', 0) or 0)}, "
                    f"open_removed={int(result.get('open_removed', 0) or 0)})"
                )
            },
        )
        return {"ok": True, **result}

    def _is_empty_action_turn(self, text: str, thinking_text: str, tool_calls: list | None = None) -> bool:
        if tool_calls:
            return False
        raw = str(text or "")
        body = strip_thinking_content(raw).strip()
        if len(body) >= int(EMPTY_ACTION_MIN_CONTENT_CHARS):
            return False
        thinking = str(thinking_text or "").strip()
        raw_low = raw.lower()
        has_think_marker = ("<think" in raw_low) or ("<|start_of_thought|>" in raw_low)
        if thinking or has_think_marker:
            return True
        return not body

    def _is_thinking_budget_exhausted(
        self,
        text: str,
        thinking_text: str,
        tool_calls: list | None = None,
        output_tokens: int = 0,
    ) -> bool:
        if tool_calls:
            return False
        if not self._is_empty_action_turn(text, thinking_text, tool_calls):
            return False
        if not str(thinking_text or "").strip():
            return False
        threshold = int(max(1, self.max_output_tokens) * float(THINKING_BUDGET_FORCE_RATIO))
        return int(output_tokens or 0) >= max(1, threshold)

    def _is_thinking_only_dead_turn(self, text: str, thinking_text: str, tool_calls: list | None = None) -> bool:
        if self._is_empty_action_turn(text, thinking_text, tool_calls):
            return True
        if tool_calls:
            return False
        body = strip_thinking_content(str(text or "")).strip()
        thinking = str(thinking_text or "").strip()
        return len(body) < int(EMPTY_ACTION_MIN_CONTENT_CHARS) and len(thinking) >= 80

    def _clear_live_thinking(self):
        with self.lock:
            self.live_thinking_text = ""
            self.live_thinking_last_emit = 0.0

    def _append_live_thinking(self, chunk: str):
        piece = str(chunk or "").strip()
        if not piece:
            return
        now_tick = now_ts()
        with self.lock:
            if self.cancel_requested or (not self.running):
                return
            self.live_thinking_text = (self.live_thinking_text + ("\n" if self.live_thinking_text else "") + piece)[-24_000:]
            self.updated_at = now_tick
            should_emit = (now_tick - self.live_thinking_last_emit) >= 0.35
            if should_emit:
                self.live_thinking_last_emit = now_tick
        if should_emit:
            self._emit(
                "thinking_delta",
                {
                    "summary": "thinking streaming",
                    "size": len(self.live_thinking_text),
                },
            )

    def _looks_nontrivial_request(self, text: str) -> bool:
        t = (text or "").strip().lower()
        if not t:
            return False
        if len(t) >= 120:
            return True
        markers = [
            # 工程/开发
            "实现", "修复", "重构", "设计", "构建", "架构", "内核", "框架",
            "死循环", "状态机", "调度", "后端", "前端", "自动化",
            "agentbus", "watchdog", "decomposition", "workflow",
            "architecture", "build", "implement", "refactor", "fix", "debug",
            "multi-step",
            # 文档/演示/设计制作
            "ppt", "pptx", "演示文稿", "幻灯片", "presentation",
            "生成报告", "制作", "做一个",
            "excel", "xlsx", "电子表格", "docx", "word",
            "pdf", "可视化", "visualization", "dashboard",
            "svg", "canvas", "动画", "animation",
            # 全栈/部署
            "api", "server", "数据库", "database", "部署", "deploy",
            "docker", "mcp", "agent", "bot", "爬虫", "crawler",
            "测试", "test", "playwright",
            # 品牌/内容
            "品牌", "brand", "theme", "gif",
            # 通用复杂任务动词
            "分析并", "总结并", "对比", "深度",
        ]
        return any(x in t for x in markers)

    def _llm_classify_task_complexity(self, goal_text: str) -> str:
        """LLM semantic pre-screening: classify task as simple/complex via 4-dimension analysis. 5s timeout."""
        goal = trim(str(goal_text or ""), 400)
        if not goal or len(goal) < 6:
            return "simple"
        import threading
        result_box = ["simple"]
        def _classify():
            try:
                rsp = self.ollama.chat(
                    [{"role": "user", "content": (
                        f"/no_think\nRate this task on 4 dimensions (1=low 2=med 3=high), then classify.\n\n"
                        f"Task: {goal}\n\n"
                        f"SCOPE: how many files/components/systems are touched?\n"
                        f"STEPS: how many distinct execution steps are needed?\n"
                        f"SKILL: does it need specialized tools, skills, research, or APIs?\n"
                        f"OUTPUT: what is expected (1=text answer, 2=single file, 3=system/multi-file)?\n\n"
                        f"Output exactly one line:\n"
                        f"SCOPE:N STEPS:N SKILL:N OUTPUT:N VERDICT:SIMPLE|COMPLEX\n"
                        f"(COMPLEX if any dimension >= 2)"
                    )}],
                    system="/no_think\nAnalyze task dimensions. One line output only.",
                    max_tokens=40,
                    think=False,
                )
                answer = str(rsp.get("content", "") or "").strip().upper()
                # Parse dimension scores
                dims: dict = {}
                for dim in ("SCOPE", "STEPS", "SKILL", "OUTPUT"):
                    m = re.search(rf"{dim}:(\d)", answer)
                    if m:
                        dims[dim.lower()] = int(m.group(1))
                if dims:
                    self._cached_complexity_dimensions = dims
                if "COMPLEX" in answer:
                    result_box[0] = "complex"
            except Exception:
                pass
        t = threading.Thread(target=_classify, daemon=True)
        t.start()
        t.join(timeout=5.0)
        return result_box[0]

    def _infer_task_profile(self, goal: str) -> dict:
        clean = strip_thinking_content(str(goal or "")).strip()
        low = clean.lower()
        explicit_complexity = infer_user_complexity_value(clean)
        # Use cached LLM complexity result (set by _agent_worker entry point)
        llm_complexity = str(getattr(self, '_cached_llm_complexity', '') or '')
        nontrivial = self._looks_nontrivial_request(clean) or llm_complexity == "complex"
        direct_question = self._looks_like_direct_question_request(clean) and llm_complexity != "complex"
        code_markers = [
            # 代码/编程
            "代码", "寫代碼", "写代码", "脚本", "模块", "函数", "class", "bug",
            "修复", "实现", "重构", "app.py", "crawler.py",
            ".py", ".js", ".ts", ".html", ".css", ".vue", ".jsx", ".tsx",
            "python", "javascript", "bash", "terminal", "tool", "patch", "edit",
            "write_file", "read_file", "build", "implement", "fix", "refactor", "debug",
            # 文档/演示生成（需要 skill 支撑）
            "ppt", "pptx", "演示文稿", "幻灯片", "presentation", "slide",
            "生成ppt", "制作ppt", "做ppt", "做一个ppt",
            "excel", "xlsx", "电子表格", "spreadsheet", "表格",
            "docx", "word", "文档", "document", "报告", "report",
            "pdf", "生成pdf", "制作pdf",
            # 设计/前端/可视化
            "html报告", "可视化", "visualization", "图表", "chart", "dashboard",
            "前端", "frontend", "ui", "界面", "landing page", "网页", "页面",
            "svg", "canvas", "动画", "animation", "设计",
            # 工程/架构
            "api", "server", "服务", "数据库", "database", "部署", "deploy",
            "docker", "容器", "微服务", "microservice", "架构",
            "mcp", "agent", "bot", "爬虫", "crawler", "scraper",
            # 测试
            "测试", "test", "单元测试", "集成测试", "playwright", "selenium",
            # 品牌/内容
            "品牌", "brand", "logo", "主题", "theme",
            "gif", "图片", "image", "插画",
        ]
        research_markers = [
            "分析", "调研", "研究", "白皮书", "论文", "report",
            "analysis", "research", "investigate", "总结", "综述",
            "对比", "compare", "benchmark", "评测", "survey",
            "阅读", "解读", "review",
        ]
        has_code_intent = any(x in low for x in code_markers)
        has_research_intent = any(x in low for x in research_markers)
        length = len(clean)
        if direct_question and (not nontrivial) and (not has_code_intent) and length <= 220:
            return {
                "task_type": "simple_qa",
                "complexity": explicit_complexity or "simple",
                "direct_objective": (
                    "Directly answer the user question in natural language. "
                    "Do not create or edit files unless explicitly requested."
                ),
                "recommended_agents": ["developer"],
                "round_budget": 2,
                "reason": "short direct question with no code intent",
                "goal_chars": int(length),
                "updated_at": float(now_ts()),
            }
        if has_code_intent and (not nontrivial) and length <= 260:
            return {
                "task_type": "simple_code",
                "complexity": explicit_complexity or "simple",
                "direct_objective": (
                    "Deliver one minimal concrete code change, run one quick verification, then conclude."
                ),
                "recommended_agents": ["developer", "reviewer"],
                "round_budget": 5,
                "reason": "small scoped code-oriented request",
                "goal_chars": int(length),
                "updated_at": float(now_ts()),
            }
        if has_research_intent and (not has_code_intent):
            return {
                "task_type": "research",
                "complexity": explicit_complexity or ("complex" if (nontrivial or length >= 280) else "simple"),
                "direct_objective": "Collect evidence first, then synthesize a concise actionable answer.",
                "recommended_agents": ["explorer", "developer", "reviewer"],
                "round_budget": 10 if (nontrivial or length >= 280) else 6,
                "reason": "research/evidence intent detected",
                "goal_chars": int(length),
                "updated_at": float(now_ts()),
            }
        if nontrivial or has_code_intent or length >= 280:
            return {
                "task_type": "engineering",
                "complexity": explicit_complexity or "complex",
                "direct_objective": (
                    "Use blackboard collaboration to implement, validate, and converge with concrete outputs."
                ),
                "recommended_agents": ["explorer", "developer", "reviewer"],
                "round_budget": 14,
                "reason": "multi-step engineering characteristics detected",
                "goal_chars": int(length),
                "updated_at": float(now_ts()),
            }
        return {
            "task_type": "general",
            "complexity": explicit_complexity or "simple",
            "direct_objective": (
                "Provide the most direct useful response with minimal orchestration, "
                "anchored to the current project context and user goal."
            ),
            "recommended_agents": ["developer"],
            "round_budget": 3,
            "reason": "default lightweight profile",
            "goal_chars": int(length),
            "updated_at": float(now_ts()),
        }

    def _is_default_session_title(self, title: str) -> bool:
        t = str(title or "").strip()
        if not t:
            return True
        low = t.lower()
        default_titles = {
            "web session",
            "session",
            "web 会话",
            "会话",
            "web 會話",
            "會話",
            "web セッション",
            "セッション",
        }
        if low in default_titles or t in default_titles:
            return True
        if re.fullmatch(
            r"(web[\s_-]*)?(session|会话|會話|セッション)[\s_-]*\d*",
            low,
            flags=re.IGNORECASE,
        ):
            return True
        if t == self.id:
            return True
        if re.fullmatch(r"sess_[a-z0-9]{6,}", low):
            return True
        return False

    def _title_context_brief(self) -> str:
        goal = self._latest_user_goal_text()
        todo_rows = []
        for row in self.todo.snapshot():
            status = str(row.get("status", "pending"))
            if status not in {"pending", "in_progress", "completed"}:
                status = "pending"
            content = normalize_work_text(row.get("content", ""), status) or str(row.get("content", "")).strip()
            if content:
                todo_rows.append(f"[{status}] {trim(content, 80)}")
            if len(todo_rows) >= 4:
                break
        task_rows = []
        for row in self.tasks.list_objects():
            status = str(row.get("status", "pending"))
            if status not in {"pending", "in_progress", "blocked", "completed"}:
                status = "pending"
            subject = normalize_work_text(row.get("subject", ""), status) or str(row.get("subject", "")).strip()
            if subject:
                task_rows.append(f"#{row.get('id')}[{status}] {trim(subject, 80)}")
            if len(task_rows) >= 4:
                break
        todos_txt = " | ".join(todo_rows) if todo_rows else "none"
        tasks_txt = " | ".join(task_rows) if task_rows else "none"
        return (
            f"goal: {trim(goal, 180)}\n"
            f"todos: {todos_txt}\n"
            f"tasks: {tasks_txt}"
        )

    def _normalize_auto_title(self, raw: str) -> str:
        text = str(raw or "").strip()
        if not text:
            return ""
        text = text.replace("\r", " ").replace("\n", " ")
        text = re.sub(r"\s+", " ", text).strip()
        text = re.sub(r"^['\"`#\-\s]+|['\"`#\-\s]+$", "", text).strip()
        text = re.sub(r"^[Tt]itle\s*[:：]\s*", "", text).strip()
        if not text:
            return ""
        if len(text) > 40:
            text = text[:40].rstrip(" -_:;,.")
        if self._is_default_session_title(text):
            return ""
        return text

    def _fallback_auto_title(self) -> str:
        goal = self._latest_user_goal_text()
        if not goal:
            return ""
        candidate = normalize_work_text(goal) or goal
        candidate = re.sub(
            r"^(实现|實現|修复|修復|构建|構建|创建|創建|请|請|帮我|幫我|需要|"
            r"implement|fix|build|create|please|need|"
            r"実装|修正|作成|構築|お願い)\s*",
            "",
            candidate,
            flags=re.IGNORECASE,
        ).strip()
        return self._normalize_auto_title(candidate)

    def _maybe_auto_rename_session_title(self, trigger: str = "") -> bool:
        now_tick = now_ts()
        with self.lock:
            current = str(self.title or "").strip()
            if not self._is_default_session_title(current):
                return False
            if (now_tick - float(self.last_auto_title_ts or 0.0)) < 12:
                return False
            self.last_auto_title_ts = now_tick

        if self.cancel_requested:
            return False

        prompt = (
            "Generate one concise session title from current coding task progress.\n"
            "Rules:\n"
            "- max 20 characters (or 3-6 English words)\n"
            "- no quotes, no markdown, no punctuation-only title\n"
            "- output title only\n\n"
            f"{self._title_context_brief()}"
        )
        candidate = ""
        try:
            rsp = self.ollama.chat(
                [{"role": "user", "content": f"/no_think\n{prompt}"}],
                system=(
                    "/no_think\n"
                    "You generate short practical session titles for developer workflow tracking. "
                    f"{model_language_instruction(self.ui_language)}"
                ),
                max_tokens=80,
                think=False,
            )
            candidate = self._normalize_auto_title(str(rsp.get("content", "") or ""))
        except Exception:
            candidate = ""
        if not candidate:
            candidate = self._fallback_auto_title()
        if not candidate:
            return False
        if self.cancel_requested:
            return False

        with self.lock:
            if self.cancel_requested:
                return False
            old_title = str(self.title or "").strip()
            if not self._is_default_session_title(old_title):
                return False
            if candidate == old_title:
                return False
            self.title = candidate
            self.updated_at = now_ts()
            self._persist()
        self._emit(
            "status",
            {
                "summary": (
                    f"session auto-renamed ({trigger or 'progress'}): "
                    f"'{trim(old_title, 36)}' -> '{candidate}'"
                )
            },
        )
        return True

    def _ensure_runtime_model_ready(self):
        active_profile = dict(self.model_profiles.get(self.active_profile_id, {}))
        if not self._profile_is_runnable(active_profile):
            if not bool(self.auto_model_switch):
                self._emit(
                    "status",
                    {
                        "summary": (
                            "runtime model is not runnable; auto model switch disabled, "
                            "please switch model manually"
                        )
                    },
                )
                return
            fallback = self._pick_runnable_selection(
                preferred_provider=str(self.ollama.provider or ""),
                exclude={f"{self.active_profile_id}::{self.ollama.model}"},
            )
            if fallback:
                self.set_runtime_selection(fallback, reset_failures=False)
                self._emit(
                    "status",
                    {
                        "summary": (
                            "runtime model auto-recovered from non-runnable profile "
                            f"to {fallback}"
                        )
                    },
                )
            return
        if str(self.ollama.provider or "").lower() != "ollama":
            return
        try:
            tags = list_ollama_models(self.ollama.base_url)
        except Exception:
            tags = []
        if not tags:
            return
        current_model = str(self.ollama.model or "").strip()
        if current_model:
            loaded = list_loaded_ollama_models(self.ollama.base_url, timeout=5)
            if current_model not in set(loaded):
                woke, wake_err = wake_ollama_model(
                    self.ollama.base_url,
                    current_model,
                    timeout=self._global_wait_timeout_seconds(),
                )
                if woke:
                    self._emit(
                        "status",
                        {"summary": f"woke pinned ollama model: {current_model}"},
                    )
                elif wake_err:
                    self._emit(
                        "status",
                        {
                            "summary": (
                                f"pinned model wake failed for '{current_model}': "
                                f"{trim(wake_err, 160)}"
                            )
                        },
                    )
        if self.ollama.model in tags:
            return
        preferred = resolve_ollama_model(self.ollama.base_url, current_model)
        if not preferred or preferred == current_model:
            return
        if not bool(self.auto_model_switch):
            self._emit(
                "status",
                {
                    "summary": (
                        f"detected unavailable ollama tag '{current_model}' in scan; "
                        "auto model switch disabled, please switch manually"
                    )
                },
            )
            return
        selection = f"{self.active_profile_id}::{preferred}"
        self.set_runtime_selection(selection, reset_failures=False)
        self._emit(
            "status",
            {
                "summary": (
                    f"model preflight switched unavailable tag '{current_model}' "
                    f"-> '{preferred}'"
                )
            },
        )

    def _active_runtime_selection(self) -> str:
        profile = dict(self.model_profiles.get(self.active_profile_id, {}))
        model = str(profile.get("model", self.ollama.model) or self.ollama.model).strip()
        return f"{self.active_profile_id}::{model}"

    def _global_wait_timeout_seconds(self) -> int:
        raw = (
            self.max_run_seconds
            or getattr(self.ollama, "timeout", 0)
            or DEFAULT_REQUEST_TIMEOUT
        )
        return normalize_timeout_seconds(
            raw,
            minimum=MIN_TIMEOUT_SECONDS,
            maximum=MAX_TIMEOUT_SECONDS,
            fallback=DEFAULT_REQUEST_TIMEOUT,
        )

    def _set_runtime_phase(self, phase: str, tool_name: str = ""):
        with self.lock:
            self.current_phase = str(phase or "idle")
            self.current_tool_name = str(tool_name or "")

    def _startup_phase(self, step: str = "") -> str:
        label = trim(str(step or "").strip(), 80)
        return f"starting:{label}" if label else "starting"

    def _call_interruptible(
        self,
        fn,
        poll_interval: float = 0.08,
        *,
        progress_label: str = "model call",
        progress_interval: float | None = None,
        progress_delay: float | None = None,
    ):
        if self.cancel_requested:
            raise OllamaError("interrupted by user", status=499)
        done = threading.Event()
        box: dict[str, object] = {}
        start_ts = time.time()
        interval = MODEL_CALL_PROGRESS_INTERVAL if progress_interval is None else float(progress_interval)
        delay = MODEL_CALL_PROGRESS_DELAY if progress_delay is None else float(progress_delay)
        label = trim(str(progress_label or "model call"), 120) or "model call"
        last_progress_emit = start_ts
        with self.lock:
            self.live_run_notice_active = True
            self.live_run_notice_label = label
            self.live_run_notice_started_at = float(start_ts)
            self.live_run_notice_elapsed = 0.0
        self._emit_transient("runtime_progress", {"state": "start", "label": label, "elapsed": 0.0})

        def worker():
            try:
                box["result"] = fn()
            except Exception as exc:
                box["error"] = exc
            finally:
                done.set()

        threading.Thread(target=worker, daemon=True).start()
        try:
            while True:
                if done.wait(poll_interval):
                    break
                if self.cancel_requested:
                    raise OllamaError("interrupted by user", status=499)
                if interval > 0:
                    now = time.time()
                    if now - start_ts >= delay and now - last_progress_emit >= interval:
                        last_progress_emit = now
                        with self.lock:
                            self.live_run_notice_elapsed = max(0.0, now - start_ts)
                        self._emit_transient(
                            "runtime_progress",
                            {
                                "state": "tick",
                                "label": label,
                                "elapsed": round(max(0.0, now - start_ts), 1),
                            },
                        )
            if "error" in box:
                err = box.get("error")
                if isinstance(err, Exception):
                    raise err
                raise OllamaError(trim(str(err), 220))
            return box.get("result", {})
        finally:
            end_elapsed = max(0.0, time.time() - start_ts)
            with self.lock:
                self.live_run_notice_elapsed = end_elapsed
                if self.running:
                    self.run_model_active_seconds = max(
                        0.0,
                        float(self.run_model_active_seconds or 0.0) + end_elapsed,
                    )
                self.live_run_notice_active = False
                self.live_run_notice_label = ""
                self.live_run_notice_started_at = 0.0
            self._emit_transient(
                "runtime_progress",
                {"state": "stop", "label": label, "elapsed": round(end_elapsed, 1)},
            )

    def _chat_with_same_model_retry(
        self,
        messages: list[dict],
        *,
        tools: list | None = None,
        system: str = "",
        max_tokens: int | None = None,
        think: bool | None = None,
        stream_thinking: bool = False,
        on_thinking_chunk=None,
        pinned_selection: str = "",
        context_label: str = "agent",
        retries: int = MODEL_OUTPUT_RETRY_TIMES,
        media_inputs: list[dict] | None = None,
    ) -> dict:
        retry_budget = max(0, int(retries or 0))
        pin = str(pinned_selection or self._active_runtime_selection()).strip() or self._active_runtime_selection()
        last_exc: OllamaError | None = None
        wake_attempted = False
        for attempt in range(1, retry_budget + 2):
            try:
                return self._call_interruptible(
                    lambda: self.ollama.chat(
                        messages,
                        tools=tools,
                        system=system,
                        max_tokens=max_tokens,
                        think=False,
                        stream_thinking=bool(stream_thinking),
                        on_thinking_chunk=on_thinking_chunk,
                        media_inputs=media_inputs,
                    ),
                    progress_label=f"{context_label} model call",
                )
            except OllamaError as exc:
                last_exc = exc
                if self.cancel_requested or "interrupted by user" in str(exc).lower():
                    raise
                # Detect media format incompatibility and auto-fallback
                exc_str = str(exc).lower()
                _media_fmt_err = media_inputs and any(
                    kw in exc_str for kw in (
                        "unknown format", "unsupported image", "invalid image",
                        "cannot process image", "image format",
                        "failed to process inputs: image",
                    )
                )
                if _media_fmt_err:
                    media_desc = ", ".join(
                        str(m.get("name", "unknown"))
                        for m in media_inputs
                        if isinstance(m, dict)
                    )
                    self._emit("status", {
                        "summary": f"media format not supported by model ({media_desc}), retrying without media"
                    })
                    fallback_note = {
                        "role": "user",
                        "content": (
                            f"[Note: The following files could not be processed as images "
                            f"by the model: {media_desc}. "
                            f"Please analyze them using text-based tools (bash/read_file) instead.]"
                        ),
                    }
                    try:
                        return self._call_interruptible(
                            lambda: self.ollama.chat(
                                list(messages) + [fallback_note],
                                tools=tools,
                                system=system,
                                max_tokens=max_tokens,
                                think=False,
                                stream_thinking=bool(stream_thinking),
                                on_thinking_chunk=on_thinking_chunk,
                                media_inputs=None,
                            ),
                            progress_label=f"{context_label} model call (no-media fallback)",
                        )
                    except OllamaError:
                        pass  # fallback also failed, continue normal retry
                wake_note = ""
                status = int(getattr(exc, "status", 0) or 0)
                if (
                    not wake_attempted
                    and str(self.ollama.provider or "").lower() == "ollama"
                    and status in {0, 408, 429, 500, 502, 503, 504}
                ):
                    wake_attempted = True
                    model_now = str(self.ollama.model or "").strip()
                    if model_now:
                        woke, wake_err = wake_ollama_model(
                            self.ollama.base_url,
                            model_now,
                            timeout=self._global_wait_timeout_seconds(),
                        )
                        if woke:
                            wake_note = " | wake=ok"
                        elif wake_err:
                            wake_note = f" | wake={trim(wake_err, 96)}"
                if attempt > retry_budget:
                    break
                self._emit(
                    "status",
                    {
                        "summary": (
                            f"{context_label} model call failed on {pin}; "
                            f"retry {attempt}/{retry_budget}: {trim(str(exc), 180)}"
                            f"{wake_note}"
                        )
                    },
                )
                time.sleep(min(1.4, 0.35 * attempt))
        raise last_exc if last_exc is not None else OllamaError("chat failed")

    def _is_allowed_absolute_write_path(self, raw_path: str) -> bool:
        txt = str(raw_path or "").strip().strip("'\"")
        if not txt.startswith("/"):
            return True
        special = {"/dev/null", "/dev/stdout", "/dev/stderr", "/dev/tty"}
        if txt in special:
            return True
        try:
            target = Path(txt).expanduser().resolve()
        except Exception:
            return False
        roots: list[Path] = [self.root.resolve(), self.files_root.resolve()]
        try:
            roots.append(self.skills.skills_root.resolve())
        except Exception:
            pass
        for root in roots:
            try:
                if target == root or target.is_relative_to(root):
                    return True
            except Exception:
                continue
        return False

    def _shell_virtual_prefix_start_boundary(self, ch: str) -> bool:
        if not ch:
            return True
        return not (ch.isalnum() or ch in "._~-/%")

    def _shell_virtual_prefix_end_boundary(self, ch: str) -> bool:
        if not ch:
            return True
        if ch == "/":
            return True
        return not (ch.isalnum() or ch in "._~-")

    def _shell_quote_virtual_root(self, path_text: str, quote_mode: str) -> str:
        txt = str(path_text or "")
        if quote_mode == "double":
            return (
                txt.replace("\\", "\\\\")
                .replace('"', '\\"')
                .replace("$", "\\$")
                .replace("`", "\\`")
            )
        if quote_mode == "single":
            return txt.replace("'", "'\"'\"'")
        return shlex.quote(txt)

    def _rewrite_shell_virtual_paths(self, command: str, cwd: Path) -> str:
        raw = str(command or "")
        if not raw or os.name == "nt":
            return raw
        try:
            workspace_root = str(cwd.resolve())
        except Exception:
            workspace_root = str(cwd)
        try:
            skills_root = str(self.skills.skills_root.resolve())
        except Exception:
            skills_root = str(self.skills.skills_root)
        try:
            js_lib_root = str(self.js_lib_root.resolve())
        except Exception:
            js_lib_root = str(self.js_lib_root)
        mappings = self.skills.shell_virtual_mappings() + [
            ("/workspace", workspace_root),
            (SKILLS_VIRTUAL_PREFIX, skills_root),
            ("/js_lib", js_lib_root),
        ]
        # Auto-quote raw absolute paths that contain spaces (prevents word-splitting)
        if " " in workspace_root and workspace_root not in ("/workspace",):
            mappings.append((workspace_root, workspace_root))
        if " " in skills_root and skills_root != SKILLS_VIRTUAL_PREFIX:
            mappings.append((skills_root, skills_root))
        if " " in js_lib_root and js_lib_root != "/js_lib":
            mappings.append((js_lib_root, js_lib_root))
        out: list[str] = []
        mode = "plain"
        i = 0
        n = len(raw)
        while i < n:
            ch = raw[i]
            if mode in {"plain", "double"} and ch == "\\" and (i + 1) < n:
                out.append(raw[i : i + 2])
                i += 2
                continue
            replaced = False
            if ch == "/":
                prev = raw[i - 1] if i > 0 else ""
                if self._shell_virtual_prefix_start_boundary(prev):
                    for prefix, target in mappings:
                        if not raw.startswith(prefix, i):
                            continue
                        next_idx = i + len(prefix)
                        next_ch = raw[next_idx] if next_idx < n else ""
                        if not self._shell_virtual_prefix_end_boundary(next_ch):
                            continue
                        out.append(self._shell_quote_virtual_root(target, mode))
                        i += len(prefix)
                        replaced = True
                        break
            if replaced:
                continue
            out.append(ch)
            if mode == "plain":
                if ch == "'":
                    mode = "single"
                elif ch == '"':
                    mode = "double"
            elif mode == "double":
                if ch == '"':
                    mode = "plain"
            else:
                if ch == "'":
                    mode = "plain"
            i += 1
        return "".join(out)

    def _shell_write_targets_outside_scope(self, command: str) -> list[str]:
        cmd = str(command or "")
        if not cmd.strip():
            return []
        low = cmd.lower()
        has_write_intent = bool(
            re.search(r"(^|[^<])>>?\s*", cmd)
            or any(
                token in low
                for token in (
                    " mkdir ",
                    " touch ",
                    " rm ",
                    " rmdir ",
                    " mv ",
                    " cp ",
                    " install ",
                    " chmod ",
                    " chown ",
                    " truncate ",
                    " tee ",
                    " sed -i",
                    " perl -i",
                    " dd ",
                )
            )
        )
        if not has_write_intent:
            return []

        targets: list[str] = []
        # Redirection targets.
        for m in re.finditer(
            r"(^|[^<])>>?\s*(?:'(?P<sq>[^']+)'|\"(?P<dq>[^\"]+)\"|(?P<raw>[^\s;&|]+))",
            cmd,
        ):
            p = str(m.group("sq") or m.group("dq") or m.group("raw") or "").strip()
            if p.startswith("/"):
                targets.append(p)

        clauses = [x for x in re.split(r"(?:&&|\|\||;)", cmd) if str(x or "").strip()]
        for clause in clauses:
            try:
                toks = shlex.split(clause, posix=True)
            except Exception:
                toks = []
            if not toks:
                continue
            tool = str(toks[0] or "").strip().lower()
            args = [t for t in toks[1:] if str(t or "").strip() and (not str(t).startswith("-"))]
            if tool in {"mkdir", "touch", "rm", "rmdir", "chmod", "chown", "truncate"}:
                for tok in args:
                    if tok.startswith("/"):
                        targets.append(tok)
            elif tool == "mv":
                for tok in args:
                    if tok.startswith("/"):
                        targets.append(tok)
            elif tool in {"cp", "install", "ln"}:
                if args:
                    dst = args[-1]
                    if dst.startswith("/"):
                        targets.append(dst)
            elif tool == "tee":
                for tok in args:
                    if tok.startswith("/"):
                        targets.append(tok)
            elif tool == "dd":
                for tok in toks[1:]:
                    if str(tok).startswith("of=/"):
                        targets.append(str(tok)[3:])

        blocked: list[str] = []
        seen: set[str] = set()
        for path_text in targets:
            p = str(path_text or "").strip()
            if not p or p in seen:
                continue
            seen.add(p)
            if not self._is_allowed_absolute_write_path(p):
                blocked.append(p)
        return blocked

    def _guard_shell_write_scope(self, command: str, cwd: Path | None = None) -> str:
        effective = self._rewrite_shell_virtual_paths(command, cwd or self.files_root)
        blocked = self._shell_write_targets_outside_scope(effective)
        if not blocked:
            return ""
        preview = ", ".join(blocked[:3])
        suffix = " ..." if len(blocked) > 3 else ""
        return (
            "Error: write blocked for absolute path(s) outside session/skills scope: "
            f"{preview}{suffix}. "
            "Use relative paths in session workspace, or use write_skill for skills."
        )

    def _run_shell_meta(self, command: str, cwd: Path, timeout: int) -> dict:
        effective_command = self._rewrite_shell_virtual_paths(command, cwd)
        meta = {
            "command": command,
            "effective_command": effective_command,
            "cwd": str(cwd),
            "timeout": timeout,
            "exit_code": None,
            "duration_ms": 0,
            "changed_files": [],
            "output": "",
            "error": "",
        }
        if any(x in effective_command for x in DANGEROUS_PATTERNS):
            meta["error"] = "Error: dangerous command blocked"
            meta["output"] = meta["error"]
            return meta
        before = self._git_status_map(cwd)
        start = time.time()
        proc: subprocess.Popen | None = None
        capture_limit = max(200_000, int(MAX_TOOL_OUTPUT) * 4)
        out_buf = bytearray()
        err_buf = bytearray()
        next_progress_emit = start + 0.8

        def _stop_process(p: subprocess.Popen):
            # shell=True may spawn child processes; stop the whole process group on POSIX.
            try:
                if os.name == "posix":
                    try:
                        os.killpg(os.getpgid(p.pid), signal.SIGTERM)
                    except Exception:
                        p.terminate()
                else:
                    p.terminate()
                p.wait(timeout=1.5)
            except Exception:
                try:
                    if os.name == "posix":
                        try:
                            os.killpg(os.getpgid(p.pid), signal.SIGKILL)
                        except Exception:
                            p.kill()
                    else:
                        p.kill()
                except Exception:
                    pass

        def _append_capture(target: bytearray, piece: bytes):
            if not piece:
                return
            target.extend(piece)
            overflow = len(target) - capture_limit
            if overflow > 0:
                del target[:overflow]

        def _merge_output_text() -> str:
            # On Windows, cmd.exe outputs in the system OEM codepage (e.g. cp936/GBK),
            # not UTF-8.  Detect and use the correct encoding for decoding.
            if os.name == "nt":
                try:
                    import locale as _lc
                    enc = _lc.getpreferredencoding(False) or "utf-8"
                except Exception:
                    enc = "utf-8"
            else:
                enc = "utf-8"
            out_text = out_buf.decode(enc, errors="replace")
            err_text = err_buf.decode(enc, errors="replace")
            return (out_text + err_text).strip()

        def _store_shell_output(output_value: str, exit_code: int | None = None):
            text = str(output_value or "").strip()
            if not text:
                text = str(meta.get("error") or "(no output)")
            if exit_code is not None:
                meta["exit_code"] = int(exit_code)
            meta.update(self._prepare_shell_output_payload(command, text, cwd=cwd))

        def _collect_with_reader_threads(proc: subprocess.Popen):
            nonlocal next_progress_emit
            reader_threads: list[threading.Thread] = []
            io_queue: queue.Queue = queue.Queue()
            active_readers: set[str] = set()

            def _spawn_reader(label: str, stream):
                if stream is None:
                    return
                active_readers.add(label)
                # Selector fallback may leave PIPE FDs in non-blocking mode.
                # Reader threads expect blocking reads to avoid early EOF/pipe close.
                try:
                    os.set_blocking(stream.fileno(), True)
                except Exception:
                    pass

                def _reader():
                    try:
                        while True:
                            try:
                                chunk = stream.read(65536)
                            except Exception:
                                break
                            if chunk is None:
                                time.sleep(0.01)
                                continue
                            if not chunk:
                                break
                            io_queue.put((label, chunk))
                    finally:
                        try:
                            stream.close()
                        except Exception:
                            pass
                        io_queue.put((label, None))

                th = threading.Thread(target=_reader, daemon=True)
                th.start()
                reader_threads.append(th)

            _spawn_reader("stdout", proc.stdout)
            _spawn_reader("stderr", proc.stderr)

            while True:
                now = time.time()
                elapsed = now - start
                if (not meta.get("error")) and self.cancel_requested:
                    _stop_process(proc)
                    meta["error"] = "Error: interrupted by user"
                    meta["exit_code"] = -130
                elif (not meta.get("error")) and timeout > 0 and elapsed >= timeout:
                    _stop_process(proc)
                    meta["error"] = f"Error: timeout ({timeout}s)"
                    meta["exit_code"] = -1
                try:
                    label, chunk = io_queue.get(timeout=0.12)
                    if chunk is None:
                        active_readers.discard(str(label))
                    elif str(label) == "stderr":
                        _append_capture(err_buf, chunk)
                    else:
                        _append_capture(out_buf, chunk)
                except queue.Empty:
                    pass
                while True:
                    try:
                        label, chunk = io_queue.get_nowait()
                    except queue.Empty:
                        break
                    if chunk is None:
                        active_readers.discard(str(label))
                    elif str(label) == "stderr":
                        _append_capture(err_buf, chunk)
                    else:
                        _append_capture(out_buf, chunk)
                if now >= next_progress_emit:
                    self._emit_transient(
                        "status",
                        {
                            "summary": (
                                f"bash running ({int(elapsed)}s, "
                                f"captured={len(out_buf) + len(err_buf)}B)"
                            )
                        },
                    )
                    next_progress_emit = now + 0.8
                if (proc.poll() is not None) and (not active_readers) and io_queue.empty():
                    break

            for th in reader_threads:
                try:
                    th.join(timeout=0.8)
                except Exception:
                    pass
            while True:
                try:
                    label, chunk = io_queue.get_nowait()
                except queue.Empty:
                    break
                if chunk is None:
                    continue
                if str(label) == "stderr":
                    _append_capture(err_buf, chunk)
                else:
                    _append_capture(out_buf, chunk)
            merged_raw = _merge_output_text()
            merged, _ = filter_runtime_noise_lines(merged_raw)
            if meta.get("error"):
                _store_shell_output(merged or str(meta["error"]))
            else:
                _store_shell_output(
                    merged or "(no output)",
                    int(proc.returncode if proc.returncode is not None else 0),
                )

        try:
            proc_env = os.environ.copy()
            proc_env["WORKSPACE_ROOT"] = str(self.root)
            proc_env["SESSION_ROOT"] = str(self.files_root)
            proc_env["SESSION_FILES_ROOT"] = str(self.files_root)
            proc_env["SKILLS_ROOT"] = str(self.skills.skills_root)
            proc_env["CLOUDS_CODER_ROOT"] = str(self.root)
            proc_env["JS_LIB_ROOT"] = str(self.js_lib_root)
            popen_kwargs = {
                "shell": True,
                "cwd": cwd,
                "stdout": subprocess.PIPE,
                "stderr": subprocess.PIPE,
                "text": False,
                "bufsize": 0,
                "start_new_session": (os.name == "posix"),
                "env": proc_env,
            }
            if os.name == "nt":
                create_group = int(getattr(subprocess, "CREATE_NEW_PROCESS_GROUP", 0) or 0)
                if create_group > 0:
                    popen_kwargs["creationflags"] = create_group
            proc = subprocess.Popen(effective_command, **popen_kwargs)
            if os.name == "nt":
                # Windows: read PIPE output via blocking reader threads + queue.
                _collect_with_reader_threads(proc)
            else:
                try:
                    with selectors.DefaultSelector() as sel:
                        if proc.stdout is not None:
                            try:
                                os.set_blocking(proc.stdout.fileno(), False)
                            except Exception:
                                pass
                            sel.register(proc.stdout, selectors.EVENT_READ, data="stdout")
                        if proc.stderr is not None:
                            try:
                                os.set_blocking(proc.stderr.fileno(), False)
                            except Exception:
                                pass
                            sel.register(proc.stderr, selectors.EVENT_READ, data="stderr")
                        while True:
                            now = time.time()
                            elapsed = now - start
                            if self.cancel_requested:
                                _stop_process(proc)
                                meta["error"] = "Error: interrupted by user"
                                meta["exit_code"] = -130
                            elif timeout > 0 and elapsed >= timeout:
                                _stop_process(proc)
                                meta["error"] = f"Error: timeout ({timeout}s)"
                                meta["exit_code"] = -1
                            events = sel.select(timeout=0.12)
                            for key, _ in events:
                                stream = key.fileobj
                                try:
                                    chunk = os.read(stream.fileno(), 65536)
                                except BlockingIOError:
                                    continue
                                except Exception:
                                    chunk = b""
                                if not chunk:
                                    try:
                                        sel.unregister(stream)
                                    except Exception:
                                        pass
                                    continue
                                if key.data == "stderr":
                                    _append_capture(err_buf, chunk)
                                else:
                                    _append_capture(out_buf, chunk)
                            if now >= next_progress_emit:
                                self._emit_transient(
                                    "status",
                                    {
                                        "summary": (
                                            f"bash running ({int(elapsed)}s, "
                                            f"captured={len(out_buf) + len(err_buf)}B)"
                                        )
                                    },
                                )
                                next_progress_emit = now + 0.8
                            if (proc.poll() is not None) and (not sel.get_map()):
                                break
                        merged_raw = _merge_output_text()
                        merged, _ = filter_runtime_noise_lines(merged_raw)
                        if meta.get("error"):
                            _store_shell_output(merged or str(meta["error"]))
                        else:
                            _store_shell_output(
                                merged or "(no output)",
                                int(proc.returncode if proc.returncode is not None else 0),
                            )
                except Exception as exc:
                    # Some platforms may reject selector registration for PIPEs.
                    # On Windows, also catch any OSError (e.g. WinError 10093 WSANOTINITIALISED).
                    if is_benign_socket_error(exc) or isinstance(exc, ValueError) or (os.name == "nt" and isinstance(exc, OSError)):
                        _collect_with_reader_threads(proc)
                    else:
                        raise
        except Exception as exc:
            # On Windows, WinError 10038 (WSAENOTSOCK) can surface here when
            # selector-based I/O is used with pipe FDs. Fall back to thread-based reading.
            if proc is not None and is_benign_socket_error(exc):
                _collect_with_reader_threads(proc)
            else:
                meta["error"] = f"Error: {exc}"
                meta["output"] = meta["error"]
                meta["exit_code"] = -1
        meta["duration_ms"] = int((time.time() - start) * 1000)
        after = self._git_status_map(cwd)
        meta["changed_files"] = self._status_delta(before, after) if before or after else []
        if not meta.get("ui_output_pages"):
            meta.update(
                self._prepare_shell_output_payload(
                    command,
                    str(meta.get("output") or meta.get("error") or "(no output)"),
                    cwd=cwd,
                )
            )
        return meta

    def _run_bash(self, command: str) -> str:
        return self._run_shell_meta(command, self.files_root, 120)["output"]

    def _fuzzy_resolve_path(self, fp: Path) -> Path:
        """If fp doesn't exist, try stripping spaces from the filename to find a close match.
        Handles the common model error of hallucinating spaces in Chinese/mixed filenames.
        Returns the resolved Path if found, otherwise the original fp unchanged."""
        if fp.exists():
            return fp
        stripped = fp.name.replace(" ", "")
        if stripped != fp.name:
            candidate = fp.parent / stripped
            if candidate.exists():
                return candidate
        try:
            query = fp.name.replace(" ", "").lower()
            for sibling in fp.parent.iterdir():
                if sibling.name.replace(" ", "").lower() == query:
                    return sibling
        except Exception:
            pass
        return fp

    def _run_read(self, path: str, limit: int | None = None, offset: int | None = None) -> str:
        try:
            rel = self._normalize_tool_path_text(path)
            fp = self._fuzzy_resolve_path(self._session_path(rel))
            rel = str(fp.relative_to(self.files_root)) if fp.is_relative_to(self.files_root) else rel
            # Multimodal: detect image/audio/video files and handle natively
            ext = fp.suffix.lower() if fp.suffix else ""
            if ext in IMAGE_EXTS:
                return self._run_read_media(fp, rel, "image")
            if ext in AUDIO_EXTS:
                return self._run_read_media(fp, rel, "audio")
            if ext in VIDEO_EXTS:
                return self._run_read_media(fp, rel, "video")
            lines = fp.read_text(encoding="utf-8").splitlines()
            total_lines = len(lines)
            if total_lines == 0:
                return ""
            offset_val = max(0, int(offset or 0))
            requested_limit = max(1, int(limit or LONG_OUTPUT_READ_PAGE_LINES))
            if offset_val >= total_lines:
                return (
                    f"[read_file page path={rel} lines=0 of {total_lines} offset={offset_val}]\n"
                    "[end_of_file]"
                )
            full_text = "\n".join(lines)
            auto_paginate = limit is None and offset_val == 0 and len(full_text) > LONG_OUTPUT_READ_PAGE_MAX_CHARS
            if not auto_paginate and limit is None and offset_val == 0 and len(full_text) <= MAX_TOOL_OUTPUT:
                return full_text
            page_parts: list[str] = []
            chars = 0
            idx = offset_val
            while idx < total_lines and len(page_parts) < requested_limit:
                line = lines[idx]
                piece = line if not page_parts else "\n" + line
                if page_parts and (chars + len(piece)) > LONG_OUTPUT_READ_PAGE_MAX_CHARS:
                    break
                if (not page_parts) and len(line) > LONG_OUTPUT_READ_PAGE_MAX_CHARS:
                    page_parts.append(line[:LONG_OUTPUT_READ_PAGE_MAX_CHARS])
                    idx += 1
                    break
                page_parts.append(piece if page_parts else line)
                chars += len(piece)
                idx += 1
            body = "".join(page_parts)
            page_no = (offset_val // requested_limit) + 1
            total_pages = max(1, (total_lines + requested_limit - 1) // requested_limit)
            out = [
                (
                    f"[read_file page path={rel} lines={offset_val + 1}-{idx} of {total_lines} "
                    f"page={page_no}/{total_pages} offset={offset_val} limit={requested_limit}]"
                ),
                body,
            ]
            if idx < total_lines:
                out.append(f"[next_page read_file path=\"{rel}\" offset={idx} limit={requested_limit}]")
            if offset_val > 0:
                prev_offset = max(0, offset_val - requested_limit)
                out.append(f"[prev_page read_file path=\"{rel}\" offset={prev_offset} limit={requested_limit}]")
            return "\n".join(part for part in out if part != "")
        except Exception as exc:
            return f"Error: {type(exc).__name__}: {exc}"

    def _run_read_media(self, fp: Path, rel: str, media_type: str) -> str:
        """Read a media file and return description or inject into multimodal context."""
        if not fp.exists():
            return f"Error: file not found: {rel}"
        caps = self._capabilities_from_profile()
        cap_key = f"input_{media_type}"
        file_size = fp.stat().st_size
        size_kb = file_size / 1024
        if bool(caps.get(cap_key, False)) and file_size < 20 * 1024 * 1024:
            # Model supports this media type — check format compatibility first
            ext = fp.suffix.lower()
            if media_type == "image" and ext == ".svg":
                # SVG: read as text source code instead of injecting as image
                try:
                    svg_text = fp.read_text(encoding="utf-8", errors="replace")
                    return (
                        f"[SVG file: {rel} ({size_kb:.1f} KB)]\n"
                        f"SVG source code (use for analysis, do not send as image):\n"
                        f"```svg\n{trim(svg_text, 12000)}\n```"
                    )
                except Exception as exc:
                    return f"Error reading SVG file: {exc}"
            if media_type == "image" and ext in IMAGE_FORMATS_NEED_CONVERSION:
                # Try converting to a safe format via Pillow
                converted, conv_mime, method = _convert_image_to_safe_format(fp)
                if converted:
                    b64 = base64.b64encode(converted).decode("ascii")
                    mime = conv_mime
                else:
                    return (
                        f"[{media_type} file: {rel} ({size_kb:.1f} KB, format={ext})] "
                        f"Note: format {ext} could not be converted for native vision. "
                        f"File exists at {fp}. Use bash tools to process it if needed."
                    )
            else:
                # Safe format — encode directly
                try:
                    b64 = base64.b64encode(fp.read_bytes()).decode("ascii")
                    mime = guess_mime_from_name(fp.name)
                except Exception as exc:
                    return f"Error reading {media_type} file: {exc}"
            media_item = {
                "type": media_type,
                "data_b64": b64,
                "mime": mime,
                "name": fp.name,
                "workspace_path": str(rel),
            }
            # Store for injection into next API call
            with self.lock:
                self._pending_media_inputs.append(media_item)
            return (
                f"[{media_type} file loaded: {rel} ({size_kb:.1f} KB, {mime})] "
                f"The {media_type} has been attached to the conversation for native {media_type} analysis. "
                f"Describe or analyze it directly."
            )
        else:
            # Model doesn't support this media type — return metadata only
            reason = "model does not support" if not caps.get(cap_key) else "file too large"
            return (
                f"[{media_type} file: {rel} ({size_kb:.1f} KB)] "
                f"Note: {reason} native {media_type} input. "
                f"File exists at {fp}. Use bash tools to process it if needed."
            )

    def _is_html_file_rel(self, path: str) -> bool:
        low = str(path or "").strip().lower()
        return low.endswith(".html") or low.endswith(".htm")

    def _resolve_offline_js_asset_for_url(self, src_url: str) -> tuple[Path | None, str]:
        if not is_external_js_src(src_url):
            return None, "not-external"
        target_url = _normalize_external_js_url(src_url)
        catalog = match_offline_js_catalog_by_url(target_url)
        if catalog:
            filename = _safe_js_filename(
                str(catalog.get("filename", "") or f"{catalog.get('id', 'lib')}.js"),
                "lib.js",
            )
            fp = (self.js_lib_root / filename).resolve()
            if fp.exists() and fp.is_file() and fp.stat().st_size > 40:
                return fp, "catalog"
            try:
                ensure_offline_js_libs(self.js_lib_root.parent, force=False)
            except Exception:
                pass
            if fp.exists() and fp.is_file() and fp.stat().st_size > 40:
                return fp, "catalog-refreshed"
        cached_fp, reason = cache_external_js_url(self.js_lib_root, target_url)
        if cached_fp and cached_fp.exists() and cached_fp.is_file():
            return cached_fp, reason
        return None, reason

    def _localize_html_js_dependencies(self, rel_path: str) -> dict:
        if not self._is_html_file_rel(rel_path):
            return {"applied": False, "summary": ""}
        try:
            html_fp = self._session_path(rel_path)
        except Exception as exc:
            return {"applied": False, "summary": f"offline-js skipped ({exc})"}
        if not html_fp.exists() or (not html_fp.is_file()):
            return {"applied": False, "summary": ""}
        src = try_read_text(html_fp)
        if src is None:
            return {"applied": False, "summary": ""}
        js_dir = (html_fp.parent / "js").resolve()
        rewritten_count = 0
        copied: list[str] = []
        unresolved: list[str] = []
        copied_set: set[str] = set()
        unresolved_set: set[str] = set()

        def _resolve_and_rewrite(url: str) -> str | None:
            nonlocal rewritten_count
            asset, reason = self._resolve_offline_js_asset_for_url(url)
            if not asset:
                key = _normalize_external_js_url(url)
                if key and key not in unresolved_set:
                    unresolved_set.add(key)
                    unresolved.append(f"{key} ({reason})")
                return None
            js_dir.mkdir(parents=True, exist_ok=True)
            dst_name = _safe_js_filename(asset.name, "lib.js")
            dst = (js_dir / dst_name).resolve()
            try:
                if (not dst.exists()) or dst.stat().st_size != asset.stat().st_size:
                    shutil.copy2(asset, dst)
            except Exception as exc:
                key = _normalize_external_js_url(url)
                if key and key not in unresolved_set:
                    unresolved_set.add(key)
                    unresolved.append(f"{key} (copy-failed:{trim(str(exc), 120)})")
                return None
            if dst_name not in copied_set:
                copied_set.add(dst_name)
                copied.append(dst_name)
            rewritten_count += 1
            return f"./js/{dst_name}"

        quoted_re = re.compile(
            r"(?is)(?P<prefix><script\b[^>]*?\bsrc\s*=\s*)(?P<q>['\"])(?P<url>[^\"']+)(?P=q)"
        )
        unquoted_re = re.compile(
            r"(?is)(?P<prefix><script\b[^>]*?\bsrc\s*=\s*)(?P<url>[^\s\"'>]+)"
        )

        def _replace_quoted(m: re.Match) -> str:
            full = m.group(0)
            url = str(m.group("url") or "").strip()
            if not is_external_js_src(url):
                return full
            repl = _resolve_and_rewrite(url)
            if not repl:
                return full
            q = str(m.group("q") or "\"")
            return f"{m.group('prefix')}{q}{repl}{q}"

        def _replace_unquoted(m: re.Match) -> str:
            full = m.group(0)
            url = str(m.group("url") or "").strip()
            if (not url) or (not is_external_js_src(url)):
                return full
            repl = _resolve_and_rewrite(url)
            if not repl:
                return full
            return f"{m.group('prefix')}{repl}"

        after = quoted_re.sub(_replace_quoted, src)
        after = unquoted_re.sub(_replace_unquoted, after)
        if after != src:
            html_fp.write_text(after, encoding="utf-8")
        if rewritten_count <= 0 and not unresolved:
            return {"applied": False, "summary": ""}
        summary = (
            f"offline-js: localized={rewritten_count}, copied={len(copied)}, "
            f"unresolved={len(unresolved)} for {self._session_rel(html_fp)}"
        )
        return {
            "applied": rewritten_count > 0,
            "summary": summary,
            "localized": rewritten_count,
            "copied": copied,
            "unresolved": unresolved,
            "path": self._session_rel(html_fp),
        }

    def _run_write(self, path: str, content: str) -> str:
        try:
            rel = self._normalize_tool_path_text(path)
            fp = self._fuzzy_resolve_path(self._session_path(rel))
            rel = str(fp.relative_to(self.files_root)) if fp.is_relative_to(self.files_root) else rel
            fp.parent.mkdir(parents=True, exist_ok=True)
            fp.write_text(content, encoding="utf-8")
            return f"Wrote {len(content)} bytes to {rel}"
        except Exception as exc:
            return f"Error: {type(exc).__name__}: {exc}"

    def _run_edit(self, path: str, old_text: str, new_text: str) -> str:
        try:
            rel = self._normalize_tool_path_text(path)
            fp = self._fuzzy_resolve_path(self._session_path(rel))
            rel = str(fp.relative_to(self.files_root)) if fp.is_relative_to(self.files_root) else rel
            content = fp.read_text(encoding="utf-8")
            if old_text not in content:
                diag = self._edit_mismatch_diagnostic(content, old_text)
                return f"Error: text not found in {rel}. {diag}"
            fp.write_text(content.replace(old_text, new_text, 1), encoding="utf-8")
            return f"Edited {rel}"
        except Exception as exc:
            return f"Error: {type(exc).__name__}: {exc}"

    def _edit_mismatch_diagnostic(self, content: str, old_text: str) -> str:
        """为 edit_file 匹配失败提供诊断信息"""
        lines = content.splitlines()
        first_line = old_text.strip().splitlines()[0].strip() if old_text.strip() else ""
        if not first_line:
            return "The old_text is empty or whitespace-only."
        # 搜索 old_text 的第一行在文件中的位置
        matches = []
        for i, line in enumerate(lines, 1):
            if first_line in line:
                matches.append(i)
        if matches:
            loc = ", ".join(str(m) for m in matches[:5])
            return (
                f"The first line of old_text was found at line(s) {loc}, "
                f"but the full multi-line match failed. "
                f"Likely cause: whitespace or indentation mismatch. "
                f"Tip: use read_file to get the exact content, then copy it precisely."
            )
        # 尝试空白规范化匹配
        norm_first = " ".join(first_line.split())
        for i, line in enumerate(lines, 1):
            norm_line = " ".join(line.split())
            if norm_first and norm_first in norm_line:
                return (
                    f"A whitespace-normalized partial match was found near line {i}. "
                    f"The old_text likely has wrong indentation or extra/missing spaces. "
                    f"Use read_file to get exact content."
                )
        return (
            f"No match found. The file has {len(lines)} lines. "
            f"The old_text first line '{first_line[:60]}' does not appear in the file. "
            f"The content may have changed since last read. Use read_file to refresh."
        )

    def _write_global_skill(self, args: dict) -> str:
        rel_raw = str(args.get("path", "") or "").strip().replace("\\", "/")
        if not rel_raw:
            return "Error: path is required"
        rel_path = Path(rel_raw)
        if rel_path.name.lower() == "skill.md":
            final_rel = rel_path.parent / "SKILL.md"
        else:
            final_rel = rel_path / "SKILL.md"
        try:
            target = safe_path(final_rel.as_posix(), self.skills.skills_root)
        except Exception as exc:
            return f"Error: invalid skill path: {exc}"
        overwrite = bool(args.get("overwrite", False))
        if target.exists() and not overwrite:
            return (
                f"Error: skill already exists at {target}. "
                "Set overwrite=true to replace it."
            )
        body = str(args.get("content", "") or "").strip()
        if not body:
            return "Error: content is required"
        meta, _ = parse_front_matter(body)
        if not meta.get("name") or not meta.get("description"):
            inferred_name = re.sub(r"[^A-Za-z0-9._-]+", "-", target.parent.name).strip("-") or "custom-skill"
            inferred_desc = "User provided reusable skill."
            if body.startswith("---"):
                # Keep user content unchanged if it already carries front matter.
                pass
            else:
                body = (
                    "---\n"
                    f"name: {inferred_name}\n"
                    f"description: {inferred_desc}\n"
                    "---\n\n"
                    f"{body}\n"
                )
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(body, encoding="utf-8")
        try:
            self._ensure_skills_ready(force=True)
            self.skill_load_cache = {}
        except Exception:
            pass
        try:
            rel_saved = target.resolve().relative_to(self.skills.skills_root.resolve()).as_posix()
        except Exception:
            rel_saved = str(target)
        self._emit(
            "skill_write",
            {
                "path": rel_saved,
                "summary": f"skill written: {rel_saved}",
            },
        )
        return f"OK: wrote skill to {rel_saved}"

    def _scan_global_skills(self) -> str:
        try:
            self._ensure_skills_ready(force=True)
        except Exception:
            pass
        payload = {
            "skills_count": len(self.skills.skills),
            "skill_names": sorted(self.skills.list_names())[:240],
            "providers": self.skills.list_providers(),
            "protocols": self.skills.list_protocols(),
            "warnings": list(self.skills.warnings),
        }
        return json_dumps(payload, indent=2)

    def run_subagent(self, prompt: str, agent_type: str = "Explore") -> str:
        subtools = [
            tool_def("bash", "Run command.", {"command": {"type": "string"}}, ["command"]),
            tool_def(
                "read_file",
                "Read file with optional line pagination.",
                {"path": {"type": "string"}, "limit": {"type": "integer"}, "offset": {"type": "integer"}},
                ["path"],
            ),
        ]
        if agent_type != "Explore":
            subtools.extend(
                [
                    tool_def("write_file", "Write file.", {"path": {"type": "string"}, "content": {"type": "string"}}, ["path", "content"]),
                    tool_def("edit_file", "Edit file.", {"path": {"type": "string"}, "old_text": {"type": "string"}, "new_text": {"type": "string"}}, ["path", "old_text", "new_text"]),
                ]
            )
        msgs = [{"role": "user", "content": prompt}]
        last_text = ""
        pinned_selection = self._active_runtime_selection()
        for _ in range(20):
            try:
                sub_system = f"You are a focused subagent. {model_language_instruction(self.ui_language)}"
                response = self._chat_with_same_model_retry(
                    msgs,
                    tools=subtools,
                    system=sub_system,
                    think=False,
                    pinned_selection=pinned_selection,
                    context_label="subagent",
                    retries=MODEL_OUTPUT_RETRY_TIMES,
                )
            except OllamaError as exc:
                return f"Error: {exc}"
            text = str(response.get("content") or "")
            tcs = response.get("tool_calls", [])
            entry = {"role": "assistant", "content": text}
            if tcs:
                entry["tool_calls"] = [
                    {
                        "id": t["id"],
                        "type": "function",
                        "function": {"name": t["function"]["name"], "arguments": json_dumps(t["function"]["arguments"])},
                    }
                    for t in tcs
                ]
            msgs.append(entry)
            last_text = text or last_text
            if not tcs:
                break
            for tc in tcs:
                name = tc["function"]["name"]
                args = tc["function"]["arguments"]
                args_error = str(tc.get("args_error", "") or "").strip()
                raw_args = tc.get("raw_arguments")
                if args_error:
                    if name in {"TodoWrite", "TodoWriteRescue"}:
                        repaired, repaired_out = self._attempt_malformed_tool_repair(name, raw_args)
                        if repaired:
                            msgs.append({"role": "tool", "tool_call_id": tc["id"], "name": name, "content": trim(repaired_out)})
                            continue
                    out = (
                        f"Error: malformed arguments for tool '{name}'. {args_error}. "
                        "Please regenerate this tool call with complete JSON arguments."
                    )
                    msgs.append({"role": "tool", "tool_call_id": tc["id"], "name": name, "content": trim(out)})
                    continue
                missing = self._missing_required_args(name, args)
                if missing:
                    repaired, repaired_out = self._attempt_malformed_tool_repair(name, args)
                    if repaired:
                        msgs.append({"role": "tool", "tool_call_id": tc["id"], "name": name, "content": trim(repaired_out)})
                        continue
                    out = (
                        f"Error: tool '{name}' missing required arguments: {', '.join(missing)}. "
                        "Likely truncated tool call. Please regenerate complete JSON arguments."
                    )
                    msgs.append({"role": "tool", "tool_call_id": tc["id"], "name": name, "content": trim(out)})
                    continue
                if name == "bash":
                    out = self._run_bash(args.get("command", ""))
                elif name == "read_file":
                    out = self._run_read(args.get("path", ""), args.get("limit"), args.get("offset"))
                elif name == "write_file":
                    out = self._run_write(args.get("path", ""), args.get("content", ""))
                elif name == "edit_file":
                    out = self._run_edit(args.get("path", ""), args.get("old_text", ""), args.get("new_text", ""))
                else:
                    out = f"Unknown tool: {name}"
                msgs.append({"role": "tool", "tool_call_id": tc["id"], "name": name, "content": trim(out)})
        return last_text or "(subagent done)"

    def _spawn_teammate(self, name: str, role: str, prompt: str) -> str:
        member = self.teammates.get(name)
        if member and member.get("status") == "working":
            return f"Error: teammate '{name}' already working"
        self.teammates[name] = {"name": name, "role": role, "status": "working", "updated_at": now_ts()}

        def worker():
            try:
                result = self.run_subagent(f"Teammate={name}, role={role}\n{prompt}", agent_type="general-purpose")
                self.bus.send(name, "lead", f"[{name}] {result}", "message")
                status = "idle"
            except Exception as exc:
                self.bus.send(name, "lead", f"[{name}] failed: {exc}", "message")
                status = "error"
            with self.lock:
                if name in self.teammates:
                    self.teammates[name]["status"] = status
                    self.teammates[name]["updated_at"] = now_ts()
                self._emit("teammate", {"summary": f"{name} -> {status}"})
                self._persist()

        threading.Thread(target=worker, daemon=True).start()
        return f"Spawned teammate '{name}' ({role})"

    def _list_teammates(self) -> str:
        if not self.teammates:
            return "No teammates."
        lines = []
        for m in self.teammates.values():
            lines.append(f"{m['name']} ({m['role']}): {m['status']}")
        return "\n".join(lines)

    def _handle_shutdown_request(self, teammate: str) -> str:
        req_id = make_id("shutdown")
        self.shutdown_requests[req_id] = {"target": teammate, "status": "pending"}
        self.bus.send("lead", teammate, "Please shut down.", "shutdown_request", {"request_id": req_id})
        if teammate in self.teammates:
            self.teammates[teammate]["status"] = "shutdown"
        return f"Shutdown request {req_id} sent to '{teammate}'"

    def _handle_plan_approval(self, request_id: str, approve: bool, feedback: str = "") -> str:
        req = self.plan_requests.get(request_id)
        if not req:
            return f"Error: unknown plan request_id '{request_id}'"
        req["status"] = "approved" if approve else "rejected"
        self.bus.send("lead", req["from"], feedback, "plan_approval_response", {"request_id": request_id, "approve": approve, "feedback": feedback})
        return f"Plan {req['status']} for '{req['from']}'"

    def _is_html_frontend_goal(self, text: str) -> bool:
        probe = str(text or "").strip().lower()
        if not probe:
            return False
        for key in HTML_FRONTEND_REQUEST_KEYWORDS:
            k = str(key or "").strip().lower()
            if k and k in probe:
                return True
        return False

    def _html_frontend_boost_instruction(self) -> str:
        goal = self._latest_user_goal_text()
        if not self._is_html_frontend_goal(goal):
            return ""
        index = load_offline_js_lib_index(self.js_lib_root)
        available_rows = [
            str(item.get("id", "")).strip()
            for item in (index.get("libs", []) if isinstance(index, dict) else [])
            if isinstance(item, dict) and bool(item.get("available", False))
        ]
        libs_hint = ", ".join([x for x in available_rows if x][:10]) if available_rows else "none"
        return (
            "Current task is likely frontend/html/report oriented. "
            "Load specialized skills when needed: "
            "load_skill('html-report-engineering'), "
            "load_skill('frontend-composition-algorithm'), "
            "load_skill('visualization-report-pipeline'), "
            "load_skill('offline-html-js-bundling'). "
            "Use this build algorithm: "
            "1) define audience + acceptance criteria; "
            "2) draft information architecture; "
            "3) scaffold semantic HTML; "
            "4) apply CSS tokens + responsive layout; "
            "5) wire JS state/data interactions; "
            "6) localize external JS dependencies to ./js from ./js_lib; "
            "7) run QA loop for desktop/mobile/a11y/performance and iterate. "
            f"Offline JS libs available now: {libs_hint}. "
            "Final exported HTML should avoid unresolved CDN-only script src."
        )

    def _contains_any_keyword(self, text: str, keywords: tuple[str, ...]) -> bool:
        probe = str(text or "").strip().lower()
        if not probe:
            return False
        for row in keywords:
            key = str(row or "").strip().lower()
            if key and key in probe:
                return True
        return False

    def _is_deep_research_goal(self, text: str) -> bool:
        return self._contains_any_keyword(text, DEEP_RESEARCH_REQUEST_KEYWORDS)

    def _http_probe_ok(self, url: str, timeout: float = 4.0) -> bool:
        target = str(url or "").strip()
        if not target:
            return False
        try:
            req = Request(target, headers={"User-Agent": "Mozilla/5.0"})
            with urlopen(req, timeout=timeout) as resp:
                status = int(getattr(resp, "status", 0) or 0)
                if 200 <= status < 400:
                    return True
        except Exception:
            return False
        return False

    def _probe_live_search_runtime(self, force: bool = False) -> dict[str, object]:
        now_tick = float(now_ts())
        cached = self.research_probe_cache if isinstance(self.research_probe_cache, dict) else {}
        checked_at = float(cached.get("checked_at", 0.0) or 0.0)
        if (not force) and checked_at > 0 and (now_tick - checked_at) < 180:
            return {
                "checked_at": checked_at,
                "online_ok": bool(cached.get("online_ok", False)),
                "search_ok": bool(cached.get("search_ok", False)),
                "mode": str(cached.get("mode", "simulated") or "simulated"),
                "reason": str(cached.get("reason", "") or ""),
            }
        online_ok = False
        search_ok = False
        reason = "offline"
        try:
            online_ok = self._http_probe_ok("https://example.com", timeout=4.0) or self._http_probe_ok(
                "https://www.wikipedia.org", timeout=4.0
            )
            if online_ok:
                search_ok = self._http_probe_ok("https://duckduckgo.com/?q=research", timeout=5.0)
                if search_ok:
                    reason = "search-ready"
                else:
                    reason = "internet-ok-search-check-failed"
            else:
                search_ok = False
                reason = "network-unreachable"
        except Exception as exc:
            online_ok = False
            search_ok = False
            reason = f"probe-error:{trim(str(exc), 120)}"
        mode = "online" if search_ok else "simulated"
        payload = {
            "checked_at": now_tick,
            "online_ok": bool(online_ok),
            "search_ok": bool(search_ok),
            "mode": mode,
            "reason": reason,
        }
        self.research_probe_cache = dict(payload)
        return payload

    def _detect_deep_research_mode(self, text: str) -> str:
        goal = str(text or "").strip()
        if not self._is_deep_research_goal(goal):
            return ""
        force_text_only = self._contains_any_keyword(goal, DEEP_RESEARCH_TEXT_ONLY_HINT_KEYWORDS)
        retrieval_requested = self._contains_any_keyword(goal, DEEP_RESEARCH_RETRIEVAL_KEYWORDS)
        if force_text_only and (not retrieval_requested):
            return "text_deep_analysis"
        if retrieval_requested:
            probe = self._probe_live_search_runtime(force=False)
            return "retrieval_integrated_online" if bool(probe.get("search_ok", False)) else "retrieval_integrated_simulated"
        return "text_deep_analysis"

    def _deep_research_boost_instruction(self) -> str:
        goal = self._latest_user_goal_text()
        mode = self._detect_deep_research_mode(goal)
        if not mode:
            return ""
        probe = self._probe_live_search_runtime(force=False)
        if mode == "text_deep_analysis":
            mode_hint = "Mode=text_deep_analysis (independent text deep analysis)."
        elif mode == "retrieval_integrated_online":
            mode_hint = "Mode=retrieval_integrated_online (internet retrieval synthesis)."
        else:
            mode_hint = (
                "Mode=retrieval_integrated_simulated (internet/search unavailable; use model-knowledge simulated retrieval cards)."
            )
        return (
            "Current task is deep-research oriented. "
            "Load specialized skills when needed: "
            "load_skill('deep-research-orchestrator'), "
            "load_skill('retrieval-synthesis-fallback'), "
            "load_skill('pdf-vision-literature-integrator'). "
            f"{mode_hint} "
            f"Search runtime probe: online_ok={bool(probe.get('online_ok', False))}, "
            f"search_ok={bool(probe.get('search_ok', False))}, reason={probe.get('reason', '')}. "
            "If analyzing PDF literature and image capability is available, integrate extracted PDF figures with textual evidence. "
            "If model image-input capability is false, skip figure extraction and stay in text-only evidence mode. "
            "Final output must be a structured markdown deep-analysis report."
        )

    def _latest_user_goal_text(self) -> str:
        for msg in reversed(self.messages):
            if msg.get("role") != "user":
                continue
            text = str(msg.get("content", "")).strip()
            if not text:
                continue
            if text.startswith("<"):
                continue
            return trim(text.replace("\n", " "), 220)
        return "current task"

    def _compose_default_direct_objective(self, base_objective: str, goal: str, task_type: str) -> str:
        base = trim(str(base_objective or "").strip(), 520)
        goal_clean = trim(strip_thinking_content(str(goal or "")).replace("\n", " ").strip(), 220)
        path_hits = re.findall(
            r"(?:[A-Za-z0-9_.-]+/)*[A-Za-z0-9_.-]+\.(?:py|js|ts|tsx|jsx|java|go|rs|md|json|yaml|yml|toml|ini|sh|html|css|c|cpp|h)",
            goal_clean,
        )
        uniq_paths: list[str] = []
        for item in path_hits:
            one = trim(str(item or "").strip(), 80)
            if one and one not in uniq_paths:
                uniq_paths.append(one)
            if len(uniq_paths) >= 3:
                break
        if uniq_paths:
            anchor = f" Project anchors: {', '.join(uniq_paths)}."
        elif goal_clean:
            anchor = f" Project anchor: {goal_clean}."
        else:
            anchor = " Project anchor: current repository context."
        if task_type == "simple_qa":
            postfix = " Keep orchestration lightweight and answer directly with project-aware specifics."
        else:
            postfix = (
                " Keep orchestration lightweight and execution-first. "
                "Use bounded creativity for ambiguous details while preserving existing architecture and constraints."
            )
        return trim(f"{base}{anchor}{postfix}", 800)

    def _normalize_task_profile(self, goal: str, raw: object) -> dict:
        base = self._infer_task_profile(goal)
        src = raw if isinstance(raw, dict) else {}
        task_type = trim(
            str(src.get("task_type", base.get("task_type", "general")) or "").strip().lower(),
            40,
        ) or str(base.get("task_type", "general"))
        if task_type not in TASK_PROFILE_TYPES:
            task_type = str(base.get("task_type", "general"))
        complexity = str(src.get("complexity", base.get("complexity", "simple")) or "").strip().lower()
        if complexity not in TASK_COMPLEXITY_LEVELS:
            complexity = str(base.get("complexity", "simple"))
        src_direct_objective = trim(str(src.get("direct_objective", "") or "").strip(), 800)
        legacy_objectives = {
            "Provide the most direct useful response with minimal orchestration.",
            (
                "Provide the most direct useful response with minimal orchestration, "
                "anchored to the current project context and user goal."
            ),
        }
        if src_direct_objective and src_direct_objective not in legacy_objectives:
            direct_objective = src_direct_objective
        else:
            direct_objective = self._compose_default_direct_objective(
                str(base.get("direct_objective", "")),
                goal,
                task_type,
            )
        rec_raw = src.get("recommended_agents", base.get("recommended_agents", []))
        recommended: list[str] = []
        if isinstance(rec_raw, list):
            for item in rec_raw:
                role = self._sanitize_agent_role(item)
                if role and role not in recommended:
                    recommended.append(role)
        if not recommended:
            recommended = list(base.get("recommended_agents", []))
        max_budget = max(1, int(getattr(self, "max_agent_rounds", MAX_AGENT_ROUNDS) or MAX_AGENT_ROUNDS))
        if int(getattr(self, 'user_task_level_override', 0) or 0) > 0:
            raw_level = int(self.user_task_level_override)
        else:
            try:
                raw_level = int(src.get("task_level", 0) or 0)
            except Exception:
                raw_level = 0
            if raw_level not in TASK_LEVEL_CHOICES:
                if task_type == "simple_qa":
                    raw_level = 1 if len(str(goal or "")) <= 180 else 2
                elif task_type in {"simple_code", "research"} and complexity == "simple":
                    raw_level = 3
                elif complexity == "complex":
                    raw_level = 4
                else:
                    raw_level = 2
        task_level = int(raw_level)
        level_policy = TASK_LEVEL_POLICIES.get(task_level, TASK_LEVEL_POLICIES[3])
        execution_mode = normalize_execution_mode(
            src.get("execution_mode", level_policy.get("execution_mode", EXECUTION_MODE_SYNC)),
            default=str(level_policy.get("execution_mode", EXECUTION_MODE_SYNC)),
        )
        assigned_expert = self._sanitize_agent_role(
            src.get("assigned_expert", level_policy.get("assigned_expert", "developer"))
        ) or self._sanitize_agent_role(level_policy.get("assigned_expert", "developer")) or "developer"
        raw_participants = src.get("participants", src.get("recommended_agents", recommended))
        participants: list[str] = []
        if isinstance(raw_participants, list):
            for item in raw_participants:
                role = self._sanitize_agent_role(item)
                if role and role not in participants:
                    participants.append(role)
        if not participants:
            fallback_roles = level_policy.get("participants", recommended)
            if isinstance(fallback_roles, list):
                for item in fallback_roles:
                    role = self._sanitize_agent_role(item)
                    if role and role not in participants:
                        participants.append(role)
        if execution_mode == EXECUTION_MODE_SINGLE:
            participants = [assigned_expert]
        else:
            min_count = 2 if task_level == 3 else 3 if task_level in {4, 5} else 1
            for role in AGENT_ROLES:
                if len(participants) >= min_count:
                    break
                if role not in participants:
                    participants.append(role)
            if assigned_expert not in participants:
                assigned_expert = participants[0] if participants else assigned_expert
        participants = participants[:3] or [assigned_expert]
        if task_level == 5:
            round_budget = 0
        else:
            try:
                budget_raw = int(src.get("round_budget", level_policy.get("round_budget", base.get("round_budget", max_budget))) or 0)
            except Exception:
                budget_raw = int(level_policy.get("round_budget", base.get("round_budget", max_budget)) or max_budget)
            round_budget = max(1, min(max_budget, budget_raw))
        requires_user_confirmation = bool(
            src.get(
                "requires_user_confirmation",
                level_policy.get("requires_user_confirmation", False),
            )
        )
        if task_level != 5:
            requires_user_confirmation = False
        scale_preference = str(src.get("scale_preference", "balanced") or "").strip().lower()
        if scale_preference not in TASK_SCALE_PREFERENCES:
            scale_preference = "balanced"
        reason = trim(str(src.get("reason", base.get("reason", "")) or "").strip(), 400)
        try:
            goal_chars = max(0, int(src.get("goal_chars", base.get("goal_chars", len(str(goal or "")))) or 0))
        except Exception:
            goal_chars = max(0, int(base.get("goal_chars", len(str(goal or ""))) or 0))
        try:
            updated_at = float(src.get("updated_at", base.get("updated_at", now_ts())) or now_ts())
        except Exception:
            updated_at = float(now_ts())
        return {
            "task_type": task_type,
            "complexity": complexity,
            "direct_objective": direct_objective,
            "recommended_agents": list(participants),
            "task_level": int(task_level),
            "execution_mode": execution_mode,
            "participants": list(participants),
            "assigned_expert": assigned_expert,
            "requires_user_confirmation": bool(requires_user_confirmation),
            "scale_preference": scale_preference,
            "round_budget": int(round_budget),
            "reason": reason or trim(str(base.get("reason", "")), 400),
            "goal_chars": int(goal_chars),
            "updated_at": float(updated_at),
        }

    def _ensure_blackboard_task_profile(self, board: dict | None = None, *, force: bool = False) -> dict:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        goal = str(bb.get("original_goal", "") or "")
        current = bb.get("task_profile", {})
        profile = self._normalize_task_profile(goal, {} if force else current)
        if profile.get("complexity") == "simple":
            logs = bb.get("execution_logs", []) if isinstance(bb.get("execution_logs"), list) else []
            tail = "\n".join(
                str((row or {}).get("content", "") or "")
                for row in logs[-3:]
                if isinstance(row, dict)
            ).lower()
            if any(tok in tail for tok in ("error", "failed", "traceback", "exception", "blocked", "not found")):
                bumped = max(int(profile.get("round_budget", 1) or 1) + 3, 8)
                profile["complexity"] = "complex"
                profile["round_budget"] = max(
                    1,
                    min(
                        int(getattr(self, "max_agent_rounds", MAX_AGENT_ROUNDS) or MAX_AGENT_ROUNDS),
                        int(bumped),
                    ),
                )
                profile["reason"] = "auto-escalated: runtime errors detected"
                profile["recommended_agents"] = ["explorer", "developer", "reviewer"]
        bb["task_profile"] = profile
        self.blackboard = bb
        return profile

    def _manager_feedback_passed_from_blackboard(self, board: dict | None = None) -> bool:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        gate_ok, _ = self._reviewer_approval_log_gate(bb)
        if not gate_ok:
            return False
        feedback = bb.get("review_feedback", []) if isinstance(bb.get("review_feedback"), list) else []
        if not feedback:
            return False
        txt = str((feedback[-1] or {}).get("content", "") if isinstance(feedback[-1], dict) else "").lower()
        return any(
            token in txt
            for token in (
                "approved",
                "review passed",
                "tests passed",
                "no issues found",
                "验证通过",
                "审核通过",
                "已通过",
            )
        )

    def _manager_has_error_log(self, board: dict | None = None) -> bool:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        logs = bb.get("execution_logs", []) if isinstance(bb.get("execution_logs"), list) else []
        if not logs:
            return False
        tail = "\n".join(
            str((row or {}).get("content", "") or "")
            for row in logs[-3:]
            if isinstance(row, dict)
        ).lower()
        return any(tok in tail for tok in ("error", "failed", "traceback", "exception", "not found", "blocked"))

    def _approval_is_stale_for_latest_user(
        self,
        board: dict | None = None,
        *,
        latest_user_ts: float | None = None,
    ) -> bool:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        approval = bb.get("approval", {}) if isinstance(bb.get("approval"), dict) else {}
        if not bool(approval.get("approved", False)):
            return False
        try:
            approval_ts = float(approval.get("ts", 0.0) or 0.0)
        except Exception:
            approval_ts = 0.0
        if latest_user_ts is None:
            latest_user_ts = self._latest_user_message_ts()
        try:
            user_ts = float(latest_user_ts or 0.0)
        except Exception:
            user_ts = 0.0
        if user_ts <= 0.0:
            return False
        if approval_ts <= 0.0:
            return True
        return bool(user_ts > approval_ts + 1e-6)

    def _can_auto_finish_from_approval(
        self,
        board: dict | None = None,
        *,
        latest_user_ts: float | None = None,
    ) -> tuple[bool, str]:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        if bool(self.runtime_goal_reset_pending):
            return False, "goal-reset-pending"
        # Plan step gate: if plan_step todos exist, ALL must be completed
        plan_step_todos = [
            t for t in bb.get("project_todos", [])
            if t.get("category") == "plan_step"
        ]
        if plan_step_todos:
            pending = [t for t in plan_step_todos if t.get("status") != "completed"]
            if pending:
                return False, f"plan-steps-incomplete:{len(pending)}/{len(plan_step_todos)}"
        # Project todo gate: coding tasks must pass compile + test
        profile = self._ensure_blackboard_task_profile(bb)
        task_type = str(profile.get("task_type", "general") or "general")
        if task_type in ("simple_code", "engineering"):
            for todo in bb.get("project_todos", []):
                if todo.get("category") in ("compile_test", "min_test") and todo.get("status") != "completed":
                    return False, f"project-todo-incomplete:{todo.get('category', '')}"
        return True, "ok"

    def _invalidate_stale_approval_if_needed(
        self,
        board: dict | None = None,
        *,
        latest_user_ts: float | None = None,
        emit_status: bool = True,
    ) -> bool:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        if not self._approval_is_stale_for_latest_user(bb, latest_user_ts=latest_user_ts):
            return False
        prev = bb.get("approval", {}) if isinstance(bb.get("approval"), dict) else {}
        bb["approval"] = {"approved": False, "by": "", "note": "", "ts": 0.0}
        if self._normalize_blackboard_status(bb.get("status", "INITIALIZING")) == "COMPLETED":
            bb["status"] = "PAUSED"
        self.blackboard = bb
        self._blackboard_history(
            "manager",
            (
                "stale approval cleared after newer user input; "
                f"previous approver={trim(str(prev.get('by', '') or ''), 40) or '-'}"
            ),
        )
        self._sync_todos_from_blackboard(reason="approval-stale-cleared", board=bb)
        if emit_status:
            self._emit(
                "status",
                {
                    "summary": (
                        "stale approval invalidated by newer user instruction; "
                        "manager will continue execution"
                    )
                },
            )
        return True

    def _latest_agent_assistant_text(self, role: str) -> str:
        role_key = self._sanitize_agent_role(role)
        if not role_key:
            return ""
        for row in reversed(self._agent_context(role_key)):
            if str(row.get("role", "") or "") != "assistant":
                continue
            txt = strip_thinking_content(str(row.get("content", "") or "")).strip()
            if txt:
                return txt
        return ""

    def _manager_progress_state(self, board: dict | None = None) -> str:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        # Hard guard: pending plan steps → never "done"
        plan_step_todos = [
            t for t in bb.get("project_todos", [])
            if t.get("category") == "plan_step"
        ]
        has_pending_plan_steps = plan_step_todos and any(
            t.get("status") != "completed" for t in plan_step_todos
        )
        can_finish, _ = self._can_auto_finish_from_approval(bb)
        if can_finish and not has_pending_plan_steps:
            return "done"
        profile = self._ensure_blackboard_task_profile(bb)
        task_type = str(profile.get("task_type", "") or "")
        if task_type == "simple_qa":
            dev_text = self._latest_agent_assistant_text("developer")
            if dev_text:
                endpoint = self._detect_endpoint_intent(dev_text, None)
                if bool(endpoint.get("matched", False)):
                    return "almost_done"
                return "in_progress"
            return "initializing"
        if self._manager_has_error_log(bb):
            return "blocked"
        research_count = len(bb.get("research_notes", []) or [])
        code_count = len(bb.get("code_artifacts", {}) or [])
        feedback_count = len(bb.get("review_feedback", []) or [])
        if code_count > 0 and (self._manager_feedback_passed_from_blackboard(bb) or feedback_count > 0):
            return "almost_done"
        if code_count > 0 or research_count > 0:
            return "in_progress"
        return "initializing"

    def _blackboard_round_budget(self, board: dict | None = None) -> int:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        profile = self._ensure_blackboard_task_profile(bb)
        max_budget = max(1, int(getattr(self, "max_agent_rounds", MAX_AGENT_ROUNDS) or MAX_AGENT_ROUNDS))
        try:
            budget = int(profile.get("round_budget", max_budget) or 0)
        except Exception:
            budget = max_budget
        if budget <= 0:
            return 0
        return max(1, min(max_budget, budget))

    def _normalize_blackboard_status(self, raw: object) -> str:
        key = str(raw or "").strip().upper()
        return key if key in BLACKBOARD_STATUSES else "INITIALIZING"

    def _new_watchdog_state(self) -> dict:
        return {
            "intent_no_tool_streak": 0,
            "repeat_no_tool_streak": 0,
            "state_unchanged_streak": 0,
            "last_no_tool_text": "",
            "last_no_tool_hash": "",
            "last_state_fp": "",
            "trigger_count": 0,
            "last_trigger_reason": "",
            "last_trigger_ts": 0.0,
        }

    def _normalize_watchdog_state(self, raw: object) -> dict:
        src = raw if isinstance(raw, dict) else {}
        out = self._new_watchdog_state()
        out["intent_no_tool_streak"] = max(0, int(src.get("intent_no_tool_streak", 0) or 0))
        out["repeat_no_tool_streak"] = max(0, int(src.get("repeat_no_tool_streak", 0) or 0))
        out["state_unchanged_streak"] = max(0, int(src.get("state_unchanged_streak", 0) or 0))
        out["last_no_tool_text"] = trim(str(src.get("last_no_tool_text", "") or "").strip(), 1200)
        out["last_no_tool_hash"] = trim(str(src.get("last_no_tool_hash", "") or "").strip(), 80)
        out["last_state_fp"] = trim(str(src.get("last_state_fp", "") or "").strip(), 120)
        out["trigger_count"] = max(0, int(src.get("trigger_count", 0) or 0))
        out["last_trigger_reason"] = trim(str(src.get("last_trigger_reason", "") or "").strip(), 200)
        out["last_trigger_ts"] = float(src.get("last_trigger_ts", 0.0) or 0.0)
        return out

    def _new_decomposition_queue_state(self) -> dict:
        return {
            "active": False,
            "trigger_reason": "",
            "created_at": 0.0,
            "cursor": 0,
            "steps": [],
            "last_error": "",
            "snapshot": "",
            "decomposer_output": "",
        }

    def _watchdog_normalize_steps(self, rows: object) -> list[dict]:
        if not isinstance(rows, list):
            return []
        out: list[dict] = []

        def _infer_target(action_type: str, instruction: str, fallback: str = "developer") -> str:
            raw = self._sanitize_agent_role(fallback) or "developer"
            low = f"{action_type} {instruction}".lower()
            if any(tok in low for tok in ("review", "verify", "validate", "test", "qa", "检查", "验证", "评审", "審查")):
                return "reviewer"
            if any(tok in low for tok in ("research", "inspect", "analy", "explore", "investigate", "分析", "调研", "調研", "探索")):
                return "explorer"
            return raw

        for idx, row in enumerate(rows[:WATCHDOG_MAX_DECOMPOSE_STEPS]):
            if not isinstance(row, dict):
                continue
            instruction = trim(
                str(
                    row.get("description", "")
                    or row.get("instruction", "")
                    or row.get("content", "")
                    or row.get("task", "")
                    or ""
                ).strip(),
                900,
            )
            if not instruction:
                continue
            action_type = trim(str(row.get("action_type", "") or "").strip(), 80)
            target = self._sanitize_agent_role(
                row.get("target", row.get("owner", row.get("role", row.get("agent", ""))))
            )
            target = target or _infer_target(action_type, instruction)
            if target == "developer" and "incremental" not in instruction.lower():
                instruction = trim(
                    (
                        f"{instruction}\n"
                        "Use incremental edits (append/targeted replace) instead of full-file overwrite unless unavoidable."
                    ),
                    1000,
                )
            try:
                step_no = int(row.get("step", idx + 1) or (idx + 1))
            except Exception:
                step_no = idx + 1
            out.append(
                {
                    "step": max(1, step_no),
                    "target": target,
                    "action_type": action_type or "execute",
                    "instruction": instruction,
                    "attempts": max(0, int(row.get("attempts", 0) or 0)),
                    "status": trim(str(row.get("status", "pending") or "pending").strip().lower(), 20) or "pending",
                    "updated_at": float(now_ts()),
                }
            )
        if not out:
            return []
        return out[:WATCHDOG_MAX_DECOMPOSE_STEPS]

    def _normalize_decomposition_queue_state(self, raw: object) -> dict:
        src = raw if isinstance(raw, dict) else {}
        out = self._new_decomposition_queue_state()
        out["active"] = bool(src.get("active", False))
        out["trigger_reason"] = trim(str(src.get("trigger_reason", "") or "").strip(), 200)
        out["created_at"] = float(src.get("created_at", 0.0) or 0.0)
        out["cursor"] = max(0, int(src.get("cursor", 0) or 0))
        out["last_error"] = trim(str(src.get("last_error", "") or "").strip(), 400)
        out["snapshot"] = trim(str(src.get("snapshot", "") or "").strip(), 4000)
        out["decomposer_output"] = trim(str(src.get("decomposer_output", "") or "").strip(), 2000)
        out["steps"] = self._watchdog_normalize_steps(src.get("steps", []))
        if out["cursor"] >= len(out["steps"]):
            out["active"] = False
        return out

    def _watchdog_state_fingerprint(self, board: dict | None = None) -> str:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        profile = self._ensure_blackboard_task_profile(bb)
        payload = {
            "status": self._normalize_blackboard_status(bb.get("status", "INITIALIZING")),
            "goal": trim(str(bb.get("original_goal", "") or "").strip(), 400),
            "active_agent": self._sanitize_agent_role(bb.get("active_agent", "")),
            "delegate": self._sanitize_agent_role((bb.get("last_delegate", {}) or {}).get("target", "")),
            "research_count": len(bb.get("research_notes", []) or []),
            "artifact_count": len(bb.get("code_artifacts", {}) or {}),
            "exec_count": len(bb.get("execution_logs", []) or []),
            "review_count": len(bb.get("review_feedback", []) or []),
            "approved": bool((bb.get("approval", {}) or {}).get("approved", False)),
            "task_type": str(profile.get("task_type", "general") or "general"),
            "complexity": str(profile.get("complexity", "simple") or "simple"),
        }
        raw = json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
        return hashlib.sha1(raw.encode("utf-8")).hexdigest()

    def _watchdog_extract_json_array(self, text: str) -> list[dict]:
        raw = str(text or "").strip()
        if not raw:
            return []
        probe_candidates: list[str] = [raw]
        fence = re.findall(r"```(?:json)?\s*([\s\S]*?)```", raw, flags=re.IGNORECASE)
        probe_candidates.extend([str(x or "").strip() for x in fence if str(x or "").strip()])
        first = raw.find("[")
        last = raw.rfind("]")
        if first >= 0 and last > first:
            probe_candidates.append(raw[first : last + 1].strip())
        for candidate in probe_candidates:
            try:
                parsed = json.loads(candidate)
            except Exception:
                continue
            if isinstance(parsed, list):
                return [dict(x) for x in parsed if isinstance(x, dict)]
        return []

    def _watchdog_intent_without_action(self, text: str) -> bool:
        clean = strip_thinking_content(str(text or "")).strip()
        if not clean:
            return False
        low = clean.lower()
        intent_markers = (
            "i will",
            "i'm going to",
            "next step",
            "plan to",
            "let me",
            "我将",
            "我會",
            "我会",
            "下一步",
            "接下来",
            "接下來",
            "计划",
            "計劃",
            "准备",
            "準備",
        )
        action_markers = (
            "wrote",
            "edited",
            "executed",
            "called",
            "ran ",
            "已完成",
            "已执行",
            "已執行",
            "已调用",
            "已調用",
            "完成了",
            "执行了",
            "執行了",
            "调用了",
            "調用了",
        )
        if any(tok in low for tok in action_markers):
            return False
        return any(tok in low for tok in intent_markers)

    def _watchdog_similarity(self, a: str, b: str) -> float:
        left = trim(strip_thinking_content(str(a or "")).strip(), 1800)
        right = trim(strip_thinking_content(str(b or "")).strip(), 1800)
        if (not left) or (not right):
            return 0.0
        return float(difflib.SequenceMatcher(None, left, right).ratio())

    def _watchdog_context_near_limit(self) -> bool:
        limit = max(1, int(self.context_token_upper_bound or TOKEN_THRESHOLD))
        try:
            used = int(self._estimate_tokens())
        except Exception:
            used = 0
        return bool(used >= int(limit * WATCHDOG_CONTEXT_NEAR_RATIO))

    def _watchdog_snapshot_payload(self, board: dict, reason: str, role: str, step: dict | None = None) -> str:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        profile = self._ensure_blackboard_task_profile(bb)
        code_rows = sorted(
            list((bb.get("code_artifacts", {}) or {}).items()),
            key=lambda item: float((item[1] or {}).get("updated_at", 0.0) if isinstance(item[1], dict) else 0.0),
            reverse=True,
        )
        payload = {
            "objective": trim(str(bb.get("original_goal", "") or "").strip(), 1800),
            "trigger_reason": trim(str(reason or "").strip(), 200),
            "active_role": self._sanitize_agent_role(role),
            "status": self._normalize_blackboard_status(bb.get("status", "INITIALIZING")),
            "task_profile": {
                "task_type": str(profile.get("task_type", "general") or "general"),
                "complexity": str(profile.get("complexity", "simple") or "simple"),
                "direct_objective": trim(str(profile.get("direct_objective", "") or "").strip(), 600),
            },
            "latest_worker_step": {
                "status": str((step or {}).get("status", "") or ""),
                "text": trim(str((step or {}).get("text", "") or "").strip(), 600),
            },
            "code_artifacts": [
                {
                    "path": str(path),
                    "summary": trim(str((item or {}).get("summary", "") or "").strip(), 200),
                }
                for path, item in code_rows[:6]
            ],
            "recent_execution_logs": [
                trim(str((row or {}).get("content", "") or "").strip(), 220)
                for row in (bb.get("execution_logs", []) or [])[-4:]
                if isinstance(row, dict)
            ],
            "recent_review_feedback": [
                trim(str((row or {}).get("content", "") or "").strip(), 220)
                for row in (bb.get("review_feedback", []) or [])[-4:]
                if isinstance(row, dict)
            ],
        }
        return trim(json_dumps(payload, indent=2), 6000)

    def _watchdog_fallback_steps(self, board: dict, reason: str) -> list[dict]:
        profile = self._ensure_blackboard_task_profile(board)
        objective = trim(str(profile.get("direct_objective", "") or "").strip(), 280) or trim(
            str(board.get("original_goal", "") or "").strip(),
            280,
        )
        raw = [
            {
                "step": 1,
                "action_type": "research",
                "target": "explorer",
                "description": (
                    "Analyze the latest blocker quickly and write concrete constraints to blackboard "
                    f"(trigger={trim(reason, 120)})."
                ),
            },
            {
                "step": 2,
                "action_type": "implement",
                "target": "developer",
                "description": (
                    "Implement one incremental fix for the current objective and provide verifiable tool output. "
                    f"Objective: {objective}"
                ),
            },
            {
                "step": 3,
                "action_type": "validate",
                "target": "reviewer",
                "description": (
                    "Run one validation pass, provide pass/fix verdict with evidence, and handoff summary request if needed."
                ),
            },
        ]
        return self._watchdog_normalize_steps(raw)

    def _watchdog_decompose_steps(self, board: dict, reason: str, *, pinned_selection: str) -> tuple[list[dict], str, str]:
        snapshot = self._watchdog_snapshot_payload(board, reason, str(board.get("active_agent", "") or ""), None)
        objective = trim(str(board.get("original_goal", "") or "").strip(), 1600)
        system_prompt = (
            "You are a task decomposer. Your only job is to split OBJECTIVE into executable micro-steps. "
            "Return strict JSON array only: "
            "[{\"step\":1,\"action_type\":\"...\",\"target\":\"explorer|developer|reviewer\",\"description\":\"...\"}]. "
            "No markdown, no prose, no code fence."
        )
        user_prompt = (
            f"OBJECTIVE:\n{objective}\n\n"
            f"TRIGGER:\n{trim(reason, 220)}\n\n"
            "SNAPSHOT:\n"
            f"{snapshot}\n\n"
            "Rules: keep steps module-level (not line-by-line), use incremental edits, "
            "and keep total steps <= 12."
        )
        raw_text = ""
        parsed_steps: list[dict] = []
        try:
            rsp = self._chat_with_same_model_retry(
                [{"role": "user", "content": user_prompt, "ts": now_ts()}],
                tools=None,
                system=system_prompt,
                max_tokens=1200,
                think=False,
                stream_thinking=False,
                pinned_selection=pinned_selection,
                context_label="watchdog decomposer",
                retries=max(1, min(2, int(MODEL_OUTPUT_RETRY_TIMES))),
            )
            raw_text = str(rsp.get("content") or "")
            parsed_steps = self._watchdog_extract_json_array(raw_text)
        except Exception as exc:
            raw_text = f"decomposer-error: {trim(str(exc), 220)}"
            parsed_steps = []
        normalized = self._watchdog_normalize_steps(parsed_steps)
        if not normalized:
            normalized = self._watchdog_fallback_steps(board, reason)
        return normalized, snapshot, trim(raw_text, 2000)

    def _watchdog_activate_decomposition(
        self,
        board: dict,
        *,
        reason: str,
        role: str,
        step: dict | None,
        pinned_selection: str,
    ) -> bool:
        dq = self._normalize_decomposition_queue_state(board.get("decomposition_queue", {}))
        if bool(dq.get("active", False)):
            return False
        steps, snapshot, raw_text = self._watchdog_decompose_steps(
            board,
            reason,
            pinned_selection=pinned_selection,
        )
        if not steps:
            return False
        dq = {
            "active": True,
            "trigger_reason": trim(str(reason or "").strip(), 200),
            "created_at": float(now_ts()),
            "cursor": 0,
            "steps": steps,
            "last_error": "",
            "snapshot": trim(snapshot, 4000),
            "decomposer_output": trim(raw_text, 2000),
        }
        wd = self._normalize_watchdog_state(board.get("watchdog", {}))
        wd["intent_no_tool_streak"] = 0
        wd["repeat_no_tool_streak"] = 0
        board["watchdog"] = wd
        board["decomposition_queue"] = dq
        self.blackboard = board
        self._blackboard_touch()
        self._blackboard_history(
            "manager",
            trim(
                (
                    "watchdog triggered decomposition "
                    f"(reason={reason}, role={self._sanitize_agent_role(role)}, "
                    f"steps={len(steps)})"
                ),
                520,
            ),
        )
        self._emit(
            "status",
            {
                "summary": (
                    "watchdog triggered; switched to stateless executor queue "
                    f"(reason={trim(reason, 90)}, steps={len(steps)})"
                )
            },
        )
        return True

    def _watchdog_escalate_to_single_developer(self, board: dict, *, reason: str = ""):
        """Watchdog 连续 stall 升级：强制降级到 Single+Developer 模式。"""
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        self.runtime_execution_mode = EXECUTION_MODE_SINGLE
        self.runtime_participants = ["developer"]
        self.runtime_assigned_expert = "developer"
        dq = self._normalize_decomposition_queue_state(bb.get("decomposition_queue", {}))
        dq["active"] = False
        bb["decomposition_queue"] = dq
        profile = self._ensure_blackboard_task_profile(bb)
        profile["execution_mode"] = EXECUTION_MODE_SINGLE
        profile["participants"] = ["developer"]
        profile["assigned_expert"] = "developer"
        bb["task_profile"] = profile
        self.blackboard = bb
        self._blackboard_touch()
        self._blackboard_history(
            "manager",
            trim(
                f"watchdog escalation: forced Single+Developer (trigger_count={int(bb.get('watchdog', {}).get('trigger_count', 0))}, reason={reason})",
                520,
            ),
        )
        self._emit(
            "status",
            {
                "summary": (
                    "watchdog escalation: multi-agent stall detected, "
                    "downgrading to Single+Developer mode"
                )
            },
        )

    def _watchdog_pick_executor_route(self, board: dict | None = None) -> tuple[dict, dict] | None:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        dq = self._normalize_decomposition_queue_state(bb.get("decomposition_queue", {}))
        if not bool(dq.get("active", False)):
            return None
        steps = list(dq.get("steps", []) or [])
        if not steps:
            return None
        cursor = max(0, int(dq.get("cursor", 0) or 0))
        while cursor < len(steps):
            status = str((steps[cursor] or {}).get("status", "") or "").strip().lower()
            if status not in {"done", "skipped"}:
                break
            cursor += 1
        if cursor >= len(steps):
            dq["active"] = False
            dq["cursor"] = len(steps)
            bb["decomposition_queue"] = dq
            self.blackboard = bb
            self._blackboard_touch()
            return None
        dq["cursor"] = cursor
        step_row = steps[cursor] if isinstance(steps[cursor], dict) else {}
        target = self._sanitize_agent_role(step_row.get("target", "")) or "developer"
        action_type = trim(str(step_row.get("action_type", "execute") or "execute").strip(), 80) or "execute"
        step_instruction = trim(str(step_row.get("instruction", "") or "").strip(), 900)
        trigger_reason = trim(str(dq.get("trigger_reason", "") or "").strip(), 180)
        total = len(steps)
        current = cursor + 1
        profile = self._ensure_blackboard_task_profile(bb)
        task_level = int(profile.get("task_level", self.runtime_task_level or 3) or 3)
        if task_level not in TASK_LEVEL_CHOICES:
            task_level = 3
        args = {
            "target": target,
            "instruction": trim(
                (
                    f"Executor mode (stateless) step {current}/{total}. "
                    f"trigger={trigger_reason or 'watchdog'}; action_type={action_type}.\n"
                    f"{step_instruction}\n"
                    "Rules: execute one concrete tool call now, keep scope narrow, "
                    "and update blackboard evidence immediately."
                ),
                1200,
            ),
            "task_level": int(task_level),
            "task_type": trim(str(profile.get("task_type", "general") or "general"), 40),
            "complexity": trim(str(profile.get("complexity", "simple") or "simple"), 20),
            "scale_preference": trim(str(profile.get("scale_preference", "balanced") or "balanced"), 20),
            "judgement": trim(
                f"watchdog-executor-step-{current}/{total}",
                200,
            ),
            "round_budget": int(profile.get("round_budget", self.runtime_round_budget or self.max_agent_rounds) or 0),
            "direct_objective": trim(str(profile.get("direct_objective", self.runtime_direct_objective or "") or ""), 800),
            "execution_mode": normalize_execution_mode(
                profile.get("execution_mode", self._effective_execution_mode()),
                default=self._effective_execution_mode(),
            ),
            "participants": profile.get("participants", self.runtime_participants),
            "assigned_expert": profile.get("assigned_expert", self.runtime_assigned_expert or "developer"),
            "requires_user_confirmation": bool(profile.get("requires_user_confirmation", False)),
            "is_mandatory": True,
            "executor_mode": True,
        }
        bb["decomposition_queue"] = dq
        self.blackboard = bb
        self._blackboard_touch()
        meta = {
            "trigger_reason": trigger_reason,
            "cursor": current,
            "total": total,
            "target": target,
            "action_type": action_type,
        }
        return args, meta

    def _watchdog_mark_step_progress(self, board: dict, role: str, step: dict | None) -> dict:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        dq = self._normalize_decomposition_queue_state(bb.get("decomposition_queue", {}))
        out = {"queue_active": bool(dq.get("active", False)), "step_advanced": False}
        if not bool(dq.get("active", False)):
            bb["decomposition_queue"] = dq
            self.blackboard = bb
            return out
        rows = list(dq.get("steps", []) or [])
        cursor = max(0, int(dq.get("cursor", 0) or 0))
        if cursor >= len(rows):
            dq["active"] = False
            dq["cursor"] = len(rows)
            bb["decomposition_queue"] = dq
            self.blackboard = bb
            return {"queue_active": False, "step_advanced": False}
        current = rows[cursor] if isinstance(rows[cursor], dict) else {}
        target = self._sanitize_agent_role(current.get("target", "")) or "developer"
        role_key = self._sanitize_agent_role(role)
        if target != role_key:
            bb["decomposition_queue"] = dq
            self.blackboard = bb
            return out
        status = str((step or {}).get("status", "") or "").strip().lower()
        text = trim(strip_thinking_content(str((step or {}).get("text", "") or "").strip()), 1200)
        tool_results = (step or {}).get("tool_results", []) if isinstance((step or {}).get("tool_results"), list) else []
        has_ok_tool = any(isinstance(row, dict) and bool(row.get("ok", False)) for row in tool_results)
        success = bool(status == "tools" and has_ok_tool)
        if (not success) and status == "no-tools" and role_key in {"explorer", "reviewer"} and len(text) >= 120:
            success = True
        attempts = max(0, int(current.get("attempts", 0) or 0)) + 1
        current["attempts"] = attempts
        current["updated_at"] = float(now_ts())
        if success:
            current["status"] = "done"
            dq["cursor"] = cursor + 1
            out["step_advanced"] = True
            dq["last_error"] = ""
        elif status in {"no-tools", "tools", "skip"}:
            if attempts >= int(WATCHDOG_STEP_MAX_ATTEMPTS):
                current["status"] = "skipped"
                dq["cursor"] = cursor + 1
                out["step_advanced"] = True
                dq["last_error"] = trim(
                    f"step {cursor + 1} skipped after {attempts} attempts ({status})",
                    300,
                )
            else:
                current["status"] = "retry"
                dq["last_error"] = trim(
                    f"step {cursor + 1} retry pending ({status})",
                    300,
                )
        rows[cursor] = current
        dq["steps"] = rows
        if int(dq.get("cursor", 0) or 0) >= len(rows):
            dq["active"] = False
            out["queue_active"] = False
            self._emit("status", {"summary": "stateless executor queue drained; returning to normal manager routing"})
        else:
            out["queue_active"] = bool(dq.get("active", False))
        bb["decomposition_queue"] = dq
        self.blackboard = bb
        return out

    def _watchdog_process_worker_step(
        self,
        board: dict,
        *,
        role: str,
        step: dict,
        state_changed: bool,
        pinned_selection: str,
    ) -> dict:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        wd = self._normalize_watchdog_state(bb.get("watchdog", {}))
        dq = self._normalize_decomposition_queue_state(bb.get("decomposition_queue", {}))
        status = str((step or {}).get("status", "") or "").strip().lower()
        text = trim(strip_thinking_content(str((step or {}).get("text", "") or "").strip()), 1200)
        wd["last_state_fp"] = self._watchdog_state_fingerprint(bb)
        if state_changed:
            wd["state_unchanged_streak"] = 0
        else:
            wd["state_unchanged_streak"] = max(0, int(wd.get("state_unchanged_streak", 0) or 0)) + 1
        if status == "tools":
            wd["intent_no_tool_streak"] = 0
            wd["repeat_no_tool_streak"] = 0
            wd["last_no_tool_text"] = ""
            wd["last_no_tool_hash"] = ""
        elif status == "no-tools":
            if self._watchdog_intent_without_action(text):
                wd["intent_no_tool_streak"] = max(0, int(wd.get("intent_no_tool_streak", 0) or 0)) + 1
            else:
                wd["intent_no_tool_streak"] = max(0, int(wd.get("intent_no_tool_streak", 0) or 0) - 1)
            prev_text = str(wd.get("last_no_tool_text", "") or "")
            sim = self._watchdog_similarity(prev_text, text)
            if sim >= float(WATCHDOG_REPEAT_SIMILARITY_THRESHOLD):
                wd["repeat_no_tool_streak"] = max(0, int(wd.get("repeat_no_tool_streak", 0) or 0)) + 1
            else:
                wd["repeat_no_tool_streak"] = 0
            wd["last_no_tool_text"] = text
            wd["last_no_tool_hash"] = hashlib.sha1(text.encode("utf-8")).hexdigest() if text else ""
        else:
            wd["intent_no_tool_streak"] = max(0, int(wd.get("intent_no_tool_streak", 0) or 0) - 1)
            wd["repeat_no_tool_streak"] = max(0, int(wd.get("repeat_no_tool_streak", 0) or 0) - 1)
        bb["watchdog"] = wd
        bb["decomposition_queue"] = dq
        self.blackboard = bb
        progress_row = self._watchdog_mark_step_progress(bb, role, step)
        bb = self._ensure_blackboard()
        dq = self._normalize_decomposition_queue_state(bb.get("decomposition_queue", {}))
        trigger_reason = ""
        _is_single = self._effective_execution_mode() == EXECUTION_MODE_SINGLE
        _intent_th = WATCHDOG_INTENT_NO_TOOL_THRESHOLD_SINGLE if _is_single else WATCHDOG_INTENT_NO_TOOL_THRESHOLD
        _repeat_th = WATCHDOG_REPEAT_NO_TOOL_THRESHOLD_SINGLE if _is_single else WATCHDOG_REPEAT_NO_TOOL_THRESHOLD
        if not bool(dq.get("active", False)):
            if int(wd.get("intent_no_tool_streak", 0) or 0) >= int(_intent_th):
                trigger_reason = "intent-without-tool-call"
            elif int(wd.get("repeat_no_tool_streak", 0) or 0) >= int(_repeat_th):
                trigger_reason = "repeated-no-tool-reply"
            elif (
                self._watchdog_context_near_limit()
                and int(wd.get("state_unchanged_streak", 0) or 0) >= int(WATCHDOG_CONTEXT_STALL_THRESHOLD)
            ):
                trigger_reason = "context-threshold-no-state-change"
            elif (
                status in {"no-tools", "skip"}
                and int(wd.get("state_unchanged_streak", 0) or 0) >= int(WATCHDOG_STATE_STALL_THRESHOLD)
            ):
                trigger_reason = "state-unchanged-stall"
        triggered = False
        if trigger_reason:
            try:
                last_trigger_ts = float(wd.get("last_trigger_ts", 0.0) or 0.0)
            except Exception:
                last_trigger_ts = 0.0
            if now_ts() - last_trigger_ts >= 1.0:
                wd["trigger_count"] = max(0, int(wd.get("trigger_count", 0) or 0)) + 1
                wd["last_trigger_reason"] = trim(str(trigger_reason or "").strip(), 200)
                wd["last_trigger_ts"] = float(now_ts())
                bb["watchdog"] = wd
                self.blackboard = bb
                self._blackboard_touch()
                # Failure ledger: record stall event
                self._ledger_record_stall(trigger_reason, "unresolved")
                if int(wd["trigger_count"]) >= 2:
                    _wd_sev = self._bump_stall_severity("watchdog", STALL_SEVERITY_WEIGHT_WATCHDOG)
                    if _wd_sev >= STALL_SEVERITY_ESCALATION_THRESHOLD:
                        if not self._escalate_stall_to_plan_mode(
                            "watchdog", last_fault_reason=trigger_reason, pinned_selection=pinned_selection,
                        ):
                            self._watchdog_escalate_to_single_developer(bb, reason=trigger_reason)
                    else:
                        self._watchdog_escalate_to_single_developer(bb, reason=trigger_reason)
                else:
                    triggered = self._watchdog_activate_decomposition(
                        bb,
                        reason=trigger_reason,
                        role=role,
                        step=step,
                        pinned_selection=pinned_selection,
                    )
                bb = self._ensure_blackboard()
        bb["watchdog"] = self._normalize_watchdog_state(bb.get("watchdog", wd))
        bb["decomposition_queue"] = self._normalize_decomposition_queue_state(bb.get("decomposition_queue", dq))
        self.blackboard = bb
        self._blackboard_touch()
        return {
            "triggered": bool(triggered),
            "trigger_reason": trigger_reason,
            "queue_active": bool((bb.get("decomposition_queue", {}) or {}).get("active", False)),
            "step_advanced": bool(progress_row.get("step_advanced", False)),
        }

    def _watchdog_execute_queue_step(self, *, pinned_selection: str) -> dict:
        board = self._ensure_blackboard()
        pick = self._watchdog_pick_executor_route(board)
        if not pick:
            dq = self._normalize_decomposition_queue_state(board.get("decomposition_queue", {}))
            return {"executed": False, "queue_active": bool(dq.get("active", False)), "stop_run": False, "interrupted": False}
        queue_args, meta = pick
        role = self._sanitize_agent_role((queue_args or {}).get("target", "")) or "developer"
        instruction = trim(str((queue_args or {}).get("instruction", "") or "").strip(), 1200)
        if not instruction:
            instruction = (
                "Executor mode step: call one concrete tool now, keep scope narrow, and update blackboard evidence."
            )
        self._inject_manager_instruction(role, instruction, is_mandatory=True, executor_mode=True)
        if role == "explorer":
            self._blackboard_set_status("RESEARCHING")
        elif role == "developer":
            self._blackboard_set_status("CODING")
        elif role == "reviewer":
            self._blackboard_set_status("REVIEWING")
        board_before_fp = self._watchdog_state_fingerprint(self._ensure_blackboard())
        step = self._multi_agent_turn(
            role,
            pinned_selection=pinned_selection,
            media_inputs_round=None,
        )
        safe_step = step if isinstance(step, dict) else {}
        self._blackboard_update_from_worker_step(role, safe_step)
        board_after = self._ensure_blackboard()
        board_after_fp = self._watchdog_state_fingerprint(board_after)
        wd_event = self._watchdog_process_worker_step(
            board_after,
            role=role,
            step=safe_step,
            state_changed=bool(board_after_fp != board_before_fp),
            pinned_selection=pinned_selection,
        )
        status = str(safe_step.get("status", "") or "").strip().lower()
        interrupted = bool(status == "interrupted")
        stop_run = False
        finish_gate_reason = ""
        if status == "tools" and bool(safe_step.get("stop_due_to_finish", False)):
            note = f"{self._agent_display_name(role)} signaled finish via tool."
            # Approval note should come from finish tool payload sync; avoid overwriting with generic text here.
            can_finish_now, finish_gate_reason = self._can_auto_finish_from_approval(
                self._ensure_blackboard(),
                latest_user_ts=self._latest_user_message_ts(),
            )
            if can_finish_now:
                self._mark_all_done_silently(note)
                stop_run = True
            else:
                self._emit(
                    "status",
                    {
                        "summary": (
                            f"executor finish deferred by gate ({finish_gate_reason}); "
                            "continue watchdog queue"
                        )
                    },
                )
        dq = self._normalize_decomposition_queue_state(self._ensure_blackboard().get("decomposition_queue", {}))
        return {
            "executed": True,
            "queue_active": bool(dq.get("active", False)),
            "stop_run": bool(stop_run),
            "interrupted": bool(interrupted),
            "role": role,
            "status": status,
            "wd_event": wd_event,
            "trigger_reason": trim(str(meta.get("trigger_reason", "") or "").strip(), 120),
            "finish_gate_reason": finish_gate_reason,
        }

    def _new_blackboard(self, goal: str = "") -> dict:
        profile = self._normalize_task_profile(goal, {})
        progress = "done" if str(profile.get("task_type", "") or "") == "simple_qa" and not str(goal or "").strip() else "initializing"
        return {
            "version": 1,
            "updated_at": float(now_ts()),
            "original_goal": trim(str(goal or "").strip(), 4000),
            "research_notes": [],
            "code_artifacts": {},
            "execution_logs": [],
            "review_feedback": [],
            "conversation_history": [],
            "status": "INITIALIZING",
            "approval": {
                "approved": False,
                "by": "",
                "note": "",
                "ts": 0.0,
            },
            "manager_cycles": 0,
            "manager_summary_attempts": 0,
            "active_agent": "",
            "last_delegate": {
                "target": "",
                "instruction": "",
                "reason": "",
                "source": "",
                "is_mandatory": False,
                "ts": 0.0,
            },
            "task_profile": profile,
            "manager_judgement": {
                "task_type": str(profile.get("task_type", "general")),
                "complexity": str(profile.get("complexity", "simple")),
                "scale_preference": str(profile.get("scale_preference", "balanced") or "balanced"),
                "progress": progress,
                "remaining_rounds": (
                    -1
                    if int(profile.get("round_budget", 0) or 0) <= 0
                    else int(profile.get("round_budget", 1) or 1)
                ),
                "updated_at": float(now_ts()),
            },
            "last_worker_reply": {
                "role": "",
                "text": "",
                "ts": 0.0,
            },
            "project_todos": [],
            "watchdog": self._new_watchdog_state(),
            "decomposition_queue": self._new_decomposition_queue_state(),
            "failure_ledger": {
                "attempted_fixes": [],
                "compilation_errors": [],
                "errors": [],
                "repeated_delegations": [],
                "stall_events": [],
                "tool_call_fingerprints": [],
            },
            "checkpoints": [],
            "persisted_manager_routes": [],
        }

    def _normalize_blackboard(self, raw: object) -> dict:
        src = raw if isinstance(raw, dict) else {}
        board = self._new_blackboard(str(src.get("original_goal", "") or ""))
        try:
            board["version"] = int(src.get("version", 1) or 1)
        except Exception:
            board["version"] = 1
        board["updated_at"] = float(src.get("updated_at", now_ts()) or now_ts())
        board["status"] = self._normalize_blackboard_status(src.get("status", board["status"]))
        board["manager_cycles"] = max(0, int(src.get("manager_cycles", 0) or 0))
        board["manager_summary_attempts"] = max(0, int(src.get("manager_summary_attempts", 0) or 0))
        board["active_agent"] = self._sanitize_agent_role(src.get("active_agent", ""))
        raw_delegate = src.get("last_delegate", {})
        if isinstance(raw_delegate, dict):
            board["last_delegate"] = {
                "target": str(raw_delegate.get("target", "") or "").strip().lower(),
                "instruction": trim(str(raw_delegate.get("instruction", "") or "").strip(), 1200),
                "reason": trim(str(raw_delegate.get("reason", "") or "").strip(), 600),
                "source": trim(str(raw_delegate.get("source", "") or "").strip(), 40),
                "is_mandatory": _to_bool_like(raw_delegate.get("is_mandatory", False), default=False),
                "ts": float(raw_delegate.get("ts", 0.0) or 0.0),
            }
        raw_approval = src.get("approval", {})
        if isinstance(raw_approval, dict):
            board["approval"] = {
                "approved": bool(raw_approval.get("approved", False)),
                "by": trim(str(raw_approval.get("by", "") or "").strip(), 60),
                "note": trim(str(raw_approval.get("note", "") or "").strip(), 1000),
                "ts": float(raw_approval.get("ts", 0.0) or 0.0),
            }
        board["task_profile"] = self._normalize_task_profile(
            str(board.get("original_goal", "") or ""),
            src.get("task_profile", {}),
        )
        raw_judgement = src.get("manager_judgement", {})
        if isinstance(raw_judgement, dict):
            board["manager_judgement"] = {
                "task_type": trim(
                    str(raw_judgement.get("task_type", board["task_profile"].get("task_type", "")) or "").strip(),
                    40,
                ),
                "complexity": (
                    str(
                        raw_judgement.get(
                            "complexity",
                            board["task_profile"].get("complexity", "simple"),
                        )
                        or ""
                    )
                    .strip()
                    .lower()
                ),
                "scale_preference": (
                    str(
                        raw_judgement.get(
                            "scale_preference",
                            board["task_profile"].get("scale_preference", "balanced"),
                        )
                        or "balanced"
                    )
                    .strip()
                    .lower()
                ),
                "progress": trim(str(raw_judgement.get("progress", "initializing") or "").strip().lower(), 40),
                "remaining_rounds": max(
                    -1,
                    int(
                        raw_judgement.get(
                            "remaining_rounds",
                            (
                                -1
                                if int(board["task_profile"].get("round_budget", 0) or 0) <= 0
                                else board["task_profile"].get("round_budget", self.max_agent_rounds)
                            ),
                        )
                        if raw_judgement.get("remaining_rounds", None) is not None
                        else (
                            -1
                            if int(board["task_profile"].get("round_budget", 0) or 0) <= 0
                            else int(board["task_profile"].get("round_budget", self.max_agent_rounds) or 0)
                        )
                    ),
                ),
                "updated_at": float(raw_judgement.get("updated_at", now_ts()) or now_ts()),
            }
        else:
            board["manager_judgement"] = {
                "task_type": str(board["task_profile"].get("task_type", "")),
                "complexity": str(board["task_profile"].get("complexity", "")),
                "scale_preference": str(board["task_profile"].get("scale_preference", "balanced") or "balanced"),
                "progress": "initializing",
                "remaining_rounds": (
                    -1
                    if int(board["task_profile"].get("round_budget", 0) or 0) <= 0
                    else int(board["task_profile"].get("round_budget", self.max_agent_rounds) or 0)
                ),
                "updated_at": float(now_ts()),
            }
        raw_last_reply = src.get("last_worker_reply", {})
        if isinstance(raw_last_reply, dict):
            board["last_worker_reply"] = {
                "role": self._sanitize_agent_role(raw_last_reply.get("role", "")),
                "text": trim(str(raw_last_reply.get("text", "") or "").strip(), 3000),
                "ts": float(raw_last_reply.get("ts", 0.0) or 0.0),
            }

        def _clean_rows(rows: object, *, key: str = "content", actor_key: str = "actor") -> list[dict]:
            out: list[dict] = []
            if not isinstance(rows, list):
                return out
            for row in rows[-(BLACKBOARD_MAX_LOG_ENTRIES * 2) :]:
                if not isinstance(row, dict):
                    continue
                txt = trim(str(row.get(key, "") or "").strip(), BLACKBOARD_MAX_TEXT)
                if not txt:
                    continue
                out.append(
                    {
                        "ts": float(row.get("ts", now_ts()) or now_ts()),
                        "actor": trim(str(row.get(actor_key, "") or "").strip(), 40),
                        key: txt,
                    }
                )
            return out[-BLACKBOARD_MAX_LOG_ENTRIES:]

        board["research_notes"] = _clean_rows(src.get("research_notes", []), key="content", actor_key="actor")
        board["execution_logs"] = _clean_rows(src.get("execution_logs", []), key="content", actor_key="actor")
        board["review_feedback"] = _clean_rows(src.get("review_feedback", []), key="content", actor_key="actor")
        board["conversation_history"] = _clean_rows(src.get("conversation_history", []), key="content", actor_key="actor")
        raw_artifacts = src.get("code_artifacts", {})
        artifacts: dict[str, dict] = {}
        if isinstance(raw_artifacts, dict):
            for p, row in list(raw_artifacts.items())[:320]:
                rel = normalize_rel_preview_path(str(p or "")) or trim(str(p or "").strip(), 280)
                if not rel:
                    continue
                item = row if isinstance(row, dict) else {}
                summary = trim(str(item.get("summary", "") or "").strip(), BLACKBOARD_MAX_TEXT)
                if not summary:
                    continue
                artifacts[rel] = {
                    "summary": summary,
                    "last_actor": trim(str(item.get("last_actor", "") or "").strip(), 40),
                    "updated_at": float(item.get("updated_at", now_ts()) or now_ts()),
                    "change_count": max(1, int(item.get("change_count", 1) or 1)),
                }
        board["code_artifacts"] = artifacts
        if not isinstance(bb_src_todos := src.get("project_todos"), list):
            board["project_todos"] = []
        else:
            clean_todos = []
            import re as _re_norm
            _mid_re_norm = _re_norm.compile(r"(?<=\S)\s+(\d+\.\d+\s)")
            for pt in bb_src_todos[:40]:
                if not isinstance(pt, dict):
                    continue
                raw_content = trim(str(pt.get("content", "") or ""), 1500)
                raw_full = trim(str(pt.get("full_content", "") or ""), 1500)
                # Migration: if full_content is empty but content has sub-steps, auto-split
                if not raw_full and raw_content and pt.get("category") == "plan_step":
                    normalized = _mid_re_norm.sub(r"\n\1", raw_content)
                    if "\n" in normalized:
                        raw_full = normalized
                        raw_content = normalized.split("\n")[0].strip()
                clean_todos.append({
                    "id": trim(str(pt.get("id", "") or ""), 20),
                    "content": trim(raw_content, 400),
                    "full_content": trim(raw_full, 1500),
                    "status": str(pt.get("status", "pending") or "pending") if str(pt.get("status", "pending") or "pending") in ("pending", "in_progress", "completed") else "pending",
                    "category": trim(str(pt.get("category", "") or ""), 40),
                    "plan_step_index": int(pt.get("plan_step_index", -1)) if pt.get("plan_step_index") is not None else -1,
                    "created_at": float(pt.get("created_at", 0.0) or 0.0),
                    "completed_at": float(pt.get("completed_at", 0.0) or 0.0) if pt.get("completed_at") else None,
                    "completed_by": trim(str(pt.get("completed_by", "") or ""), 40),
                    "evidence": trim(str(pt.get("evidence", "") or ""), 200),
                })
            board["project_todos"] = clean_todos
        # Preserve plan step cursor/total (used by _advance_plan_step and UI progress)
        raw_cursor = src.get("plan_step_cursor")
        if raw_cursor is not None:
            try:
                board["plan_step_cursor"] = int(raw_cursor)
            except Exception:
                pass
        raw_total = src.get("plan_step_total")
        if raw_total is not None:
            try:
                board["plan_step_total"] = int(raw_total)
            except Exception:
                pass
        board["watchdog"] = self._normalize_watchdog_state(src.get("watchdog", {}))
        board["decomposition_queue"] = self._normalize_decomposition_queue_state(
            src.get("decomposition_queue", {})
        )
        # Preserve plan-mode data through normalization
        raw_plan = src.get("plan")
        if isinstance(raw_plan, dict):
            board["plan"] = raw_plan
        # Preserve failure_ledger, checkpoints, persisted_manager_routes
        raw_fl = src.get("failure_ledger")
        board["failure_ledger"] = self._normalize_failure_ledger(raw_fl) if isinstance(raw_fl, dict) else {
            "attempted_fixes": [],
            "compilation_errors": [],
            "errors": [],
            "repeated_delegations": [],
            "stall_events": [],
            "tool_call_fingerprints": [],
        }
        raw_cp = src.get("checkpoints")
        board["checkpoints"] = list(raw_cp)[-CHECKPOINT_MAX_COUNT:] if isinstance(raw_cp, list) else []
        raw_pmr = src.get("persisted_manager_routes")
        board["persisted_manager_routes"] = list(raw_pmr)[-PERSISTED_ROUTES_MAX:] if isinstance(raw_pmr, list) else []
        # Preserve loaded_skills across normalization
        raw_loaded_skills = src.get("loaded_skills")
        if isinstance(raw_loaded_skills, dict) and raw_loaded_skills:
            clean_skills: dict[str, dict] = {}
            for skey, sinfo in list(raw_loaded_skills.items())[:10]:
                if isinstance(sinfo, dict):
                    clean_skills[str(skey)] = {
                        "loaded_at": float(sinfo.get("loaded_at", 0.0) or 0.0),
                        "size": int(sinfo.get("size", 0) or 0),
                        "preview": trim(str(sinfo.get("preview", "") or ""), 300),
                    }
            if clean_skills:
                board["loaded_skills"] = clean_skills
        goal_sig = trim(str(src.get("loaded_skills_goal_sig", "") or ""), 80)
        if goal_sig:
            board["loaded_skills_goal_sig"] = goal_sig
        goal_preview = trim(str(src.get("loaded_skills_goal_preview", "") or ""), 240)
        if goal_preview:
            board["loaded_skills_goal_preview"] = goal_preview
        # Preserve step_files registry across normalization
        raw_step_files = src.get("step_files")
        if isinstance(raw_step_files, dict):
            clean_sf: dict[str, list] = {}
            for sf_key, sf_entries in raw_step_files.items():
                if isinstance(sf_entries, list):
                    clean_sf[str(sf_key)] = sf_entries[-30:]
            if clean_sf:
                board["step_files"] = clean_sf
        return board

    def _normalize_failure_ledger(self, raw: dict) -> dict:
        fl: dict = {
            "attempted_fixes": [],
            "compilation_errors": [],
            "errors": [],
            "repeated_delegations": [],
            "stall_events": [],
            "tool_call_fingerprints": [],
        }
        if not isinstance(raw, dict):
            return fl
        def _safe_list(key: str, max_len: int) -> list[dict]:
            items = raw.get(key)
            if not isinstance(items, list):
                return []
            out: list[dict] = []
            for item in items[-max_len:]:
                if isinstance(item, dict):
                    out.append(item)
            return out
        fl["attempted_fixes"] = _safe_list("attempted_fixes", FAILURE_LEDGER_MAX_FIXES)
        fl["compilation_errors"] = _safe_list("compilation_errors", FAILURE_LEDGER_MAX_COMPILE_ERRORS)
        fl["errors"] = _safe_list("errors", FAILURE_LEDGER_MAX_ERRORS)
        fl["repeated_delegations"] = _safe_list("repeated_delegations", FAILURE_LEDGER_MAX_DELEGATIONS)
        fl["stall_events"] = _safe_list("stall_events", FAILURE_LEDGER_MAX_STALLS)
        fl["tool_call_fingerprints"] = _safe_list("tool_call_fingerprints", FAILURE_LEDGER_MAX_TOOL_FPS)
        return fl

    def _ledger_record_fix_attempt(self, file: str, error: str, fix: str, result: str, actor: str):
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        fixes = fl.get("attempted_fixes", [])
        fixes.append({
            "file": trim(str(file or ""), 260),
            "error": trim(str(error or ""), 400),
            "fix": trim(str(fix or ""), 400),
            "result": trim(str(result or ""), 200),
            "actor": trim(str(actor or ""), 40),
            "round": int(getattr(self, "agent_round_index", 0) or 0),
            "ts": float(now_ts()),
        })
        fl["attempted_fixes"] = fixes[-FAILURE_LEDGER_MAX_FIXES:]
        bb["failure_ledger"] = fl
        self.blackboard = bb

    def _ledger_update_fix_attempt_status(self, file: str, new_status: str):
        """Update status of most recent fix_attempt for a file."""
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        fixes = fl.get("attempted_fixes", [])
        for fx in reversed(fixes):
            if not isinstance(fx, dict):
                continue
            fx_file = str(fx.get("file", "") or "")
            if fx_file and (fx_file.endswith(file) or file.endswith(fx_file)):
                if fx.get("result") in ("pending", "applied"):
                    fx["result"] = new_status
                    break
        fl["attempted_fixes"] = fixes
        bb["failure_ledger"] = fl
        self.blackboard = bb

    def _ledger_verify_fix_attempts_on_success(self, category: str):
        """After successful bash, mark 'applied' fix_attempts as verified."""
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        fixes = fl.get("attempted_fixes", [])
        for fx in fixes:
            if isinstance(fx, dict) and fx.get("result") == "applied":
                fx["result"] = f"verified({category})"
        fl["attempted_fixes"] = fixes
        bb["failure_ledger"] = fl
        self.blackboard = bb

    def _ledger_mark_fix_attempts_failed(self, category: str, error_msg: str):
        """After failed bash, mark 'applied' fix_attempts as failed."""
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        fixes = fl.get("attempted_fixes", [])
        for fx in fixes:
            if isinstance(fx, dict) and fx.get("result") == "applied":
                fx["result"] = f"failed({category}): {trim(error_msg, 120)}"
        fl["attempted_fixes"] = fixes
        bb["failure_ledger"] = fl
        self.blackboard = bb

    def _continuation_failure_briefing(self) -> str:
        """Generate failure context summary for continuation scenarios."""
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger", {})
        if not isinstance(fl, dict):
            return ""
        lines = []
        # Edit stalls
        if self.developer_edit_fail_streaks:
            stuck = [f"{k} ({v} failures)" for k, v in self.developer_edit_fail_streaks.items()]
            lines.append(f"Edit stalls: {'; '.join(stuck)}")
        # Failed fixes
        fixes = fl.get("attempted_fixes", [])
        failed = [fx for fx in fixes if isinstance(fx, dict) and "failed" in str(fx.get("result", "") or "").lower()]
        if failed:
            lines.append("Failed fixes:")
            for fx in failed[-3:]:
                lines.append(f"  - {trim(str(fx.get('file','')),80)}: {trim(str(fx.get('result','')),120)}")
        # Unresolved errors
        unresolved = [e for e in fl.get("errors", []) if isinstance(e, dict) and int(e.get("count", 0) or 0) > 0]
        if unresolved:
            lines.append("Unresolved errors:")
            for e in unresolved[:3]:
                lines.append(f"  - [{e.get('category','')}] {e.get('file','')}: {trim(str(e.get('error_msg','')),150)}")
        if not lines:
            return ""
        return "FAILURE CONTEXT (from previous attempt):\n" + "\n".join(lines) + "\n"

    # --- Unified error detection helpers (修改 3) ---

    def _detect_error_category(self, cmd_str: str) -> str | None:
        """Match a command string against ERROR_CATEGORY_DEFS, return first matching category name."""
        cmd_lower = str(cmd_str or "").lower()
        for cat_name, cat_def in ERROR_CATEGORY_DEFS:
            if any(kw in cmd_lower for kw in cat_def.get("cmd_keywords", [])):
                return cat_name
        return None

    def _check_output_has_errors(self, output: str, category: str) -> bool:
        """Check if output contains error patterns for the given category."""
        out_lower = str(output or "").lower()
        cat_def = dict(ERROR_CATEGORY_DEFS).get(category, {})
        return any(pat.lower() in out_lower for pat in cat_def.get("output_patterns", []))

    def _extract_error_lines(self, output: str, category: str, max_lines: int = 3) -> list[tuple[str, str]]:
        """Scan output lines for error patterns, return [(file_hint, error_line), ...]."""
        cat_def = dict(ERROR_CATEGORY_DEFS).get(category, {})
        patterns = [p.lower() for p in cat_def.get("output_patterns", [])]
        results: list[tuple[str, str]] = []
        for ln in str(output or "").split("\n"):
            if any(pat in ln.lower() for pat in patterns):
                file_hint = ""
                parts = ln.split(":")
                if len(parts) >= 2 and ("." in parts[0] or "/" in parts[0]):
                    file_hint = parts[0].strip()
                results.append((file_hint, ln.strip()))
                if len(results) >= max_lines:
                    break
        return results

    # --- Unified error record / clear / sync (修改 4) ---

    def _ledger_record_error(self, category: str, file: str, error_msg: str):
        """Record an error into fl['errors'] with category field. Dedup by fingerprint."""
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        errors = fl.get("errors", [])
        fp = hashlib.sha1((str(category or "") + str(file or "") + str(error_msg or "")).encode("utf-8")).hexdigest()[:12]
        for entry in errors:
            if entry.get("fingerprint") == fp:
                entry["count"] = int(entry.get("count", 1) or 1) + 1
                entry["last_round"] = int(getattr(self, "agent_round_index", 0) or 0)
                fl["errors"] = errors
                bb["failure_ledger"] = fl
                self.blackboard = bb
                self._sync_compilation_errors_compat()
                return
        errors.append({
            "fingerprint": fp,
            "category": str(category or ""),
            "file": trim(str(file or ""), 260),
            "error_msg": trim(str(error_msg or ""), 400),
            "count": 1,
            "first_round": int(getattr(self, "agent_round_index", 0) or 0),
            "last_round": int(getattr(self, "agent_round_index", 0) or 0),
        })
        fl["errors"] = errors[-FAILURE_LEDGER_MAX_ERRORS:]
        bb["failure_ledger"] = fl
        self.blackboard = bb
        self._sync_compilation_errors_compat()

    def _ledger_clear_errors(self, category: str | None = None):
        """Clear errors from fl['errors']. If category given, only that category; else all."""
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        if category is None:
            fl["errors"] = []
            fl["attempted_fixes"] = []
        else:
            fl["errors"] = [e for e in fl.get("errors", []) if e.get("category") != category]
            # Clear attempted_fixes that match files in the cleared category
            fl["attempted_fixes"] = [
                fx for fx in fl.get("attempted_fixes", [])
                if not (isinstance(fx, dict) and fx.get("category") == category)
            ]
        bb["failure_ledger"] = fl
        self.blackboard = bb
        self._sync_compilation_errors_compat()

    def _sync_compilation_errors_compat(self):
        """Sync fl['compilation_errors'] from fl['errors'] where category=='compilation' for backward compat."""
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        fl["compilation_errors"] = [
            e for e in fl.get("errors", [])
            if isinstance(e, dict) and e.get("category") == "compilation"
        ]
        bb["failure_ledger"] = fl
        self.blackboard = bb

    # --- Thin wrappers for backward compatibility (修改 4d, 4e) ---

    def _ledger_record_compile_error(self, file: str, error_msg: str):
        self._ledger_record_error("compilation", file, error_msg)

    def _ledger_clear_compile_errors(self):
        self._ledger_clear_errors("compilation")

    # --- Unified tool result error processing (修改 5) ---

    def _process_tool_result_errors(self, name: str, args: dict, output: str, ok: bool, role_key: str):
        """Detect and record errors from tool results, or clear on success."""
        # --- edit_file 错误处理 ---
        if name == "edit_file" and isinstance(args, dict):
            edit_path = str(args.get("path", "") or "").strip()
            if not ok and "text not found" in str(output or "").lower():
                self._ledger_record_error("edit_mismatch", edit_path or "unknown", trim(str(output or ""), 300))
                count = int(self.developer_edit_fail_streaks.get(edit_path, 0) or 0) + 1
                self.developer_edit_fail_streaks[edit_path] = count
                self.developer_edit_last_diag[edit_path] = trim(str(output or ""), 500)
                if count >= 2:
                    self._inject_edit_recovery_hint(edit_path, count, str(output or ""), role_key)
            elif ok and edit_path:
                self.developer_edit_fail_streaks.pop(edit_path, None)
                self.developer_edit_last_diag.pop(edit_path, None)
                if not self.developer_edit_fail_streaks:
                    self._ledger_clear_errors("edit_mismatch")
                self._ledger_update_fix_attempt_status(edit_path, "applied")
            return

        # --- 原有 bash 处理逻辑 ---
        if name != "bash" or not isinstance(args, dict):
            return
        cmd_str = str(args.get("command", "") or "").lower()
        category = self._detect_error_category(cmd_str)
        if not category:
            return
        if not ok:
            error_lines = self._extract_error_lines(str(output or ""), category)
            for file_hint, err_line in error_lines:
                self._ledger_record_error(category, file_hint or cmd_str[:80], trim(err_line, 300))
            self._ledger_mark_fix_attempts_failed(category, trim(str(output or ""), 200))
        else:
            out_lower = str(output or "").lower()
            cat_def = dict(ERROR_CATEGORY_DEFS).get(category, {})
            negatives = cat_def.get("success_negatives", [])
            if not any(neg.lower() in out_lower for neg in negatives):
                self._ledger_clear_errors(category)
                # Auto-deactivate reviewer debug mode when errors are resolved
                if bool(self.reviewer_debug_mode) and not self._manager_has_error_log():
                    self._deactivate_reviewer_debug_mode("errors resolved")
                self._ledger_verify_fix_attempts_on_success(category)

    # --- Generalized error context (修改 6) ---

    def _recent_error_context(self, max_chars: int = 800) -> str:
        """Build context string from all error categories in fl['errors']."""
        bb = self._ensure_blackboard()
        lines: list[str] = []
        fl = bb.get("failure_ledger", {})
        if isinstance(fl, dict):
            all_errors = fl.get("errors", [])
            unresolved = [e for e in all_errors if isinstance(e, dict) and int(e.get("count", 0) or 0) > 0]
            if unresolved:
                # Group by category
                by_cat: dict[str, list] = {}
                for e in unresolved:
                    cat = str(e.get("category", "unknown") or "unknown")
                    by_cat.setdefault(cat, []).append(e)
                cat_labels = dict(ERROR_CATEGORY_DEFS)
                for cat, errs in by_cat.items():
                    label = cat_labels.get(cat, {}).get("label", cat.upper()) if cat in cat_labels else cat.upper()
                    lines.append(f"UNRESOLVED {label.upper()}:")
                    for e in errs[:5]:
                        f = str(e.get("file", "") or "")
                        msg = str(e.get("error_msg", "") or "")
                        cnt = int(e.get("count", 1) or 1)
                        lines.append(f"  [{f}] {trim(msg, 200)} (seen {cnt}x)")
            fixes = fl.get("attempted_fixes", [])
            if fixes:
                lines.append("PREVIOUSLY ATTEMPTED FIXES (all failed):")
                for fx in fixes[-3:]:
                    if isinstance(fx, dict):
                        lines.append(f"  - {trim(str(fx.get('fix', '') or ''), 120)} -> {trim(str(fx.get('result', '') or ''), 60)}")
        logs = bb.get("execution_logs", []) if isinstance(bb.get("execution_logs"), list) else []
        _all_kw = ("error:", "fatal error", "syntax error", "compile error", "build failed",
                    "traceback", "exception", "failed", "panic:", "FAIL:", "AssertionError")
        for entry in reversed(logs[-6:]):
            if not isinstance(entry, dict):
                continue
            txt = str(entry.get("content", "") or "")
            if any(kw in txt.lower() for kw in _all_kw):
                lines.append(f"LAST ERROR OUTPUT:\n{trim(txt, 400)}")
                break
        if not lines:
            return ""
        return trim("\n".join(lines), max_chars)

    def _recent_compile_error_context(self, max_chars: int = 800) -> str:
        return self._recent_error_context(max_chars=max_chars)

    def _ledger_record_delegation(self, target: str, instruction: str):
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        delegations = fl.get("repeated_delegations", [])
        fp = hashlib.sha1(str(instruction or "").encode("utf-8")).hexdigest()[:12]
        for entry in delegations:
            if entry.get("instruction_hash") == fp and entry.get("target") == target:
                entry["count"] = int(entry.get("count", 1) or 1) + 1
                entry["last_round"] = int(getattr(self, "agent_round_index", 0) or 0)
                fl["repeated_delegations"] = delegations
                bb["failure_ledger"] = fl
                self.blackboard = bb
                return
        delegations.append({
            "target": trim(str(target or ""), 40),
            "instruction_hash": fp,
            "instruction_preview": trim(str(instruction or ""), 200),
            "count": 1,
            "first_round": int(getattr(self, "agent_round_index", 0) or 0),
            "last_round": int(getattr(self, "agent_round_index", 0) or 0),
        })
        fl["repeated_delegations"] = delegations[-FAILURE_LEDGER_MAX_DELEGATIONS:]
        bb["failure_ledger"] = fl
        self.blackboard = bb

    def _ledger_record_stall(self, reason: str, resolution: str):
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        stalls = fl.get("stall_events", [])
        stalls.append({
            "reason": trim(str(reason or ""), 200),
            "resolution": trim(str(resolution or ""), 200),
            "round": int(getattr(self, "agent_round_index", 0) or 0),
            "ts": float(now_ts()),
        })
        fl["stall_events"] = stalls[-FAILURE_LEDGER_MAX_STALLS:]
        bb["failure_ledger"] = fl
        self.blackboard = bb

    def _ledger_record_tool_call(self, tool_name: str, args: dict):
        bb = self._ensure_blackboard()
        fl = bb.get("failure_ledger")
        if not isinstance(fl, dict):
            return
        fps = fl.get("tool_call_fingerprints", [])
        try:
            args_str = json_dumps(args) if isinstance(args, dict) else str(args or "")
        except Exception:
            args_str = str(args or "")
        fp = hashlib.sha1((str(tool_name or "") + args_str).encode("utf-8")).hexdigest()[:16]
        for entry in fps:
            if entry.get("fingerprint") == fp:
                entry["count"] = int(entry.get("count", 1) or 1) + 1
                entry["last_round"] = int(getattr(self, "agent_round_index", 0) or 0)
                fl["tool_call_fingerprints"] = fps
                bb["failure_ledger"] = fl
                self.blackboard = bb
                return
        fps.append({
            "fingerprint": fp,
            "tool_name": trim(str(tool_name or ""), 60),
            "count": 1,
            "first_round": int(getattr(self, "agent_round_index", 0) or 0),
            "last_round": int(getattr(self, "agent_round_index", 0) or 0),
        })
        fl["tool_call_fingerprints"] = fps[-FAILURE_LEDGER_MAX_TOOL_FPS:]
        bb["failure_ledger"] = fl
        self.blackboard = bb

    def _ensure_blackboard(self) -> dict:
        if not isinstance(self.blackboard, dict) or not self.blackboard:
            self.blackboard = self._new_blackboard(self._latest_user_goal_text())
        self.blackboard = self._normalize_blackboard(self.blackboard)
        return self.blackboard

    def _blackboard_touch(self):
        board = self._ensure_blackboard()
        board["updated_at"] = float(now_ts())
        self.blackboard = board

    def _blackboard_reset_for_goal(self, goal: str):
        # Preserve plan state when safe, but refresh loaded skills on goal change.
        old_bb = self._ensure_blackboard()
        preserved_skills = old_bb.get("loaded_skills", {})
        preserved_skills_sig = str(old_bb.get("loaded_skills_goal_sig", "") or "")
        new_goal_sig = self._loaded_skills_goal_signature(goal)
        preserved_plan = old_bb.get("plan", {})
        preserved_todos = old_bb.get("project_todos", [])
        preserved_cursor = old_bb.get("plan_step_cursor", None)
        preserved_total = old_bb.get("plan_step_total", None)
        self.blackboard = self._new_blackboard(goal)
        if (
            isinstance(preserved_skills, dict)
            and preserved_skills
            and preserved_skills_sig
            and preserved_skills_sig == new_goal_sig
        ):
            self.blackboard["loaded_skills"] = preserved_skills
            self.blackboard["loaded_skills_goal_sig"] = preserved_skills_sig
            self.blackboard["loaded_skills_goal_preview"] = trim(str(goal or ""), 240)
        # Restore plan state if plan is active (any phase) or todos have pending work
        has_active_plan = (
            isinstance(preserved_plan, dict)
            and preserved_plan.get("phase") in ("executing", "research", "synthesis", "awaiting_choice")
        )
        has_active_todos = isinstance(preserved_todos, list) and any(
            t.get("status") != "completed" for t in preserved_todos if isinstance(t, dict)
        )
        if has_active_plan or has_active_todos:
            if isinstance(preserved_plan, dict):
                self.blackboard["plan"] = preserved_plan
            if isinstance(preserved_todos, list) and preserved_todos:
                self.blackboard["project_todos"] = preserved_todos
            if preserved_cursor is not None:
                self.blackboard["plan_step_cursor"] = preserved_cursor
            if preserved_total is not None:
                self.blackboard["plan_step_total"] = preserved_total
        self.manager_context = []
        self.agent_messages = [m for m in self.agent_messages if m.get("agent_role") != "manager"]
        self.manager_routes = []
        self._blackboard_history("manager", f"new goal accepted: {trim(goal, 300)}")
        self._sync_todos_from_blackboard(reason="goal-reset", board=self.blackboard)

    def _blackboard_history(self, actor: str, content: str):
        txt = trim(str(content or "").strip(), BLACKBOARD_MAX_TEXT)
        if not txt:
            return
        board = self._ensure_blackboard()
        rows = list(board.get("conversation_history", []))
        rows.append({"ts": float(now_ts()), "actor": trim(str(actor or "").strip(), 40), "content": txt})
        board["conversation_history"] = rows[-BLACKBOARD_MAX_LOG_ENTRIES:]
        self._blackboard_touch()

    def _blackboard_append_section(self, section: str, actor: str, content: str):
        key = str(section or "").strip()
        _ALLOWED = {"research_notes", "execution_logs", "review_feedback",
                     "plan_findings", "plan_proposal", "plan_steps", "plan_risks",
                     "skill_analysis"}
        if key not in _ALLOWED:
            return
        txt = trim(str(content or "").strip(), BLACKBOARD_MAX_TEXT)
        if not txt:
            return
        board = self._ensure_blackboard()
        rows = list(board.get(key, []))
        rows.append({"ts": float(now_ts()), "actor": trim(str(actor or "").strip(), 40), "content": txt})
        board[key] = rows[-BLACKBOARD_MAX_LOG_ENTRIES:]
        self._blackboard_touch()

    def _blackboard_upsert_artifact(self, rel_path: str, summary: str, actor: str):
        path = normalize_rel_preview_path(str(rel_path or "")) or trim(str(rel_path or "").strip(), 280)
        if not path:
            return
        txt = trim(str(summary or "").strip(), BLACKBOARD_MAX_TEXT)
        if not txt:
            return
        board = self._ensure_blackboard()
        artifacts = dict(board.get("code_artifacts", {}))
        prev = artifacts.get(path, {}) if isinstance(artifacts.get(path), dict) else {}
        artifacts[path] = {
            "summary": txt,
            "last_actor": trim(str(actor or "").strip(), 40),
            "updated_at": float(now_ts()),
            "change_count": max(1, int(prev.get("change_count", 0) or 0) + 1),
        }
        if len(artifacts) > 240:
            rows = sorted(artifacts.items(), key=lambda item: float(item[1].get("updated_at", 0.0) or 0.0))
            artifacts = dict(rows[-240:])
        board["code_artifacts"] = artifacts
        self._blackboard_touch()

    def _todo_owner_display_name(self, owner: str) -> str:
        return self._agent_display_name(owner)

    def _todo_stage_focus_owner(self, board: dict | None = None) -> str:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        approval = bb.get("approval", {}) if isinstance(bb.get("approval"), dict) else {}
        if bool(approval.get("approved", False)):
            return ""
        delegate = bb.get("last_delegate", {}) if isinstance(bb.get("last_delegate"), dict) else {}
        delegate_target = self._sanitize_agent_role(delegate.get("target", ""))
        if delegate_target:
            return delegate_target
        active = self._sanitize_agent_role(bb.get("active_agent", ""))
        if active:
            return active
        profile = self._ensure_blackboard_task_profile(bb)
        mode = normalize_execution_mode(
            profile.get("execution_mode", self._effective_execution_mode()),
            default=self._effective_execution_mode(),
        )
        if mode == EXECUTION_MODE_SINGLE:
            expert = self._sanitize_agent_role(profile.get("assigned_expert", self.runtime_assigned_expert))
            if expert:
                return expert
        status = self._normalize_blackboard_status(bb.get("status", "INITIALIZING"))
        if status in {"INITIALIZING", "PAUSED"}:
            return "manager"
        if status == "RESEARCHING":
            return "explorer"
        if status == "CODING":
            return "developer"
        if status in {"TESTING", "REVIEWING"}:
            return "reviewer"
        return "manager"

    def _todo_node_anchor(self, board: dict | None = None) -> tuple[str, float, dict]:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        delegate = bb.get("last_delegate", {}) if isinstance(bb.get("last_delegate"), dict) else {}
        try:
            anchor_ts = float(delegate.get("ts", 0.0) or 0.0)
        except Exception:
            anchor_ts = 0.0
        if anchor_ts <= 0.0:
            profile = self._ensure_blackboard_task_profile(bb)
            try:
                anchor_ts = float(profile.get("updated_at", 0.0) or 0.0)
            except Exception:
                anchor_ts = 0.0
        if anchor_ts <= 0.0:
            try:
                anchor_ts = float(bb.get("updated_at", 0.0) or 0.0)
            except Exception:
                anchor_ts = 0.0
        cycle = max(0, int(bb.get("manager_cycles", 0) or 0))
        target = self._sanitize_agent_role(delegate.get("target", ""))
        anchor_id = f"n{cycle}:{target or '-'}:{int(anchor_ts)}"
        return anchor_id, float(anchor_ts), delegate

    def _todo_owner_has_node_evidence(
        self,
        owner: str,
        anchor_ts: float,
        board: dict | None = None,
    ) -> bool:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        role = str(owner or "").strip().lower()
        if role not in {"manager", "explorer", "developer", "reviewer"}:
            return False
        since = max(0.0, float(anchor_ts or 0.0))

        def _rows_hit(rows: object, actor: str = "") -> bool:
            arr = rows if isinstance(rows, list) else []
            actor_key = str(actor or "").strip().lower()
            for row in reversed(arr):
                if not isinstance(row, dict):
                    continue
                try:
                    ts = float(row.get("ts", 0.0) or 0.0)
                except Exception:
                    ts = 0.0
                if ts + 1e-6 < since:
                    break
                if actor_key and str(row.get("actor", "") or "").strip().lower() != actor_key:
                    continue
                if str(row.get("content", "") or "").strip():
                    return True
            return False

        last_reply = bb.get("last_worker_reply", {}) if isinstance(bb.get("last_worker_reply"), dict) else {}
        last_role = self._sanitize_agent_role(last_reply.get("role", ""))
        try:
            last_ts = float(last_reply.get("ts", 0.0) or 0.0)
        except Exception:
            last_ts = 0.0
        last_text = str(last_reply.get("text", "") or "").strip()
        if last_role == role and last_ts + 1e-6 >= since and last_text:
            return True

        if role == "manager":
            delegate = bb.get("last_delegate", {}) if isinstance(bb.get("last_delegate"), dict) else {}
            target = self._sanitize_agent_role(delegate.get("target", ""))
            try:
                delegate_ts = float(delegate.get("ts", 0.0) or 0.0)
            except Exception:
                delegate_ts = 0.0
            return bool(target and delegate_ts + 1e-6 >= since)

        if role == "explorer":
            return (
                _rows_hit(bb.get("research_notes", []), actor="explorer")
                or _rows_hit(bb.get("execution_logs", []), actor="explorer")
            )

        if role == "developer":
            artifacts = bb.get("code_artifacts", {}) if isinstance(bb.get("code_artifacts"), dict) else {}
            for item in artifacts.values():
                if not isinstance(item, dict):
                    continue
                if str(item.get("last_actor", "") or "").strip().lower() != "developer":
                    continue
                try:
                    updated_at = float(item.get("updated_at", 0.0) or 0.0)
                except Exception:
                    updated_at = 0.0
                if updated_at + 1e-6 >= since:
                    return True
            return _rows_hit(bb.get("execution_logs", []), actor="developer")

        approval = bb.get("approval", {}) if isinstance(bb.get("approval"), dict) else {}
        if bool(approval.get("approved", False)):
            try:
                approval_ts = float(approval.get("ts", 0.0) or 0.0)
            except Exception:
                approval_ts = 0.0
            if approval_ts + 1e-6 >= since:
                return True
        return (
            _rows_hit(bb.get("review_feedback", []), actor="reviewer")
            or _rows_hit(bb.get("execution_logs", []), actor="reviewer")
        )

    def _todo_owner_rows_from_blackboard(self, board: dict | None = None) -> list[dict]:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        profile = self._ensure_blackboard_task_profile(bb)
        approval = bb.get("approval", {}) if isinstance(bb.get("approval"), dict) else {}
        approved = bool(approval.get("approved", False))
        task_type = str(profile.get("task_type", "general") or "general")
        mode = normalize_execution_mode(
            profile.get("execution_mode", self._effective_execution_mode()),
            default=self._effective_execution_mode(),
        )
        assigned = self._sanitize_agent_role(profile.get("assigned_expert", self.runtime_assigned_expert)) or "developer"
        participants: list[str] = []
        raw_participants = profile.get("participants", self.runtime_participants)
        if isinstance(raw_participants, list):
            for item in raw_participants:
                role = self._sanitize_agent_role(item)
                if role and role not in participants:
                    participants.append(role)
        if mode == EXECUTION_MODE_SINGLE:
            participants = [assigned]
        if not participants:
            participants = [assigned]
        owners = ["manager"] + [role for role in participants if role not in {"manager"}]
        owners_unique: list[str] = []
        for owner in owners:
            if owner and owner not in owners_unique:
                owners_unique.append(owner)
        owners = owners_unique

        anchor_id, anchor_ts, delegate = self._todo_node_anchor(bb)
        delegate_target = self._sanitize_agent_role(delegate.get("target", ""))
        objective = trim(str(profile.get("direct_objective", "") or "").strip(), 220)
        instruction = trim(str(delegate.get("instruction", "") or "").strip(), 220)
        node_topic = objective or instruction or trim(str(bb.get("original_goal", "") or "").strip(), 220)

        def _owner_desc(owner: str) -> str:
            if owner == "manager":
                if delegate_target:
                    return self._ui_text(
                        "node_desc_manager_active",
                        target=self._agent_display_name(delegate_target),
                    )
                return self._ui_text("node_desc_manager")
            if owner == "explorer":
                if delegate_target == "explorer":
                    return self._ui_text("node_desc_explorer_active")
                return self._ui_text("node_desc_explorer")
            if owner == "developer":
                if delegate_target == "developer":
                    return self._ui_text("node_desc_developer_active")
                return self._ui_text("node_desc_developer")
            if owner == "reviewer":
                if delegate_target == "reviewer":
                    return self._ui_text("node_desc_reviewer_active")
                return self._ui_text("node_desc_reviewer")
            return self._ui_text("node_desc_generic")

        finish_ok, _ = self._can_auto_finish_from_approval(bb)
        rows: list[dict] = []
        for owner in owners:
            key = f"bb:node:{anchor_id}:owner:{owner}"
            desc = _owner_desc(owner)
            label = self._todo_owner_display_name(owner)
            content = f"[{label}] {desc}"
            if finish_ok and approved:
                done = True
            elif owner == "manager":
                done = bool(delegate_target) and anchor_ts > 0.0
            else:
                done = self._todo_owner_has_node_evidence(owner, anchor_ts, bb)
            if task_type == "simple_qa" and owner == "reviewer" and (not done):
                done = self._todo_owner_has_node_evidence("developer", anchor_ts, bb)
            row_status = "completed" if bool(done) else "pending"
            rows.append(
                {
                    "key": key,
                    "owner": owner,
                    "content": content,
                    "status": row_status,
                    "activeForm": f"Pending ({label}): {desc}",
                }
            )

        focus = self._todo_stage_focus_owner(bb)
        if focus and focus not in owners:
            focus = ""
        if focus:
            for row in rows:
                if str(row.get("owner", "") or "").strip().lower() == focus and row.get("status") != "completed":
                    row["status"] = "in_progress"
                    break
        if not any(str(x.get("status", "")) == "in_progress" for x in rows):
            for row in rows:
                if row.get("status") == "pending":
                    row["status"] = "in_progress"
                    break

        for row in rows:
            owner = str(row.get("owner", "") or "")
            label = self._todo_owner_display_name(owner)
            text = str(row.get("content", "") or "")
            text = re.sub(r"^\[[^\]]+\]\s*", "", text).strip() or text
            status_value = str(row.get("status", "pending") or "pending")
            topic_suffix = ""
            if node_topic and status_value == "in_progress":
                topic_suffix = self._ui_text("todo_node_suffix", topic=trim(node_topic, 140))
            if status_value == "in_progress":
                row["activeForm"] = self._ui_text(
                    "todo_working_owner",
                    owner=label,
                    content=f"{text}{topic_suffix}",
                )
            elif status_value == "completed":
                row["activeForm"] = self._ui_text("todo_completed_owner", owner=label, content=text)
            else:
                row["activeForm"] = self._ui_text("todo_pending_owner", owner=label, content=text)
        return rows

    # ── Project-based todo generation & status tracking ──────────────

    def _generate_project_todos_from_profile(self, board: dict | None = None) -> list[dict]:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        profile = self._ensure_blackboard_task_profile(bb)
        task_type = str(profile.get("task_type", "general") or "general")
        objective = trim(str(profile.get("direct_objective", "") or ""), 200)

        if task_type == "simple_qa":
            return [
                {
                    "content": self._ui_text("project_answer_objective", objective=objective)
                    if objective
                    else self._ui_text("project_answer_default"),
                    "category": "implement",
                }
            ]

        if task_type in ("simple_code", "engineering"):
            return [
                {"content": self._ui_text("project_analyze_requirements"), "category": "setup"},
                {
                    "content": self._ui_text("project_implement_objective", objective=objective)
                    if objective
                    else self._ui_text("project_implement_default"),
                    "category": "implement",
                },
                {"content": self._ui_text("project_compile_check"), "category": "compile_test"},
                {"content": self._ui_text("project_min_test"), "category": "min_test"},
            ]

        if task_type == "research":
            return [
                {
                    "content": self._ui_text("project_research_objective", objective=objective)
                    if objective
                    else self._ui_text("project_research_default"),
                    "category": "implement",
                },
                {"content": self._ui_text("project_research_summary"), "category": "review"},
            ]

        return [
            {
                "content": self._ui_text("project_execute_objective", objective=objective)
                if objective
                else self._ui_text("project_execute_default"),
                "category": "implement",
            }
        ]

    def _init_project_todos(self, board: dict | None = None):
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        if bb.get("project_todos"):
            return
        # 如果有已审批的 plan steps，优先用 plan steps 生成 todos
        plan = bb.get("plan", {})
        if isinstance(plan, dict) and plan.get("phase") == "executing" and plan.get("steps"):
            plan_todos = self._build_plan_todos_from_steps(plan.get("steps", []), limit=40)
            if plan_todos:
                bb["project_todos"] = plan_todos
                bb["plan_step_cursor"] = 0
                bb["plan_step_total"] = len(plan_todos)
                self.blackboard = bb
                self._blackboard_touch()
                return
        raw = self._generate_project_todos_from_profile(bb)
        bb["project_todos"] = [
            {
                "id": f"pt:{i:03d}",
                "content": t["content"],
                "status": "pending",
                "category": t["category"],
                "created_at": float(now_ts()),
                "completed_at": None,
                "completed_by": "",
                "evidence": "",
            }
            for i, t in enumerate(raw)
        ]
        self.blackboard = bb
        self._blackboard_touch()

    def _has_compile_pass_evidence(self, board: dict | None = None) -> bool:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        logs = bb.get("execution_logs", []) if isinstance(bb.get("execution_logs"), list) else []
        if not logs:
            return False
        positive = ("compiled successfully", "build successful", "0 error", "编译成功",
                     "syntax ok", "no errors", "build succeeded", "compilation successful")
        negative = ("error:", "fatal error", "syntax error", "compile error", "build failed")
        for entry in reversed(logs[-6:]):
            txt = str((entry or {}).get("content", "") or "").lower() if isinstance(entry, dict) else str(entry or "").lower()
            if not txt:
                continue
            if any(neg in txt for neg in negative):
                continue
            if any(pos in txt for pos in positive):
                return True
        return False

    def _has_test_pass_evidence(self, board: dict | None = None) -> bool:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        logs = bb.get("execution_logs", []) if isinstance(bb.get("execution_logs"), list) else []
        feedback = bb.get("review_feedback", []) if isinstance(bb.get("review_feedback"), list) else []
        positive = ("test passed", "tests passed", "测试通过", "运行正常",
                     "all tests pass", "ok", "passed", "test succeeded")
        negative = ("failed", "error", "failure", "测试失败")
        combined = list(logs[-6:]) + list(feedback[-4:])
        for entry in reversed(combined[-8:]):
            txt = str((entry or {}).get("content", "") or "").lower() if isinstance(entry, dict) else str(entry or "").lower()
            if not txt:
                continue
            if any(neg in txt for neg in negative):
                continue
            if any(pos in txt for pos in positive):
                return True
        return False

    def _update_project_todo_status(self, board: dict | None = None):
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        todos = bb.get("project_todos", [])
        if not todos:
            return
        code_count = len(bb.get("code_artifacts", {}) or {})
        research_count = len(bb.get("research_notes", []) or [])
        feedback_pass = self._manager_feedback_passed_from_blackboard(bb)

        for todo in todos:
            if todo.get("status") == "completed":
                continue
            cat = todo.get("category", "")
            if cat == "setup" and (research_count > 0 or code_count > 0):
                todo.update(
                    status="completed",
                    completed_at=float(now_ts()),
                    evidence=self._ui_text("evidence_structure_analyzed"),
                )
            elif cat == "implement" and code_count > 0:
                todo.update(
                    status="completed",
                    completed_at=float(now_ts()),
                    completed_by="developer",
                    evidence=self._ui_text("evidence_files_produced", count=code_count),
                )
            elif cat == "compile_test" and self._has_compile_pass_evidence(bb):
                todo.update(
                    status="completed",
                    completed_at=float(now_ts()),
                    evidence=self._ui_text("evidence_compile_passed"),
                )
            elif cat == "min_test" and self._has_test_pass_evidence(bb):
                todo.update(
                    status="completed",
                    completed_at=float(now_ts()),
                    evidence=self._ui_text("evidence_test_passed"),
                )
            elif cat == "review" and feedback_pass:
                todo.update(
                    status="completed",
                    completed_at=float(now_ts()),
                    evidence=self._ui_text("evidence_review_passed"),
                )
            elif cat == "plan_step":
                # Plan steps 不自动完成，由 _advance_plan_step 显式推进
                # 但如果当前步骤之前的所有步骤都完成了，标记当前步骤为 in_progress
                if todo.get("status") == "pending":
                    step_idx = int(todo.get("plan_step_index", 0) or 0)
                    all_prior_done = all(
                        t.get("status") == "completed"
                        for t in todos
                        if t.get("category") == "plan_step"
                        and int(t.get("plan_step_index", 0) or 0) < step_idx
                    )
                    if all_prior_done and not any(
                        t.get("status") == "in_progress"
                        for t in todos
                        if t.get("category") == "plan_step"
                    ):
                        todo["status"] = "in_progress"

        if not any(t.get("status") == "in_progress" for t in todos):
            for t in todos:
                if t.get("status") == "pending":
                    t["status"] = "in_progress"
                    break

        bb["project_todos"] = todos
        self.blackboard = bb

    def _instruction_implies_step_advance(self, instruction: str, reason: str = "") -> bool:
        """Detect if manager instruction semantically implies current plan step is done."""
        bb = self._ensure_blackboard()
        plan_steps = [t for t in bb.get("project_todos", []) if t.get("category") == "plan_step"]
        if not plan_steps:
            return False
        # Must have an in_progress step to advance
        current = None
        for t in plan_steps:
            if t.get("status") == "in_progress":
                current = t
                break
        if not current:
            return False
        text = (str(instruction or "") + " " + str(reason or "")).lower()
        # Patterns that indicate step completion — only BACKWARD-looking signals
        # (agent/manager explicitly says a step is done, NOT forward-looking dispatch instructions)
        step_done_patterns = (
            "审查通过", "通过审查", "已通过", "已完成", "完成了",
            "step completed", "step done", "step passed",
            "阶段完成", "阶段通过", "phase complete",
            "步骤 1.1 已完成", "步骤 1.2 已完成", "步骤 1.3 已完成",
            "步骤 1.4 已完成", "步骤 1.5 已完成",
        )
        # NOTE: intentionally excluded forward-looking dispatch patterns:
        #   "现在执行步骤", "执行步骤 1.2", "执行步骤 1.3", "进入下一步", "next step",
        #   "proceed to step", "进入 step", "开始 step" — these are manager dispatch
        #   instructions, NOT evidence that the current step was completed.
        import re
        current_idx = int(current.get("plan_step_index", 0) or 0)
        # Only advance when an agent explicitly says "进入 Step N" where N > current+1
        # (skipping ahead), NOT when manager dispatches the very next step.
        next_step_pattern = re.search(
            r'(?:进入|enter|move\s+to|start|proceed\s+to)\s*(?:step\s*)?(\d+)',
            text, re.IGNORECASE
        )
        if next_step_pattern:
            mentioned_step = int(next_step_pattern.group(1))
            if mentioned_step > current_idx + 2:  # must skip at least 2 ahead to be meaningful
                return True
        # "完成步骤 1.1，开始 1.2" — only if explicitly marking current step done
        step_ref = re.search(r'(?:完成|finished|done)\s*步骤\s*1\.(\d+)', text)
        if step_ref:
            ref_sub = int(step_ref.group(1))
            if ref_sub == current_idx + 1:  # explicitly says current step (1-based) is done
                return True
        return any(pat in text for pat in step_done_patterns)

    def _advance_plan_step(self, evidence: str = "", actor: str = "developer"):
        bb = self._ensure_blackboard()
        todos = bb.get("project_todos", [])
        if not todos:
            return False
        current = None
        for t in todos:
            if t.get("category") == "plan_step" and t.get("status") == "in_progress":
                current = t
                break
        if not current:
            return False
        current["status"] = "completed"
        current["completed_at"] = float(now_ts())
        current["completed_by"] = actor
        current["evidence"] = trim(str(evidence or "").strip(), 200) or self._ui_text("step_completed_evidence")
        # 推进 cursor，激活下一步
        cursor = int(bb.get("plan_step_cursor", 0) or 0)
        bb["plan_step_cursor"] = cursor + 1
        next_step = None
        for t in todos:
            if t.get("category") == "plan_step" and t.get("status") == "pending":
                next_step = t
                break
        if next_step:
            next_step["status"] = "in_progress"
            step_idx = int(next_step.get("plan_step_index", 0) or 0) + 1
            total = int(bb.get("plan_step_total", len(todos)) or len(todos))
            self._emit("status", {
                "summary": self._ui_text(
                    "plan_step_summary",
                    step=step_idx,
                    total=total,
                    content=trim(str(next_step.get("content", "") or ""), 120),
                )
            })
        self.blackboard = bb
        self._blackboard_touch()
        # Persist step status change to plan.md
        try:
            self._update_plan_file_step_status()
        except Exception:
            pass  # Plan file update is best-effort
        # 步骤推进时按 parent_step_id 清除对应步骤的 worker 子任务
        # 保留 completed 的 worker 项和不属于当前步骤的 worker 项
        completed_step_id = str(current.get("id", "") or "")
        try:
            _snap = self.todo.snapshot()
            _clean = [
                r for r in _snap
                if str(r.get("parent_step_id", "") or "") != completed_step_id
                or str(r.get("status", "") or "").lower() == "completed"
            ]
            if len(_clean) < len(_snap):
                with self.todo.lock:
                    self.todo.items = _clean
        except Exception:
            pass
        # Immediately sync todos so UI reflects plan step advancement
        self._sync_todos_from_blackboard(reason=f"plan-step-advanced:{cursor + 1}", board=bb)
        # Inject hint for the next step (works in both single and multi-agent mode)
        if next_step:
            try:
                _ns_idx = int(next_step.get("plan_step_index", 0) or 0) + 1
                _ns_total = int(bb.get("plan_step_total", 0) or 0)
                _ns_text = trim(str(next_step.get("content", "") or ""), 200)
                _ns_id = str(next_step.get("id", "") or "")
                _ns_label = self._ui_text("plan_step_label", step=_ns_idx, total=_ns_total)
                _hint = self._ui_text(
                    "plan_step_hint",
                    step_label=_ns_label,
                    step_text=_ns_text,
                    plan_path=PLAN_FILE_RELATIVE_PATH,
                    parent_step_id=_ns_id,
                )
                target_roles: tuple[str, ...] = ()
                if self._is_multi_agent_mode():
                    active_role = str(bb.get("active_agent", "") or actor)
                    if active_role:
                        target_roles = (active_role,)
                self._append_plan_guidance_bubble(
                    _hint,
                    target_roles=target_roles,
                    summary=f"plan step bubble injected ({_ns_idx}/{_ns_total})",
                )
            except Exception:
                pass
        return True

    def _post_execution_plan_step_check(self, route: dict, worker_step: dict):
        """After worker execution, check if current plan step should advance based on evidence."""
        bb = self._ensure_blackboard()
        current = next(
            (t for t in bb.get("project_todos", [])
             if t.get("category") == "plan_step" and t.get("status") == "in_progress"),
            None,
        )
        if not current:
            # No plan steps — detect finish_current_task for pure-sync mode coordination.
            # Sets sync_worker_round_done flag so the sync loop can signal the manager.
            # Only reachable in pure sync mode (no plan steps); plan+sync always has `current`
            # set, so this branch never executes for plan modes.
            results = worker_step.get("tool_results", []) or []
            called_finish = any(
                isinstance(r, dict) and r.get("ok")
                and str(r.get("name", "")) in ("finish_current_task", "finish_task")
                for r in results
            )
            if called_finish:
                bb["sync_worker_round_done"] = True
                self._save_blackboard(bb)
            return
        # 1. Manager explicitly requested advancement
        manager_requested = bool(route.get("advance_plan_step_requested", False))
        # 2. Worker produced concrete tool outputs
        worker_produced_output = self._worker_step_has_evidence(worker_step)
        # 3. All subtasks for this step are completed
        subtasks_all_done = self._step_subtasks_all_completed(current)
        # 4. Phase-based file+bash evidence (implement requires BOTH write + bash)
        step_content = str(current.get("full_content", "") or current.get("content", "") or "").lower()
        phase = self._plan_step_phase_hint(step_content)
        results = worker_step.get("tool_results", []) or []
        wrote_files = any(
            isinstance(r, dict) and r.get("ok", False)
            and str(r.get("name", "")) in ("write_file", "edit_file")
            for r in results
        )
        ran_bash_ok = any(
            isinstance(r, dict) and r.get("ok", False) and str(r.get("name", "")) == "bash"
            for r in results
        )
        phase_evidence = False
        if phase in ("research", "design") and wrote_files:
            phase_evidence = True
        elif phase == "implement" and wrote_files and ran_bash_ok:
            phase_evidence = True
        elif phase in ("test", "review") and ran_bash_ok:
            phase_evidence = True
        # Advance when:
        # - Manager requested AND worker produced output, OR
        # - All subtasks completed AND worker produced output, OR
        # - Phase heuristics confirm (write+bash for implement)
        has_strong_evidence = worker_produced_output and (
            manager_requested or subtasks_all_done or phase_evidence
        )
        if has_strong_evidence:
            evidence = self._collect_step_evidence(current, worker_step)
            self._advance_plan_step(
                evidence=evidence,
                actor=str(route.get("target", "developer") or "developer"),
            )

    def _worker_step_has_evidence(self, step: dict) -> bool:
        """Check if worker step produced concrete tool outputs."""
        results = step.get("tool_results", []) or []
        return any(
            r.get("ok", False) and str(r.get("name", "")) in (
                "write_file", "edit_file", "bash", "read_file",
                "write_to_blackboard",
            )
            for r in results
            if isinstance(r, dict)
        )

    def _step_subtasks_all_completed(self, plan_step: dict) -> bool:
        """Check if all worker subtasks linked to this plan step are completed.
        Filters out cross-step subtasks (e.g., 2.1 under step 1) to prevent blocking."""
        step_id = str(plan_step.get("id", "") or "")
        if not step_id:
            return False
        snap = self.todo.snapshot()
        worker_owners = {"developer", "explorer", "reviewer"}
        worker_items = [
            r for r in snap
            if str(r.get("owner", "") or "").lower() in worker_owners
            and str(r.get("parent_step_id", "") or "") == step_id
        ]
        if not worker_items:
            expected = self._extract_plan_step_subtasks(plan_step, limit=5)
            if expected:
                return False
            # Fallback: no parent_step_id linkage — check ALL worker items
            all_worker = [
                r for r in snap
                if str(r.get("owner", "") or "").lower() in worker_owners
            ]
            if all_worker:
                return all(str(r.get("status", "")).lower() == "completed" for r in all_worker)
            return True  # No worker items at all → nothing blocks advancement
        # Extract major step number from plan step content (e.g., "1. Project init" → "1")
        import re
        step_content = str(plan_step.get("full_content", "") or plan_step.get("content", "") or "")
        _m = re.match(r"^(\d+)\.", step_content.strip())
        active_major = _m.group(1) if _m else ""
        # Filter out cross-step subtasks (N.M where N != active major)
        if active_major:
            _cross_re = re.compile(r"^(\d+)\.\d+\s")
            relevant = []
            for r in worker_items:
                rc = str(r.get("content", "") or "").strip()
                cm = _cross_re.match(rc)
                if cm and cm.group(1) != active_major:
                    continue  # Skip cross-step items — don't let them block advancement
                relevant.append(r)
            if relevant:
                worker_items = relevant
        return all(str(r.get("status", "")).lower() == "completed" for r in worker_items)

    def _collect_step_evidence(self, plan_step: dict, worker_step: dict) -> str:
        """Collect evidence summary from worker step for plan step completion."""
        parts = []
        results = worker_step.get("tool_results", []) or []
        for r in results:
            if not isinstance(r, dict) or not r.get("ok", False):
                continue
            name = str(r.get("name", ""))
            if name in ("write_file", "edit_file"):
                path = str(r.get("args", {}).get("path", "") or "")
                parts.append(f"{name}: {path}")
            elif name == "bash":
                cmd = trim(str(r.get("args", {}).get("command", "") or ""), 80)
                parts.append(f"bash: {cmd}")
            elif name == "read_file":
                path = str(r.get("args", {}).get("path", "") or "")
                parts.append(f"read: {path}")
        return trim("; ".join(parts) or "post-execution evidence", 200)

    def _get_active_plan_step(self, board: dict | None = None) -> dict | None:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        todos = bb.get("project_todos", []) if isinstance(bb.get("project_todos", []), list) else []
        for todo in todos:
            if isinstance(todo, dict) and todo.get("category") == "plan_step" and todo.get("status") == "in_progress":
                return todo
        return None

    def _current_plan_worker_owner(self, board: dict | None = None) -> str:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        delegate = bb.get("last_delegate", {}) if isinstance(bb.get("last_delegate"), dict) else {}
        candidates = [
            str(self.active_agent_role or "").strip().lower(),
            str(bb.get("active_agent", "") or "").strip().lower(),
            str(delegate.get("target", "") or "").strip().lower(),
        ]
        for cand in candidates:
            if cand in {"developer", "explorer", "reviewer"}:
                return cand
        return "developer"

    def _active_plan_worker_todo_rows(self, step_id: str, role: str = "") -> list[dict]:
        step_key = str(step_id or "").strip()
        if not step_key:
            return []
        role_key = self._sanitize_agent_role(role)
        all_rows: list[dict] = []
        for row in self.todo.snapshot():
            if not isinstance(row, dict):
                continue
            if str(row.get("parent_step_id", "") or "").strip() != step_key:
                continue
            owner = str(row.get("owner", "") or "").strip().lower()
            if owner not in {"developer", "explorer", "reviewer"}:
                continue
            all_rows.append(dict(row))
        if not all_rows:
            return []
        rows = [r for r in all_rows if str(r.get("owner", "") or "").strip().lower() == role_key] if role_key else list(all_rows)
        if role_key and not rows:
            rows = list(all_rows)
        order = {"in_progress": 0, "pending": 1, "completed": 2}
        rows.sort(
            key=lambda r: (
                order.get(str(r.get("status", "pending") or "pending").strip().lower(), 9),
                str(r.get("owner", "") or "").strip().lower(),
                str(r.get("content", "") or "").strip().lower(),
            )
        )
        return rows

    def _active_plan_step_has_worker_todos(self, role: str = "") -> bool:
        step = self._get_active_plan_step()
        if not isinstance(step, dict):
            return False
        step_id = str(step.get("id", "") or "").strip()
        if not step_id:
            return False
        return bool(self._active_plan_worker_todo_rows(step_id, role=role))

    def _todo_runtime_has_worker_rows(self, role: str = "") -> bool:
        if self._get_active_plan_step() is not None:
            return self._active_plan_step_has_worker_todos(role=role)
        return bool(self.todo.snapshot())

    def _plan_worker_todo_identity(self, row: dict | None) -> str:
        import re

        if not isinstance(row, dict):
            return ""
        content = normalize_work_text(str(row.get("content", "") or "")) or str(row.get("content", "") or "")
        content = re.sub(r"\s+", " ", content.strip().lower())
        if not content:
            return ""
        match = re.match(r"^(\d+\.\d+)\b", content)
        if match:
            return f"substep:{match.group(1)}"
        return f"text:{content}"

    def _merge_plan_worker_todo_items(self, items: list[dict], role: str = "") -> str:
        if not isinstance(items, list):
            raise ValueError("items must be array")
        active_step = self._get_active_plan_step()
        if not isinstance(active_step, dict):
            return self.todo.update(items)
        step_id = trim(str(active_step.get("id", "") or ""), 20)
        if not step_id:
            return self.todo.update(items)
        role_key = self._sanitize_agent_role(role) or self._current_plan_worker_owner()
        existing = self.todo.snapshot()
        preserved: list[dict] = []
        target_rows: list[dict] = []
        worker_owners = {"developer", "explorer", "reviewer"}
        for row in existing:
            if not isinstance(row, dict):
                continue
            owner = str(row.get("owner", "") or "").strip().lower()
            row_step_id = trim(str(row.get("parent_step_id", "") or ""), 20)
            if owner in worker_owners and row_step_id == step_id:
                target_rows.append(dict(row))
            else:
                preserved.append(dict(row))

        merged_by_identity: dict[str, dict] = {}
        ordered_identities: list[str] = []
        for row in target_rows:
            identity = self._plan_worker_todo_identity(row)
            if not identity:
                continue
            if identity not in merged_by_identity:
                merged_by_identity[identity] = dict(row)
                ordered_identities.append(identity)

        incoming_normalized: list[dict] = []
        for idx, item in enumerate(items):
            if isinstance(item, str):
                raw = {"content": item, "status": "pending"}
            elif isinstance(item, dict):
                raw = dict(item)
            else:
                raise ValueError(f"item {idx}: invalid type")
            key = trim(str(raw.get("key", "") or "").strip(), 120)
            if key.startswith("bb:"):
                incoming_normalized.append(raw)
                continue
            owner = str(raw.get("owner", "") or "").strip().lower()
            if owner not in worker_owners:
                raw["owner"] = role_key
            parent_step_id = trim(str(raw.get("parent_step_id", "") or ""), 20)
            if not parent_step_id:
                raw["parent_step_id"] = step_id
            incoming_normalized.append(raw)

        passthrough_rows = [row for row in incoming_normalized if str(row.get("key", "") or "").startswith("bb:")]
        incoming_worker_rows = [row for row in incoming_normalized if not str(row.get("key", "") or "").startswith("bb:")]

        for row in incoming_worker_rows:
            identity = self._plan_worker_todo_identity(row)
            if not identity:
                identity = f"ad-hoc:{len(ordered_identities)}:{trim(str(row.get('content', '') or ''), 80)}"
            merged = dict(merged_by_identity.get(identity, {}))
            if "activeForm" not in row and "active_form" not in row:
                merged.pop("activeForm", None)
            merged.update(row)
            merged["owner"] = str(merged.get("owner", "") or role_key).strip().lower() or role_key
            merged["parent_step_id"] = trim(str(merged.get("parent_step_id", "") or step_id), 20) or step_id
            merged_by_identity[identity] = merged
            if identity not in ordered_identities:
                ordered_identities.append(identity)

        merged_target_rows = [merged_by_identity[i] for i in ordered_identities if i in merged_by_identity]
        final_rows = preserved + passthrough_rows + merged_target_rows
        return self.todo.update(final_rows)

    def _merge_owner_scoped_todo_items(self, items: list[dict], role: str = "") -> str:
        if not isinstance(items, list):
            raise ValueError("items must be array")
        role_key = self._sanitize_agent_role(role)
        if role_key not in {"developer", "explorer", "reviewer"}:
            return self.todo.update(items)
        existing = self.todo.snapshot()
        preserved: list[dict] = []
        for row in existing:
            if not isinstance(row, dict):
                continue
            key = str(row.get("key", "") or "").strip()
            owner = str(row.get("owner", "") or "").strip().lower()
            if key.startswith("bb:"):
                preserved.append(dict(row))
                continue
            if owner == role_key:
                continue
            preserved.append(dict(row))
        normalized: list[dict] = []
        for idx, item in enumerate(items):
            if isinstance(item, str):
                row = {"content": item, "status": "pending"}
            elif isinstance(item, dict):
                row = dict(item)
            else:
                raise ValueError(f"item {idx}: invalid type")
            if str(row.get("key", "") or "").startswith("bb:"):
                normalized.append(row)
                continue
            row["owner"] = role_key
            normalized.append(row)
        return self.todo.update(preserved + normalized)

    def _append_instruction_bubble(self, content: str, *, target_roles: tuple[str, ...] = (), summary: str = "") -> bool:
        text = trim(str(content or "").strip(), 2200)
        if not text:
            return False
        recent = self.messages[-8:]
        if any(str(row.get("content", "") or "").strip() == text for row in recent if isinstance(row, dict)):
            return False
        stamp = now_ts()
        self.messages.append({"role": "user", "content": text, "ts": stamp})
        for role in target_roles:
            self._append_agent_context_message(
                role,
                {
                    "role": "system",
                    "content": text,
                    "ts": stamp,
                    "agent_role": role,
                },
                mirror_to_global=False,
            )
        if summary:
            self._emit("status", {"summary": trim(summary, 120)})
        return True

    def _build_plan_guidance_notice_data(self, content: str, *, summary: str = "") -> dict:
        text = trim(str(content or "").strip(), 2200)
        if not text:
            return {}
        lang = normalize_ui_language(getattr(self, "ui_language", DEFAULT_UI_LANGUAGE))
        if lang == "zh-CN":
            title = "计划执行提示"
            note = "当前计划步骤与 Todo 规则已同步到本轮执行上下文。"
        elif lang == "zh-TW":
            title = "計畫執行提示"
            note = "目前計畫步驟與 Todo 規則已同步到本輪執行上下文。"
        elif lang == "ja":
            title = "計画実行ガイド"
            note = "現在の計画ステップと Todo ルールは今回の実行コンテキストへ同期されました。"
        else:
            title = "Plan Execution Guidance"
            note = "The active plan step and Todo rules were synced into the current execution context."
        bb = self._ensure_blackboard()
        step = self._current_plan_step_row(bb)
        total = int(bb.get("plan_step_total", 0) or 0)
        step_idx = int(step.get("plan_step_index", 0) or 0) + 1 if isinstance(step, dict) else 0
        step_text = trim(str(step.get("content", "") or ""), 160) if isinstance(step, dict) else ""
        step_id = str(step.get("id", "") or "") if isinstance(step, dict) else ""
        step_label = (
            self._ui_text("plan_step_label", step=step_idx, total=max(1, total))
            if step_idx > 0
            else ""
        )
        subtitle_parts = [part for part in (step_label, step_text) if part]
        subtitle = " · ".join(subtitle_parts) or trim(str(summary or ""), 120) or PLAN_FILE_RELATIVE_PATH
        pills: list[dict] = []
        if step_label:
            pills.append({"text": step_label, "tone": "info"})
        if step_id:
            pills.append({"text": step_id, "tone": "neutral", "mono": True})
        rows = [{"label": "plan.md", "value": PLAN_FILE_RELATIVE_PATH, "mono": True}]
        if step_id:
            rows.append({"label": "parent_step_id", "value": step_id, "mono": True})
        return {
            "title": title,
            "subtitle": subtitle,
            "note": note,
            "body": text,
            "pills": pills,
            "rows": rows,
        }

    def _append_plan_guidance_bubble(self, content: str, *, target_roles: tuple[str, ...] = (), summary: str = "") -> bool:
        text = trim(str(content or "").strip(), 2200)
        if not text:
            return False
        recent = self.messages[-10:]
        if any(str(row.get("content", "") or "").strip() == text for row in recent if isinstance(row, dict)):
            return False
        stamp = now_ts()
        notice_data = self._build_plan_guidance_notice_data(text, summary=summary)
        self.messages.append({"role": "user", "content": text, "ts": stamp, "_ui_hidden": True})
        self.messages.append(
            {
                "role": "system",
                "content": "",
                "ts": stamp,
                "type": "plan_notice",
                "agent_role": "planner",
                "data": notice_data,
            }
        )
        self._emit(
            "message",
            {
                "role": "system",
                "type": "plan_notice",
                "text": "",
                "data": notice_data,
                "agent_role": "planner",
                "summary": trim(summary or str(notice_data.get("subtitle", "") or "plan guidance"), 120),
            },
        )
        for role in target_roles:
            self._append_agent_context_message(
                role,
                {
                    "role": "system",
                    "content": text,
                    "ts": stamp,
                    "agent_role": role,
                },
                mirror_to_global=False,
            )
        return True

    def _build_plan_todo_reminder_text(self, plan_step: dict, *, missing_subtasks: bool = False) -> str:
        if missing_subtasks:
            return (
                "<reminder>"
                "Please call TodoWrite now to update the current subtask before continuing. "
                "If it fails/repeats, switch to TodoWriteRescue."
                "</reminder>"
            )
        return (
            "<reminder>"
            "Update your todos now: finish the current subtask in TodoWrite before moving on."
            "</reminder>"
        )

    def _plan_todo_discipline_prompt(self, role: str = "", *, for_manager: bool = False) -> str:
        step = self._get_active_plan_step()
        if not isinstance(step, dict):
            return ""
        step_id = trim(str(step.get("id", "") or ""), 20)
        step_idx = int(step.get("plan_step_index", 0) or 0) + 1
        step_text = trim(str(step.get("content", "") or ""), 220)
        rows = self._active_plan_worker_todo_rows(step_id, role=role)
        current = next((r for r in rows if str(r.get("status", "") or "").strip().lower() == "in_progress"), None)
        pending = [r for r in rows if str(r.get("status", "") or "").strip().lower() == "pending"]
        completed = [r for r in rows if str(r.get("status", "") or "").strip().lower() == "completed"]
        if not rows:
            todo_state = (
                f"No worker subtasks exist yet for this step. BEFORE any implementation work or step-advancing tool call, "
                f"start with TodoWrite for THIS step only (parent_step_id='{step_id}') and create 3-5 subtasks with exactly one in_progress. "
            )
        else:
            state_parts: list[str] = []
            if current:
                state_parts.append(
                    f"Current in_progress subtask: {trim(str(current.get('content', '') or ''), 160)}. "
                )
            elif pending:
                state_parts.append(
                    f"Next pending subtask: {trim(str(pending[0].get('content', '') or ''), 160)}. "
                )
            state_parts.append(
                f"Existing worker subtasks for this step: {len(completed)} completed, {len(pending)} pending. "
            )
            todo_state = "".join(state_parts)
        if for_manager:
            return (
                f"PLAN/TODO DISCIPLINE: `{PLAN_FILE_RELATIVE_PATH}` is the authoritative execution path. "
                f"Delegate ONLY against the current in-progress plan step (Step {step_idx}: {step_text}). "
                f"{todo_state}"
                "Treat existing worker subtasks as live execution state, not optional notes. "
                "In every delegation, explicitly tell the owner to finish the current in_progress subtask first. "
                "After EACH completed subtask, require a manual TodoWrite or TodoWriteRescue update before the owner starts the next subtask. "
                "Do not let the owner silently batch multiple subtasks without updating todos. "
                "Do not route to finish_current_task while the approved plan still has unfinished steps."
            )
        return (
            f"PLAN/TODO DISCIPLINE: `{PLAN_FILE_RELATIVE_PATH}` is authoritative. "
            f"Work ONLY on the current in-progress plan step (Step {step_idx}: {step_text}). "
            f"{todo_state}"
            "If step subtasks already exist, continue the current in_progress subtask first instead of inventing a parallel path. "
            "After EACH completed subtask, immediately call TodoWrite or TodoWriteRescue to mark it completed and set the next subtask to in_progress before continuing. "
            "Do not wait until the end of the step to update todos. "
            "Do not call finish_current_task for a subtask or a single plan step; use it only when the overall user task is truly complete."
        )

    def _append_plan_single_todo_reminder(self, plan_step: dict, *, missing_subtasks: bool = False) -> bool:
        if not isinstance(plan_step, dict):
            return False
        step_idx = int(plan_step.get("plan_step_index", 0) or 0) + 1
        now_tick = now_ts()
        if (now_tick - self.last_todo_reminder_ts) < 8:
            return False
        content = self._build_plan_todo_reminder_text(plan_step, missing_subtasks=missing_subtasks)
        if not content:
            return False
        self.messages.append({"role": "user", "content": content, "ts": now_tick})
        self.last_todo_reminder_ts = now_tick
        self.todo_reminder_count += 1
        self._emit(
            "status",
            {
                "summary": (
                    "plan+single todo reminder injected "
                    f"(step={step_idx}, missing_subtasks={'yes' if missing_subtasks else 'no'})"
                )
            },
        )
        return True

    def _extract_plan_step_subtasks(self, plan_step: dict, limit: int = 5) -> list[str]:
        import re

        if not isinstance(plan_step, dict):
            return []
        raw = str(plan_step.get("full_content", "") or plan_step.get("content", "") or "")
        if not raw.strip():
            return []
        lines = [trim(str(line or "").strip(), 300) for line in raw.replace("\r\n", "\n").split("\n")]
        lines = [line for line in lines if line]
        if not lines:
            return []
        header = lines[0]
        numbered: list[str] = []
        bullet_fallback: list[str] = []
        substep_re = re.compile(r"^(?:[-*•]\s*)?(\d+\.\d+)\s+(.+)$")
        bullet_re = re.compile(r"^(?:[-*•]\s+)(.+)$")
        shellish_re = re.compile(r"^(?:mkdir|npx|npm|pnpm|yarn|pip|python|pytest|node|go|cargo|git|curl|wget)\b", re.I)
        for raw_line in lines[1:]:
            line = trim(raw_line, 300)
            if not line:
                continue
            m = substep_re.match(line)
            if m:
                text = f"{m.group(1)} {trim(m.group(2), 260)}".strip()
                if text and text not in numbered:
                    numbered.append(text)
                continue
            mb = bullet_re.match(line)
            if mb:
                text = trim(mb.group(1), 260)
                if text and not shellish_re.match(text):
                    bullet_fallback.append(text)
        picked = numbered or bullet_fallback
        if not picked:
            prose = [line for line in lines[1:] if not shellish_re.match(line)]
            for line in prose[: max(1, limit)]:
                text = trim(line, 260)
                if text and text != header and text not in picked:
                    picked.append(text)
        if not picked:
            phase = self._plan_step_phase_hint(raw.lower())
            phase_defaults = {
                "research": ["Read relevant context", "Collect required references", "Summarize findings for this step"],
                "design": ["Define the implementation scope", "Draft the interfaces for this step", "Confirm the design constraints"],
                "implement": ["Create the required files", "Implement the core logic for this step", "Run a quick verification"],
                "test": ["Prepare the test inputs", "Run the required checks", "Review the failing and passing results"],
                "review": ["Inspect the generated changes", "Validate the critical paths", "Summarize review findings"],
            }
            picked = phase_defaults.get(phase, ["Break down the current step", "Execute the core work", "Verify the result"])
        out: list[str] = []
        max_items = max(1, min(int(limit or 5), 7))
        for text in picked:
            clean = normalize_work_text(text) or str(text or "").strip()
            if not clean or clean == header or clean in out:
                continue
            out.append(clean)
            if len(out) >= max_items:
                break
        return out

    def _ensure_worker_todos_for_plan_step(self, plan_step: dict | None, force_refresh: bool = False, owner: str = "") -> bool:
        if not isinstance(plan_step, dict):
            return False
        step_id = trim(str(plan_step.get("id", "") or ""), 20)
        if not step_id:
            return False
        expected = self._extract_plan_step_subtasks(plan_step, limit=5)
        if not expected:
            return False
        owner_key = str(owner or "").strip().lower()
        if owner_key not in {"developer", "explorer", "reviewer"}:
            owner_key = self._current_plan_worker_owner()

        import re

        def _fingerprint(text: str) -> str:
            base = normalize_work_text(str(text or "")) or str(text or "")
            return re.sub(r"\s+", " ", base.strip().lower())

        expected_keys = [_fingerprint(text) for text in expected if _fingerprint(text)]
        if not expected_keys:
            return False
        snap = self.todo.snapshot()
        worker_owners = {"developer", "explorer", "reviewer"}
        linked_rows = [
            dict(row) for row in snap
            if isinstance(row, dict)
            and str(row.get("owner", "") or "").strip().lower() in worker_owners
            and str(row.get("parent_step_id", "") or "").strip() == step_id
        ]
        linked_by_key: dict[str, dict] = {}
        for row in linked_rows:
            fp = _fingerprint(str(row.get("content", "") or ""))
            if fp and fp not in linked_by_key:
                linked_by_key[fp] = row
        already_exact = (
            len(linked_rows) == len(expected_keys)
            and all(key in linked_by_key for key in expected_keys)
        )
        if already_exact and not force_refresh:
            return False
        replacement: list[dict] = []
        for text in expected:
            fp = _fingerprint(text)
            prev = linked_by_key.get(fp, {})
            status = str(prev.get("status", "pending") or "pending").strip().lower()
            if status not in {"pending", "in_progress", "completed"}:
                status = "pending"
            row = {
                "content": text,
                "status": status,
                "owner": str(prev.get("owner", "") or owner_key).strip().lower() or owner_key,
                "parent_step_id": step_id,
            }
            replacement.append(row)
        if replacement and not any(r.get("status") == "in_progress" for r in replacement) and any(r.get("status") == "pending" for r in replacement):
            for row in replacement:
                if row.get("status") == "pending":
                    row["status"] = "in_progress"
                    break
        if not replacement:
            return False
        preserved = [
            dict(row) for row in snap
            if isinstance(row, dict)
            and not (
                str(row.get("owner", "") or "").strip().lower() in worker_owners
                and str(row.get("parent_step_id", "") or "").strip() == step_id
            )
        ]
        with self.todo.lock:
            self.todo.items = preserved + replacement
        return True

    def _single_agent_plan_step_check(self, tool_results: list[dict]):
        """In single-agent mode, check if current plan step should be advanced based on tool results."""
        bb = self._ensure_blackboard()
        todos = bb.get("project_todos", [])
        plan_steps = [t for t in todos if t.get("category") == "plan_step"]
        if not plan_steps:
            # No plan steps — just sync todos
            self._sync_todos_from_blackboard(reason="single-agent-round")
            return
        current = None
        for t in plan_steps:
            if t.get("status") == "in_progress":
                current = t
                break
        if not current:
            self._sync_todos_from_blackboard(reason="single-agent-round")
            return
        # Heuristic: check if tool results indicate step completion
        step_content = str(current.get("full_content", "") or current.get("content", "") or "").lower()
        phase = self._plan_step_phase_hint(step_content)
        wrote_files = any(
            str(r.get("name", "")) in ("write_file", "edit_file") and r.get("ok", False)
            for r in tool_results
        )
        ran_bash_ok = any(
            str(r.get("name", "")) == "bash" and r.get("ok", False)
            for r in tool_results
        )
        # Auto-advance conditions:
        should_advance = False
        # Priority 1: Check if worker subtasks are all completed (most reliable signal)
        subtasks_done = self._step_subtasks_all_completed(current)
        if subtasks_done and (wrote_files or ran_bash_ok):
            should_advance = True
        # Priority 2: Phase-based heuristics (strict — implement requires BOTH write + bash)
        if not should_advance:
            if phase in ("research", "design") and wrote_files:
                should_advance = True
            elif phase == "implement" and wrote_files and ran_bash_ok:
                # Strict: implement step needs both file writes AND successful bash
                should_advance = True
            elif phase in ("test", "review") and ran_bash_ok and not any(
                not r.get("ok", False) for r in tool_results if str(r.get("name", "")) == "bash"
            ):
                should_advance = True
        # Also check if the agent explicitly mentioned step completion
        if not should_advance:
            # Check last assistant message for step completion signals
            last_text = ""
            for msg in reversed(self.messages[-3:]):
                if msg.get("role") == "assistant":
                    last_text = str(msg.get("content", "") or "").lower()
                    break
            step_done_signals = ("step completed", "步骤完成", "step done", "完成了", "已完成",
                                 "next step", "下一步", "proceed to step", "进入下一")
            if any(sig in last_text for sig in step_done_signals):
                should_advance = True
        if should_advance:
            evidence = f"single-agent auto-advance: phase={phase}, wrote={wrote_files}, bash_ok={ran_bash_ok}"
            self._advance_plan_step(evidence=evidence, actor="single")
            try:
                self._inject_current_plan_step_execution_hints()
            except Exception:
                pass
        else:
            self._sync_todos_from_blackboard(reason="single-agent-round")

    def _todo_project_rows_from_blackboard(self, board: dict | None = None) -> list[dict]:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        todos = bb.get("project_todos", [])
        if not todos:
            return self._todo_owner_rows_from_blackboard(bb)
        rows = []
        for todo in todos:
            s = todo.get("status", "pending")
            c = todo.get("content", "")
            ev = todo.get("evidence", "")
            af = {
                "in_progress": self._ui_text("todo_working", content=c),
                "completed": self._ui_text("todo_completed", content=f"{c}" + (f" ({ev})" if ev else "")),
            }.get(s, self._ui_text("todo_pending", content=c))
            rows.append({"key": f"bb:proj:{todo.get('id', '')}", "content": c, "status": s, "activeForm": af})
        return rows

    def _sync_todos_from_blackboard(self, reason: str = "", board: dict | None = None):
        if bool(self.runtime_reclassify_required):
            return
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        # In single mode, still sync plan_step todos if they exist
        has_plan_steps = any(
            isinstance(t, dict) and t.get("category") == "plan_step"
            for t in (bb.get("project_todos", []) if isinstance(bb.get("project_todos"), list) else [])
        )
        if not self._is_multi_agent_mode() and not has_plan_steps:
            return
        self._init_project_todos(bb)
        self._update_project_todo_status(bb)
        plan_data = bb.get("plan", {}) if isinstance(bb.get("plan"), dict) else {}
        if has_plan_steps and str(plan_data.get("phase", "") or "").strip() == "executing":
            try:
                self._update_plan_file_step_status()
            except Exception:
                pass
        system_rows = self._todo_project_rows_from_blackboard(bb)
        existing = self.todo.snapshot()
        worker_rows: list[dict] = []
        non_system_rows: list[dict] = []
        for row in existing:
            if not isinstance(row, dict):
                continue
            key = str(row.get("key", "") or "").strip()
            owner = str(row.get("owner", "") or "").strip().lower()
            is_system_key = key.startswith(("bb:owner:", "bb:node:", "bb:proj:"))
            # Preserve worker-owned items (from TodoWrite) separately
            is_worker_item = owner in ("developer", "explorer", "reviewer") and not is_system_key
            if is_worker_item:
                worker_rows.append(dict(row))
                continue
            if is_system_key or owner == "manager":
                continue
            non_system_rows.append(dict(row))
        if has_plan_steps:
            worker_rows = [r for r in worker_rows if str(r.get("parent_step_id", "") or "").strip()]
            non_system_rows = []
        # Smart trim: keep all active (in_progress/pending) system rows,
        # but only recent 3 completed system rows to save capacity for worker subtasks
        active_system = [r for r in system_rows if r.get("status") != "completed"]
        completed_system = [r for r in system_rows if r.get("status") == "completed"]
        trimmed_system = active_system + completed_system[-3:]
        # ── Subtask conflict guard ──
        # Remove worker subtasks whose content duplicates a plan step to prevent
        # the UI from showing the same task twice (once as plan step, once as subtask).
        if trimmed_system:
            import re as _re_dedup
            plan_content_set = set()
            for sr in trimmed_system:
                pc = str(sr.get("content", "") or "").strip().lower()
                if pc:
                    plan_content_set.add(pc)
                    # Also add first line only (sub-step headers match full step content)
                    first_line = pc.split("\n")[0].strip()
                    if first_line:
                        plan_content_set.add(first_line)
            # Build stripped-prefix set for fuzzy matching ("步骤 1：XXX" → "XXX")
            _num_prefix_re = _re_dedup.compile(r"^(?:步骤\s*\d+[：:]\s*|\d+\.\s*|step\s*\d+[：:]\s*)", _re_dedup.IGNORECASE)
            plan_stripped_set = set()
            for sr in trimmed_system:
                pc = str(sr.get("content", "") or "").strip().lower()
                stripped = _num_prefix_re.sub("", pc).strip()
                if stripped and len(stripped) > 4:
                    plan_stripped_set.add(stripped)
            # Find current active step major number for cross-step detection
            _active_major = ""
            for sr in trimmed_system:
                if sr.get("status") == "in_progress":
                    mc = str(sr.get("content", "") or "")
                    _am = _re_dedup.match(r"^(\d+)\.", mc)
                    if _am:
                        _active_major = _am.group(1)
                    break
            _cross_step_re = _re_dedup.compile(r"^(\d+)\.\d+\s")
            deduped_worker = []
            for wr in worker_rows:
                wc = str(wr.get("content", "") or "").strip().lower()
                if not wc:
                    deduped_worker.append(wr)
                    continue
                # Layer 1: Exact match
                if wc in plan_content_set:
                    continue
                # Layer 2: Stripped prefix match
                wc_stripped = _num_prefix_re.sub("", wc).strip()
                if wc_stripped and wc_stripped in plan_stripped_set:
                    continue
                # Layer 3: Cross-step detection — reject N.M subtasks where N != active major
                if _active_major:
                    cm = _cross_step_re.match(wc)
                    if cm and cm.group(1) != _active_major:
                        continue
                deduped_worker.append(wr)
            worker_rows = deduped_worker
        remaining_cap = max(0, 40 - len(trimmed_system) - len(worker_rows))
        merged = list(trimmed_system) + worker_rows + non_system_rows[:remaining_cap]
        try:
            todo_out = self.todo.update(merged)
        except Exception:
            return
        if todo_out != self.todo.no_changes_text() and reason:
            self._emit(
                "status",
                {"summary": self._ui_text("status_project_todos_synced", reason=trim(reason, 120))},
            )

    def _blackboard_set_status(self, status: str, note: str = ""):
        board = self._ensure_blackboard()
        board["status"] = self._normalize_blackboard_status(status)
        if note:
            self._blackboard_history("manager", f"status={board['status']} | {trim(note, 500)}")
        self._blackboard_touch()
        self._sync_todos_from_blackboard(reason=f"status={board['status']}", board=board)

    def _blackboard_mark_approved(self, note: str, actor: str = "reviewer"):
        board = self._ensure_blackboard()
        board["approval"] = {
            "approved": True,
            "by": trim(str(actor or "").strip(), 40),
            "note": trim(str(note or "").strip(), 1000),
            "ts": float(now_ts()),
        }
        board["status"] = "COMPLETED"
        self._blackboard_touch()
        self._sync_todos_from_blackboard(reason="approved", board=board)

    # --- Reviewer Debug Mode ---

    def _activate_reviewer_debug_mode(self, error_context: str = ""):
        """Activate reviewer debug mode — reviewer gets write access to fix bugs."""
        if bool(self.reviewer_debug_mode):
            return  # already active
        self.reviewer_debug_mode = True
        self.reviewer_debug_rounds = 0
        self.reviewer_debug_context = trim(str(error_context or ""), 1000)
        self._emit("status", {
            "summary": "reviewer debug mode ACTIVATED — reviewer can now edit files to fix bugs"
        })

    def _deactivate_reviewer_debug_mode(self, reason: str = ""):
        """Deactivate reviewer debug mode — reviewer returns to read-only."""
        if not bool(self.reviewer_debug_mode):
            return
        self.reviewer_debug_mode = False
        rounds_used = int(self.reviewer_debug_rounds)
        self.reviewer_debug_rounds = 0
        self.reviewer_debug_context = ""
        self._emit("status", {
            "summary": f"reviewer debug mode DEACTIVATED ({reason or 'resolved'}; {rounds_used} rounds used)"
        })

    def _check_reviewer_debug_mode_timeout(self) -> bool:
        """Check if debug mode should be deactivated due to round limit.
        Returns True if debug mode was deactivated (should switch to developer)."""
        if not bool(self.reviewer_debug_mode):
            return False
        self.reviewer_debug_rounds = int(self.reviewer_debug_rounds or 0) + 1
        if self.reviewer_debug_rounds > REVIEWER_DEBUG_MODE_MAX_ROUNDS:
            self._deactivate_reviewer_debug_mode("round limit exceeded")
            return True
        return False

    def _auto_summary_on_finish(self) -> str:
        """Generate concise summary from blackboard state when run ends."""
        bb = self._ensure_blackboard()
        artifacts = bb.get("code_artifacts", {}) if isinstance(bb.get("code_artifacts"), dict) else {}
        logs = bb.get("execution_logs", []) if isinstance(bb.get("execution_logs"), list) else []
        feedback = bb.get("review_feedback", []) if isinstance(bb.get("review_feedback"), list) else []
        summary_parts = []
        if artifacts:
            file_list = ", ".join(list(artifacts.keys())[:10])
            summary_parts.append(f"Modified files: {file_list}")
        if feedback:
            last_fb = feedback[-1] if feedback else {}
            fb_content = str(last_fb.get("content", "") or "") if isinstance(last_fb, dict) else str(last_fb)
            if fb_content:
                summary_parts.append(f"Review: {trim(fb_content, 200)}")
        if logs:
            recent_logs = logs[-3:]
            log_strs = []
            for log_entry in recent_logs:
                if isinstance(log_entry, dict):
                    log_strs.append(trim(str(log_entry.get("content", "") or ""), 80))
                elif isinstance(log_entry, str):
                    log_strs.append(trim(log_entry, 80))
            if log_strs:
                summary_parts.append(f"Logs: {'; '.join(log_strs)}")
        summary = "; ".join(summary_parts) or "Task completed."
        bb["status"] = "COMPLETED"
        bb["approval"] = {
            "approved": True,
            "by": "auto",
            "note": summary,
            "ts": float(now_ts()),
        }
        self._blackboard_touch()
        self._emit("status", {"summary": f"[auto-summary] {trim(summary, 400)}"})
        return summary

    def _blackboard_read_state_markdown(self, max_items: int = 6) -> str:
        board = self._ensure_blackboard()
        profile = self._ensure_blackboard_task_profile(board)
        judgement = board.get("manager_judgement", {}) if isinstance(board.get("manager_judgement"), dict) else {}
        mx = max(1, min(20, int(max_items or 6)))
        goal = trim(str(board.get("original_goal", "") or "").strip(), 1800)
        status = self._normalize_blackboard_status(board.get("status", "INITIALIZING"))
        delegate = board.get("last_delegate", {}) if isinstance(board.get("last_delegate"), dict) else {}
        watchdog = board.get("watchdog", {}) if isinstance(board.get("watchdog"), dict) else {}
        dq = board.get("decomposition_queue", {}) if isinstance(board.get("decomposition_queue"), dict) else {}
        dq_steps = dq.get("steps", []) if isinstance(dq.get("steps"), list) else []
        dq_cursor = max(0, int(dq.get("cursor", 0) or 0))
        dq_total = len(dq_steps)
        lines = [
            "## Blackboard State",
            f"- status: {status}",
            f"- goal: {goal or '(empty)'}",
            f"- task_level: {int(profile.get('task_level', 0) or 0) or '(unset)'}",
            f"- execution_mode: {profile.get('execution_mode', self._effective_execution_mode())}",
            f"- scale_preference: {profile.get('scale_preference', 'balanced')}",
            f"- task_type: {profile.get('task_type', 'general')}",
            f"- complexity: {profile.get('complexity', 'simple')}",
            f"- direct_objective: {trim(str(profile.get('direct_objective', '') or ''), 260)}",
            f"- participants: {', '.join(profile.get('participants', profile.get('recommended_agents', [])) or []) or '(none)'}",
            (
                "- round_budget: "
                + (
                    "unlimited"
                    if int(profile.get("round_budget", 0) or 0) <= 0
                    else str(int(profile.get("round_budget", self.max_agent_rounds) or self.max_agent_rounds))
                )
            ),
            f"- active_agent: {board.get('active_agent', '') or '(none)'}",
            f"- manager_cycles: {int(board.get('manager_cycles', 0) or 0)}",
            f"- manager_summary_attempts: {int(board.get('manager_summary_attempts', 0) or 0)}",
            (
                "- watchdog: "
                f"intent_no_tool={int(watchdog.get('intent_no_tool_streak', 0) or 0)}, "
                f"repeat_no_tool={int(watchdog.get('repeat_no_tool_streak', 0) or 0)}, "
                f"state_unchanged={int(watchdog.get('state_unchanged_streak', 0) or 0)}, "
                f"trigger_count={int(watchdog.get('trigger_count', 0) or 0)}"
            ),
            (
                "- decomposition_queue: "
                f"active={bool(dq.get('active', False))}, "
                f"cursor={dq_cursor}, total={dq_total}, "
                f"trigger_reason={trim(str(dq.get('trigger_reason', '') or ''), 140)}"
            ),
            (
                "- manager_judgement: "
                f"{trim(str(judgement.get('progress', 'initializing') or ''), 40)}"
                f" | remaining="
                f"{('unlimited' if int(judgement.get('remaining_rounds', 0) or 0) < 0 else int(judgement.get('remaining_rounds', profile.get('round_budget', self.max_agent_rounds)) or 0))}"
            ),
            (
                "- last_delegate: "
                f"{delegate.get('target', '') or '(none)'} | "
                f"{trim(str(delegate.get('instruction', '') or '').strip(), 240)} "
                f"| mandatory={bool(delegate.get('is_mandatory', False))}"
            ),
            f"- research_notes: {len(board.get('research_notes', []) or [])}",
            f"- code_artifacts: {len(board.get('code_artifacts', {}) or {})}",
            f"- execution_logs: {len(board.get('execution_logs', []) or [])}",
            f"- review_feedback: {len(board.get('review_feedback', []) or [])}",
            f"- collaboration_history: {len(board.get('conversation_history', []) or [])}",
        ]
        approval = board.get("approval", {}) if isinstance(board.get("approval"), dict) else {}
        if bool(approval.get("approved", False)):
            lines.append(f"- approval: true by {approval.get('by', '')} | {trim(str(approval.get('note', '') or ''), 220)}")
        else:
            lines.append("- approval: false")
        last_worker_reply = board.get("last_worker_reply", {}) if isinstance(board.get("last_worker_reply"), dict) else {}
        last_role = self._sanitize_agent_role(last_worker_reply.get("role", ""))
        last_text = trim(str(last_worker_reply.get("text", "") or "").strip(), 220)
        if last_role and last_text:
            lines.append(f"- last_worker_reply: [{last_role}] {last_text}")

        def _render_tail(title: str, rows: object):
            lines.append(f"\n### {title}")
            arr = rows if isinstance(rows, list) else []
            if not arr:
                lines.append("- (none)")
                return
            for row in arr[-mx:]:
                if not isinstance(row, dict):
                    continue
                actor = trim(str(row.get("actor", "") or "").strip(), 24)
                txt = trim(str(row.get("content", "") or "").strip(), 360)
                if not txt:
                    continue
                lines.append(f"- [{actor or 'agent'}] {txt}")

        _render_tail("Recent Research Notes", board.get("research_notes", []))
        _render_tail("Recent Collaboration History", board.get("conversation_history", []))
        art = board.get("code_artifacts", {})
        lines.append("\n### Recent Code Artifacts")
        if isinstance(art, dict) and art:
            rows = sorted(
                list(art.items()),
                key=lambda item: float(
                    (item[1] or {}).get("updated_at", 0.0) if isinstance(item[1], dict) else 0.0
                ),
                reverse=True,
            )
            for path, item in rows[:mx]:
                details = item if isinstance(item, dict) else {}
                lines.append(
                    f"- {path} | {trim(str(details.get('summary', '') or '').strip(), 240)} "
                    f"(by={details.get('last_actor', '') or '-'})"
                )
        else:
            lines.append("- (none)")
        _render_tail("Recent Execution Logs", board.get("execution_logs", []))
        _render_tail("Recent Review Feedback", board.get("review_feedback", []))

        proj_todos = board.get("project_todos", [])
        if proj_todos:
            has_plan_steps = any(pt.get("category") == "plan_step" for pt in proj_todos)
            title = "Plan Steps" if has_plan_steps else "Project Tasks"
            lines.append(f"\n### {title}")
            for pt in proj_todos:
                s = pt.get("status", "pending")
                c = trim(str(pt.get("content", "") or ""), 200)
                ev = trim(str(pt.get("evidence", "") or ""), 100)
                if s == "completed":
                    mark = "[x]"
                elif s == "in_progress":
                    mark = "[>]"
                else:
                    mark = "[ ]"
                prefix = f"Step {int(pt.get('plan_step_index', 0) or 0) + 1}: " if has_plan_steps else ""
                suffix = f" — {ev}" if ev else ""
                lines.append(f"- {mark} {prefix}{c}{suffix}")

        return "\n".join(lines)

