    def _auto_context_recall_for_recovery(self) -> bool:
        if not self.context_archives:
            return False
        recent = self.messages[-16:]
        for row in reversed(recent):
            content = str(row.get("content", "") or "")
            if "<auto-context-recall>" in content:
                return False
        try:
            recalled = self._context_recall({"recent_segments": 1, "max_messages": 24, "offset": 0})
        except Exception:
            return False
        text = str(recalled or "").strip()
        if (not text) or text.startswith("Error:"):
            return False
        self.messages.append(
            {
                "role": "user",
                "content": f"<auto-context-recall>\n{trim(text, 7000)}\n</auto-context-recall>",
                "ts": now_ts(),
            }
        )
        self._emit("status", {"summary": "auto context_recall injected for recovery"})
        return True

    def _extract_text_items_from_raw_args(self, raw: object) -> list[str]:
        if isinstance(raw, dict):
            items = raw.get("items")
            if isinstance(items, list):
                out = []
                for item in items:
                    if isinstance(item, dict):
                        text = str(item.get("content", item.get("text", item.get("title", "")))).strip()
                    else:
                        text = str(item).strip()
                    if text and text not in out:
                        out.append(text)
                if out:
                    return out[:7]
        text = str(raw or "")
        if not text.strip():
            return []
        out = []
        # Try quoted string extraction first (best for truncated JSON arrays)
        for m in re.finditer(r'"([^"\\]*(?:\\.[^"\\]*)*)"', text):
            token = m.group(1)
            low = token.strip().lower()
            if low in {"items", "content", "status", "activeform", "in_progress_index"}:
                continue
            try:
                token_decoded = bytes(token, "utf-8").decode("unicode_escape")
            except Exception:
                token_decoded = token
            token_decoded = token_decoded.strip()
            if token_decoded and token_decoded not in out:
                out.append(token_decoded)
        if out:
            return out[:7]
        # Fallback: parse non-empty lines / bullets
        for line in text.splitlines():
            s = line.strip().strip(",")
            s = re.sub(r"^[\-\*\d\.\)\s]+", "", s).strip()
            if not s:
                continue
            if s.lower() in {"items", "content", "status", "activeform"}:
                continue
            if s not in out:
                out.append(s)
        return out[:7]

    def _resolve_context_archive_segment(self, segment_id: str) -> dict | None:
        sid = str(segment_id or "").strip()
        if not sid:
            return None
        for seg in reversed(self.context_archives):
            if str(seg.get("id", "")) == sid:
                return seg
        return None

    def _load_context_archive_messages(self, seg: dict) -> list[dict]:
        rel_path = str(seg.get("path", "")).strip()
        if not rel_path:
            return []
        fp = (self.root / rel_path).resolve()
        if not fp.exists() or not fp.is_file():
            return []
        rows: list[dict] = []
        try:
            with fp.open("r", encoding="utf-8") as handle:
                for line in handle:
                    raw = line.strip()
                    if not raw:
                        continue
                    obj = parse_json_object(raw, {})
                    if not isinstance(obj, dict):
                        continue
                    rows.append(obj)
        except Exception:
            return []
        return rows

    def _context_recall(self, args: dict) -> str:
        segment_id = str(args.get("segment_id", "") or "").strip()
        query = str(args.get("query", "") or "").strip()
        recent_segments = int(args.get("recent_segments", 2) or 2)
        max_messages = int(args.get("max_messages", 30) or 30)
        offset = int(args.get("offset", 0) or 0)
        include_tools = bool(args.get("include_tools", True))
        recent_segments = max(1, min(20, recent_segments))
        max_messages = max(1, min(120, max_messages))
        offset = max(0, offset)

        segments: list[dict] = []
        if segment_id:
            seg = self._resolve_context_archive_segment(segment_id)
            if not seg:
                return f"Error: unknown archive segment '{segment_id}'"
            segments = [seg]
        else:
            segments = list(self.context_archives[-recent_segments:])
        if not segments:
            return "No archived context segments available."

        query_low = query.lower()
        matches: list[dict] = []
        for seg in segments:
            seg_id = str(seg.get("id", ""))
            rows = self._load_context_archive_messages(seg)
            for idx, row in enumerate(rows):
                role = str(row.get("role", ""))
                if not include_tools and role == "tool":
                    continue
                content = str(row.get("content", ""))
                if query_low:
                    pool = f"{role}\n{row.get('name', '')}\n{content}".lower()
                    if query_low not in pool:
                        continue
                out_row = {
                    "segment_id": seg_id,
                    "index": idx,
                    "role": role,
                    "name": row.get("name", ""),
                    "tool_call_id": row.get("tool_call_id", ""),
                    "ts": float(row.get("ts", 0.0) or 0.0),
                    "content": trim(content, 6000),
                }
                if "thinking" in row:
                    out_row["thinking"] = trim(row.get("thinking", ""), 2500)
                matches.append(out_row)

        total = len(matches)
        page = matches[offset : offset + max_messages]
        selected_segments = [
            {
                "id": str(seg.get("id", "")),
                "reason": str(seg.get("reason", "")),
                "messages": int(seg.get("messages", 0) or 0),
                "created_at": float(seg.get("created_at", 0.0) or 0.0),
                "path": str(seg.get("path", "")),
            }
            for seg in segments
        ]
        payload = {
            "query": query,
            "segment_id": segment_id or "",
            "segments_considered": selected_segments,
            "total_matches": total,
            "offset": offset,
            "returned": len(page),
            "next_offset": (offset + len(page)) if (offset + len(page)) < total else None,
            "matches": page,
        }
        return json_dumps(payload, indent=2)

    def _attempt_malformed_tool_repair(self, name: str, raw_args: object) -> tuple[bool, str]:
        # Safe auto-repair only for todo tools; file/code tools require regenerate.
        if name not in {"TodoWrite", "TodoWriteRescue"}:
            return False, ""
        items = self._extract_text_items_from_raw_args(raw_args)
        if not items:
            return False, "no recoverable todo items from malformed arguments"
        try:
            output = self._dispatch_tool("TodoWriteRescue", {"items": items, "in_progress_index": 0})
            return True, output
        except Exception as exc:
            return False, f"rescue failed: {exc}"

    def _missing_required_args(self, name: str, args: dict) -> list[str]:
        name = canonicalize_tool_name(name)
        required = TOOL_REQUIRED_ARGS.get(name, [])
        if not required:
            return []
        if not isinstance(args, dict):
            return list(required)
        missing = []
        for key in required:
            if key not in args:
                missing.append(key)
        return missing

    def _dispatch_tool(self, name: str, args: dict, agent_role: str = "") -> str:
        """Top-level tool dispatcher with error isolation and per-tool timeout."""
        name = canonicalize_tool_name(name)
        if not name:
            return "Error: ValueError: tool name is required"
        if not isinstance(args, dict):
            return "Error: TypeError: tool arguments must be a JSON object"
        role_key = self._sanitize_agent_role(agent_role)
        if role_key and (not self._tool_allowed_for_agent(role_key, name)):
            return f"Error: tool '{name}' is not allowed for agent role '{role_key}'"
        try:
            # Bash has its own timeout mechanism; skip external timeout for it
            if name == "bash":
                return self._dispatch_tool_inner(name, args, role_key)
            timeout = _TOOL_TIMEOUT_MAP.get(name, _DEFAULT_TOOL_TIMEOUT)
            if timeout <= 0:
                return self._dispatch_tool_inner(name, args, role_key)
            with concurrent.futures.ThreadPoolExecutor(max_workers=1, thread_name_prefix=f"tool-{name}") as pool:
                future = pool.submit(self._dispatch_tool_inner, name, args, role_key)
                try:
                    return future.result(timeout=timeout)
                except concurrent.futures.TimeoutError:
                    self._emit("error", {
                        "summary": f"tool '{name}' timed out after {timeout}s",
                    })
                    return f"Error: tool '{name}' timed out after {timeout} seconds. The operation may still be running in the background."
        except Exception as exc:
            tb_lines = traceback.format_exc()
            self._emit("error", {
                "summary": f"tool dispatch error: {name}: {trim(str(exc), 300)}",
                "traceback": trim(tb_lines, 2000),
            })
            return f"Error: {type(exc).__name__}: {trim(str(exc), 500)}"

    def _dispatch_tool_inner(self, name: str, args: dict, role_key: str = "") -> str:
        """Inner tool dispatcher — all tool logic lives here."""
        if name == "bash":
            guard_error = self._guard_shell_write_scope(str(args.get("command", "") or ""), self.files_root)
            if guard_error:
                return guard_error
            meta = self._run_shell_meta(args["command"], self.files_root, 120)
            self._emit(
                "command",
                {
                    "name": "bash",
                    "command": meta["command"],
                    "effective_command": meta.get("effective_command", meta["command"]),
                    "cwd": meta["cwd"],
                    "exit_code": meta["exit_code"],
                    "duration_ms": meta["duration_ms"],
                    "changed_files": meta["changed_files"],
                    "output": meta.get("ui_output_preview", trim(meta["output"], 1200)),
                    "ui_output_pages": meta.get("ui_output_pages", []),
                    "ui_output_page_count": meta.get("ui_output_page_count", 0),
                    "ui_output_page_total": meta.get("ui_output_page_total", 0),
                    "ui_truncated": bool(meta.get("ui_truncated", False)),
                    "model_truncated": bool(meta.get("model_truncated", False)),
                    "buffer_ref": meta.get("buffer_ref", ""),
                    "buffer_chars": int(meta.get("buffer_chars", 0) or 0),
                    "temp_output_path": meta.get("temp_output_path", ""),
                    "long_output_strategy": meta.get("long_output_strategy", "inline"),
                    "output_page_index": int(meta.get("output_page_index", 1) or 1),
                    "output_page_count": int(meta.get("output_page_count", 1) or 1),
                    "output_full_chars": int(meta.get("output_full_chars", 0) or 0),
                    "output_full_lines": int(meta.get("output_full_lines", 0) or 0),
                    "summary": (
                        f"bash ({meta['exit_code']}) {meta['command'][:80]}"
                        + (" · long-output buffered" if meta.get("temp_output_path") else "")
                        + (" · model-paged" if meta.get("model_truncated") else "")
                    ),
                },
            )
            return meta["output"]
        if name == "read_file":
            illegal = self._reject_non_workspace_absolute_tool_path(args.get("path", ""))
            if illegal:
                return illegal
            try:
                rel = self._normalize_tool_path_text(args["path"])
                fp = self._session_path(rel)
                rel = self._session_rel(fp)
            except Exception as exc:
                return f"Error: {type(exc).__name__}: {exc}"
            out = self._run_read(rel, args.get("limit"), args.get("offset"))
            limit_val = int(args.get("limit", 0) or 0) if args.get("limit") is not None else 0
            offset_val = int(args.get("offset", 0) or 0) if args.get("offset") is not None else 0
            summary = f"read file: {rel}"
            if offset_val > 0 or limit_val > 0:
                summary += (
                    f" offset={offset_val}"
                    + (f" limit={limit_val}" if limit_val > 0 else "")
                )
            self._emit(
                "file_read",
                {"path": rel, "offset": offset_val, "limit": limit_val, "summary": summary},
            )
            return out
        if name == "write_file":
            illegal = self._reject_non_workspace_absolute_tool_path(args.get("path", ""))
            if illegal:
                return illegal
            protected = self._runtime_managed_path_tool_error(args.get("path", ""), "write_file")
            if protected:
                return protected
            try:
                rel = self._normalize_tool_path_text(args["path"])
                fp = self._session_path(rel)
                rel = self._session_rel(fp)
            except Exception as exc:
                return f"Error: {type(exc).__name__}: {exc}"
            existed = fp.exists()
            before_text = try_read_text(fp, max_bytes=CODE_PREVIEW_STAGE_MAX_BYTES) or ""
            out = self._run_write(rel, args["content"])
            if not out.startswith("Error"):
                offline_result = self._localize_html_js_dependencies(rel)
                summary = str(offline_result.get("summary", "") or "").strip()
                if summary:
                    self._emit("status", {"summary": summary})
                    out = f"{out}\n{summary}"
                after_text = try_read_text(fp, max_bytes=CODE_PREVIEW_STAGE_MAX_BYTES) or ""
                diff, added, deleted = make_unified_diff(rel, before_text, after_text)
                numbered = make_numbered_diff(before_text, after_text)
                numbered_text = render_numbered_diff_text(numbered)
                code_stage = self._record_code_preview_stage(
                    rel_path=rel,
                    before_text=before_text,
                    after_text=after_text,
                    change_type=("added" if not existed else "modified"),
                    tool_name="write_file",
                    added=added,
                    deleted=deleted,
                )
                patch_payload = {
                    "path": rel,
                    "abs_path": str(fp),
                    "session_rel_path": rel,
                    "session_root": str(self.files_root),
                    "change_type": "added" if not existed else "modified",
                    "added": added,
                    "deleted": deleted,
                    "diff": trim(diff, 30_000),
                    "diff_numbered": trim(numbered_text, 30_000),
                    "diff_rows": numbered,
                    "summary": f"file {'added' if not existed else 'modified'}: {rel} (+{added}/-{deleted})",
                }
                if code_stage:
                    patch_payload["code_stage"] = code_stage
                self._emit(
                    "file_patch",
                    patch_payload,
                )
            return out
        if name == "edit_file":
            illegal = self._reject_non_workspace_absolute_tool_path(args.get("path", ""))
            if illegal:
                return illegal
            protected = self._runtime_managed_path_tool_error(args.get("path", ""), "edit_file")
            if protected:
                return protected
            try:
                rel = self._normalize_tool_path_text(args["path"])
                fp = self._session_path(rel)
                rel = self._session_rel(fp)
            except Exception as exc:
                return f"Error: {type(exc).__name__}: {exc}"
            before_text = try_read_text(fp, max_bytes=CODE_PREVIEW_STAGE_MAX_BYTES) or ""
            out = self._run_edit(rel, args["old_text"], args["new_text"])
            if not out.startswith("Error"):
                offline_result = self._localize_html_js_dependencies(rel)
                summary = str(offline_result.get("summary", "") or "").strip()
                if summary:
                    self._emit("status", {"summary": summary})
                    out = f"{out}\n{summary}"
                after_text = try_read_text(fp, max_bytes=CODE_PREVIEW_STAGE_MAX_BYTES) or ""
                diff, added, deleted = make_unified_diff(rel, before_text, after_text)
                numbered = make_numbered_diff(before_text, after_text)
                numbered_text = render_numbered_diff_text(numbered)
                code_stage = self._record_code_preview_stage(
                    rel_path=rel,
                    before_text=before_text,
                    after_text=after_text,
                    change_type="modified",
                    tool_name="edit_file",
                    added=added,
                    deleted=deleted,
                )
                patch_payload = {
                    "path": rel,
                    "abs_path": str(fp),
                    "session_rel_path": rel,
                    "session_root": str(self.files_root),
                    "change_type": "modified",
                    "added": added,
                    "deleted": deleted,
                    "diff": trim(diff, 30_000),
                    "diff_numbered": trim(numbered_text, 30_000),
                    "diff_rows": numbered,
                    "summary": f"file modified: {rel} (+{added}/-{deleted})",
                }
                if code_stage:
                    patch_payload["code_stage"] = code_stage
                self._emit(
                    "file_patch",
                    patch_payload,
                )
            return out
        if name == "TodoWrite":
            # Protect plan_step todos: worker TodoWrite creates sub-items, not replacements
            bb = self._ensure_blackboard()
            has_plan_steps = any(
                t.get("category") == "plan_step"
                for t in bb.get("project_todos", [])
            )
            if has_plan_steps:
                items = args.get("items", [])
                if isinstance(items, list):
                    for item in items:
                        if isinstance(item, dict) and not item.get("key", "").startswith("bb:"):
                            item["owner"] = str(role_key or "developer")
                result = self._merge_plan_worker_todo_items(items, role=str(role_key or "developer"))
            elif self._is_multi_agent_mode() and role_key in {"developer", "explorer", "reviewer"}:
                items = args.get("items", [])
                if isinstance(items, list):
                    for item in items:
                        if isinstance(item, dict) and not item.get("key", "").startswith("bb:"):
                            item["owner"] = str(role_key)
                result = self._merge_owner_scoped_todo_items(items, role=str(role_key))
            else:
                result = self.todo.update(args["items"])
            # Step completion skill recheck: if any item just got marked completed, re-evaluate skills
            # This fires in ALL modes (single/sync/plan) when developer writes todos
            try:
                new_items = args.get("items", [])
                if isinstance(new_items, list) and any(
                    isinstance(it, dict) and str(it.get("status", it.get("state", ""))).lower() in {"completed", "done", "finished", "finish"}
                    for it in new_items
                ):
                    self._refresh_loaded_skills_for_execution_focus(trigger="step-completed")  # noqa: E501
                    pass  # Skills are loaded on-demand by the model
            except Exception:
                pass
            return result
        if name == "TodoWriteRescue":
            result = self._todo_write_rescue(args)
            # Also recheck skills on rescue write (likely a recovery situation)
            try:
                pass  # Skills are loaded on-demand by the model via load_skill
            except Exception:
                pass
            return result
        if name in {"finish_task", "finish_current_task", "mark_done"}:
            summary = trim(str(args.get("summary", "") or "").strip(), 400)
            bb_finish = self._ensure_blackboard()
            plan_steps = [
                t for t in bb_finish.get("project_todos", [])
                if isinstance(t, dict) and t.get("category") == "plan_step"
            ]
            unfinished_steps = [
                t for t in plan_steps
                if str(t.get("status", "") or "").strip().lower() in {"pending", "in_progress"}
            ]
            if unfinished_steps:
                active_step = next(
                    (t for t in unfinished_steps if str(t.get("status", "") or "").strip().lower() == "in_progress"),
                    unfinished_steps[0],
                )
                active_idx = int(active_step.get("plan_step_index", 0) or 0) + 1
                active_total = max(1, int(bb_finish.get("plan_step_total", 0) or len(plan_steps) or 1))
                active_label = self._ui_text("plan_step_label", step=active_idx, total=active_total)
                active_text = trim(str(active_step.get("content", "") or ""), 140)
                return (
                    f"Error: {name} is reserved for finishing the overall user task, not a subtask or a single plan step. "
                    f"The approved plan is still active at {active_label}: {active_text}. "
                    "Update TodoWrite/TodoWriteRescue for the current subtask and keep following the current plan step."
                )
            if role_key == "explorer":
                delegate = bb_finish.get("last_delegate", {}) if isinstance(bb_finish.get("last_delegate"), dict) else {}
                delegate_target = self._sanitize_agent_role(delegate.get("target", ""))
                delegate_reason = str(delegate.get("reason", "") or "").strip().lower()
                if delegate_target == "explorer" and "summary-handoff" in delegate_reason:
                    return (
                        "Error: explorer summary handoff step must not call finish tool. "
                        "Write structured summary to blackboard first, then wait for manager close."
                    )
            if self._finish_requires_structured_summary(role_key, name):
                if role_key == "reviewer" and not self._recent_agent_used_tools(
                    role_key,
                    {"read_from_blackboard"},
                    lookback=24,
                    max_age_seconds=420.0,
                ):
                    return (
                        "Error: reviewer finalization requires blackboard evidence read. "
                        "Call read_from_blackboard first (sections: code_artifacts, execution_logs, "
                        "review_feedback, status), then call finish_task with structured summary."
                    )
                if not self._final_summary_sufficient(summary, strict=True):
                    return (
                        "Error: structured final summary is required before finish. "
                        "Provide finish_task.summary with: "
                        "(1) changes/files touched, "
                        "(2) validation evidence (tests/commands/results), "
                        "(3) residual risks or next steps. "
                        "If evidence is missing, read_from_blackboard first or ask Explorer for final_summary_request."
                    )
            if name == "finish_task":
                todo_mark = self.todo.complete_all_open(summary)
            else:
                todo_mark = self.todo.complete_active(summary)
            # Deactivate reviewer debug mode on finish
            if bool(self.reviewer_debug_mode) and role_key == "reviewer":
                self._deactivate_reviewer_debug_mode("reviewer finished")
            updated = int(todo_mark.get("updated", 0) or 0)
            if updated > 0:
                self._emit(
                    "status",
                    {
                        "summary": (
                            f"{name} acknowledged; todos completed="
                            f"{updated}/{int(todo_mark.get('total', 0) or 0)}"
                        )
                    },
                )
            return (
                f"{name} acknowledged{': ' + summary if summary else ''}; "
                f"todo_completed={updated}"
            )
        if name == "task":
            return self.run_subagent(args["prompt"], args.get("agent_type", "Explore"))
        if name == "list_skills":
            self._ensure_skills_ready(force=False)
            return ", ".join(self.skills.list_names())
        if name == "load_skill":
            source = f"manual:{role_key or 'single'}"
            return self._load_skill_with_cache(args["name"], load_source=source)
        if name == "list_skill_providers":
            self._ensure_skills_ready(force=False)
            return json_dumps(self.skills.list_providers(), indent=2)
        if name == "list_skill_protocols":
            self._ensure_skills_ready(force=False)
            return json_dumps(self.skills.list_protocols(), indent=2)
        if name == "write_skill":
            return self._write_global_skill(args)
        if name == "scan_skills":
            return self._scan_global_skills()
        if name == "compress":
            return "Compress requested."
        if name == "context_recall":
            return self._context_recall(args)
        if name == "query_code_library":
            cb = getattr(self, "query_code_library_callback", None)
            if not callable(cb):
                return "Error: code library query is not available in this session"
            try:
                out = cb(self, dict(args or {}))
                return str(out if out is not None else "")
            except Exception as exc:
                return f"Error: code library query failed: {exc}"
        if name == "query_knowledge_library":
            cb = getattr(self, "query_knowledge_library_callback", None)
            if not callable(cb):
                return "Error: knowledge library query is not available in this session"
            try:
                out = cb(self, dict(args or {}))
                return str(out if out is not None else "")
            except Exception as exc:
                return f"Error: knowledge library query failed: {exc}"
        if name == "generate_media":
            media_type = str(args.get("media_type", "") or "").strip().lower()
            if media_type not in {"image", "audio", "video"}:
                return "Error: media_type must be one of image/audio/video"
            prompt = str(args.get("prompt", "") or "").strip()
            if not prompt:
                return "Error: prompt is required"
            cap_key = f"output_{media_type}"
            caps = self._ensure_active_profile_capabilities(force_probe=False)
            if not bool(caps.get(cap_key, False)):
                caps = self._ensure_active_profile_capabilities(force_probe=True)
            if not bool(caps.get(cap_key, False)):
                return (
                    f"Error: active model '{self.ollama.model}' does not support {media_type} output "
                    f"(capability={cap_key}=false after active probe)"
                )
            try:
                generated = self.ollama.generate_media(
                    media_type,
                    prompt,
                    size=str(args.get("size", "") or "").strip(),
                    duration=int(args.get("duration", 0) or 0),
                    fmt=str(args.get("format", "") or "").strip(),
                    extra=args.get("extra") if isinstance(args.get("extra"), dict) else None,
                )
                saved = self._save_generated_media(
                    media_type,
                    generated,
                    filename=str(args.get("filename", "") or "").strip(),
                )
                return json_dumps(saved, indent=2)
            except Exception as exc:
                return f"Error: generate_media failed: {exc}"
        if name == "background_run":
            raw_command = str(args.get("command", "") or "")
            guard_error = self._guard_shell_write_scope(raw_command, self.files_root)
            if guard_error:
                return guard_error
            effective_command = self._rewrite_shell_virtual_paths(raw_command, self.files_root)
            out = self.bg.run(effective_command, int(args.get("timeout", 120)))
            out_filtered, _ = filter_runtime_noise_lines(str(out or ""))
            payload = self._prepare_shell_output_payload(raw_command, out_filtered or "(no output)", cwd=self.files_root)
            self._emit(
                "command",
                {
                    "name": "background_run",
                    "command": raw_command,
                    "effective_command": effective_command,
                    "cwd": str(self.files_root),
                    "output": payload.get("ui_output_preview", ""),
                    "ui_output_pages": payload.get("ui_output_pages", []),
                    "ui_output_page_count": payload.get("ui_output_page_count", 0),
                    "ui_output_page_total": payload.get("ui_output_page_total", 0),
                    "ui_truncated": bool(payload.get("ui_truncated", False)),
                    "model_truncated": bool(payload.get("model_truncated", False)),
                    "buffer_ref": payload.get("buffer_ref", ""),
                    "buffer_chars": int(payload.get("buffer_chars", 0) or 0),
                    "temp_output_path": payload.get("temp_output_path", ""),
                    "long_output_strategy": payload.get("long_output_strategy", "inline"),
                    "output_page_index": int(payload.get("output_page_index", 1) or 1),
                    "output_page_count": int(payload.get("output_page_count", 1) or 1),
                    "output_full_chars": int(payload.get("output_full_chars", 0) or 0),
                    "output_full_lines": int(payload.get("output_full_lines", 0) or 0),
                    "summary": (
                        f"background_run: {raw_command[:80]}"
                        + (" · long-output buffered" if payload.get("temp_output_path") else "")
                        + (" · model-paged" if payload.get("model_truncated") else "")
                    ),
                },
            )
            return str(payload.get("output", out_filtered or "(no output)"))
        if name == "check_background":
            return self.bg.check(args.get("task_id"))
        if name == "task_create":
            return self.tasks.create(args["subject"], args.get("description", ""))
        if name == "task_get":
            return self.tasks.get(int(args["task_id"]))
        if name == "task_update":
            return self.tasks.update(int(args["task_id"]), args.get("status"), args.get("add_blocked_by"), args.get("add_blocks"))
        if name == "task_list":
            return self.tasks.list_all()
        if name == "claim_task":
            return self.tasks.claim(int(args["task_id"]), "lead")
        if name == "spawn_teammate":
            return self._spawn_teammate(args["name"], args["role"], args["prompt"])
        if name == "list_teammates":
            return self._list_teammates()
        if name == "ask_colleague":
            to_role = self._sanitize_agent_role(args.get("to", ""))
            intent = trim(str(args.get("intent", "") or "").strip(), 80)
            content = trim(str(args.get("content", "") or "").strip(), 4000)
            from_role = role_key or "developer"
            if not to_role:
                return "Error: ask_colleague.to must be explorer/developer/reviewer"
            if not intent:
                return "Error: ask_colleague.intent is required"
            if not content:
                return "Error: ask_colleague.content is required"
            if intent == "fix_request":
                required_markers = ["ERROR:", "ROOT_CAUSE:", "FIX:"]
                soft_markers = ["FILE:", "LINE:", "CATEGORY:"]
                missing = [m for m in required_markers if m not in content.upper()]
                missing_soft = [m for m in soft_markers if m not in content.upper()]
                if missing or missing_soft:
                    hint_parts = []
                    if missing:
                        hint_parts.append(f"Missing required: {', '.join(missing)}")
                    if missing_soft:
                        hint_parts.append(f"Recommended: {', '.join(missing_soft)}")
                    content = (
                        f"{content}\n\n"
                        "[SYSTEM NOTE: fix_request should include structured fields: "
                        "ERROR: <exact error>, FILE: <path>, LINE: <number>, "
                        "ROOT_CAUSE: <analysis>, CATEGORY: <compilation|runtime|test|lint|build|deploy>, "
                        "FIX: <specific change>. "
                        f"{'; '.join(hint_parts)}]"
                    )
            env = self._agent_send_bus(from_role, to_role, intent, content)
            return (
                f"agent_bus sent ({env.get('from')} -> {env.get('to')}, "
                f"intent={env.get('intent')}, id={env.get('id')})"
            )
        if name == "read_from_blackboard":
            section = str(args.get("section", "all") or "all").strip().lower()
            limit = max(1, min(20, int(args.get("limit", 6) or 6)))
            board = self._ensure_blackboard()
            if section in {"", "all"}:
                return self._blackboard_read_state_markdown(max_items=limit)
            if section == "original_goal":
                return trim(str(board.get("original_goal", "") or "").strip(), 4000) or "(empty)"
            if section == "status":
                wd = board.get("watchdog", {}) if isinstance(board.get("watchdog"), dict) else {}
                dq = board.get("decomposition_queue", {}) if isinstance(board.get("decomposition_queue"), dict) else {}
                return json_dumps(
                    {
                        "status": board.get("status", "INITIALIZING"),
                        "active_agent": board.get("active_agent", ""),
                        "manager_cycles": int(board.get("manager_cycles", 0) or 0),
                        "manager_summary_attempts": int(board.get("manager_summary_attempts", 0) or 0),
                        "approval": board.get("approval", {}),
                        "last_delegate": board.get("last_delegate", {}),
                        "watchdog": {
                            "intent_no_tool_streak": int(wd.get("intent_no_tool_streak", 0) or 0),
                            "repeat_no_tool_streak": int(wd.get("repeat_no_tool_streak", 0) or 0),
                            "state_unchanged_streak": int(wd.get("state_unchanged_streak", 0) or 0),
                            "trigger_count": int(wd.get("trigger_count", 0) or 0),
                            "last_trigger_reason": trim(str(wd.get("last_trigger_reason", "") or "").strip(), 160),
                        },
                        "decomposition_queue": {
                            "active": bool(dq.get("active", False)),
                            "trigger_reason": trim(str(dq.get("trigger_reason", "") or "").strip(), 160),
                            "cursor": int(dq.get("cursor", 0) or 0),
                            "total": len(dq.get("steps", []) or []),
                            "last_error": trim(str(dq.get("last_error", "") or "").strip(), 220),
                        },
                    },
                    indent=2,
                )
            if section == "code_artifacts":
                artifacts = board.get("code_artifacts", {})
                if not isinstance(artifacts, dict):
                    artifacts = {}
                rows = sorted(
                    list(artifacts.items()),
                    key=lambda item: float((item[1] or {}).get("updated_at", 0.0) if isinstance(item[1], dict) else 0.0),
                    reverse=True,
                )
                return json_dumps({k: v for k, v in rows[:limit]}, indent=2)
            if section in {"research_notes", "execution_logs", "review_feedback", "conversation_history"}:
                rows = board.get(section, [])
                if not isinstance(rows, list):
                    rows = []
                return json_dumps(rows[-limit:], indent=2)
            return f"Error: unsupported blackboard section '{section}'"
        if name == "write_to_blackboard":
            section = str(args.get("section", "") or "").strip().lower()
            content = trim(str(args.get("content", "") or "").strip(), BLACKBOARD_MAX_TEXT)
            status_hint = str(args.get("status", "") or "").strip()
            actor = role_key or "developer"
            if not section or not content:
                return "Error: section and content are required"
            # Normalize plan-mode sections: plan.findings → plan_findings, etc.
            section = section.replace(".", "_")
            if section in {"research_notes", "execution_logs", "review_feedback",
                           "plan_findings", "plan_proposal", "plan_steps", "plan_risks",
                           "skill_analysis"}:
                self._blackboard_append_section(section, actor, content)
                self._blackboard_append_section(section, actor, content)
            elif section == "conversation_history":
                self._blackboard_history(actor, content)
            elif section == "status":
                self._blackboard_set_status(status_hint or content, content)
            else:
                return f"Error: unsupported blackboard section '{section}'"
            if status_hint and section != "status":
                self._blackboard_set_status(status_hint, f"{actor} updated {section}")
            return (
                f"blackboard updated: section={section}, actor={actor}, "
                f"status={self._ensure_blackboard().get('status', 'INITIALIZING')}"
            )
        if name == "send_message":
            return self.bus.send("lead", args["to"], args["content"], args.get("msg_type", "message"))
        if name == "read_inbox":
            return json_dumps(self.bus.read_inbox("lead"), indent=2)
        if name == "broadcast":
            return self.bus.broadcast("lead", args["content"], list(self.teammates.keys()))
        if name == "shutdown_request":
            return self._handle_shutdown_request(args["teammate"])
        if name == "plan_approval":
            return self._handle_plan_approval(args["request_id"], bool(args["approve"]), args.get("feedback", ""))
        if name == "worktree_create":
            return self.worktrees.create(args["name"], args.get("task_id"), args.get("base_ref", "HEAD"))
        if name == "worktree_list":
            return self.worktrees.list_all()
        if name == "worktree_status":
            return self.worktrees.status(args["name"])
        if name == "worktree_run":
            wt_path = self.worktrees.resolve_path(args["name"])
            if wt_path is None:
                return f"Error: unknown worktree '{args['name']}'"
            guard_error = self._guard_shell_write_scope(str(args.get("command", "") or ""), wt_path)
            if guard_error:
                return guard_error
            meta = self._run_shell_meta(args["command"], wt_path, 300)
            self._emit(
                "command",
                {
                    "name": "worktree_run",
                    "worktree": args["name"],
                    "command": meta["command"],
                    "effective_command": meta.get("effective_command", meta["command"]),
                    "cwd": meta["cwd"],
                    "exit_code": meta["exit_code"],
                    "duration_ms": meta["duration_ms"],
                    "changed_files": meta["changed_files"],
                    "output": meta.get("ui_output_preview", trim(meta["output"], 1200)),
                    "ui_output_pages": meta.get("ui_output_pages", []),
                    "ui_output_page_count": meta.get("ui_output_page_count", 0),
                    "ui_output_page_total": meta.get("ui_output_page_total", 0),
                    "ui_truncated": bool(meta.get("ui_truncated", False)),
                    "model_truncated": bool(meta.get("model_truncated", False)),
                    "buffer_ref": meta.get("buffer_ref", ""),
                    "buffer_chars": int(meta.get("buffer_chars", 0) or 0),
                    "temp_output_path": meta.get("temp_output_path", ""),
                    "long_output_strategy": meta.get("long_output_strategy", "inline"),
                    "output_page_index": int(meta.get("output_page_index", 1) or 1),
                    "output_page_count": int(meta.get("output_page_count", 1) or 1),
                    "output_full_chars": int(meta.get("output_full_chars", 0) or 0),
                    "output_full_lines": int(meta.get("output_full_lines", 0) or 0),
                    "summary": (
                        f"worktree_run ({meta['exit_code']}) {args['name']}: {meta['command'][:70]}"
                        + (" · long-output buffered" if meta.get("temp_output_path") else "")
                        + (" · model-paged" if meta.get("model_truncated") else "")
                    ),
                },
            )
            return meta["output"]
        if name == "worktree_keep":
            return self.worktrees.keep(args["name"])
        if name == "worktree_remove":
            return self.worktrees.remove(args["name"], bool(args.get("force", False)), bool(args.get("complete_task", False)))
        if name == "worktree_events":
            return self.worktrees.events_recent(int(args.get("limit", 20)))
        return f"Unknown tool: {name}"

    def _live_input_delay_locked(self) -> tuple[int, str]:
        phase = str(self.current_phase or "")
        tool = str(self.current_tool_name or "")
        if tool in {"write_file", "edit_file"} or phase in {"tool:write_file", "tool:edit_file"}:
            return LIVE_INPUT_DELAY_WRITE_ROUNDS, "write-phase"
        if phase.startswith("tool:"):
            return LIVE_INPUT_DELAY_TOOL_ROUNDS, "tool-phase"
        return LIVE_INPUT_DELAY_NORMAL_ROUNDS, "thinking-phase"

    def _enqueue_running_user_input(self, content: str) -> dict:
        text = trim(str(content or "").strip(), 6000)
        if not text:
            raise ValueError("content required")
        with self.lock:
            self.live_input_seq += 1
            delay_rounds, delay_reason = self._live_input_delay_locked()
            round_idx = int(self.agent_round_index)
            row = {
                "id": int(self.live_input_seq),
                "content": text,
                "queued_at": now_ts(),
                "queued_round": round_idx,
                "delay_rounds": int(delay_rounds),
                "next_round": int(round_idx + delay_rounds),
                "applied_count": 0,
                "last_applied_round": -1,
                "delay_reason": delay_reason,
                "run_generation": int(self.run_generation),
            }
            self.pending_user_inputs.append(row)
            self.pending_user_inputs = self.pending_user_inputs[-40:]
            self.updated_at = now_ts()
            self._persist()
        self._emit(
            "status",
            {
                "summary": (
                    "live user input queued "
                    f"(id={row['id']}, delay_rounds={delay_rounds}, reason={delay_reason})"
                )
            },
        )
        return row

    def _inject_pending_user_inputs(self) -> int:
        injected: list[dict] = []
        with self.lock:
            if not self.pending_user_inputs:
                return 0
            round_idx = int(self.agent_round_index)
            current_generation = int(self.run_generation)
            kept: list[dict] = []
            for row in list(self.pending_user_inputs):
                row_generation = int(row.get("run_generation", current_generation) or current_generation)
                if row_generation != current_generation:
                    continue
                next_round = int(row.get("next_round", round_idx) or round_idx)
                if round_idx < next_round:
                    kept.append(row)
                    continue
                content = trim(str(row.get("content", "") or "").strip(), 6000)
                if not content:
                    continue
                self._refresh_runtime_code_reference(content)
                applied = int(row.get("applied_count", 0) or 0) + 1
                delay_rounds = int(row.get("delay_rounds", 0) or 0)
                base_weight = (
                    float(LIVE_INPUT_WEIGHT_BASE_DELAYED)
                    if delay_rounds > 0
                    else float(LIVE_INPUT_WEIGHT_BASE_NORMAL)
                )
                weight_step = (
                    float(LIVE_INPUT_WEIGHT_STEP_DELAYED)
                    if delay_rounds > 0
                    else float(LIVE_INPUT_WEIGHT_STEP_NORMAL)
                )
                weight = min(1.0, base_weight + weight_step * max(0, applied - 1))
                priority = "low" if weight < 0.55 else ("medium" if weight < 0.9 else "high")
                payload = (
                    "<live-user-adjustment "
                    f"id=\"{int(row.get('id', 0) or 0)}\" "
                    f"priority=\"{priority}\" "
                    f"weight=\"{weight:.2f}\">"
                    f"\n{content}\n"
                    "</live-user-adjustment>"
                )
                self.messages.append({"role": "user", "content": payload, "ts": now_ts()})
                self.runtime_reclassify_goal = trim(content, 4000)
                # Only trigger reclassification in auto mode (no user override)
                if int(getattr(self, 'user_task_level_override', 0) or 0) > 0:
                    self.runtime_reclassify_required = False
                else:
                    self.runtime_reclassify_required = True
                self.runtime_goal_reset_pending = True
                injected.append(
                    {
                        "id": int(row.get("id", 0) or 0),
                        "weight": weight,
                        "priority": priority,
                        "applied": applied,
                        "content": content,
                    }
                )
                row["applied_count"] = applied
                row["last_applied_round"] = round_idx
                if applied < LIVE_INPUT_MAX_INJECTIONS and weight < 0.999:
                    row["next_round"] = round_idx + LIVE_INPUT_REINJECT_INTERVAL
                    kept.append(row)
            self.pending_user_inputs = kept[-40:]
            if injected:
                self.updated_at = now_ts()
                self._persist()
        for item in injected:
            # Merge user feedback with plan direction (outside lock — may do LLM call)
            self._merge_user_feedback_with_plan(item["content"])
            self._emit(
                "status",
                {
                    "summary": (
                        "live input applied "
                        f"(id={item['id']}, priority={item['priority']}, weight={item['weight']:.2f}, "
                        f"pass={item['applied']}/{LIVE_INPUT_MAX_INJECTIONS})"
                    )
                },
            )
        return len(injected)

    def _user_feedback_conflict_score(self, user_text: str, step_desc: str = "") -> float:
        """Score 0.0–1.0 via LLM semantic analysis: how strongly user feedback conflicts with current plan.
        Falls back to 0.5 on error."""
        if not str(user_text or "").strip():
            return 0.0
        try:
            ctx = [
                {"role": "system", "content": (
                    "You are a semantic conflict analyzer. "
                    "Given a user's mid-execution feedback and the current task step, "
                    "output ONLY a JSON object: {\"score\": <float 0.0-1.0>, \"reason\": \"<brief>\"}. "
                    "score=0.0 means fully aligned (minor tweak/clarification). "
                    "score=1.0 means direct contradiction/override (user wants opposite direction). "
                    "No other text."
                ), "ts": now_ts()},
                {"role": "user", "content": (
                    f"Current step: {trim(step_desc, 300) or 'unknown'}\n"
                    f"User feedback: {trim(user_text, 500)}\n"
                    "Output JSON only."
                ), "ts": now_ts()},
            ]
            resp = self._chat_with_same_model_retry(
                ctx,
                tools=None,
                system=None,
                max_tokens=80,
                think=False,
                stream_thinking=False,
                context_label="feedback-conflict-score",
                retries=1,
            )
            text = str(resp.get("content", "") or "").strip()
            # Extract JSON from response
            import re as _re
            m = _re.search(r'\{[^}]+\}', text)
            if m:
                parsed = parse_json_object(m.group(0), {})
                score = float(parsed.get("score", 0.5) or 0.5)
                return max(0.0, min(1.0, score))
        except Exception:
            pass
        return 0.5

    def _merge_user_feedback_with_plan(self, user_text: str):
        """When user provides feedback during execution, inject plan-aware merge note into manager context."""
        bb = self._ensure_blackboard()
        plan = bb.get("plan", {})
        if not isinstance(plan, dict):
            return
        current_step = None
        for t in bb.get("project_todos", []):
            if t.get("category") == "plan_step" and t.get("status") == "in_progress":
                current_step = t
                break
        step_desc = trim(str(current_step.get("content", "") if current_step else "none"), 200)
        is_plan_executing = plan.get("phase") == "executing"
        conflict_score = self._user_feedback_conflict_score(user_text, step_desc)
        if conflict_score >= 0.8:
            conflict_level = "HIGH"
            directive = (
                "USER OVERRIDE: This feedback DIRECTLY CONFLICTS with the current plan step. "
                "You MUST prioritize the user's instruction over the original plan. "
                "Adjust the current step's approach immediately to comply with user's requirement. "
                "Do NOT continue the original approach."
            )
        elif conflict_score >= 0.5:
            conflict_level = "MEDIUM"
            directive = (
                "This feedback modifies the current approach. "
                "Re-evaluate the current step and adjust delegation to incorporate user's requirement. "
                "User's direction takes precedence over plan details."
            )
        else:
            conflict_level = "LOW"
            directive = (
                "Minor feedback — integrate with current work direction. "
                "Adjust approach if needed but maintain progress."
            )
        if is_plan_executing:
            merge_note = (
                f"<user-feedback-merge conflict=\"{conflict_level}\" score=\"{conflict_score:.2f}\">\n"
                f"User provided new input during plan execution: {trim(user_text, 500)}\n"
                f"Current plan step: {step_desc}\n"
                f"{directive}\n"
                f"</user-feedback-merge>"
            )
        else:
            merge_note = (
                f"<user-feedback-merge conflict=\"{conflict_level}\" score=\"{conflict_score:.2f}\">\n"
                f"User provided new input: {trim(user_text, 500)}\n"
                f"{directive}\n"
                f"</user-feedback-merge>"
            )
        if self._is_multi_agent_mode():
            self._append_manager_context({
                "role": "system",
                "content": merge_note,
                "ts": now_ts(),
                "agent_role": "manager",
            })
        else:
            # single mode: inject directly into message history so the model sees it
            self.messages.append({
                "role": "user",
                "content": merge_note,
                "ts": now_ts(),
            })

    def _is_restart_scenario(self) -> bool:
        """Check if current state is a restart after finished/aborted task."""
        bb = self._ensure_blackboard()
        status = str(bb.get("status", "") or "").upper()
        approval = bb.get("approval", {}) if isinstance(bb.get("approval"), dict) else {}
        return status in ("COMPLETED", "ABORTED") or bool(approval.get("approved", False))

    def _fuse_restart_intent(self, user_text: str):
        """Fuse user intent with plan/context intent on restart.
        Priority: 1. user intent, 2. plan intent, 3. context intent."""
        bb = self._ensure_blackboard()
        plan = bb.get("plan", {}) if isinstance(bb.get("plan"), dict) else {}
        original_goal = trim(str(bb.get("original_goal", "") or ""), 500)
        plan_steps = plan.get("steps", []) if isinstance(plan.get("steps"), list) else []
        # Detect pure continuation
        _CONTINUE_PHRASES = {
            "继续", "continue", "go on", "接着", "接续", "keep going", "proceed",
            "继续执行", "接着做", "go ahead", "next", "下一步",
        }
        is_continuation = str(user_text or "").strip().lower().rstrip("!.。！") in _CONTINUE_PHRASES
        if is_continuation and plan_steps:
            # Pure continuation — inherit plan intent fully
            pending = [s for i, s in enumerate(plan_steps) if i >= int(bb.get("plan_step_cursor", 0) or 0)]
            if pending:
                fused = (
                    f"<intent-fusion type='continuation'>\n"
                    f"User said: {trim(user_text, 100)}\n"
                    f"Continuing approved plan. Original goal: {original_goal}\n"
                    f"Remaining steps: {', '.join(trim(str(s), 80) for s in pending[:5])}\n"
                    f"{self._continuation_failure_briefing()}"
                    f"Resume from where we left off. Do NOT restart.\n"
                    f"</intent-fusion>"
                )
                self.messages.append({"role": "user", "content": fused, "ts": now_ts()})
                # Don't reset blackboard — continue
                self.runtime_goal_reset_pending = False
                return
        if is_continuation and original_goal:
            # Continuation without plan — inherit context intent
            fused = (
                f"<intent-fusion type='context-continuation'>\n"
                f"User said: {trim(user_text, 100)}\n"
                f"Continue previous work. Original goal: {original_goal}\n"
                f"{self._continuation_failure_briefing()}"
                f"Resume from current state. Do NOT restart.\n"
                f"</intent-fusion>"
            )
            self.messages.append({"role": "user", "content": fused, "ts": now_ts()})
            self.runtime_goal_reset_pending = False
            return
        # New instruction — fuse with context but user intent takes priority
        if original_goal:
            fused = (
                f"<intent-fusion type='new-with-context'>\n"
                f"New user instruction: {trim(user_text, 500)}\n"
                f"Previous context: {original_goal}\n"
                f"User's new instruction takes priority. Use previous context for background only.\n"
                f"</intent-fusion>"
            )
            self.messages.append({"role": "user", "content": fused, "ts": now_ts()})

    def submit_user_message(self, content: str):
        start_worker = False
        dropped_stale_inputs = 0
        removed_runtime_hints = 0
        with self.lock:
            if self.running:
                pass
            else:
                if self.pending_user_inputs:
                    dropped_stale_inputs = len(self.pending_user_inputs)
                # Preserve plan state if awaiting user choice
                _awaiting_plan_choice = bool(
                    self.runtime_plan_proposal
                    and not self.runtime_plan_approved
                )
                removed_runtime_hints = self._reset_runtime_state_locked(purge_runtime_hints=True)
                if _awaiting_plan_choice:
                    # Restore plan proposal so choice can be parsed
                    self.runtime_plan_mode_needed = True
                    self._restore_runtime_policy_from_blackboard_locked()
                # Reset completed plan/todo/skills blackboard state so the manager
                # does not see status=COMPLETED on the very first round and immediately finish.
                # But preserve plan state if user is continuing an existing task.
                if not _awaiting_plan_choice:
                    clean_goal_pre = trim(str(content or "").strip(), 4000)
                    if self._is_continuation_input(clean_goal_pre):
                        pass  # Preserve plan state for continuation
                    else:
                        self._reset_blackboard_plan_state_locked()
                self.run_generation = int(self.run_generation) + 1
                clean_goal = trim(str(content or "").strip(), 4000)
                self._refresh_runtime_code_reference(clean_goal or content)
                self.messages.append({"role": "user", "content": content, "ts": now_ts()})
                # Parse plan choice immediately after clean_goal is available
                if _awaiting_plan_choice:
                    choice = self._parse_plan_choice(clean_goal, self.runtime_plan_proposal)
                    if choice:
                        self.runtime_plan_choice = choice
                        self.runtime_plan_approved = True
                        self.runtime_plan_mode_needed = False
                        self.stall_severity_score = 0
                        self.stall_severity_sources = []
                        self.stall_escalation_triggered = False
                        self._inject_plan_into_context(choice)
                        self.runtime_reclassify_required = False
                        self.runtime_goal_reset_pending = False
                # Restart intent fusion: merge user/plan/context intents
                if self._is_restart_scenario():
                    self._fuse_restart_intent(clean_goal)
                self.runtime_reclassify_goal = clean_goal
                # Skip reclassification for plan choice responses — preserve complexity
                # Also skip when user has manually set task level override
                _has_user_override = int(getattr(self, 'user_task_level_override', 0) or 0) > 0
                if _awaiting_plan_choice or self._is_plan_choice_response(clean_goal) or _has_user_override:
                    self.runtime_reclassify_required = False
                else:
                    self.runtime_reclassify_required = True
                self.runtime_goal_reset_pending = True
                self.running = True
                self.current_phase = "starting"
                self.current_tool_name = ""
                self.updated_at = now_ts()
                self._emit("message", {"role": "user", "text": content, "summary": "user message"})
                self._persist()
                start_worker = True
        if dropped_stale_inputs > 0:
            self._emit(
                "status",
                {
                    "summary": (
                        "stale delayed live inputs cleared before new run "
                        f"(count={dropped_stale_inputs})"
                    )
                },
            )
        if removed_runtime_hints > 0:
            self._emit(
                "status",
                {
                    "summary": (
                        "cleared runtime control hints before new run "
                        f"(count={removed_runtime_hints})"
                    )
                },
            )
        if not start_worker:
            row = self._enqueue_running_user_input(content)
            return {
                "ok": True,
                "queued": True,
                "running": True,
                "queue_id": int(row.get("id", 0) or 0),
                "delay_rounds": int(row.get("delay_rounds", 0) or 0),
                "delay_reason": str(row.get("delay_reason", "")),
            }
        threading.Thread(target=self._agent_worker, daemon=True).start()
        return {"ok": True, "queued": False, "running": True}

    def manual_compact(self):
        with self.lock:
            self._auto_compact("manual")
            self.updated_at = now_ts()
            self._persist()

    def interrupt(self):
        with self.lock:
            self.cancel_requested = True
            phase = str(self.current_phase or "idle")
            tool = str(self.current_tool_name or "")
            self._emit(
                "status",
                {
                    "summary": (
                        "interrupt requested "
                        f"(phase={phase}{', tool=' + tool if tool else ''})"
                    )
                },
            )
            self._persist()

    def _reviewer_approval_log_gate(self, board: dict | None = None) -> tuple[bool, str]:
        bb = board if isinstance(board, dict) else self._ensure_blackboard()
        logs = bb.get("execution_logs", []) if isinstance(bb.get("execution_logs"), list) else []
        if not logs:
            return False, "execution_logs is empty"
        latest = ""
        for row in reversed(logs):
            if not isinstance(row, dict):
                continue
            txt = str(row.get("content", "") or "").strip()
            if txt:
                latest = txt
                break
        if not latest:
            return False, "latest execution log is empty"
        low = latest.lower()
        error_tokens = (
            "error",
            "failed",
            "traceback",
            "exception",
            "not found",
            "blocked",
            "exit=1",
            "exit code 1",
            "non-zero",
        )
        if any(tok in low for tok in error_tokens):
            return False, "latest execution log indicates error/failure"
        return True, "ok"

    def _reviewer_deems_done(self, text: str) -> bool:
        clean = strip_thinking_content(str(text or "")).strip()
        if not clean:
            return False
        gate_ok, gate_reason = self._reviewer_approval_log_gate()
        if not gate_ok:
            now = now_ts()
            if (now - float(self.last_reviewer_gate_warn_ts or 0.0)) >= 3.0:
                self.last_reviewer_gate_warn_ts = now
                self._emit("status", {"summary": f"reviewer approval blocked: {gate_reason}"})
            return False
        if self._looks_like_conclusive_reply(clean):
            return True
        low = clean.lower()
        markers = [
            "review passed",
            "approved",
            "no issues found",
            "tests passed",
            "verified",
            "验证通过",
            "审核通过",
            "已通过",
            "检查通过",
        ]
        return any(x in low for x in markers)

    def _multi_agent_turn(
        self,
        role: str,
        *,
        pinned_selection: str,
        media_inputs_round: list[dict] | None = None,
    ) -> dict:
        role_key = self._sanitize_agent_role(role)
        if not role_key:
            return {"status": "skip", "reason": "invalid-role"}
        ctx = self._agent_context(role_key)
        if not ctx:
            return {"status": "skip", "reason": "empty-context", "role": role_key}
        self._microcompact_agent_messages(ctx)
        with self.lock:
            self.current_phase = f"agent:{role_key}:model-call"
            self.current_tool_name = ""
            self.active_agent_role = role_key
        response = self._chat_with_same_model_retry(
            ctx,
            tools=self._tools_for_agent(role_key),
            system=self._agent_role_system_prompt(role_key),
            max_tokens=self.max_output_tokens,
            think=False,
            stream_thinking=False,
            on_thinking_chunk=self._append_live_thinking,
            pinned_selection=pinned_selection,
            context_label=f"{role_key} turn",
            retries=MODEL_OUTPUT_RETRY_TIMES,
            media_inputs=media_inputs_round,
        )
        text = str(response.get("content") or "")
        thinking_text = str(response.get("thinking") or "").strip()
        text_main, embedded_thinking = split_thinking_content(text)
        if embedded_thinking:
            if thinking_text:
                thinking_text = trim(f"{thinking_text}\n\n{embedded_thinking}", 24_000)
            else:
                thinking_text = embedded_thinking
        text = text_main
        tool_calls = response.get("tool_calls", [])
        text, text_filter_meta = self._sanitize_assistant_text_for_runtime(text, tool_calls)
        if bool(text_filter_meta.get("filtered", False)):
            reason = str(text_filter_meta.get("reason", "") or "").strip()
            if reason == "oversized_raw_toolcall":
                self._inject_toolcall_overflow_hint(role_key)
        assistant = {"role": "assistant", "content": text, "ts": now_ts(), "agent_role": role_key}
        if thinking_text:
            assistant["thinking"] = thinking_text
        if tool_calls:
            assistant["tool_calls"] = [
                {
                    "id": tc["id"],
                    "type": "function",
                    "function": {
                        "name": tc["function"]["name"],
                        "arguments": json_dumps(tc["function"]["arguments"]),
                    },
                }
                for tc in tool_calls
            ]
        self._append_agent_context_message(role_key, assistant, mirror_to_global=True)
        if (text.strip() or thinking_text) and not tool_calls:
            emit_text = text if text.strip() else "[thinking-only output]"
            self._emit_agent_message(role_key, emit_text, summary=f"{self._agent_display_name(role_key)} response")
        if not tool_calls:
            if self._current_delegate_is_mandatory_for(role_key):
                self._append_agent_context_message(
                    role_key,
                    {
                        "role": "system",
                        "content": self._apply_agent_language_policy(
                            "[mandatory-reminder] Manager marked this turn as mandatory execution. "
                            "You must call at least one concrete tool in your next reply; "
                            "text-only advice is not allowed.",
                            max_len=1000,
                        ),
                        "ts": now_ts(),
                        "agent_role": role_key,
                    },
                    mirror_to_global=False,
                )
                self._emit(
                    "status",
                    {
                        "summary": (
                            f"{self._agent_display_name(role_key)} returned no tool calls under mandatory delegate; "
                            "mandatory reminder injected"
                        )
                    },
                )
            return {"status": "no-tools", "role": role_key, "text": text, "thinking": thinking_text}
        with self.lock:
            self.current_phase = f"agent:{role_key}:tool-dispatch"
            self.current_tool_name = ""
        stop_due_to_finish = False
        tool_results: list[dict] = []
        for tc in tool_calls:
            if self.cancel_requested:
                return {"status": "interrupted", "role": role_key}
            name = tc["function"]["name"]
            with self.lock:
                self.current_phase = f"agent:{role_key}:tool:{name}"
                self.current_tool_name = name
            args = tc["function"]["arguments"]
            args_error = str(tc.get("args_error", "") or "").strip()
            if args_error:
                output = (
                    f"Error: malformed arguments for tool '{name}'. {args_error}. "
                    "Please regenerate this tool call with complete JSON arguments."
                )
            else:
                missing = self._missing_required_args(name, args)
                if missing:
                    output = (
                        f"Error: tool '{name}' missing required arguments: {', '.join(missing)}. "
                        "Please regenerate complete JSON arguments."
                    )
                else:
                    try:
                        output = self._dispatch_tool(name, args, agent_role=role_key)
                    except Exception as exc:
                        output = f"Error: {exc}"
            raw_output = str(output or "")
            filtered_output, filtered_rows = filter_runtime_noise_lines(raw_output)
            if filtered_rows > 0:
                if filtered_output:
                    output = filtered_output
                elif raw_output.startswith("Error:"):
                    output = "Error: runtime socket noise filtered"
                else:
                    output = "(no output)"
            self._append_agent_context_message(
                role_key,
                {
                    "role": "tool",
                    "tool_call_id": tc["id"],
                    "name": name,
                    "content": trim(output),
                    "ts": now_ts(),
                    "agent_role": role_key,
                },
                mirror_to_global=False,
            )
            self._emit(
                "tool_result",
                {
                    "name": name,
                    "agent_role": role_key,
                    "result": trim(output, 500),
                    "summary": f"{self._agent_display_name(role_key)} tool: {name}",
                },
            )
            item = {
                "name": name,
                "args": args if isinstance(args, dict) else {},
                "output": trim(str(output or ""), 3000),
                "ok": not str(output).startswith("Error:"),
            }
            # Atomic blackboard sync: update shared state immediately after each tool result.
            self._blackboard_update_from_tool_result(role_key, item)
            # Failure ledger: record tool call and detect errors (unified)
            self._ledger_record_tool_call(name, args if isinstance(args, dict) else {})
            self._process_tool_result_errors(name, args if isinstance(args, dict) else {}, output, item["ok"], role_key)
            # Failure ledger: record edit_file as potential fix attempt if errors exist
            if name in ("edit_file", "write_file") and isinstance(args, dict):
                fl = self._ensure_blackboard().get("failure_ledger", {})
                all_errors = fl.get("errors", []) if isinstance(fl, dict) else []
                edit_path = str(args.get("path", "") or "").strip()
                if all_errors and edit_path:
                    matching = [e for e in all_errors if edit_path.endswith(str(e.get("file", "") or "")) or str(e.get("file", "") or "").endswith(edit_path)]
                    if matching:
                        fix_desc = trim(str(args.get("new_text", "") or args.get("content", "") or ""), 300)
                        self._ledger_record_fix_attempt(
                            edit_path,
                            trim(str(matching[-1].get("error_msg", "") or ""), 300),
                            fix_desc,
                            "applied" if item["ok"] else "failed(edit_error)",
                            role_key,
                        )
            item["bb_applied"] = True
            tool_results.append(item)
            if name in {"finish_task", "finish_current_task", "mark_done"} and (not str(output).startswith("Error:")):
                stop_due_to_finish = True
                break
        with self.lock:
            self.current_phase = f"agent:{role_key}:post-tools"
            self.current_tool_name = ""
        return {
            "status": "tools",
            "role": role_key,
            "stop_due_to_finish": bool(stop_due_to_finish),
            "tool_results": tool_results,
        }

    def _multi_agent_no_tool_transition(
        self,
        role: str,
        text: str,
        *,
        mode: str,
        idle_counts: dict[str, int],
    ) -> tuple[bool, str]:
        role_key = self._sanitize_agent_role(role)
        clean_text = strip_thinking_content(str(text or "")).strip()
        def _lang_payload(seed: str) -> str:
            return self._apply_agent_language_policy(seed, max_len=2000)
        if self._current_delegate_is_mandatory_for(role_key):
            self._emit(
                "status",
                {
                    "summary": (
                        f"mandatory delegate still unmet for {self._agent_display_name(role_key)}; "
                        "keep pushing concrete tool execution"
                    )
                },
            )
            return False, role_key
        if bool(self.arbiter_enabled) and len(clean_text) >= int(ARBITER_TRIGGER_MIN_CONTENT_CHARS):
            decision = self._call_arbiter_llm(clean_text, "")
            status = str(decision.get("status", "") or "").strip().upper()
            if status == "TASK_COMPLETED":
                if role_key in {"reviewer", "developer"}:
                    self._mark_all_done_silently(str(decision.get("reasoning", "") or ""))
                    self._emit(
                        "status",
                        {
                            "summary": (
                                f"{self._agent_display_name(role_key)} arbiter-completed task; "
                                "run stopped"
                            )
                        },
                    )
                    return True, role_key
            elif status == "VALID_PLANNING":
                self._inject_arbiter_continue_hint(decision)
                self._emit(
                    "status",
                    {
                        "summary": (
                            f"{self._agent_display_name(role_key)} planning validated by arbiter; "
                            "continuing execution"
                        )
                    },
                )
                return False, role_key
        if mode == EXECUTION_MODE_SEQUENTIAL:
            if role_key == "explorer":
                payload = _lang_payload(
                    clean_text or "Proceed with implementation by user goal, and refine Todo first when necessary."
                )
                self._agent_send_bus("explorer", "developer", "execute_plan", payload)
                return False, "developer"
            if role_key == "developer":
                payload = _lang_payload(
                    clean_text or "Developer completed this implementation batch. Please run review now."
                )
                self._agent_send_bus("developer", "reviewer", "review_request", payload)
                return False, "reviewer"
            if role_key == "reviewer":
                if self._reviewer_deems_done(clean_text):
                    self._blackboard_mark_approved(clean_text or "review approved", role_key)
                    can_finish_now, finish_gate_reason = self._can_auto_finish_from_approval(
                        self._ensure_blackboard(),
                        latest_user_ts=self._latest_user_message_ts(),
                    )
                    if can_finish_now:
                        self._mark_all_done_silently(clean_text)
                        return True, "reviewer"
                    self._emit(
                        "status",
                        {
                            "summary": (
                                "reviewer completion deferred by gate: "
                                f"{finish_gate_reason}; continue collaboration"
                            )
                        },
                    )
                    return False, "reviewer"
                payload = _lang_payload(
                    clean_text or "Review did not pass. Please fix based on diffs and resubmit."
                )
                self._agent_send_bus("reviewer", "developer", "fix_request", payload)
                return False, "developer"
            return False, "explorer"
        # sync mode relay
        if role_key == "explorer":
            payload = _lang_payload(clean_text or "Explorer tip: continue implementation aligned with the objective.")
            self._agent_send_bus("explorer", "developer", "tip", payload)
        elif role_key == "developer":
            payload = _lang_payload(clean_text or "Development output for this step is ready. Please review.")
            self._agent_send_bus("developer", "reviewer", "review_request", payload)
        elif role_key == "reviewer":
            if self._reviewer_deems_done(clean_text):
                self._blackboard_mark_approved(clean_text or "review approved", role_key)
                can_finish_now, finish_gate_reason = self._can_auto_finish_from_approval(
                    self._ensure_blackboard(),
                    latest_user_ts=self._latest_user_message_ts(),
                )
                if can_finish_now:
                    self._mark_all_done_silently(clean_text)
                    return True, role_key
                self._emit(
                    "status",
                    {
                        "summary": (
                            "reviewer completion deferred by gate: "
                            f"{finish_gate_reason}; continue collaboration"
                        )
                    },
                )
                return False, role_key
            payload = _lang_payload(clean_text or "Issues detected. Please fix and submit again.")
            self._agent_send_bus("reviewer", "developer", "fix_request", payload)
        # Prevent indefinite silent loops.
        if max(idle_counts.values() or [0]) >= 6:
            self._emit(
                "status",
                {"summary": "multi-agent idle threshold reached; pausing run for user input"},
            )
            return True, role_key
        return False, role_key

    def _multi_agent_sync_blackboard_worker(self, *, pinned_selection: str):
        idle_counts = {role: 0 for role in AGENT_ROLES}
        _prev_delegation_hash = ""
        _repeat_delegation_count = 0
        media_last_user_ts = -1.0
        media_inputs_pool: list[dict] | None = None
        media_seen_ts_by_role: dict[str, float] = {
            "manager": 0.0,
            "explorer": 0.0,
            "developer": 0.0,
            "reviewer": 0.0,
        }
        board = self._ensure_blackboard()
        profile = self._ensure_blackboard_task_profile(board)
        budget_val = self._blackboard_round_budget(board)
        # Fix 7: Pure sync no-plan — if complex task and no plan steps exist, prompt manager
        # to create them before delegating. Guard: only fires when no plan_step items exist,
        # so plan+sync mode (which already has plan steps) is completely unaffected.
        _sync_has_plan = any(
            isinstance(t, dict) and t.get("category") == "plan_step"
            for t in board.get("project_todos", [])
        )
        _sync_complexity = str(profile.get("complexity", "simple") or "simple")
        if not _sync_has_plan and _sync_complexity in ("moderate", "complex", "expert"):
            self.messages.append({
                "role": "system",
                "content": (
                    "[SYNC-INIT] No plan steps found for this task. Before delegating to workers, "
                    "use write_to_blackboard to add 3-5 plan_step items to project_todos. "
                    'Each item: {"category":"plan_step","content":"N. Step title",'
                    '"status":"pending","owner":"manager"}. '
                    "This enables proper todo tracking and completion detection."
                ),
                "ts": now_ts(),
            })
        self._blackboard_set_status("INITIALIZING", "sync collaborative loop started")
        self._emit(
            "status",
            {
                "summary": (
                    f"manager task profile: type={profile.get('task_type','general')}, "
                    f"complexity={profile.get('complexity','simple')}, "
                    f"round_budget={'unlimited' if int(budget_val) <= 0 else int(budget_val)}"
                )
            },
        )
        rounds_used = 0
        budget_compact_notified = False
        while rounds_used < self.max_agent_rounds:
            current_budget = self._blackboard_round_budget()
            compact_mode = bool(current_budget > 0 and rounds_used >= current_budget)
            if compact_mode and (not budget_compact_notified):
                budget_compact_notified = True
                self._emit(
                    "status",
                    {
                        "summary": (
                            "sync compact mode enabled after reaching internal budget "
                            f"({current_budget}/{self.max_agent_rounds}); continuing without early stop"
                        )
                    },
                )
            rounds_used += 1
            if self.cancel_requested:
                self._emit("status", {"summary": "run interrupted"})
                break
            if self.stall_escalation_triggered:
                self._emit("status", {"summary": "sync loop break: stall escalated to plan mode"})
                break
            self._inject_pending_user_inputs()
            self._apply_auto_compact_if_needed("auto:multi-sync")
            # Periodic checkpoint in multi-agent sync loop
            if rounds_used % CHECKPOINT_INTERVAL_ROUNDS == 0:
                self._maybe_create_checkpoint()
            # Auto-rename session title in sync mode
            if rounds_used in (1, 3, 6):
                try:
                    self._maybe_auto_rename_session_title("sync-progress")
                except Exception:
                    pass
            with self.lock:
                self.agent_round_index = int(self.agent_round_index) + 1
                self.current_phase = "manager:dispatch"
                self.current_tool_name = ""
            latest_user_ts = self._latest_user_message_ts()
            if latest_user_ts > media_last_user_ts:
                media_last_user_ts = latest_user_ts
                media_inputs_pool = self._recent_multimodal_inputs()
                self._emit_multimodal_attach_status(
                    scope="multi-agent sync",
                    media_inputs=media_inputs_pool,
                    roles=["manager", "explorer", "developer", "reviewer"],
                )
            manager_media_inputs = self._resolve_role_multimodal_payload(
                role="manager",
                latest_user_ts=latest_user_ts,
                media_inputs_pool=media_inputs_pool,
                media_seen_ts_by_role=media_seen_ts_by_role,
            )
            # AgentBus fast-route: skip manager if a valid worker handoff is pending
            bus_route = self._drain_agentbus_fast_route()
            if bus_route:
                target = bus_route["to"]
                instruction = trim(str(bus_route.get("payload", "") or ""), 1400)
                route = {
                    "target": target,
                    "instruction": instruction,
                    "source": "agentbus-direct",
                    "is_mandatory": False,
                    "executor_mode": False,
                }
            else:
                route = self._manager_delegate_turn(
                    pinned_selection=pinned_selection,
                    media_inputs_round=manager_media_inputs,
                )
            target = str(route.get("target", "") or "").strip().lower()
            instruction = trim(str(route.get("instruction", "") or "").strip(), 1400)
            if compact_mode and target in AGENT_ROLES:
                instruction = trim(
                    "Compact execution mode: output one concrete action with minimal reasoning and immediate blackboard update.\n"
                    + instruction,
                    1400,
                )
            if target == "finish":
                note = instruction or "manager completed run"
                self._blackboard_mark_approved(note, "manager")
                self._mark_all_done_silently(note)
                self._emit("status", {"summary": "manager decided finish; run paused"})
                break
            # Detect manager stuck: same instruction repeated N times → force advance + break
            import hashlib as _hl_mgr
            _cur_hash = _hl_mgr.sha1((target + "|" + instruction).encode("utf-8")).hexdigest()[:12]
            if _cur_hash == _prev_delegation_hash:
                _repeat_delegation_count += 1
            else:
                _repeat_delegation_count = 0
            _prev_delegation_hash = _cur_hash
            if _repeat_delegation_count >= 3:
                self._emit("status", {"summary": f"manager stuck: repeated identical delegation x{_repeat_delegation_count + 1}; forcing advance"})
                _bb_stuck = self._ensure_blackboard()
                _stuck_step = next(
                    (t for t in _bb_stuck.get("project_todos", [])
                     if t.get("category") == "plan_step" and t.get("status") == "in_progress"),
                    None,
                )
                if _stuck_step:
                    self._advance_plan_step(evidence="manager stuck: repeated delegation", actor="manager")
                else:
                    self._blackboard_mark_approved("manager stuck loop break", "manager")
                    self._mark_all_done_silently("manager stuck: repeated delegation break")
                    break
                _repeat_delegation_count = 0
            role = self._sanitize_agent_role(target) or "developer"
            self._inject_manager_instruction(
                role,
                instruction,
                is_mandatory=bool(route.get("is_mandatory", False)),
                executor_mode=bool(route.get("executor_mode", False)),
            )
            if role == "explorer":
                self._blackboard_set_status("RESEARCHING")
            elif role == "developer":
                self._blackboard_set_status("CODING")
            elif role == "reviewer":
                self._blackboard_set_status("REVIEWING")
            role_media_inputs = self._resolve_role_multimodal_payload(
                role=role,
                latest_user_ts=latest_user_ts,
                media_inputs_pool=media_inputs_pool,
                media_seen_ts_by_role=media_seen_ts_by_role,
            )
            board_before_fp = self._watchdog_state_fingerprint(self._ensure_blackboard())
            step = self._multi_agent_turn(
                role,
                pinned_selection=pinned_selection,
                media_inputs_round=role_media_inputs,
            )
            self._blackboard_update_from_worker_step(role, step)
            # Post-execution plan step advancement (replaces pre-execution advancement)
            self._post_execution_plan_step_check(route, step if isinstance(step, dict) else {})
            # Fix 6b: Pure sync no-plan — read worker-done signal and notify manager
            _bb_sync = self._ensure_blackboard()
            if _bb_sync.pop("sync_worker_round_done", False):
                self._save_blackboard(_bb_sync)
                self._append_agent_context_message(
                    "manager",
                    {
                        "role": "system",
                        "content": (
                            "[worker-done] Worker completed the current task and called finish_current_task. "
                            "Assess progress: assign the next task or conclude the session."
                        ),
                        "ts": now_ts(),
                        "agent_role": "manager",
                    },
                    mirror_to_global=False,
                )
            # Nudge: if worker wrote files but didn't call TodoWrite, inject reminder
            _step_dict = step if isinstance(step, dict) else {}
            _step_results = _step_dict.get("tool_results", []) or []
            _wrote = any(isinstance(r, dict) and r.get("ok") and str(r.get("name", "")) in ("write_file", "edit_file") for r in _step_results)
            _did_todo = any(isinstance(r, dict) and str(r.get("name", "")) in {"TodoWrite", "TodoWriteRescue"} for r in _step_results)
            if _wrote and not _did_todo:
                _bb_nudge = self._ensure_blackboard()
                _cur_step = next((t for t in _bb_nudge.get("project_todos", []) if t.get("category") == "plan_step" and t.get("status") == "in_progress"), None)
                if _cur_step:
                    _msg = self._build_plan_todo_reminder_text(
                        _cur_step,
                        missing_subtasks=not self._active_plan_step_has_worker_todos(role),
                    )
                    if _msg:
                        self._append_instruction_bubble(
                            _msg,
                            target_roles=(role,),
                            summary=f"plan+sync todo reminder injected ({role})",
                        )
            # ── Agent turn 结束后的终止检测：结论性回复 + 无待办 + 无错误 → 自动 finish ──
            agent_text = self._latest_agent_assistant_text(role)
            if (
                agent_text
                and self._looks_like_conclusive_reply(agent_text)
                and not self.todo.has_open_items()
                and not self._manager_has_error_log(self._ensure_blackboard())
            ):
                self._blackboard_mark_approved(
                    f"conclusive reply from {role}: auto-finish", role
                )
                self._mark_all_done_silently(f"conclusive reply from {role}")
                self._emit(
                    "status",
                    {"summary": f"agent '{role}' gave conclusive reply; finishing run"},
                )
                break
            board_after = self._ensure_blackboard()
            board_after_fp = self._watchdog_state_fingerprint(board_after)
            wd_event = self._watchdog_process_worker_step(
                board_after,
                role=role,
                step=step if isinstance(step, dict) else {},
                state_changed=bool(board_after_fp != board_before_fp),
                pinned_selection=pinned_selection,
            )
            status = str(step.get("status", "") or "")
            if bool(wd_event.get("triggered", False)):
                idle_counts[role] = 0
                continue
            if status == "interrupted":
                break
            if status == "skip":
                idle_counts[role] = int(idle_counts.get(role, 0) or 0) + 1
            elif status == "tools":
                idle_counts[role] = 0
                if bool(step.get("stop_due_to_finish", False)):
                    note = f"{self._agent_display_name(role)} signaled finish via tool."
                    # Approval note should come from finish tool payload sync; avoid overwriting with generic text here.
                    can_finish_now, finish_gate_reason = self._can_auto_finish_from_approval(
                        self._ensure_blackboard(),
                        latest_user_ts=self._latest_user_message_ts(),
                    )
                    if not can_finish_now:
                        if role == "reviewer" and finish_gate_reason == "reviewer-summary-missing":
                            self._emit(
                                "status",
                                {
                                    "summary": (
                                        "reviewer finish deferred: final summary missing; "
                                        "manager will reroute to explorer summary synthesis"
                                    )
                                },
                            )
                        else:
                            self._emit(
                                "status",
                                {
                                    "summary": (
                                        f"finish deferred by gate ({finish_gate_reason}); "
                                        "manager will continue routing"
                                    )
                                },
                            )
                        continue
                    self._auto_summary_on_finish()
                    self._mark_all_done_silently(note)
                    self._emit(
                        "status",
                        {"summary": "finish tool called in sync collaborative mode; run paused"},
                    )
                    break
            elif status == "no-tools":
                idle_counts[role] = int(idle_counts.get(role, 0) or 0) + 1
                clean_text = strip_thinking_content(str(step.get("text", "") or "")).strip()
                active_profile = self._ensure_blackboard_task_profile()
                task_type = str(active_profile.get("task_type", "") or "")
                if role == "developer" and task_type == "simple_qa" and clean_text:
                    endpoint = self._detect_endpoint_intent(clean_text, None)
                    if bool(endpoint.get("matched", False)) or (
                        len(clean_text) >= 40 and (not self._looks_like_incomplete_reply(clean_text))
                    ):
                        note = "developer provided direct answer for simple task"
                        self._blackboard_mark_approved(note, role)
                        self._mark_all_done_silently(note)
                        self._emit("status", {"summary": "simple task answered; run paused"})
                        break
                if role == "reviewer" and self._reviewer_deems_done(clean_text):
                    done_note = clean_text or "review approved"
                    self._blackboard_mark_approved(done_note, role)
                    can_finish_now, finish_gate_reason = self._can_auto_finish_from_approval(
                        self._ensure_blackboard(),
                        latest_user_ts=self._latest_user_message_ts(),
                    )
                    if not can_finish_now:
                        if finish_gate_reason == "reviewer-summary-missing":
                            self._emit(
                                "status",
                                {
                                    "summary": (
                                        "reviewer approved; final summary still missing. "
                                        "reviewer should hand off explorer via agentbus before finish"
                                    )
                                },
                            )
                        else:
                            self._emit(
                                "status",
                                {"summary": f"reviewer approval deferred by gate: {finish_gate_reason}"},
                            )
                        continue
                    self._mark_all_done_silently(done_note)
                    self._emit("status", {"summary": "reviewer approved; run paused"})
                    break
            if max(idle_counts.values() or [0]) >= 8:
                self._blackboard_set_status("PAUSED", "idle threshold reached in sync collaborative loop")
                self._emit(
                    "status",
                    {
                        "summary": (
                            "sync collaborative mode paused after repeated idle rounds; "
                            "please provide follow-up instruction"
                        )
                    },
                )
                break
        else:
            summary = self._auto_summary_on_finish()
            self._mark_all_done_silently(f"budget exhausted: {summary}")
            self._emit("status", {"summary": f"Budget exhausted ({self.max_agent_rounds} rounds). {trim(summary, 300)}"})

    def _multi_agent_worker(self, *, pinned_selection: str):
        mode = self._effective_execution_mode()
        if mode == EXECUTION_MODE_SYNC:
            self._multi_agent_sync_blackboard_worker(pinned_selection=pinned_selection)
            return
        profile = self._ensure_blackboard_task_profile()
        role_order = [
            role
            for role in [self._sanitize_agent_role(x) for x in profile.get("participants", AGENT_ROLES)]
            if role
        ] or ["explorer", "developer", "reviewer"]
        current_role = role_order[0]
        sync_index = 0
        idle_counts = {role: 0 for role in AGENT_ROLES}
        media_last_user_ts = -1.0
        media_inputs_pool: list[dict] | None = None
        media_seen_ts_by_role: dict[str, float] = {
            "manager": 0.0,
            "explorer": 0.0,
            "developer": 0.0,
            "reviewer": 0.0,
        }
        for _ in range(self.max_agent_rounds):
            if self.cancel_requested:
                self._emit("status", {"summary": "run interrupted"})
                break
            self._apply_auto_compact_if_needed("auto:multi-seq")
            with self.lock:
                self.agent_round_index = int(self.agent_round_index) + 1
            latest_user_ts = self._latest_user_message_ts()
            if latest_user_ts > media_last_user_ts:
                media_last_user_ts = latest_user_ts
                media_inputs_pool = self._recent_multimodal_inputs()
                self._emit_multimodal_attach_status(
                    scope="multi-agent sequential",
                    media_inputs=media_inputs_pool,
                    roles=role_order,
                )
            dq = self._normalize_decomposition_queue_state(
                self._ensure_blackboard().get("decomposition_queue", {})
            )
            if bool(dq.get("active", False)):
                queue_exec = self._watchdog_execute_queue_step(
                    pinned_selection=pinned_selection,
                )
                if bool(queue_exec.get("interrupted", False)):
                    break
                if bool(queue_exec.get("stop_run", False)):
                    self._emit("status", {"summary": "watchdog executor completed task; run paused"})
                    break
                if not bool(queue_exec.get("executed", False)):
                    if bool(queue_exec.get("queue_active", False)):
                        self._emit(
                            "status",
                            {"summary": "watchdog queue active but no executable step; pausing to avoid deadlock"},
                        )
                        break
                    continue
                idle_counts[str(queue_exec.get("role", "") or "developer")] = 0
                continue
            role = current_role if mode == EXECUTION_MODE_SEQUENTIAL else role_order[sync_index % len(role_order)]
            role_media_inputs = self._resolve_role_multimodal_payload(
                role=role,
                latest_user_ts=latest_user_ts,
                media_inputs_pool=media_inputs_pool,
                media_seen_ts_by_role=media_seen_ts_by_role,
            )
            board_before_fp = self._watchdog_state_fingerprint(self._ensure_blackboard())
            step = self._multi_agent_turn(
                role,
                pinned_selection=pinned_selection,
                media_inputs_round=role_media_inputs,
            )
            safe_step = step if isinstance(step, dict) else {}
            self._blackboard_update_from_worker_step(role, safe_step)
            board_after = self._ensure_blackboard()
            board_after_fp = self._watchdog_state_fingerprint(board_after)
            wd_event = self._watchdog_process_worker_step(
                board_after,
                role=role,
                step=safe_step,
                state_changed=bool(board_after_fp != board_before_fp),
                pinned_selection=pinned_selection,
            )
            if bool(wd_event.get("triggered", False)):
                idle_counts[role] = 0
                continue
            status = str(safe_step.get("status", "") or "")
            if status == "interrupted":
                break
            if status == "skip":
                idle_counts[role] = int(idle_counts.get(role, 0) or 0) + 1
                if mode == EXECUTION_MODE_SYNC:
                    sync_index += 1
                    continue
                # sequential mode fallback: move to developer if explorer has already spoken at least once
                if role == "explorer":
                    current_role = "developer"
                continue
            if status == "tools":
                idle_counts[role] = 0
                if bool(safe_step.get("stop_due_to_finish", False)):
                    self._emit("status", {"summary": "finish tool called; run paused and awaiting user instruction"})
                    break
                if mode == EXECUTION_MODE_SEQUENTIAL:
                    if role == "explorer":
                        current_role = "developer"
                    elif role == "developer":
                        current_role = "reviewer"
                    elif role == "reviewer":
                        current_role = "developer"
                    continue
                if mode == EXECUTION_MODE_SYNC:
                    sync_index += 1
                continue
            if status == "no-tools":
                idle_counts[role] = int(idle_counts.get(role, 0) or 0) + 1
                should_stop, next_role = self._multi_agent_no_tool_transition(
                    role,
                    str(safe_step.get("text", "") or ""),
                    mode=mode,
                    idle_counts=idle_counts,
                )
                if should_stop:
                    break
                if mode == EXECUTION_MODE_SEQUENTIAL:
                    current_role = next_role or current_role
                else:
                    sync_index += 1
                continue
        else:
            summary = self._auto_summary_on_finish()
            self._mark_all_done_silently(f"budget exhausted: {summary}")
            self._emit("status", {"summary": f"Budget exhausted ({self.max_agent_rounds} rounds). {trim(summary, 300)}"})

    # ── Plan Mode Methods ──

    def _plan_mode_worker(self, pinned_selection: str):
        """Plan mode: explorer 调研 → manager 综合 → emit 方案 → 等待用户选择"""
        # Phase 1: Explorer 调研
        self._emit("status", {"summary": "plan-mode: research phase started"})
        bb = self._ensure_blackboard()
        bb["status"] = "PLANNING"
        bb["plan"] = {"phase": "research", "findings": []}
        self.blackboard = bb

        # Auto-discover and load relevant skills before research
        try:
            pass  # Skills are loaded on-demand by the model via load_skill
        except Exception:
            pass

        research_prompt = self._plan_mode_research_prompt()
        self._seed_plan_mode_explorer_context(research_prompt)

        for r in range(PLAN_MODE_EXPLORER_MAX_ROUNDS):
            if self.cancel_requested:
                return
            self._inject_pending_user_inputs()
            step = self._plan_mode_explorer_turn(pinned_selection, round_idx=r)
            if step.get("status") in ("no-tools", "skip", "interrupted"):
                break
            self._plan_mode_update_findings(step)

        # Phase 2: Manager 综合分析
        # Inject pending user inputs before synthesis
        self._inject_pending_user_inputs()
        # Check if user sent a substantive goal change during research
        if self._has_pending_goal_change():
            self._emit("status", {"summary": "plan-mode: user changed task during research, restarting"})
            self.runtime_plan_mode_needed = False
            self.runtime_plan_approved = False
            return

        self._emit("status", {"summary": "plan-mode: synthesizing proposals"})
        bb = self._ensure_blackboard()
        if not isinstance(bb.get("plan"), dict):
            bb["plan"] = {"phase": "synthesis", "findings": []}
        bb["plan"]["phase"] = "synthesis"
        self.blackboard = bb

        # Synthesis with retry (up to 2 attempts) + minimal fallback
        proposal = None
        for _synth_attempt in range(2):
            proposal = self._plan_mode_synthesize_proposal(pinned_selection)
            if proposal and proposal.get("options"):
                break
            if _synth_attempt == 0:
                self._emit("status", {"summary": "plan-mode: synthesis retry"})
        if not proposal or not proposal.get("options"):
            # Last resort: minimal fallback with simpler prompt and higher token budget
            proposal = self._synthesis_minimal_fallback(pinned_selection)
        if not proposal or not proposal.get("options"):
            self._emit("status", {"summary": "plan-mode: synthesis failed, falling back to direct execution"})
            self.runtime_plan_mode_needed = False
            self.runtime_plan_approved = True
            return

        # Synthesis Step 1: 立即写 plan.md（与 synthesis 思维连续，避免信息丢失）
        self.runtime_plan_proposal = proposal
        try:
            self._write_plan_file(self._format_plan_file_preselection(proposal))
        except Exception:
            pass
        self._emit("status", {"summary": "plan-mode: plan.md written"})

        # Synthesis Step 2: 更新 blackboard + 生成精简 bubble
        bb = self._ensure_blackboard()
        if not isinstance(bb.get("plan"), dict):
            bb["plan"] = {"phase": "awaiting_choice", "findings": []}
        bb["plan"]["phase"] = "awaiting_choice"
        bb["plan"]["proposal"] = proposal
        self.blackboard = bb

        # Phase 3: Emit bubble 到前端（纯输出，不做额外思考）
        bubble_text = self._format_plan_bubble_preselection(proposal)
        self.messages.append({
            "role": "assistant",
            "content": bubble_text,
            "ts": now_ts(),
            "agent_role": "planner",
        })
        self._emit("message", {
            "role": "assistant",
            "text": trim(bubble_text, int(ASSISTANT_MESSAGE_EVENT_MAX_CHARS)),
            "summary": "plan-mode proposal",
            "agent_role": "planner",
        })
        self._emit("status", {"summary": "plan-mode: awaiting user choice"})

    def _plan_mode_research_prompt(self) -> str:
        goal = trim(str(self.runtime_reclassify_goal or self._latest_user_goal_text() or ""), 4000)
        lang_note = model_language_instruction(self.ui_language)
        os_note = _detect_os_shell_instruction()
        # Include loaded skill summaries in research prompt
        bb_skills = self._ensure_blackboard().get("loaded_skills", {})
        skills_section = ""
        if isinstance(bb_skills, dict) and bb_skills:
            skill_previews = []
            for skey, sinfo in list(bb_skills.items())[:3]:
                preview = trim(str(sinfo.get("preview", "") if isinstance(sinfo, dict) else ""), 200)
                if preview:
                    skill_previews.append(f"- **{skey}**: {preview}")
            if skill_previews:
                skills_section = (
                    "\n## Loaded Skills\n"
                    + "\n".join(skill_previews)
                    + "\n\nCRITICAL: For each loaded skill, you MUST:\n"
                    "1. Read the skill's full content from your context (it was injected as <loaded-skill>)\n"
                    "2. Identify the skill's concrete workflow steps (e.g., what scripts to run, what files to read/write)\n"
                    "3. List the specific tool calls and file paths each skill requires\n"
                    "4. Include these details in your plan_findings so the synthesis phase can produce actionable steps\n"
                )
        return (
            f"You are in plan-mode research phase. Your task is to analyze the following request "
            f"WITHOUT making any modifications.\n\n"
            f"## User Request\n{goal}\n\n"
            f"{skills_section}"
            f"## Instructions\n"
            f"1. Call `list_skills` FIRST to discover available skills — identify which skills are relevant "
            f"to this task and note their names and capabilities in your findings.\n"
            f"2. List all uploaded/workspace files with `ls uploaded/` or `ls` to know what inputs are available\n"
            f"3. Read uploaded files (.parsed.md preferred over .pdf) to understand their content and structure\n"
            f"4. If relevant skills exist, call `load_skill` to load the most relevant one and analyze its "
            f"workflow steps, scripts, tools, and file paths\n"
            f"5. Identify key technical details, data points, and structure needed for the output\n"
            f"6. Assess risks and note any ambiguities that need user input\n"
            f"7. DO NOT write, edit, or create any files. Read-only analysis only.\n"
            f"8. Write your findings to the blackboard under 'plan_findings'. Include:\n"
            f"   - Relevant skills found (names, what they do, how to invoke them)\n"
            f"   - File inventory (uploaded files, their types, sizes, key content)\n"
            f"   - Skill workflow breakdown (concrete tools, scripts, paths for each relevant skill)\n"
            f"   - Content analysis (key themes, structure, data points extracted from inputs)\n"
            f"9. For coding tasks, identify the test strategy:\n"
            f"   - What build/compilation commands are available? (Makefile, npm, cargo, cmake, etc.)\n"
            f"   - What test frameworks/suites exist? (pytest, jest, go test, etc.)\n"
            f"   - What are the critical paths that must be tested?\n"
            f"   - Record these in plan_findings under 'test_strategy'.\n\n"
            f"Workspace: \"{self.files_root}\" ($SESSION_ROOT)\n"
            f"{os_note}\n"
            f"{lang_note}"
        )

    def _seed_plan_mode_explorer_context(self, research_prompt: str):
        os_note = _detect_os_shell_instruction()
        skills_block = self._skills_awareness_block(for_role="explorer")
        self._append_agent_context_message("explorer", {
            "role": "system",
            "content": (
                "You are Explorer in plan-mode (read-only research). "
                "Analyze the codebase to understand the task scope. "
                "Do NOT modify any files. Use read_file, bash (read-only commands), "
                "list_skills, load_skill, and blackboard tools only. "
                f"{skills_block}"
                "IMPORTANT: If the task requires specialized output (PPTX, reports, deep research, code review), "
                "call list_skills first to discover relevant skills, then note in plan_findings which skills to use. "
                f"{os_note} "
                f"{model_language_instruction(self.ui_language)}"
            ),
            "ts": now_ts(),
            "agent_role": "explorer",
        }, mirror_to_global=False)
        self._append_agent_context_message("explorer", {
            "role": "user",
            "content": research_prompt,
            "ts": now_ts(),
            "agent_role": "explorer",
        }, mirror_to_global=False)

    def _plan_mode_explorer_turn(self, pinned_selection: str, round_idx: int) -> dict:
        ctx = self._agent_context("explorer")
        if not ctx:
            return {"status": "skip", "reason": "empty-context"}
        # Build filtered tool list (read-only allowlist)
        filtered_tools = []
        for tool in TOOLS:
            fn = tool.get("function", {}) if isinstance(tool, dict) else {}
            name = str(fn.get("name", "")).strip()
            if name in PLAN_MODE_RESEARCH_TOOL_ALLOWLIST:
                filtered_tools.append(tool)
        if not filtered_tools:
            filtered_tools = self._tools_for_agent("explorer")
        with self.lock:
            self.current_phase = f"plan-mode:explorer:round-{round_idx}"
            self.current_tool_name = ""
            self.active_agent_role = "explorer"
        # Build skills awareness block (same as sync/single mode)
        skills_block = self._skills_awareness_block(for_role="explorer")
        response = self._chat_with_same_model_retry(
            ctx,
            tools=filtered_tools,
            system=(
                "You are Explorer in plan-mode research. Read-only analysis. "
                "Do NOT create, write, or edit files. "
                f"Workspace: \"{self.files_root}\" ($SESSION_ROOT). "
                f"{skills_block}"
                f"{_detect_os_shell_instruction()} "
                f"{model_language_instruction(self.ui_language)}"
            ),
            max_tokens=self.max_output_tokens,
            think=False,
            stream_thinking=False,
            on_thinking_chunk=self._append_live_thinking,
            pinned_selection=pinned_selection,
            context_label=f"plan-mode explorer round {round_idx}",
            retries=MODEL_OUTPUT_RETRY_TIMES,
        )
        text = str(response.get("content") or "")
        thinking_text = str(response.get("thinking", "") or "").strip()
        tool_calls = response.get("tool_calls", [])
        text, _ = self._sanitize_assistant_text_for_runtime(text, tool_calls)
        assistant = {"role": "assistant", "content": text, "ts": now_ts(), "agent_role": "explorer"}
        if thinking_text:
            assistant["thinking"] = thinking_text
        if tool_calls:
            assistant["tool_calls"] = [
                {
                    "id": tc["id"],
                    "type": "function",
                    "function": {
                        "name": tc["function"]["name"],
                        "arguments": json_dumps(tc["function"]["arguments"]),
                    },
                }
                for tc in tool_calls
            ]
        self._append_agent_context_message("explorer", assistant, mirror_to_global=False)
        # B4: Emit planner research bubble for user visibility (persist in messages)
        if text.strip() or thinking_text:
            planner_msg = {
                "role": "assistant",
                "content": text.strip(),
                "ts": now_ts(),
                "agent_role": "planner",
            }
            if thinking_text:
                planner_msg["thinking"] = thinking_text
            self.messages.append(planner_msg)
            emit_data = {
                "role": "assistant",
                "agent_role": "planner",
                "text": trim(text, int(ASSISTANT_MESSAGE_EVENT_MAX_CHARS)),
                "summary": f"plan-mode: research round {round_idx + 1}",
            }
            if thinking_text:
                emit_data["thinking"] = trim(thinking_text, 2000)
            self._emit("message", emit_data)
        if not tool_calls:
            return {"status": "no-tools", "text": text}
        # Execute tool calls (read-only)
        for tc in tool_calls:
            if self.cancel_requested:
                return {"status": "interrupted"}
            fn_name = tc["function"]["name"]
            fn_args = tc["function"]["arguments"]
            # Block write operations in bash
            if fn_name == "bash":
                cmd = str(fn_args.get("command", "") if isinstance(fn_args, dict) else "")
                cmd_lower = cmd.lower().strip()
                write_indicators = ("rm ", "mv ", "cp ", ">", ">>", "tee ", "dd ", "write_file", "edit_file", "mkdir ", "touch ")
                if any(cmd_lower.startswith(w) or f" {w}" in cmd_lower for w in write_indicators):
                    result_content = "[plan-mode] Write operations are blocked during research phase."
                    self._append_agent_context_message("explorer", {
                        "role": "tool",
                        "tool_call_id": tc["id"],
                        "content": result_content,
                        "ts": now_ts(),
                        "agent_role": "explorer",
                    }, mirror_to_global=False)
                    continue
            try:
                raw_output = self._dispatch_tool(fn_name, fn_args, agent_role="explorer")
            except Exception as exc:
                raw_output = f"Error: {exc}"
            result_content = str(raw_output or "")
            self._append_agent_context_message("explorer", {
                "role": "tool",
                "tool_call_id": tc["id"],
                "content": trim(result_content, 8000),
                "ts": now_ts(),
                "agent_role": "explorer",
            }, mirror_to_global=False)
            # B5: Emit tool result as planner bubble
            self._emit("tool_result", {
                "name": fn_name,
                "agent_role": "planner",
                "result": trim(result_content, 500),
                "summary": f"plan-mode research: {fn_name}",
            })
        return {"status": "ok", "tool_count": len(tool_calls), "text": text}

    def _plan_mode_update_findings(self, step: dict):
        bb = self._ensure_blackboard()
        plan = bb.get("plan", {})
        if not isinstance(plan, dict):
            plan = {"phase": "research", "findings": []}
        findings = plan.get("findings", [])
        if not isinstance(findings, list):
            findings = []
        text = trim(str(step.get("text", "") or ""), 2000)
        if text:
            findings.append({"round": len(findings), "content": text, "ts": now_ts()})
        findings = findings[-20:]
        plan["findings"] = findings
        bb["plan"] = plan
        self.blackboard = bb
        # B6: Emit findings status as planner
        if text:
            self._emit("status", {
                "summary": f"plan-mode: finding #{len(findings)} collected",
                "agent_role": "planner",
            })

    # ------------------------------------------------------------------
    # Stall severity tracking & plan-mode escalation
    # ------------------------------------------------------------------

    def _bump_stall_severity(self, source: str, points: int) -> int:
        self.stall_severity_score = max(0, int(self.stall_severity_score or 0)) + int(points)
        self.stall_severity_sources.append({
            "source": trim(str(source), 80),
            "points": int(points),
            "ts": now_ts(),
            "cumulative": int(self.stall_severity_score),
        })
        self.stall_severity_sources = self.stall_severity_sources[-12:]
        self._emit("status", {
            "summary": f"stall-severity +{points} ({source}); total={self.stall_severity_score}"
        })
        return int(self.stall_severity_score)

    def _decay_stall_severity(self, points: int = 2):
        if int(self.stall_severity_score or 0) > 0:
            self.stall_severity_score = max(0, int(self.stall_severity_score) - int(points))

    def _collect_stall_context(self, fault_counter: int = 0, last_fault_reason: str = "") -> dict:
        goal = trim(str(self.runtime_reclassify_goal or self._latest_user_goal_text() or ""), 2000)
        stall_events = list(self.stall_severity_sources[-8:])
        error_ctx = trim(self._recent_error_context(600), STALL_ESCALATION_CONTEXT_MAX_CHARS)
        recent_tools: list[str] = []
        for msg in reversed(self.messages[-30:]):
            tc_list = msg.get("tool_calls", [])
            if isinstance(tc_list, list):
                for tc in tc_list:
                    fn = tc.get("function", {})
                    if isinstance(fn, dict):
                        recent_tools.append(str(fn.get("name", "")))
            if len(recent_tools) >= 20:
                break
        repeated = []
        seen: dict[str, int] = {}
        for t in recent_tools:
            seen[t] = seen.get(t, 0) + 1
        for t, c in seen.items():
            if c >= 3:
                repeated.append(f"{t}(x{c})")
        open_todos: list[str] = []
        try:
            snap = self.todo.snapshot()
            for item in (snap or [])[:6]:
                if isinstance(item, dict) and str(item.get("status", "")).strip().lower() != "done":
                    open_todos.append(trim(str(item.get("text", "")), 120))
        except Exception:
            pass
        bb = self._ensure_blackboard()
        task_level = 0
        try:
            task_level = int(bb.get("task_profile", {}).get("task_level", 0) or 0)
        except Exception:
            pass
        return {
            "goal": goal,
            "task_level": task_level,
            "stall_events": stall_events,
            "error_context": error_ctx,
            "repeated_tools": repeated,
            "recent_tools": recent_tools[:12],
            "open_todos": open_todos,
            "fault_counter": int(fault_counter),
            "last_fault_reason": trim(str(last_fault_reason or ""), 300),
            "severity_score": int(self.stall_severity_score),
        }

    def _escalate_stall_to_plan_mode(
        self,
        trigger_source: str,
        fault_counter: int = 0,
        last_fault_reason: str = "",
        pinned_selection: str = "",
    ) -> bool:
        if self.stall_escalation_triggered:
            return False
        if self.runtime_plan_mode_needed or self.runtime_plan_proposal:
            return False
        stall_ctx = self._collect_stall_context(fault_counter, last_fault_reason)
        task_level = int(stall_ctx.get("task_level", 0) or 0)
        user_pref = str(self.plan_mode_user_preference or "auto").lower()
        if task_level < STALL_ESCALATION_MIN_LEVEL or user_pref == "off":
            self._emit_stall_conclusion(trigger_source, last_fault_reason, stall_ctx)
            self.stall_escalation_triggered = True
            return True
        self.stall_escalation_triggered = True
        self.stall_escalation_round = int(self.agent_round_index or 0)
        self._blackboard_set_status("STALL_PLANNING", f"stall escalation from {trigger_source}")
        self._ledger_record_stall(f"stall-escalation:{trigger_source}", "plan-mode-escalation")
        exec_mode = self._effective_execution_mode()
        if exec_mode == EXECUTION_MODE_SINGLE:
            self._escalate_stall_single_mode(stall_ctx, pinned_selection)
        else:
            self._escalate_stall_sync_mode(stall_ctx, pinned_selection)
        return True

    def _escalate_stall_single_mode(self, stall_context: dict, pinned_selection: str):
        proposal = self._plan_mode_synthesize_stall_proposal(stall_context, pinned_selection)
        if not proposal or not proposal.get("options"):
            self._emit_stall_conclusion(
                "synthesis-failed",
                stall_context.get("last_fault_reason", ""),
                stall_context,
            )
            return
        self.runtime_plan_proposal = proposal
        self.runtime_plan_mode_needed = True
        self.runtime_plan_approved = False
        md = self._format_plan_proposal_markdown(proposal)
        stall_header = self._format_stall_findings(stall_context)
        full_md = f"{stall_header}\n\n{md}"
        self.messages.append({
            "role": "assistant",
            "content": full_md,
            "ts": now_ts(),
            "agent_role": "planner",
        })
        self._emit("message", {
            "role": "assistant",
            "text": full_md,
            "summary": "stall escalation: plan proposal generated",
            "agent_role": "planner",
        })

    def _escalate_stall_sync_mode(self, stall_context: dict, pinned_selection: str):
        self._escalate_stall_single_mode(stall_context, pinned_selection)

    def _plan_mode_synthesize_stall_proposal(self, stall_context: dict, pinned_selection: str) -> dict:
        goal = trim(str(stall_context.get("goal", "")), 2000)
        findings_text = self._format_stall_findings(stall_context)
        synthesis_prompt = (
            f"The agent has stalled while working on the user's task. "
            f"Based on the failure analysis below, generate a structured recovery plan "
            f"with up to {PLAN_MODE_MAX_OPTIONS} differentiated options.\n\n"
            f"## User's Original Goal\n{goal}\n\n"
            f"## Failure Analysis\n{findings_text}\n\n"
            f"## Instructions\n"
            f"Generate 3 recovery options with MEANINGFULLY DIFFERENT approaches:\n"
            f"- Option A: Direct workaround — bypass the blocker with an alternative method\n"
            f"- Option B: Different path — re-approach the goal from a completely different angle\n"
            f"- Option C: Minimal viable + user action items — do what's possible now, list what the user needs to do manually\n\n"
            f"Call the submit_plan_proposal tool with:\n"
            f"- context: brief failure analysis (what was tried, what failed, why)\n"
            f"- options: array of 3 options, each with id (A/B/C), title, summary, steps, pros, cons, risk\n"
            f"- recommended: id of the recommended option\n\n"
            f"{model_language_instruction(self.ui_language)}"
        )
        synthesis_ctx = [
            {"role": "system", "content": "You are a recovery planner analyzing execution failures and proposing alternative approaches.", "ts": now_ts()},
            {"role": "user", "content": synthesis_prompt, "ts": now_ts()},
        ]
        try:
            response = self._chat_with_same_model_retry(
                synthesis_ctx,
                tools=self._plan_mode_synthesis_tools(),
                system="Generate a structured stall recovery plan. Use the submit_plan_proposal tool.",
                max_tokens=STALL_PLAN_SYNTHESIS_MAX_TOKENS,
                think=False,
                stream_thinking=False,
                on_thinking_chunk=self._append_live_thinking,
                pinned_selection=pinned_selection,
                context_label="stall-plan synthesis",
                retries=MODEL_OUTPUT_RETRY_TIMES,
            )
            tool_calls = response.get("tool_calls", [])
            for tc in tool_calls:
                if tc.get("function", {}).get("name") == "submit_plan_proposal":
                    args = tc["function"].get("arguments", {})
                    if isinstance(args, dict) and args.get("options"):
                        return dict(args)
        except Exception as exc:
            self._emit("status", {"summary": f"stall plan synthesis error: {exc}"})
        return {}

    def _emit_stall_conclusion(self, trigger_source: str, last_fault_reason: str = "", stall_context: dict | None = None):
        ctx = stall_context or self._collect_stall_context(last_fault_reason=last_fault_reason)
        lines = [self._ui_text("stall_execution_blocked_title")]
        lines.append(self._ui_text("stall_stop_reason", reason=trim(str(trigger_source), 200)))
        if last_fault_reason:
            lines.append(self._ui_text("stall_error_details", detail=trim(str(last_fault_reason), 400)))
        error_ctx = str(ctx.get("error_context", "") or "").strip()
        if error_ctx:
            lines.append(f"\n{self._ui_text('stall_recent_error')}\n```\n{trim(error_ctx, 600)}\n```")
        repeated = ctx.get("repeated_tools", [])
        if repeated:
            lines.append(f"\n{self._ui_text('stall_repeated_tools', tools=', '.join(repeated))}")
        lines.append(f"\n{self._ui_text('stall_suggested_actions')}")
        lines.append(self._ui_text("stall_action_1"))
        lines.append(self._ui_text("stall_action_2"))
        lines.append(self._ui_text("stall_action_3"))
        lines.append(f"\n{self._ui_text('stall_continue_prompt')}")
        conclusion_md = "\n".join(lines)
        self.messages.append({
            "role": "assistant",
            "content": conclusion_md,
            "ts": now_ts(),
            "agent_role": "planner",
        })
        self._emit("message", {
            "role": "assistant",
            "text": conclusion_md,
            "summary": f"stall conclusion: {trigger_source}",
            "agent_role": "planner",
        })

    def _format_stall_findings(self, stall_context: dict) -> str:
        lines = [self._ui_text("stall_analysis_title")]
        goal = str(stall_context.get("goal", "") or "").strip()
        if goal:
            lines.append(self._ui_text("stall_goal", goal=trim(goal, 400)))
        lines.append(self._ui_text("stall_severity", score=stall_context.get("severity_score", 0)))
        events = stall_context.get("stall_events", [])
        if events:
            lines.append(f"\n{self._ui_text('stall_events')}")
            for ev in events[-6:]:
                if isinstance(ev, dict):
                    lines.append(
                        self._ui_text(
                            "stall_event_line",
                            source=ev.get("source", "?"),
                            points=ev.get("points", 0),
                            cumulative=ev.get("cumulative", "?"),
                        )
                    )
        error_ctx = str(stall_context.get("error_context", "") or "").strip()
        if error_ctx:
            lines.append(f"\n{self._ui_text('stall_error_context')}\n```\n{trim(error_ctx, 500)}\n```")
        repeated = stall_context.get("repeated_tools", [])
        if repeated:
            lines.append(f"\n{self._ui_text('stall_repeated_tools_label', tools=', '.join(repeated))}")
        fault_reason = str(stall_context.get("last_fault_reason", "") or "").strip()
        if fault_reason:
            lines.append(self._ui_text("stall_last_fault_reason", reason=trim(fault_reason, 200)))
        open_todos = stall_context.get("open_todos", [])
        if open_todos:
            lines.append(f"\n{self._ui_text('stall_open_todos')}")
            for t in open_todos[:4]:
                lines.append(f"- {trim(str(t), 100)}")
        return "\n".join(lines)

    def _plan_mode_synthesize_proposal(self, pinned_selection: str) -> dict:
        bb = self._ensure_blackboard()
        plan_data = bb.get("plan", {})
        findings = plan_data.get("findings", []) if isinstance(plan_data, dict) else []
        findings_text = "\n\n".join(
            f"### Finding {i+1}\n{f.get('content', '')}"
            for i, f in enumerate(findings) if isinstance(f, dict)
        )
        goal = trim(str(self.runtime_reclassify_goal or self._latest_user_goal_text() or ""), 4000)
        # Include loaded skill guidance in synthesis
        bb_skills = bb.get("loaded_skills", {})
        skills_section = ""
        if isinstance(bb_skills, dict) and bb_skills:
            skill_previews = []
            for skey, sinfo in list(bb_skills.items())[:3]:
                preview = trim(str(sinfo.get("preview", "") if isinstance(sinfo, dict) else ""), 300)
                if preview:
                    skill_previews.append(f"- {skey}: {preview}")
            if skill_previews:
                skills_section = (
                    "\n## Available Skills\n"
                    + "\n".join(skill_previews)
                    + "\n\nWhen skills are loaded, each step MUST specify concrete actions:\n"
                    "- Which tool to call (bash, read_file, write_file, etc.)\n"
                    "- Which specific file paths to use (e.g., 'Read uploaded/IEDM_.parsed.md')\n"
                    "- What output to produce at each step\n"
                    "Decompose each skill's workflow into 3-5 substeps based on the skill's instructions.\n\n"
                )
        synthesis_prompt = (
            f"Based on the research findings below, generate a structured plan proposal "
            f"with up to {PLAN_MODE_MAX_OPTIONS} options for the user to choose from.\n\n"
            f"## User Request\n{goal}\n\n"
            f"## Research Findings\n{trim(findings_text, 6000)}\n\n"
            f"{skills_section}"
            f"## Instructions\n"
            f"Call the submit_plan_proposal tool with:\n"
            f"- context: brief background analysis\n"
            f"- options: array of 1-{PLAN_MODE_MAX_OPTIONS} options, each with id (A/B/C), title, summary, steps, pros, cons, risk\n"
            f"- recommended: id of the recommended option\n\n"
            f"STEP QUALITY REQUIREMENTS:\n"
            f"- Each step must be a concrete, actionable instruction (NOT vague like 'analyze reports')\n"
            f"- Include specific file paths (e.g., 'Read uploaded/IEDM_.parsed.md to extract key findings')\n"
            f"- CRITICAL: Only reference scripts and tools that ACTUALLY EXIST in the skill directories or workspace. "
            f"DO NOT invent script names like 'analyze_reports.py' or 'generate_pptx.js' that don't exist. "
            f"Use the real scripts found in /skills/ directories (e.g., project_manager.py, svg_to_pptx.py).\n"
            f"- When a loaded skill defines a specific workflow, follow that workflow's actual tools and scripts.\n"
            f"- For complex tasks, produce 8-15 detailed steps, not 3-5 vague ones\n"
            f"- Each step should be completable in 1-3 tool calls\n"
            f"\nSTEP STRUCTURE — MAJOR STEPS WITH SUB-STEPS:\n"
            f"Organize steps into MAJOR numbered groups. Each major step has:\n"
            f"  1) A summary title line: \"N. Summary Title\" (e.g., \"1. Project Initialization\")\n"
            f"  2) Sub-steps: \"N.1 Sub-step title\\nConcrete details\\nN.2 Next sub-step\\nDetails\"\n"
            f"\nThe steps array should contain one string per MAJOR step. "
            f"Each string starts with the summary title, followed by sub-steps.\n"
            f"\nExample steps array with 3 major steps:\n"
            f"[\n"
            f"  \"1. Project Initialization and Build\\n"
            f"1.1 Initialize project structure\\n"
            f"Create directories: src/python/, src/fortran/, tests/, docs/\\n"
            f"1.2 Configure build system\\n"
            f"Create CMakeLists.txt with Fortran compiler config\\n"
            f"Run: cmake -B build -S . && cmake --build build\",\n"
            f"  \"2. Core Module Implementation\\n"
            f"2.1 Implement data model\\n"
            f"Create src/models/data.py with schema definitions\\n"
            f"2.2 Implement business logic\\n"
            f"Create src/services/processor.py\",\n"
            f"  \"3. Testing and Documentation\\n"
            f"3.1 Unit tests\\n"
            f"Create tests/test_models.py\\n"
            f"Run: pytest tests/\\n"
            f"3.2 Write documentation\\n"
            f"Create docs/README.md\"\n"
            f"]\n"
            f"\nRules:\n"
            f"- Each major step = one array element with summary title + 2-5 sub-steps\n"
            f"- Summary title captures the THEME of that group (not just repeat the first sub-step)\n"
            f"- Sub-steps include specific file paths, commands, or expected outputs\n"
            f"- Aim for 5-8 major steps for complex tasks, 3-5 for simpler ones\n"
            f"\n"
            f"Make options meaningfully different (e.g. different approaches, scope levels, or trade-offs).\n"
            "\nVERIFICATION & TESTING:\n"
            "Judge from the task content and research findings whether the task involves writing, "
            "modifying, or generating code/scripts/configurations. If it does:\n"
            "- Include compile/build/lint verification steps after implementation steps.\n"
            "- Include a dedicated testing step with SPECIFIC run commands (e.g. `python -m pytest`, `npm test`) before final review.\n"
            "- Testing step sub-steps must end with: actually RUNNING the tests and checking exit code, not just writing test files.\n"
            "- For large plans (10+ steps), insert intermediate test checkpoints.\n"
            "- If the task modifies existing code, include a regression test step.\n"
            "- The LAST step must include a sub-step: 'Generate delivery report: summarize what was built, how to run it, and key outputs.'\n"
            "If the task is pure research, analysis, or document generation with no executable code, "
            "skip compile/test steps — use your judgement.\n"
        )
        synthesis_prompt += f"{model_language_instruction(self.ui_language)}"
        synthesis_ctx = [
            {"role": "system", "content": (
                "You are a technical architect synthesizing research into actionable plans. "
                "When skills are referenced in the findings, incorporate their actual workflow steps into plan options. "
                f"{self._skills_awareness_block(for_role='developer')}"
            ), "ts": now_ts()},
            {"role": "user", "content": synthesis_prompt, "ts": now_ts()},
        ]
        response = self._chat_with_same_model_retry(
            synthesis_ctx,
            tools=self._plan_mode_synthesis_tools(),
            system="Generate a structured plan proposal. Use the submit_plan_proposal tool.",
            max_tokens=PLAN_MODE_MANAGER_SYNTHESIS_MAX_TOKENS,
            think=False,
            stream_thinking=False,
            on_thinking_chunk=self._append_live_thinking,
            pinned_selection=pinned_selection,
            context_label="plan-mode synthesis",
            retries=MODEL_OUTPUT_RETRY_TIMES,
        )
        tool_calls = response.get("tool_calls", [])
        for tc in tool_calls:
            if tc.get("function", {}).get("name") == "submit_plan_proposal":
                args = tc["function"].get("arguments", {})
                if isinstance(args, dict) and args.get("options"):
                    return dict(args)
        return {}

    def _synthesis_minimal_fallback(self, pinned_selection: str) -> dict:
        """Last-resort: ask model for a single simple plan with higher max_tokens."""
        goal = trim(str(self.runtime_reclassify_goal or self._latest_user_goal_text() or ""), 2000)
        bb = self._ensure_blackboard()
        findings = bb.get("plan", {}).get("findings", []) if isinstance(bb.get("plan"), dict) else []
        findings_text = "\n".join(
            trim(str(f.get("content", "") if isinstance(f, dict) else ""), 600)
            for f in (findings[:5] if isinstance(findings, list) else [])
        )
        prompt = (
            f"Generate ONE simple plan for this task. Call submit_plan_proposal with exactly 1 option.\n\n"
            f"Task: {goal}\n\nFindings: {trim(findings_text, 3000)}\n\n"
            f"Return a single option with id='A', title, summary, and 5-10 concrete steps.\n"
            f"{model_language_instruction(self.ui_language)}"
        )
        ctx = [
            {"role": "system", "content": "You must call submit_plan_proposal tool.", "ts": now_ts()},
            {"role": "user", "content": prompt, "ts": now_ts()},
        ]
        try:
            response = self._chat_with_same_model_retry(
                ctx,
                tools=self._plan_mode_synthesis_tools(),
                system="Call submit_plan_proposal now.",
                max_tokens=6000,
                think=False,
                stream_thinking=False,
                on_thinking_chunk=self._append_live_thinking,
                pinned_selection=pinned_selection,
                context_label="plan-mode minimal fallback",
                retries=2,
            )
            for tc in response.get("tool_calls", []):
                if tc.get("function", {}).get("name") == "submit_plan_proposal":
                    args = tc["function"].get("arguments", {})
                    if isinstance(args, dict) and args.get("options"):
                        return dict(args)
        except Exception:
            pass
        return {}

    def _has_pending_goal_change(self) -> bool:
        """Check if user sent a substantive goal change (not just plan choice or continuation)."""
        with self.lock:
            for row in self.pending_user_inputs:
                content = str(row.get("content", "") or "").strip().lower()
                if not content:
                    continue
                if content in {
                    "继续", "繼續", "continue", "go on", "接着", "接著", "続行", "続けて",
                    "a", "b", "c", "方案a", "方案b", "方案c", "案a", "案b", "案c",
                    "keep going", "proceed", "確認", "确认",
                }:
                    continue
                if len(content) > 10:
                    return True
        return False

    def _plan_mode_synthesis_tools(self) -> list:
        return [tool_def(
            "submit_plan_proposal",
            "Submit a structured plan proposal with multiple options for user review.",
            {
                "context": {"type": "string", "description": "Background analysis of the task"},
                "options": {
                    "type": "array",
                    "items": {
                        "type": "object",
                        "properties": {
                            "id": {"type": "string"},
                            "title": {"type": "string"},
                            "summary": {"type": "string"},
                            "steps": {"type": "array", "items": {"type": "string"}},
                            "pros": {"type": "string"},
                            "cons": {"type": "string"},
                            "risk": {"type": "string", "enum": ["low", "medium", "high"]},
                        },
                        "required": ["id", "title", "summary", "steps"],
                    },
                },
                "recommended": {"type": "string", "description": "ID of recommended option"},
            },
            ["context", "options", "recommended"],
        )]

    # ── Plan MD File helpers ──────────────────────────────────────────

    def _plan_file_path(self) -> Path:
        """Plan MD file path (inside files_root sandbox, accessible via read_file)."""
        return self.files_root / ".clouds_coder" / "plan.md"

    def _write_plan_file(self, content: str) -> bool:
        """Atomically write plan.md: write tmp → os.replace."""
        import uuid as _uuid_mod
        target = self._plan_file_path()
        target.parent.mkdir(parents=True, exist_ok=True)
        tmp = target.with_suffix(f".{_uuid_mod.uuid4().hex[:8]}.tmp")
        try:
            tmp.write_text(content, encoding="utf-8")
            os.replace(str(tmp), str(target))
            return True
        except Exception:
            try:
                tmp.unlink(missing_ok=True)
            except Exception:
                pass
            return False

    def _read_plan_file(self) -> str:
        """Read plan.md; returns empty string if file does not exist."""
        try:
            p = self._plan_file_path()
            return p.read_text(encoding="utf-8") if p.exists() else ""
        except Exception:
            return ""

    def _build_plan_todos_from_steps(self, raw_steps: list, *, limit: int = 40) -> list[dict]:
        grouped_steps = self._group_plan_steps(raw_steps if isinstance(raw_steps, list) else [])
        plan_todos: list[dict] = []
        for i, step in enumerate(grouped_steps[:max(1, int(limit))]):
            step_text = trim(str(step or "").strip(), 1500)
            if not step_text:
                continue
            step_lines = step_text.split("\n")
            step_header = trim(step_lines[0].strip(), 400)
            plan_todos.append(
                {
                    "id": f"pt:{i:03d}",
                    "content": step_header,
                    "full_content": step_text,
                    "status": "in_progress" if not plan_todos else "pending",
                    "category": "plan_step",
                    "plan_step_index": i,
                    "created_at": float(now_ts()),
                    "completed_at": None,
                    "completed_by": "",
                    "evidence": "",
                }
            )
        return plan_todos

    def _format_plan_file_preselection(self, proposal: dict) -> str:
        """Full MD content with ALL options for model review (no char limit)."""
        lines = [self._ui_text("plan_file_proposals_title")]
        context = str(proposal.get("context", "") or "").strip()
        if context:
            lines.append(self._ui_text("plan_file_background", context=context))
        recommended = str(proposal.get("recommended", "") or "").strip()
        options = proposal.get("options", [])
        if not isinstance(options, list):
            options = []
        for opt in options[:PLAN_MODE_MAX_OPTIONS]:
            if not isinstance(opt, dict):
                continue
            opt_id = str(opt.get("id", "") or "").strip()
            title = str(opt.get("title", "") or "").strip()
            header = self._ui_text("plan_file_option", id=opt_id, title=title)
            if opt_id == recommended:
                header += self._ui_text("plan_file_recommended")
            lines.append("---\n")
            lines.append(header)
            summary = str(opt.get("summary", "") or "").strip()
            if summary:
                lines.append(summary)
            steps = opt.get("steps", [])
            if isinstance(steps, list) and steps:
                lines.append(f"\n{self._ui_text('plan_file_steps')}")
                import re as _re_plan
                _mid_re = _re_plan.compile(r"(?<=\S)\s+(\d+\.\d+\s)")
                for i, s in enumerate(steps):
                    step_str = str(s or "").strip()
                    # Normalize: split mid-string N.N sub-step numbers onto own lines
                    step_str = _mid_re.sub(r"\n\1", step_str)
                    if "\n" in step_str:
                        # Multi-line step: first line as header, rest as nested list
                        step_lines = step_str.split("\n")
                        lines.append(f"{i + 1}. {step_lines[0]}")
                        for sub in step_lines[1:]:
                            stripped = sub.strip()
                            if stripped:
                                lines.append(f"   - {stripped}")
                    else:
                        lines.append(f"{i + 1}. {step_str}")
            pros = str(opt.get("pros", "") or "").strip()
            if pros:
                lines.append(f"\n{self._ui_text('plan_file_pros', text=pros)}")
            cons = str(opt.get("cons", "") or "").strip()
            if cons:
                lines.append(self._ui_text("plan_file_cons", text=cons))
            risk = str(opt.get("risk", "") or "").strip()
            if risk:
                lines.append(self._ui_text("plan_file_risk", text=risk))
            lines.append("")
        lines.append("---")
        lines.append(self._ui_text("plan_file_awaiting_choice"))
        return "\n".join(lines)

    def _format_plan_file_execution(self, choice_id: str) -> str:
        """Render execution-phase plan.md with live step statuses from blackboard."""
        bb = self._ensure_blackboard()
        plan = bb.get("plan", {}) if isinstance(bb.get("plan"), dict) else {}
        plan_choice = str(plan.get("chosen", "") or choice_id).strip() or choice_id
        title = trim(str(plan.get("title", "") or "").strip(), 240)
        summary = trim(str(plan.get("summary", "") or "").strip(), 1200)
        if not title or not summary:
            proposal = self.runtime_plan_proposal or {}
            chosen = next(
                (
                    o for o in proposal.get("options", [])
                    if isinstance(o, dict) and o.get("id") == plan_choice
                ),
                None,
            )
            if not title:
                title = trim(str((chosen or {}).get("title", "") or plan_choice).strip(), 240)
            if not summary:
                summary = trim(str((chosen or {}).get("summary", "") or "").strip(), 1200)
        todos = bb.get("project_todos", [])
        plan_todos = [t for t in todos if t.get("category") == "plan_step"]
        if not plan_todos and isinstance(plan.get("steps"), list):
            plan_todos = self._build_plan_todos_from_steps(plan.get("steps", []))
        total = len(plan_todos)
        completed = sum(1 for t in plan_todos if t.get("status") == "completed")
        active_row = next(
            (t for t in plan_todos if str(t.get("status", "") or "") == "in_progress"),
            None,
        )
        if isinstance(active_row, dict):
            current_idx = int(active_row.get("plan_step_index", 0) or 0) + 1
        elif total > 0:
            current_idx = min(total, completed + (0 if completed >= total else 1))
        else:
            current_idx = 0

        lines = [self._ui_text("active_plan_title", title=title)]
        lines.append(self._ui_text("active_plan_status", current=current_idx, total=total))
        lines.append(self._ui_text("active_plan_chosen", choice=plan_choice))
        from datetime import datetime as _dt_cls
        lines.append(self._ui_text("active_plan_updated", updated=_dt_cls.now().isoformat(timespec="seconds")))
        if summary:
            lines.append(self._ui_text("active_plan_summary", summary=summary))
        lines.append(self._ui_text("active_plan_steps"))
        import re as _re_exec
        _mid_re_exec = _re_exec.compile(r"(?<=\S)\s+(\d+\.\d+\s)")
        for t in plan_todos:
            idx = int(t.get("plan_step_index", 0) or 0) + 1
            full = str(t.get("full_content", "") or t.get("content", "")).strip()
            # Normalize: split concatenated N.N sub-steps onto own lines
            full = _mid_re_exec.sub(r"\n\1", full)
            header = full.split("\n")[0] if "\n" in full else full
            sub_lines = [ln for ln in full.split("\n")[1:] if ln.strip()] if "\n" in full else []
            status = str(t.get("status", "pending") or "pending")
            if status == "completed":
                actor = str(t.get("completed_by", "") or "")
                evidence = str(t.get("evidence", "") or "")
                lines.append(self._ui_text("active_plan_step_done", idx=idx, header=header))
                for sub in sub_lines:
                    lines.append(f"  - {sub.strip()}")
                meta_parts = []
                if actor:
                    meta_parts.append(self._ui_text("active_plan_completed_by", actor=actor))
                if evidence:
                    meta_parts.append(self._ui_text("active_plan_evidence", evidence=evidence))
                if meta_parts:
                    lines.append(f"  > {' | '.join(meta_parts)}")
            elif status == "in_progress":
                lines.append(self._ui_text("active_plan_step_current", idx=idx, header=header))
                for sub in sub_lines:
                    lines.append(f"  - {sub.strip()}")
            else:
                lines.append(self._ui_text("active_plan_step_pending", idx=idx, header=header))
                for sub in sub_lines:
                    lines.append(f"  - {sub.strip()}")
        return "\n".join(lines) + "\n"

    def _update_plan_file_step_status(self) -> bool:
        """Re-render execution-phase plan.md from current blackboard state and write atomically."""
        choice_id = str(self.runtime_plan_choice or "")
        if not choice_id:
            bb = self._ensure_blackboard()
            plan_data = bb.get("plan", {})
            choice_id = str(plan_data.get("chosen", "") if isinstance(plan_data, dict) else "")
        if not choice_id:
            return False
        content = self._format_plan_file_execution(choice_id)
        return self._write_plan_file(content)

    def _format_plan_bubble_preselection(self, proposal: dict) -> str:
        """Condensed bubble for UI (under PLAN_BUBBLE_MAX_CHARS). No full step listing."""
        lines = [self._ui_text("plan_bubble_title")]
        context = str(proposal.get("context", "") or "").strip()
        if context:
            lines.append(self._ui_text("plan_bubble_background", context=trim(context, 300)))
        recommended = str(proposal.get("recommended", "") or "").strip()
        options = proposal.get("options", [])
        if not isinstance(options, list):
            options = []
        for opt in options[:PLAN_MODE_MAX_OPTIONS]:
            if not isinstance(opt, dict):
                continue
            opt_id = str(opt.get("id", "") or "").strip()
            title = str(opt.get("title", "") or "").strip()
            is_rec = opt_id == recommended
            header = self._ui_text("plan_bubble_option", id=opt_id, title=title)
            if is_rec:
                header += self._ui_text("plan_bubble_recommended")
            lines.append(header)
            summary = str(opt.get("summary", "") or "").strip()
            if summary:
                lines.append(trim(summary, 200))
            steps = opt.get("steps", [])
            step_count = len(steps) if isinstance(steps, list) else 0
            risk = str(opt.get("risk", "") or "").strip()
            meta = self._ui_text("plan_bubble_steps", count=step_count)
            if risk:
                meta += f" | {self._ui_text('plan_bubble_risk', risk=risk)}"
            lines.append(meta)
            lines.append("")
        lines.append("---")
        lines.append(self._ui_text("plan_bubble_full_ref", path=PLAN_FILE_RELATIVE_PATH))
        lines.append(self._ui_text("plan_bubble_reply"))
        return trim("\n".join(lines), PLAN_BUBBLE_MAX_CHARS)

    def _plan_file_read_instruction(self) -> str:
        """Short instruction for models: read the plan file instead of embedding full plan text."""
        # Find active step id for parent_step_id linkage
        bb = self._ensure_blackboard()
        active_step_id = ""
        active_step_idx = 0
        for t in bb.get("project_todos", []):
            if isinstance(t, dict) and t.get("category") == "plan_step" and t.get("status") == "in_progress":
                active_step_id = str(t.get("id", "") or "")
                active_step_idx = int(t.get("plan_step_index", 0) or 0) + 1
                break
        todo_note = ""
        if active_step_id:
            todo_note = self._ui_text(
                "plan_read_todo_note",
                step_label=self._ui_text("plan_step_label", step=active_step_idx, total=int(bb.get("plan_step_total", 0) or 0)),
                parent_step_id=active_step_id,
            )
        return (
            self._ui_text("plan_read_instruction", path=PLAN_FILE_RELATIVE_PATH)
            + todo_note
        )

    def _inject_current_plan_step_execution_hints(self):
        """Inject the active-step plan/todo hints after plan approval or step advance."""
        bb = self._ensure_blackboard()
        step = self._current_plan_step_row(bb)
        if not isinstance(step, dict):
            return
        total = int(bb.get("plan_step_total", 0) or 0)
        step_idx = int(step.get("plan_step_index", 0) or 0) + 1
        step_text = trim(str(step.get("content", "") or ""), 200)
        step_id = str(step.get("id", "") or "")
        step_label = self._ui_text("plan_step_label", step=step_idx, total=max(1, total))
        hint_rows: list[str] = []
        plan_msg = trim(self._plan_file_read_instruction(), 2000)
        if plan_msg:
            hint_rows.append(plan_msg)
        step_hint = trim(
            self._ui_text(
                "plan_step_hint",
                step_label=step_label,
                step_text=step_text,
                plan_path=PLAN_FILE_RELATIVE_PATH,
                parent_step_id=step_id,
            ),
            2000,
        )
        if step_hint and step_hint not in hint_rows:
            hint_rows.append(step_hint)
        if not hint_rows:
            return
        target_roles = ("explorer", "developer") if self._is_multi_agent_mode() else ()
        for content in hint_rows:
            self._append_plan_guidance_bubble(
                content,
                target_roles=target_roles,
                summary="plan guidance bubble injected",
            )

    @staticmethod
    def _group_plan_steps(raw_steps: list) -> list[str]:
        """Group flat step array by major step number (first digit of N.N).

        All 1.x sub-steps merge into one logical step, all 2.x into another, etc.
        If a step has the format "N. Summary title" (single digit, no sub-number),
        it becomes the group header. Otherwise a header is synthesized from the
        first sub-step.

        Handles LLM output where sub-steps may be separate array elements OR
        concatenated in one string with spaces/newlines.

        Returns a list where each element is one major step (multi-line string):
          "1. Summary Title\\n1.1 Sub-step A\\nDetail...\\n1.2 Sub-step B\\n..."
        """
        import re
        if not raw_steps or not isinstance(raw_steps, list):
            return list(raw_steps or [])
        # Patterns
        sub_step_re = re.compile(r"^(\d+)\.(\d+)\s")   # "N.M ..."
        major_step_re = re.compile(r"^(\d+)\.\s")       # "N. ..." (summary line)
        mid_numbered_re = re.compile(r"(?<=\S)\s+(\d+\.\d+\s)")
        # Phase 0: Normalize — split mid-string N.N onto own lines
        normalized: list[str] = []
        for s in raw_steps:
            text = str(s or "").strip()
            if not text:
                continue
            fixed = mid_numbered_re.sub(r"\n\1", text)
            for line in fixed.split("\n"):
                stripped = line.strip()
                if stripped:
                    normalized.append(stripped)
        if not normalized:
            return [str(s) for s in raw_steps if str(s or "").strip()]
        # Phase 1: Check if any N.N sub-step headers exist
        has_sub_steps = any(sub_step_re.match(ln) for ln in normalized)
        if not has_sub_steps:
            return normalized
        # Phase 2: Group by major number (first digit of N.N)
        from collections import OrderedDict
        major_groups: OrderedDict[str, list[str]] = OrderedDict()
        major_headers: dict[str, str] = {}  # major_num → "N. Summary" if provided
        orphan_lines: list[str] = []
        current_major: str = ""
        for line in normalized:
            m_sub = sub_step_re.match(line)
            m_major = major_step_re.match(line)
            if m_sub:
                major_num = m_sub.group(1)
                current_major = major_num
                if major_num not in major_groups:
                    major_groups[major_num] = []
                major_groups[major_num].append(line)
            elif m_major:
                # "N. Summary title" line → store as header for this major group
                major_num = m_major.group(1)
                current_major = major_num
                major_headers[major_num] = line
                if major_num not in major_groups:
                    major_groups[major_num] = []
            else:
                # Detail line → attach to current major group
                if current_major and current_major in major_groups:
                    major_groups[current_major].append(line)
                else:
                    orphan_lines.append(line)
        # Phase 3: Build output — each major group becomes one step
        result: list[str] = []
        if orphan_lines:
            result.append("\n".join(orphan_lines))
        for major_num, lines in major_groups.items():
            if not lines:
                continue
            header = major_headers.get(major_num, "")
            if not header:
                # Synthesize header from first sub-step: "N. <first sub-step title>"
                first_sub = lines[0]
                m = sub_step_re.match(first_sub)
                if m:
                    # Extract title part after "N.M "
                    title_part = first_sub[m.end():].split("\n")[0].strip()
                    # Remove detail after title (heuristic: title is before first Chinese/action verb)
                    header = f"{major_num}. {title_part}" if title_part else f"{major_num}. Step {major_num}"
                else:
                    header = f"{major_num}. Step {major_num}"
            result.append(header + "\n" + "\n".join(lines))
        return result

    # ── (legacy) _format_plan_proposal_markdown ──────────────────────

    def _format_plan_proposal_markdown(self, proposal: dict) -> str:
        lines = [self._ui_text("plan_proposal_title")]
